#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        int min_val_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_val_idx]) {
                min_val_idx = i;
            }
        }

        long long total_spells = 0;
        long long min_val = a[min_val_idx];

        for (int i = 0; i < n; ++i) {
            if (i == min_val_idx) {
                continue;
            }
            // Calculate how many times min_val can be added to a[i]
            // without exceeding k.
            // a[i] + x * min_val <= k
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

