#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for both coal and crafting: k * y + k.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks.
        long long sticks_to_acquire = total_sticks_required - 1;

        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades needed: ceil(sticks_to_acquire / (x - 1)).
        // Using integer division for ceil: (a + b - 1) / b
        long long type1_trades = (sticks_to_acquire + (x - 1) - 1) / (x - 1);

        // Total trades = type1_trades (to get enough sticks) + k (to get k coal)
        long long total_trades = type1_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

