#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> result;
        // We need to select n numbers.
        // The strategy is to select n even numbers,
        // specifically starting from 4n and going downwards by 2,
        // skipping numbers that are multiples of 4.
        // This ensures:
        // 1. All numbers are even, so gcd(a,b) >= 2.
        // 2. No number divides another.
        //    If a | b, then b = k*a.
        //    If a and b are both of the form 2*(2m+1), then k must be odd.
        //    If k is odd and k > 1, then b >= 3a.
        //    By selecting numbers that are "close" to each other,
        //    we can avoid this.
        //    Specifically, we select numbers of the form 2 * (2k+1).
        //    These are 6, 10, 14, 18, 22, ...
        //    If we pick n such numbers, say x_1 < x_2 < ... < x_n.
        //    If x_i | x_j, then x_j = k * x_i.
        //    Since all x_i are of the form 2 * odd, then k must be odd.
        //    The smallest odd k > 1 is 3. So x_j >= 3 * x_i.
        //    The numbers we pick are 4n-2, 4n-6, 4n-10, ...
        //    The largest number is 4n-2.
        //    The smallest number we pick will be 4n - 2 - 4*(n-1) = 4n - 2 - 4n + 4 = 2.
        //    However, we need to ensure that the numbers are not multiples of each other.
        //    The problem statement example for n=3 gives 4 6 10.
        //    Here 4 is 2*2, 6 is 2*3, 10 is 2*5.
        //    gcd(4,6)=2, gcd(4,10)=2, gcd(6,10)=2.
        //    No number divides another.
        //    The example for n=4 gives 14 10 12 8.
        //    These are 2*7, 2*5, 2*6, 2*4.
        //    All are even. No number divides another.
        //    The strategy is to pick numbers from 4n down to 1,
        //    taking every second number, but skipping multiples of 4.
        //    This means we pick numbers of the form 2 * (odd number).
        //    For example, for n=2, 4n=8.
        //    Numbers are 8, 7, 6, 5, 4, 3, 2, 1.
        //    We need 2 numbers.
        //    Start from 4n.
        //    4n-2, 4n-6, 4n-10, ...
        //    For n=2, 4n=8.
        //    8-2=6. Add 6.
        //    8-6=2. Add 2.
        //    Result: 6 2. (Example output: 6 4. My strategy gives 6 2. Both are valid.)
        //    Let's re-evaluate the example output.
        //    n=2: 6 4. gcd(6,4)=2. 4 does not divide 6, 6 does not divide 4. Valid.
        //    n=3: 4 6 10. gcd(4,6)=2, gcd(4,10)=2, gcd(6,10)=2. Valid.
        //    n=4: 14 10 12 8. All are even. No number divides another. Valid.
        //    The example outputs seem to pick numbers that are all even.
        //    And they are not necessarily of the form 2 * odd.
        //    For n=4, 12 and 8 are multiples of 4.
        //    The key is that all numbers are even, so gcd is at least 2.
        //    And no number divides another.
        //    If we pick numbers from 4n down to 1, and only pick even numbers,
        //    and ensure no number divides another.
        //    A simple strategy: pick numbers 4n-2, 4n-4, 4n-6, ..., 4n-2*n.
        //    This gives n even numbers.
        //    The numbers would be 4n-2, 4n-4, ..., 2n.
        //    Let's check this strategy.
        //    All numbers are even, so gcd(a,b) >= 2. Condition 1 satisfied.
        //    Do any of these numbers divide another?
        //    Let a = 2k and b = 2j, where k, j are integers.
        //    The numbers are 2n, 2n+2, ..., 4n-2.
        //    If a divides b, then b = m*a for some integer m.
        //    Since a and b are even, m can be any integer.
        //    The smallest number is 2n. The largest is 4n-2.
        //    If 2n divides any other number 2j in the set, then 2j = m * 2n => j = m*n.
        //    The numbers are 2n, 2n+2, ..., 4n-2.
        //    The multiples of 2n in this range are only 2n itself (m=1).
        //    If m=2, then 2*2n = 4n. This is not in the set (4n-2 is max).
        //    So 2n does not divide any other number in the set.
        //    Consider any two numbers 2k and 2j from the set, where 2n <= 2k < 2j <= 4n-2.
        //    If 2k divides 2j, then 2j = m * 2k => j = m*k.
        //    Since 2k < 2j, m must be >= 2.
        //    So 2j >= 2 * 2k = 4k.
        //    But 2j <= 4n-2.
        //    And 2k >= 2n.
        //    So 4k >= 4n.
        //    This means 2j >= 4n.
        //    However, the maximum value in our set is 4n-2.
        //    So 2j cannot be >= 4n.
        //    Therefore, no number in the set {2n, 2n+2, ..., 4n-2} can divide another number in the set.
        //    This strategy works!

        for (int i = 0; i < n; ++i) {
            result.push_back(4 * n - 2 * i);
        }
        // The numbers generated are 4n, 4n-2, 4n-4, ..., 4n-2*(n-1).
        // This is 4n, 4n-2, ..., 2n+2.
        // This set has n numbers.
        // All are even, so gcd(a,b) >= 2.
        // Smallest is 2n+2. Largest is 4n.
        // If a | b, then b = m*a. Since a,b are even, m can be any integer.
        // Since a < b, m >= 2.
        // So b >= 2a.
        // Smallest number is 2n+2.
        // If 2n+2 divides any other number b in the set, then b >= 2*(2n+2) = 4n+4.
        // But the largest number in the set is 4n.
        // So no number can divide another.
        // This strategy is correct and simpler.

        // Let's re-check the example outputs with this strategy:
        // n=2: 4n=8. Numbers: 8, 6. Output: 6 4. My strategy: 8 6. Both valid.
        // n=3: 4n=12. Numbers: 12, 10, 8. Output: 4 6 10. My strategy: 12 10 8. Both valid.
        // n=4: 4n=16. Numbers: 16, 14, 12, 10. Output: 14 10 12 8. My strategy: 16 14 12 10. Both valid.

        // The strategy is to pick n numbers: 4n, 4n-2, 4n-4, ..., 4n-2*(n-1).
        // This is equivalent to picking 2n+2, 2n+4, ..., 4n.
        // Let's print them in increasing order for consistency, though order doesn't matter.
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 + 2 * i << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

