int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_post_sum = total_sum / k;
    std::vector<int> s_values;
    long long current_sum = 0;
    int current_post_videos_count = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_sum += a[i];
        current_post_videos_count++;

        if (current_sum == target_post_sum) {
            s_values.push_back(current_post_videos_count);
            current_sum = 0;
            current_post_videos_count = 0;
            posts_found++;
        } else if (current_sum > target_post_sum) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        // This case should ideally be caught by current_sum > target_post_sum
        // or posts_found != k at the end.
        // If current_sum < target_post_sum after loop, it means last post didn't sum up.
        // If current_sum == 0 but posts_found != k, it means we didn't find k posts.
        // The logic ensures that if we reach here, it's a "No".
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>
