int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last element

        // Iterate from the second to last element backwards
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is the new minimum for the suffix starting at i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_one = false;
    bool has_minus_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No operation needed for this element, or it's already correct.
            // If a[i] was 1 or -1, it contributes to has_one/has_minus_one for elements before it.
            // If a[i] was 0, it doesn't affect has_one/has_minus_one.
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. This requires a previous element to be 1.
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. This requires a previous element to be -1.
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // Update has_one and has_minus_one for the next iteration (elements with index < i).
        // The current a[i] is no longer available as a source for elements with index < i.
        // So, if a[i] was the only 1 or -1, we need to reflect that.
        // However, the problem states "choose any pair (i, j) such that 1 <= i < j <= n".
        // This means a[k] for k < i can be used to modify a[i].
        // The values `has_one` and `has_minus_one` track if there's *any* 1 or -1
        // in the prefix `a[0...i-1]`.
        // When we process `a[i]`, we need to know if `a[0...i-1]` contains 1 or -1.
        // After processing `a[i]`, we move to `a[i-1]`.
        // The `has_one` and `has_minus_one` flags should represent the state of `a[0...i-1]`
        // for the current `i`.
        // So, we update them *after* checking `a[i]`.
        if (a[i] == 1) {
            has_one = false; // This 1 is now "used up" for future elements (i.e., elements to its left)
                             // It means we can't use a[i] to modify a[k] where k < i.
                             // We need to check if there's another 1 in a[0...i-1].
                             // This requires re-scanning or maintaining counts.
                             // Let's re-evaluate the logic for has_one/has_minus_one.
        }
        if (a[i] == -1) {
            has_minus_one = false;
        }
    }

    // The above logic for `has_one` and `has_minus_one` is flawed.
    // `has_one` should indicate if there is *any* `a[k] == 1` for `k < i`.
    // `has_minus_one` should indicate if there is *any* `a[k] == -1` for `k < i`.
    // Let's restart the loop with correct tracking.

    has_one = false;
    has_minus_one = false;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            has_one = true;
        } else if (a[i] == -1) {
            has_minus_one = true;
        }
    }

    possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            // No action needed for a[i].
        } else if (a[i] < b[i]) {
            // Need to increase a[i]. Requires a 1 from a[0...i-1].
            if (!has_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i]
            // Need to decrease a[i]. Requires a -1 from a[0...i-1].
            if (!has_minus_one) {
                possible = false;
                break;
            }
        }

        // After processing a[i], this element a[i] is no longer available as a source
        // for elements to its left (i.e., for a[k] where k < i).
        // So, if a[i] was the only 1 or -1 in the prefix a[0...i],
        // then for the next iteration (i-1), has_one/has_minus_one might change.
        // This means we need to track counts, not just boolean flags.

        // Let's use a different approach:
        // Iterate from left to right.
        // For a[0], it must be equal to b[0] because no element can be added to it.
        // For a[i], it can be modified by any a[k] where k < i.
        // So, to make a[i] equal to b[i]:
        // If a[i] < b[i], we need to add positive values. This requires at least one '1' in a[0...i-1].
        // If a[i] > b[i], we need to add negative values. This requires at least one '-1' in a[0...i-1].
        // If a[i] == b[i], no action needed.

        // The crucial observation is that the values a[k] (k < i) are *original* values.
        // The problem states "Add a_i to a_j". This means the *current* value of a_i is added.
        // However, the example "transform [1, -1, 0] to [1, -1, -2]" by (2,3) twice, then (1,2) twice.
        // Initial: [1, -1, 0]
        // (2,3) twice: a[2] = a[2] + a[1] = 0 + (-1) = -1. Array: [1, -1, -1]
        //              a[2] = a[2] + a[1] = -1 + (-1) = -2. Array: [1, -1, -2]
        // (1,2) twice: a[1] = a[1] + a[0] = -1 + 1 = 0. Array: [1, 0, -2]
        //              a[1] = a[1] + a[0] = 0 + 1 = 1. Array: [1, 1, -2]
        // This implies that a[i] can change, and then that changed a[i] can be used to modify a[j] (j > i).
        // This makes the problem much harder, as the available '1's and '-1's can propagate.

        // Let's re-read the problem statement very carefully:
        // "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // This is ambiguous. Does a_i refer to the *original* a_i or the *current* a_i?
        // The example implies *current* a_i.
        // If it's current a_i, then the values of a[k] (k < i) can change, and those changed values can be added to a[i].
        // This means a[0] can never change.
        // a[1] can be changed by a[0].
        // a[2] can be changed by a[0] or a[1] (which itself might have been changed by a[0]).

        // Let's consider the elements from left to right (i = 0 to n-1).
        // For a[0]: it cannot be changed. So, a[0] must be equal to b[0]. If not, impossible.
        // For a[i] (i > 0):
        // We need to transform a[i] to b[i].
        // The elements a[0], ..., a[i-1] are available to modify a[i].
        // Let's say we have counts of 1s and -1s in the prefix a[0...i-1].
        // Let `ones_count` be the number of 1s in `a[0...i-1]`.
        // Let `minus_ones_count` be the number of -1s in `a[0...i-1]`.
        // If `a[i] < b[i]`: We need to add `b[i] - a[i]` to `a[i]`. This requires adding positive values.
        //   This is possible if `ones_count > 0`.
        // If `a[i] > b[i]`: We need to add `b[i] - a[i]` to `a[i]`. This requires adding negative values.
        //   This is possible if `minus_ones_count > 0`.
        // If `a[i] == b[i]`: No operations needed for `a[i]`.

        // The key is that once an element `a[k]` (where `k < i`) is used to modify `a[i]`,
        // its value `a[k]` is not consumed. It remains available to modify `a[i]` again, or `a[j]` (j > i).
        // So, we only need to know if there *exists* a 1 or a -1 in the prefix.

        // Let's try the left-to-right approach with boolean flags for existence.
        // `can_add_one` means there's at least one '1' in `a[0...i-1]`.
        // `can_add_minus_one` means there's at least one '-1' in `a[0...i-1]`.

        bool can_add_one = false;
        bool can_add_minus_one = false;
        bool possible_final = true;

        for (int i = 0; i < n; ++i) {
            if (i == 0) {
                if (a[0] != b[0]) {
                    possible_final = false;
                    break;
                }
            } else {
                if (a[i] < b[i]) {
                    if (!can_add_one) {
                        possible_final = false;
                        break;
                    }
                } else if (a[i] > b[i]) {
                    if (!can_add_minus_one) {
                        possible_final = false;
                        break;
                    }
                }
            }

            // Update flags for the next iteration (i+1)
            if (a[i] == 1) {
                can_add_one = true;
            } else if (a[i] == -1) {
                can_add_minus_one = true;
            }
        }

        if (possible_final) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
}

