        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            int val;
            std::cin >> val;
            if (i != j) { // Only consider a_i,j where i != j
                max_val_in_row = std::max(max_val_in_row, val);
            }
        }
        // If max_val_in_row is 0, it means all other p_j are 0, which is impossible for a permutation of 1 to n.
        // This case only happens if n=1, but problem constraints say n >= 2.
        // If max_val_in_row is 0, it means all a_i,j for j!=i are 0.
        // This implies min(p_i, p_j) = 0 for all j!=i.
        // This would mean p_i = 0 or p_j = 0, which is not possible for 1 to n.
        // The only way max_val_in_row could be 0 is if n=1, but n>=2.
        // So max_val_in_row will always be at least 1.
        p[i] = max_val_in_row;
    }

    // Check if any element in p is 0. If so, it means that p_i must be n.
    // This happens if all other p_j are smaller than p_i, and the largest of those p_j is 0.
    // This logic is flawed. The max_val_in_row is the largest of min(p_i, p_j).
    // If p_i is the largest element (n), then min(p_i, p_j) = p_j.
    // So max_val_in_row would be max(p_j) for j!=i, which is n-1.
    // If p_i is not n, then p_i < n.
    // Then max_val_in_row = max_{j!=i} (min(p_i, p_j)).
    // This value will be p_i if there is some p_j > p_i.
    // Or it will be max_{j!=i, p_j < p_i} (p_j) if all p_j < p_i.
    // The key insight is that if p_i is not n, then there must be some p_k = n.
    // For that p_k, a_i,k = min(p_i, p_k) = min(p_i, n) = p_i.
    // So p_i must appear as one of the a_i,j values.
    // Therefore, max_val_in_row will be p_i if p_i is not n.
    // If p_i is n, then max_val_in_row will be n-1 (the largest element other than n).
    // So, if p_i is n, the calculated max_val_in_row will be n-1.
    // If p_i is not n, the calculated max_val_in_row will be p_i.
    // This means that if p[i] (calculated as max_val_in_row) is n-1, it could be that the actual p_i is n.
    // We need to find if any p[i] is n-1 and if all other p[j] are distinct and less than n.
    // If there is no 'n' in the reconstructed permutation, it means one of the 'n-1's should actually be 'n'.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means one of the elements that was supposed to be n
        // was calculated as n-1 (because min(n, p_j) = p_j, and max of p_j for j!=i is n-1).
        // We need to find an element that is n-1 and change it to n.
        // Since it's guaranteed a solution exists, there will be exactly one such element.
        // Or, more generally, we need to find the missing number from 1 to n.
        // The values in p are {p_1, p_2, ..., p_n} where one of them is n-1 and should be n,
        // and the rest are the actual values.
        // The set of values {p_0, ..., p_{n-1}} will contain all numbers from 1 to n-1,
        // but one number will be duplicated (the one that should be n-1, but is now n-1 because the actual n was replaced by n-1).
        // And the number n will be missing.
        // Example: n=3, p={1,2,3}.
        // p_0=1: max(min(1,2), min(1,3)) = max(1,1) = 1.
        // p_1=2: max(min(2,1), min(2,3)) = max(1,2) = 2.
        // p_2=3: max(min(3,1), min(3,2)) = max(1,2) = 2.
        // So calculated p would be {1,2,2}.
        // Here, n=3 is missing. One of the 2s should be 3.
        // We need to find the value that is missing from the set {1, ..., n}.
        // The sum of numbers from 1 to n is n*(n+1)/2.
        // The sum of numbers in our current p is sum(p_i).
        // The difference (n*(n+1)/2 - sum(p_i)) will be the missing number.
        // No, this is not correct. The sum of p_i will be sum(1..n-1) + (n-1) = n*(n-1)/2 + (n-1).
        // The missing number is n.
        // The number that is duplicated is n-1.
        // So, we need to find an element that is n-1 and change it to n.
        // Since it's guaranteed a solution exists, there will be exactly one such element.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
