int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) + 1 = i - last_r_pos.
                // Or simply, the distance from last_r_pos to i+1 is (i+1) - last_r_pos.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1); // Distance from last_r_pos+1 to i+1
                last_r_pos = i; // Update last_r_pos to current 'R' cell index (0-indexed)
            }
        }
        // After the loop, consider the jump from the last 'R' to n+1.
        // The last 'R' was at last_r_pos (0-indexed).
        // The cell is last_r_pos + 1 (1-indexed).
        // The target is n+1.
        // The distance is (n + 1) - (last_r_pos + 1) + 1 = n - last_r_pos + 1.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 is always q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i was not seen before as a prefix max.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number less than q_i (which is q_{i-1})
            // and not yet used. We need to find the smallest available number.
            // The numbers available are those from 1 to n that are not in used_numbers.
            // We need to find the largest available number that is less than q_i.
            // Or, more simply, we can fill these in later.
            // For now, mark p_i as a placeholder (e.g., 0) and fill it with available numbers.
            p[i] = 0; // Placeholder
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order

    // Fill in the placeholders (p_i where q_i == q_{i-1})
    int current_available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (p[i] == 0) { // This is a placeholder
            if (current_available_idx >= available_numbers.size()) {
                possible = false; // Not enough available numbers
                break;
            }
            int num_to_assign = available_numbers[current_available_idx];
            if (num_to_assign > q[i]) { // q[i] is q_{i-1} here
                possible = false; // Cannot assign a number larger than the current prefix max
                break;
            }
            p[i] = num_to_assign;
            current_available_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

