    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long k = 1;            // k for the current staircase (n = 2^k - 1)
        while (true) {
            if (x >= current_cost) {
                x -= current_cost;
                count++;
                k++;
                // Calculate cost for the next staircase (n = 2^k - 1)
                // The cost for n = 2^k - 1 is (2^k - 1) * (2^k) / 2
                // This can be rewritten as (2^k - 1) * 2^(k-1)
                // The previous cost was (2^(k-1) - 1) * 2^(k-2)
                // The difference in cost is (2^k - 1) * 2^(k-1) - (2^(k-1) - 1) * 2^(k-2)
                // This is not how the recurrence works.
                // The recurrence is: cost(k) = 2 * cost(k-1) + 2^(k-1)
                // cost(k) = (2^k - 1) * 2^(k-1)
                // Let's calculate it directly to avoid overflow with intermediate 2^k
                // The cost for n = 2^k - 1 is (2^k - 1) * 2^(k-1)
                // We need to calculate (2^k - 1) * 2^(k-1)
                // This is equivalent to (2^(k-1) * 2 - 1) * 2^(k-1)
                // Or (2^k - 1) * (2^k / 2)
                // The previous cost was (2^(k-1) - 1) * 2^(k-2)
                // The next cost is (2^k - 1) * 2^(k-1)
                // This can be written as (2 * (2^(k-1)) - 1) * 2^(k-1)
                // Let's use the recurrence relation:
                // C_k = 2 * C_{k-1} + 2^(k-1)
                // C_1 = 1 (for n=1)
                // C_2 = 2*1 + 2^1 = 4 (for n=3)
                // C_3 = 2*4 + 2^2 = 12 (for n=7)
                // C_4 = 2*12 + 2^3 = 32 (for n=15)
                // C_k = (2^k - 1) * 2^(k-1)
                // The recurrence is C_k = 2 * C_{k-1} + 2^(k-1)
                // C_k = 2 * C_{k-1} + (1LL << (k-1))
                // Check for overflow before calculating next_cost
                // Max x is 10^18.
                // If current_cost is already very large, 2 * current_cost might overflow.
                // 2^(k-1) can also be large.
                // The maximum value for current_cost is when k is around 60.
                // For k=60, 2^(k-1) is 2^59.
                // current_cost for k=60 is (2^60 - 1) * 2^59. This is approx 2^119, which overflows long long.
                // Let's check the maximum k for which current_cost fits in long long.
                // (2^k - 1) * 2^(k-1) <= 10^18
                // Approx 2^(2k-1) <= 10^18
                // 2k-1 <= log2(10^18) approx 18 * log2(10) approx 18 * 3.32 approx 59.79
                // 2k-1 <= 59
                // 2k <= 60
                // k <= 30
                // So k can go up to 30.
                // For k=30, current_cost = (2^30 - 1) * 2^29.
                // 2^30 approx 10^9. 2^29 approx 0.5 * 10^9.
                // current_cost approx 0.5 * 10^18. This fits.
                // Next k=31: current_cost = (2^31 - 1) * 2^30. This is approx 10^18 * 10^9 = 10^27, overflows.
                // So we need to be careful with the calculation of current_cost.
                // The recurrence C_k = 2 * C_{k-1} + 2^(k-1) is safer.
                // We need to check if 2 * current_cost + (1LL << (k-1)) overflows.
                // (1LL << (k-1)) is 2^(k-1).
                // If k-1 >= 63, then (1LL << (k-1)) overflows.
                // So if k >= 64, we stop.
                if (k >= 63) { // 2^(k-1) would overflow if k-1 >= 63
                    break;
                }
                long long term_2_pow_k_minus_1 = (1LL << (k - 1));
                // Check for overflow for 2 * current_cost
                if (current_cost > (LLONG_MAX / 2)) { // LLONG_MAX is from <climits>
                    break;
                }
                long long next_cost_candidate = 2 * current_cost;
                // Check for overflow for next_cost_candidate + term_2_pow_k_minus_1
                if (next_cost_candidate > (LLONG_MAX - term_2_pow_k_minus_1)) {
                    break;
                }
                current_cost = next_cost_candidate + term_2_pow_k_minus_1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The total number of students available: 3 * k <= c + m + x
        // 2. The number of coders available: k <= c (since each team needs at least one coder)
        // 3. The number of mathematicians available: k <= m (since each team needs at least one mathematician)
        //
        // Combining these, k must be less than or equal to min(c, m, (c + m + x) / 3).
        //
        // Let's prove this.
        // Suppose we form 'k' teams.
        // We need at least 'k' coders and at least 'k' mathematicians.
        // So, c >= k and m >= k.
        // The remaining students are (c - k) coders, (m - k) mathematicians, and 'x' students with no specialization.
        // The total number of remaining students is (c - k) + (m - k) + x.
        // Each of the 'k' teams needs 3 members. We've already assigned 1 coder and 1 mathematician to each.
        // So, each team still needs 1 more member.
        // These 'k' additional members must come from the remaining students.
        // Thus, (c - k) + (m - k) + x >= k.
        // c + m + x - 2k >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3
        //
        // So, the maximum number of teams is indeed min(c, m, (c + m + x) / 3).
        // This logic holds because if we can satisfy these conditions, we can always form the teams.
        // For example, if k = min(c, m, (c + m + x) / 3):
        // We take k coders and k mathematicians.
        // We have c-k coders, m-k mathematicians, and x unspecialized students left.
        // Total remaining students: (c-k) + (m-k) + x.
        // We need to assign one more student to each of the k teams.
        // We know (c-k) + (m-k) + x >= k (from the derivation c+m+x >= 3k).
        // So we have enough students to fill the third slot for each team.
        // We can prioritize using unspecialized students first, then coders, then mathematicians.
        // This strategy ensures that we meet the "at least one coder, at least one mathematician" requirement for each team,
        // and we have enough total students to fill all 3*k slots.

        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

