int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right ends of the range [1, k+1]
    // For example, if k=2, range is [1,3]. We want diffs 1, 2.
    // 1, 3, 2. Diffs: |1-3|=2, |3-2|=1.
    // If k=3, range is [1,4]. We want diffs 1, 2, 3.
    // 1, 4, 2, 3. Diffs: |1-4|=3, |4-2|=2, |2-3|=1.
    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) {
            p[i] = left++;
        } else {
            p[i] = right--;
        }
    }

    // For the remaining n - (k+1) elements, we need to ensure no new distinct differences are introduced.
    // The smallest difference generated by the first k+1 elements is 1.
    // If we append numbers in increasing order from k+2 to n, the differences will all be 1.
    // For example, if k=2, n=5. First k+1=3 elements: 1, 3, 2.
    // Remaining elements: 4, 5. Append them: 1, 3, 2, 4, 5.
    // Diffs: |1-3|=2, |3-2|=1, |2-4|=2, |4-5|=1.
    // Distinct diffs: {1, 2}. Count is 2. This works.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

