void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index 'i' such that a[i] < a[i-1]
    // This marks the end of the non-increasing suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now, a[i...n-1] is non-increasing.
    // If i is 0, the whole array is non-increasing.

    // Find the rightmost index 'j' such that a[j] > a[j-1]
    // This marks the end of the non-decreasing suffix
    // We start searching from 'i' because any elements before 'i'
    // are part of the prefix that must be removed anyway if 'i' is not 0.
    // If a[i...n-1] is non-increasing, then a[i] is the smallest element
    // in that suffix that could potentially start a non-decreasing sequence.
    // We need to find the first element from the right that breaks the non-decreasing property.
    // So, we look for a[j-1] > a[j] starting from i-1 down to 0.
    int j = i; // Start from the point where the non-increasing suffix begins
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now, a[j...i-1] is non-decreasing.
    // The elements a[j...n-1] form the candidate suffix.
    // The length of the prefix to remove is j.

    std::cout << j << std::endl;
}

