#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::vector<std::string> result(4);

    if (total_toys == 1) {
        result[0] = (a == 1) ? "Ya" : "Tidak";
        result[1] = (b == 1) ? "Ya" : "Tidak";
        result[2] = (c == 1) ? "Ya" : "Tidak";
        result[3] = (d == 1) ? "Ya" : "Tidak";
    } else {
        // Box 1: (-inf, -1]
        // Final toy must be negative and magnitude >= 1
        // This requires an odd number of negative factors.
        // This requires at least one factor with magnitude >= 1.
        // It's possible to achieve this if:
        // 1. There's an odd number of negative toys (b_neg_count % 2 == 1).
        // 2. There's at least one toy with magnitude >= 1 (a+d > 0).
        // 3. It's possible to make the final magnitude >= 1.
        //    This is always possible if a+d > 0, by strategically multiplying with small values.
        //    E.g., if we have a toy in Box 4 (value > 1) and a toy in Box 2 (value < 0),
        //    we can make the final value in Box 1 by multiplying the Box 4 toy with a Box 2 toy
        //    that has a sufficiently large magnitude (e.g., -0.9) and then multiplying with other toys.
        //    The only way to *not* be able to make magnitude >= 1 is if all initial toys have magnitude < 1 (b+c == total_toys).
        //    But if a+d > 0, then we have at least one toy with magnitude >= 1.
        //    So, if a+d > 0, we can always make the final magnitude >= 1.
        //    If a+d == 0, then all toys are in B or C. All products will have magnitude < 1.
        //    So, if a+d == 0, Box 1 and Box 4 are impossible.
        bool can_be_box1 = false;
        if (a + d > 0) { // At least one toy with magnitude >= 1
            if ((a + b) % 2 == 1) { // Odd number of negative toys
                can_be_box1 = true;
            }
        }
        result[0] = can_be_box1 ? "Ya" : "Tidak";

        // Box 2: (-1, 0)
        // Final toy must be negative and magnitude < 1
        // This requires an odd number of negative factors.
        // This requires that it's possible to make the final magnitude < 1.
        // This is always possible if b+c > 0 (i.e., not all toys have magnitude >= 1).
        // If all toys have magnitude >= 1 (b+c == 0), then the final magnitude will be >= 1.
        bool can_be_box2 = false;
        if ((a + b) % 2 == 1) { // Odd number of negative toys
            if (b + c > 0) { // At least one toy with magnitude < 1
                can_be_box2 = true;
            } else if (a + d == 1 && (a == 1 || d == 1)) { // Special case: one toy, it's in A or D.
                // This case is handled by total_toys == 1.
                // If total_toys > 1 and b+c == 0, then all toys are in A or D.
                // All products will have magnitude >= 1. So cannot be Box 2.
            }
        }
        result[1] = can_be_box2 ? "Ya" : "Tidak";

        // Box 3: (0, 1)
        // Final toy must be positive and magnitude < 1
        // This requires an even number of negative factors.
        // This requires that it's possible to make the final magnitude < 1.
        bool can_be_box3 = false;
        if ((a + b) % 2 == 0) { // Even number of negative toys
            if (b + c > 0) { // At least one toy with magnitude < 1
                can_be_box3 = true;
            }
        }
        result[2] = can_be_box3 ? "Ya" : "Tidak";

        // Box 4: [1, inf)
        // Final toy must be positive and magnitude >= 1
        // This requires an even number of negative factors.
        // This requires at least one factor with magnitude >= 1.
        bool can_be_box4 = false;
        if (a + d > 0) { // At least one toy with magnitude >= 1
            if ((a + b) % 2 == 0) { // Even number of negative toys
                can_be_box4 = true;
            }
        }
        result[3] = can_be_box4 ? "Ya" : "Tidak";
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

