    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int last_diff_01 = -1; // Index of the last '0' in a that needs to be '1' in b
    int last_diff_10 = -1; // Index of the last '1' in a that needs to be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (last_diff_10 != -1) { // Found a '1' in a that needs to be '0' in b
                    // We can swap a[last_diff_10] and a[i]
                    // a[last_diff_10] was '1', becomes '0' (matches b[last_diff_10])
                    // a[i] was '0', becomes '1' (matches b[i])
                    total_cost += (i - last_diff_10);
                    last_diff_10 = -1; // This '10' mismatch is resolved
                } else {
                    // Cannot resolve with a swap yet, mark this '01' mismatch
                    last_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (last_diff_01 != -1) { // Found a '0' in a that needs to be '1' in b
                    // We can swap a[last_diff_01] and a[i]
                    // a[last_diff_01] was '0', becomes '1' (matches b[last_diff_01])
                    // a[i] was '1', becomes '0' (matches b[i])
                    total_cost += (i - last_diff_01);
                    last_diff_01 = -1; // This '01' mismatch is resolved
                } else {
                    // Cannot resolve with a swap yet, mark this '10' mismatch
                    last_diff_10 = i;
                }
            }
        }
    }

    // Any remaining mismatches must be resolved by flipping
    if (last_diff_01 != -1) {
        total_cost += 1;
    }
    if (last_diff_10 != -1) {
        total_cost += 1;
    }

    std::cout << total_cost << std::endl;

