int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // Pointer for the rightmost point satisfying the condition

    for (int i = 0; i < n; ++i) {
        // Advance right_ptr until x[right_ptr] > x[i] + d or right_ptr reaches end
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }

        // At this point, all points from x[i+1] to x[right_ptr-1] satisfy x_k - x_i <= d.
        // We need to choose two points from this range (i+1 to right_ptr-1).
        // The number of available points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x_j, x_k such that i < j < k.
        // If m >= 2, we can choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = static_cast<long long>(right_ptr - 1 - i);
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

