    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
            pos[p[i]] = i;
        }

        std::string result = "";
        int current_min_idx = pos[1];
        int current_max_idx = pos[1];

        for (int m = 1; m <= n; ++m) {
            // For m=1, the segment is just [1].
            // For m > 1, we extend the segment to include m.
            // The new segment must contain all numbers from 1 to m.
            // This means its minimum element must be 1 and maximum must be m.
            // The length must be m.

            // Update current_min_idx and current_max_idx to include the position of 'm'.
            // This effectively expands the segment [min_idx, max_idx] to cover all numbers from 1 to m.
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);

            // Check if the current segment [current_min_idx, current_max_idx]
            // satisfies the conditions for 'm' to be beautiful.
            // 1. The length of the segment must be 'm'.
            //    Length = current_max_idx - current_min_idx + 1.
            // 2. The segment must contain all numbers from 1 to 'm'.
            //    This is implicitly handled by how current_min_idx and current_max_idx are updated.
            //    Since we always expand the segment to include 'm', and we started with '1',
            //    the segment [current_min_idx, current_max_idx] will always contain all numbers
            //    from 1 to 'm'. The only remaining condition is its length.
            if (current_max_idx - current_min_idx + 1 == m) {
                result += '1';
            } else {
                result += '0';
            }
        }
        std::cout << result << "\n";
    }
