#include <numeric>
#include <functional>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        long long current_sum = 0;
        long long current_xor_sum = 0;
        for (int i = 0; i < n; ++i) {
            long long a;
            std::cin >> a;
            current_sum += a;
            current_xor_sum ^= a;
        }

        // We need to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
        // Let's try to append two elements first.
        // We want to find x, y such that (current_sum + x + y) = 2 * (current_xor_sum ^ x ^ y)
        // A simple strategy is to make the XOR sum equal to the current_xor_sum, and then adjust the sum.
        // Let's append two elements: current_xor_sum and current_sum.
        // New XOR sum: current_xor_sum ^ current_xor_sum ^ current_sum = current_sum
        // New sum: current_sum + current_xor_sum + current_sum = 2 * current_sum + current_xor_sum
        // This doesn't directly lead to the condition.

        // A known trick for these problems is to append elements that simplify the XOR sum.
        // Let's append two elements: X and S.
        // New XOR sum: X_new = current_xor_sum ^ X ^ S
        // New sum: S_new = current_sum + X + S
        // We want S_new = 2 * X_new.

        // Consider appending two elements: current_xor_sum and current_sum.
        // Let X = current_xor_sum, S = current_sum.
        // Appended elements: X, S.
        // New XOR sum: X_new = X ^ X ^ S = S.
        // New sum: S_new = S + X + S = 2S + X.
        // We need 2S + X = 2 * S. This implies X = 0, which is not generally true.

        // Let's try to append two elements such that the final XOR sum is X.
        // If we append X, then the XOR sum becomes X ^ X = 0.
        // If we append 0, then the XOR sum remains X.
        // This suggests appending X and then something else.

        // A common strategy for these problems is to append two elements:
        // 1. The current XOR sum (X)
        // 2. The current sum (S) + current XOR sum (X)
        // Let's try this.
        // Append b1 = current_xor_sum.
        // New XOR sum: current_xor_sum ^ current_xor_sum = 0.
        // New sum: current_sum + current_xor_sum.
        // Now we need to append one more element, say b2, such that:
        // (current_sum + current_xor_sum + b2) = 2 * (0 ^ b2) = 2 * b2.
        // current_sum + current_xor_sum = b2.
        // So, b2 = current_sum + current_xor_sum.

        // This means we can append two elements:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum
        // Let's verify this.
        // Initial sum = S, initial XOR sum = X.
        // Appended elements: X, S+X.
        // Final sum: S + X + (S+X) = 2S + 2X.
        // Final XOR sum: X ^ X ^ (S+X) = 0 ^ (S+X) = S+X.
        // Check condition: (2S + 2X) = 2 * (S+X).
        // This is true! 2S + 2X = 2S + 2X.

        // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
        // The problem statement says "at most 3 elements". This solution uses 2 elements.
        // The values can be large, up to 10^9 for initial elements, sum can be 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 (approx 10^9).
        // current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.
        // The output format requires s and then s integers.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
    return 0;
}

