void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Handle friends with w_i = 1 first
    // These friends get 2 * largest_available_number
    // Assign the k largest numbers from 'a' to these friends.
    // Since w is sorted, friends with w_i = 1 will be at the beginning.
    // We iterate from the largest elements of 'a' and assign them to friends with w_i = 1.
    int a_idx = n - 1; // Pointer to the largest available element in 'a'
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_idx];
            a_idx--;
        } else {
            // All remaining friends have w_i > 1.
            // Since w is sorted, all w[j] for j < i will also be > 1.
            // We can break here and handle them in the next loop.
            break;
        }
    }

    // Handle friends with w_i > 1
    // These friends get max_val + min_val.
    // To maximize, they should get one of the remaining largest numbers as max_val,
    // and one of the remaining smallest numbers as min_val.
    // The largest numbers are already assigned to friends with w_i = 1.
    // The remaining largest numbers are from a_idx down to 0.
    // The smallest numbers are from a[0] upwards.

    // Assign the remaining largest numbers (from a_idx down to 0) as max_val for friends with w_i > 1.
    // Since w is sorted, friends with larger w_i values are at the end.
    // We iterate through w from largest w_i (which are at the end of the sorted w array)
    // and assign them the largest available numbers from 'a'.
    // The loop for w_i = 1 already processed from k-1 downwards.
    // So we continue from where it left off.
    int current_a_max_idx = n - 1; // This pointer was decremented for w_i = 1 friends.
                                   // It now points to the largest available element for w_i > 1 friends.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[current_a_max_idx]; // Assign largest available as max_val
            current_a_max_idx--;
        } else {
            // All remaining w[j] for j < i are 1, which are already handled.
            break;
        }
    }

    // Assign the remaining smallest numbers as min_val for friends with w_i > 1.
    // These friends need w_i - 1 additional numbers, including the min_val.
    // The smallest numbers are from a[0] upwards.
    int a_min_idx = 0; // Pointer to the smallest available element in 'a'
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_min_idx]; // Assign smallest available as min_val
            a_min_idx += (w[i] - 1); // Consume w_i - 1 elements for this friend
        }
    }

    std::cout << total_happiness << std::endl;
}

