int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // can potentially form an "ab" pair with this 'b'.
            // When an 'a' to its left forms "ab" and becomes "bba",
            // the 'a' effectively moves past this 'b'.
            // The number of steps this 'b' contributes is equal to
            // the current count of 'a's to its left.
            // Each such 'a' will eventually pass this 'b'.
            // When an 'a' passes a 'b', it generates 2 new 'b's.
            // The 'a' itself moves to the right of the new 'b'.
            // The original 'b' moves to the left.
            // The key insight is that each 'a' to the left of a 'b'
            // will eventually "pass" that 'b'.
            // When 'a' passes 'b', it takes `count_a` steps.
            // The `count_a` represents the number of 'a's that are
            // currently to the left of the current 'b' and have not yet
            // been processed (i.e., have not yet formed an "ab" with a 'b'
            // to their right).
            // Each 'a' that passes this 'b' effectively doubles the number
            // of 'a's that are "active" for future 'b's.
            // So, for each 'b', we add `count_a` to `total_steps`.
            // Then, `count_a` itself doubles because each 'a' that passed
            // this 'b' effectively creates a new 'a' that is now to the
            // left of the next 'b' (or rather, the 'a' itself is still active
            // and has moved past this 'b', and the new 'b's are created).
            // The `count_a` represents the number of 'a's that are "waiting"
            // to be processed by 'b's to their right.
            // When an 'a' encounters a 'b', it performs an operation.
            // This operation consumes the 'a' and 'b' to produce "bba".
            // The 'a' is now to the right of the first 'b'.
            // The 'a' is still to the left of the second 'b'.
            // This means the 'a' effectively moves past the 'b', and the
            // number of 'a's that can interact with subsequent 'b's doubles.
            // The number of steps for this 'b' is `count_a`.
            // The number of 'a's that can interact with 'b's further left
            // (which are processed later in reverse iteration) doubles.
            total_steps = (total_steps + count_a) % mod;
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it simply adds to the count of 'a's
            // that are to the left of any subsequent 'b's (when iterating
            // from right to left, these 'b's are to the right of this 'a').
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

