#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>
#include <map>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    // p is divisible by q. So p itself is not a valid x.
    // We need to find a divisor of p, say x, such that x % q != 0.
    // We want the largest such x.

    // First, find prime factors of q.
    std::map<long long, int> q_prime_factors;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            while (temp_q % i == 0) {
                q_prime_factors[i]++;
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        q_prime_factors[temp_q]++;
    }

    long long max_x = 1;

    // Iterate through each prime factor f of q.
    // For each f, we try to remove as many factors of f from p as needed
    // to make p no longer divisible by q, but still divisible by q/f.
    // More precisely, we want to find a divisor x of p such that x % q != 0.
    // If p is divisible by q, then p = k * q for some integer k.
    // We are looking for x = p / (f^a) such that x % q != 0.
    // This means p / (f^a) is not divisible by q.
    // This is equivalent to p / (f^a) is not divisible by q.
    // The condition x % q != 0 means that there is at least one prime factor f_j of q
    // such that the exponent of f_j in x is less than the exponent of f_j in q.

    // For each prime factor f of q, we can try to construct a candidate x.
    // A candidate x would be p divided by some power of f.
    // We want to find the smallest power of f, say f^k, such that (p / f^k) % q != 0.
    // To maximize x, we want to divide p by the smallest possible factor.
    // This means we want to divide p by f^k where k is minimal such that (p / f^k) % q != 0.
    // For each prime factor `f` of `q`:
    // Calculate `p_prime_f_count`: count of `f` in `p`.
    // Calculate `q_prime_f_count`: count of `f` in `q`.
    // If `p_prime_f_count < q_prime_f_count`, then `p` is not divisible by `q` (contradiction, as we are in the `p % q == 0` branch).
    // So, `p_prime_f_count >= q_prime_f_count` for all prime factors `f` of `q`.
    // To make `x = p / f^k` not divisible by `q`, we need to reduce the count of `f` in `x`
    // to be less than `q_prime_f_count`.
    // The smallest `k` to achieve this is `k = p_prime_f_count - q_prime_f_count + 1`.
    // Then `x = p / (f^k)` will have `q_prime_f_count - 1` factors of `f`,
    // making it not divisible by `q` (specifically, not divisible by `f^q_prime_f_count`).
    // We want to maximize `x`, so we want to minimize `f^k`.
    // This means we want to minimize `f^k` over all prime factors `f` of `q`.
    // So, for each prime factor `f` of `q`, calculate `p_div_f_power = p`.
    // While `p_div_f_power % q == 0` and `p_div_f_power % f == 0`:
    //   `p_div_f_power /= f`.
    // This `p_div_f_power` is a candidate for `x`.
    // We take the maximum of all such candidates.

    for (auto const& [factor, count] : q_prime_factors) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

