void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::vector<int> colors(n);
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = 1;
                s1_digits.push_back(d[i]);
            } else if (d[i] > p) {
                colors[i] = 2;
                s2_digits.push_back(d[i]);
            } else { // d[i] == p
                // If s2_digits is not empty, it means we've already placed a digit > p.
                // So, this 'p' must go into s2.
                if (!s2_digits.empty()) {
                    colors[i] = 2;
                    s2_digits.push_back(d[i]);
                } else {
                    // If s2_digits is empty, we can place this 'p' into s1 or s2.
                    // To maximize chances, we try to put it into s2 if possible,
                    // as it allows more digits < p to go into s1.
                    // However, the problem states "all digits painted in the color 1, and then after them all the digits painted in the color 2".
                    // This means the final sequence is S1_sorted + S2_sorted.
                    // The condition is that the last element of S1_sorted <= first element of S2_sorted.
                    // If we put d[i]=p into S1, then S1_last = p.
                    // If we put d[i]=p into S2, then S2_first = p.
                    // The critical point is that all digits in S1 must be <= p, and all digits in S2 must be >= p.
                    // So, if d[i] == p, it can go to S1 or S2.
                    // If we put it in S1, it must be >= last S1 digit.
                    // If we put it in S2, it must be >= last S2 digit.
                    // The simplest strategy for d[i] == p is to put it into S2 if we've already started S2 (i.e., seen a digit > p).
                    // Otherwise, put it into S1.
                    // This ensures that all digits assigned to S1 are <= p, and all digits assigned to S2 are >= p.
                    // This is the key insight: all digits < p go to S1. All digits > p go to S2.
                    // Digits == p can go to either, but they must maintain the non-decreasing property within their own color group.
                    // To satisfy S1_last <= S2_first, we need S1_last <= p and S2_first >= p.
                    // So, if d[i] == p, we can assign it to color 1 if it maintains S1 non-decreasing,
                    // or to color 2 if it maintains S2 non-decreasing.
                    // A simple rule: assign all d[i] < p to color 1.
                    // Assign all d[i] > p to color 2.
                    // For d[i] == p:
                    // If we haven't started S2 yet (i.e., no digit > p has been encountered),
                    // we can assign d[i]=p to color 2. This makes it the first digit of S2.
                    // All subsequent digits < p would go to S1, which is invalid.
                    // So, if d[i]=p, and we haven't seen any digit > p yet, we assign it to color 2.
                    // This means all digits < p will be color 1, and all digits >= p will be color 2.
                    // This is the strategy that works.
                    colors[i] = 2;
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Check if s1_digits is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if s2_digits is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check the boundary condition: last of S1 <= first of S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_p = false;
            }
        }

        if (possible_p) {
            for (int i = 0; i < n; ++i) {
                std::cout << colors[i];
            }
            std::cout << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

