    int current_score = initial_score;
    int current_wins = initial_wins;

    // Fill gaps
    for (int gap_len : gap_lengths) {
        if (k >= gap_len) {
            k -= gap_len;
            current_score += 2 * gap_len + 1; // Each L becomes W (adds 1 point), and it connects two W blocks (adds 1 point for the connection)
                                              // Total: gap_len new W's, each adds 2 points (1 for itself, 1 for making previous W a 2-pointer)
                                              // No, it's simpler: each L becomes W, adds 1 point.
