#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Enforce s[i] == s[i+k]
    // For each residue class modulo k, all characters must be the same.
    // If there's a conflict (e.g., s[j] = '0' and s[j+k] = '1'), it's impossible.
    // Otherwise, determine the character for each residue class.
    std::vector<char> determined_char(k, '?'); // Stores the determined char for s[i % k]

    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int residue = i % k;
            if (determined_char[residue] == '?') {
                determined_char[residue] = s[i];
            } else if (determined_char[residue] != s[i]) {
                // Conflict detected: s[i] and s[i-k] (or s[i+k]) are different
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Fill in '?' based on determined_char
    // This step is not strictly necessary for correctness if we only care about counts,
    // but it helps to visualize and ensures consistency.
    // For the purpose of counting, we can just use determined_char directly.

    // Step 3: Check the first k characters for balance
    // The first k characters (s[0]...s[k-1]) must form a k-balanced substring.
    // This means it must have k/2 zeros and k/2 ones.
    // Since s[i] == s[i+k] is enforced, if s[0...k-1] is k-balanced,
    // then all other substrings of length k will also be k-balanced.
    // For example, s[1...k] will have the same characters as s[0...k-1]
    // just shifted, because s[0] == s[k], s[1] == s[k+1], etc.
    // So, we only need to check the balance of the first k characters.

    int zeros = 0;
    int ones = 0;
    int question_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (determined_char[i] == '0') {
            zeros++;
        } else if (determined_char[i] == '1') {
            ones++;
        } else { // determined_char[i] == '?'
            question_marks++;
        }
    }

    // We need k/2 zeros and k/2 ones.
    // We have 'zeros' fixed zeros, 'ones' fixed ones, and 'question_marks' to fill.
    // The number of zeros we need to fill is (k/2 - zeros).
    // The number of ones we need to fill is (k/2 - ones).

    int needed_zeros = k / 2 - zeros;
    int needed_ones = k / 2 - ones;

    if (needed_zeros < 0 || needed_ones < 0) {
        // Already have too many zeros or ones
        std::cout << "NO\n";
        return;
    }

    if (needed_zeros + needed_ones == question_marks) {
        // We can fill the '?'s exactly to meet the balance requirement
        std::cout << "YES\n";
    } else {
        // Not enough '?'s or too many '?'s to achieve the balance
        std::cout << "NO\n";
    }
}

