    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1: can move left (x-1). If 0, cannot move left.
            // This means it cannot reach any point with X < current_x.
            // So, the target X must be >= current_x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f3: can move right (x+1). If 0, cannot move right.
            // This means it cannot reach any point with X > current_x.
            // So, the target X must be <= current_x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4: can move down (y-1). If 0, cannot move down.
            // This means it cannot reach any point with Y < current_y.
            // So, the target Y must be >= current_y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }

            // f2: can move up (y+1). If 0, cannot move up.
            // This means it cannot reach any point with Y > current_y.
            // So, the target Y must be <= current_y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // A valid point exists. The problem guarantees that if a solution exists,
            // one exists within [-10^5, 10^5].
            // We can pick any point within the valid range.
            // For example, (min_x, min_y) or (max_x, max_y) or (0,0) if it's in range.
            // The problem statement guarantees that if a point exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // So, we can just output min_x and min_y, clamping them if necessary,
            // but given the problem constraints and guarantee, min_x and min_y
            // will be within the required range if a solution exists.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;
    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2. Since MOD is prime and > 2, we can use modular inverse.
    // Modular inverse of 2 modulo MOD is (MOD + 1) / 2.
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r must be != 0. So no valid r.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // One of b_minus_1 or b_val must be even.
        // Divide by 2 before modulo to avoid issues with (X/2) % MOD != (X % MOD / 2) % MOD
        // if X % MOD is odd.
        if (b_minus_1 % 2 == 0) {
            b_minus_1 /= 2;
        } else { // b_val must be even
            b_val /= 2;
        }
        sum_r_val = (b_minus_1 % MOD * (b_val % MOD)) % MOD;
    }

    // Calculate sum_k_term = sum_{k=1 to a} (k * b + 1)
    // sum_k_term = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // sum_k_term = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a + 1) / 2
    long long sum_k_val;
    long long a_val = a;
    long long a_plus_1_val = a + 1;

    if (a_val % 2 == 0) {
        a_val /= 2;
    } else {
        a_plus_1_val /= 2;
    }
    long long sum_1_to_a = (a_val % MOD * (a_plus_1_val % MOD)) % MOD;

    long long term_b_times_sum_1_to_a = (b % MOD * sum_1_to_a) % MOD;
    long long term_a = a % MOD;

    sum_k_val = (term_b_times_sum_1_to_a + term_a) % MOD;

    // Total sum = sum_k_term * sum_r
    long long total_sum = (sum_k_val * sum_r_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

