#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        std::sort(a.begin(), a.end());

        long long min_val = a[0];
        long long total_spells = 0;

        for (int i = 1; i < n; ++i) {
            // For each pile a[i] (where i > 0, so it's not the smallest pile),
            // we can add min_val to it multiple times.
            // The number of times we can add min_val to a[i] without exceeding k is:
            // (k - a[i]) / min_val
            // This is integer division, which correctly gives the floor.
            total_spells += (k - a[i]) / min_val;
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form '1' (from "one"): requires one 'o', one 'n', one 'e'
    // To form '0' (from "zero"): requires one 'z', one 'e', one 'r', one 'o'

    // Prioritize '1's to make the number as large as possible
    int num_ones = 0;
    if (count_n > 0 && count_o > 0 && count_e > 0) {
        num_ones = std::min({count_n, count_o, count_e});
    }

    // Consume letters for '1's
    count_n -= num_ones;
    count_o -= num_ones;
    count_e -= num_ones;

    // Now form '0's from remaining letters
    int num_zeros = 0;
    if (count_z > 0 && count_e > 0 && count_r > 0 && count_o > 0) {
        num_zeros = std::min({count_z, count_e, count_r, count_o});
    }

    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

