#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required = (k * y) + k = k * (y + 1).
        long long total_sticks_required = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) more sticks.
        // Each stick trade (1 stick for x sticks) gives us (x - 1) net sticks.
        // Number of stick trades needed = ceil((total_sticks_required - 1) / (x - 1)).
        // Using integer division: (A + B - 1) / B for ceil(A/B)
        long long stick_trades = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = stick trades + coal trades.
        // Coal trades = k (since 1 trade gives 1 coal).
        long long total_trades = stick_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

