        long long coins = 0;
        for (int i = 0; i < n; ++i) {
            long long val;
            std::cin >> val;
            if (val > 0) {
                current_positive_balance += val;
            } else { // val <= 0
                // We need to move |val| units into this position.
                // We prefer to use the current_positive_balance (free moves from left).
                // If current_positive_balance is not enough, the deficit must be covered by
                // moves from right to left (costly moves).
                long long needed = -val;
                if (current_positive_balance >= needed) {
                    current_positive_balance -= needed;
                } else {
                    // current_positive_balance is exhausted.
                    // The remaining 'needed - current_positive_balance' must come from
                    // elements to the right, incurring cost.
                    coins += (needed - current_positive_balance);
                    current_positive_balance = 0; // All positive balance used up
                }
            }
        }
        std::cout << coins << "\n";
    }
    return 0;
}

