#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) { // Can only increase if there's a 1 before it
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) { // Can only decrease if there's a -1 before it
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation needed for this element.
        // The presence of 1 or -1 before it doesn't matter for this specific element,
        // but it might matter for subsequent elements.
        // The has_pos_one and has_neg_one flags are updated based on original a[i] values.
        // This is correct because operations only add to a_j, they don't change a_i for i < j.
        // So, the ability to add 1 or -1 to future elements depends on the *original* presence of 1 or -1.
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // Since n can be up to 150000, dynamic allocation with vector is appropriate.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Edge case: no days
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // Edge case: only one day, no later prices to compare
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price.
        // The last price a[n-1] is never a bad price itself.
        int min_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, we compare its price a[i] with the minimum price
        // encountered so far in the suffix a[i+1...n-1].
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price is greater than the minimum price in the suffix,
                // it means there's a later day with a lower price, so a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means a[i] is
                // either equal to or less than min_suffix.
                // In this case, a[i] itself becomes the new minimum for the suffix
                // starting from i.
                min_suffix = a[i];
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

