int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
                            // If last_R_pos is 0, it means the frog is at cell 0.
                            // If last_R_pos is k, it means the frog is at cell k, and s[k-1] was 'R'.
                            // The next jump must be from k+1.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at index i (cell i+1),
                // it means the frog can jump from last_R_pos to i+1.
                // The distance needed for this jump is (i+1) - last_R_pos.
                // We need to find the maximum such distance.
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update last_R_pos to the current 'R' cell
            }
        }

        // After iterating through the string, the frog needs to jump from the last 'R' cell
        // (or cell 0 if no 'R's were found) to cell n+1.
        // The distance for this final jump is (n + 1) - last_R_pos.
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // With 2n students, and each class having an odd number of students,
        // the smallest possible class size is 1.
        // If class 1 has size 1, its median is its only element.
        // If class 2 has size 2n-1, its median is the (n-1)-th element after sorting.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we pick the smallest n elements for one class and the largest n elements for the other,
        // this doesn't guarantee odd sizes.
        //
        // The key insight is that to minimize the difference between medians,
        // we should make the medians as close as possible.
        //
        // Let the two classes be C1 and C2.
        // Let |C1| = 2k1 + 1 and |C2| = 2k2 + 1.
        // (2k1 + 1) + (2k2 + 1) = 2n => 2k1 + 2k2 + 2 = 2n => k1 + k2 = n - 1.
        //
        // The median of C1 is its (k1+1)-th element.
        // The median of C2 is its (k2+1)-th element.
        //
        // To minimize the difference, we want the medians to be adjacent in the sorted full list.
        //
        // Consider the case where one class has size 1.
        // Let C1 = {a_i}. Median is a_i.
        // Then C2 contains the remaining 2n-1 elements.
        // The median of C2 would be the (n)-th element among the 2n-1 elements.
        //
        // The optimal strategy is to sort all elements.
        // The median of a class of size (2k+1) is the (k+1)-th element.
        //
        // For the two classes to have medians as close as possible,
        // we should pick the elements for the classes such that their medians
        // are the middle two elements of the entire sorted array.
        //
        // The elements in the sorted array are a_0, a_1, ..., a_{2n-1}.
        // The two "middle" elements are a_{n-1} and a_n.
        //
        // If we assign a_{n-1} to be the median of the first class (C1)
        // and a_n to be the median of the second class (C2).
        //
        // For a_{n-1} to be the median of C1, C1 must have at least n elements less than or equal to a_{n-1}
        // and at least n elements greater than or equal to a_{n-1}.
        // This means C1 must have at least n elements.
        //
        // For a_n to be the median of C2, C2 must have at least n+1 elements less than or equal to a_n
        // and at least n+1 elements greater than or equal to a_n.
        // This means C2 must have at least n+1 elements.
        //
        // This logic is a bit complex. Let's simplify.
        //
        // The problem asks for the minimum absolute difference.
        // Consider the sorted array: a_0, a_1, ..., a_{2n-1}.
        //
        // We need to pick two medians.
        // Let's say we pick a_i as the median for the first class and a_j as the median for the second class.
        //
        // The crucial observation is that the two medians must be $a_{n-1}$ and $a_n$.
        //
        // Why?
        // Suppose we have a partition into C1 and C2, with medians m1 and m2.
        // Let's assume m1 <= m2.
        //
        // For m1 to be the median of C1, C1 must contain at least (k1+1) elements <= m1
        // and at least (k1+1) elements >= m1.
        //
        // For m2 to be the median of C2, C2 must contain at least (k2+1) elements <= m2
        // and at least (k2+1) elements >= m2.
        //
        // The total number of elements is 2n.
        // The total number of elements less than or equal to m1 is at most the index of m1 in the sorted array + 1.
        // The total number of elements greater than or equal to m2 is at most (2n - index of m2).
        //
        // Consider the elements a_0, ..., a_{n-1} and a_n, ..., a_{2n-1}.
        //
        // If we choose a_i as the median of the first class and a_j as the median of the second class,
        // where i < n-1 or j > n.
        //
        // Let's try to construct a partition where a_{n-1} and a_n are the medians.
        //
        // Class 1: {a_0, a_1, ..., a_{n-1}}
        // Class 2: {a_n, a_{n+1}, ..., a_{2n-1}}
        //
        // This partition is not valid because each class has size n, which is not necessarily odd.
        //
        // The problem states that each class must have an odd number of students.
        //
        // The simplest partition that satisfies the odd size constraint is when n=1.
        // 2n = 2 students. a_0, a_1.
        // Class 1: {a_0}. Median = a_0. Size = 1 (odd).
        // Class 2: {a_1}. Median = a_1. Size = 1 (odd).
        // Difference = |a_1 - a_0|.
        // In this case, n-1 = 0, n = 1. So a_{n-1} = a_0, a_n = a_1.
        // The difference is a_n - a_{n-1}.
        //
        // This pattern holds. The minimum difference is always a_n - a_{n-1}.
        //
        // Proof sketch:
        // Let the sorted array be $A = [a_0, a_1, \dots, a_{2n-1}]$.
        // We need to partition $A$ into two sets $C_1$ and $C_2$, both of odd size.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // We want to minimize $|m_1 - m_2|$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can always construct a partition where $m_1 = a_{n-1}$ and $m_2 = a_n$.
        //
        // Let $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is not valid because sizes are $n$.
        //
        // Let's try to make $a_{n-1}$ the median of one class and $a_n$ the median of the other.
        //
        // Consider the partition:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n-1}\}$
        // Class 2: $\{a_n\}$
        // This is not valid. Class 1 has $2n-1$ elements, Class 2 has 1 element. Both are odd.
        // Median of Class 2 is $a_n$.
        // Median of Class 1 (size $2n-1$) is the $n$-th element.
        // The elements of Class 1 are $a_0, \dots, a_{n-1}, a_{n+1}, \dots, a_{2n-1}$.
        // If we sort Class 1, its $n$-th element is $a_{n-1}$.
        // So, medians are $a_{n-1}$ and $a_n$. The difference is $a_n - a_{n-1}$.
        // This is a valid partition.
        //
        // Can we achieve a smaller difference?
        // Suppose there exists a partition with medians $m_1, m_2$ such that $|m_1 - m_2| < a_n - a_{n-1}$.
        // This implies that $m_1$ and $m_2$ must both be within the range $[a_{n-1}, a_n]$.
        // If $m_1 < a_{n-1}$ and $m_2 < a_{n-1}$, then both medians are less than $a_{n-1}$.
        // If $m_1 > a_n$ and $m_2 > a_n$, then both medians are greater than $a_n$.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$.
        //
        // $C_1$ has $2k_1+1$ elements. $m_1$ is the $(k_1+1)$-th element.
        // $C_2$ has $2k_2+1$ elements. $m_2$ is the $(k_2+1)$-th element.
        // $k_1+k_2 = n-1$.
        //
        // The number of elements in $C_1$ less than or equal to $m_1$ is $k_1+1$.
        // The number of elements in $C_2$ less than or equal to $m_2$ is $k_2+1$.
        //
        // The total number of elements less than or equal to $m_1$ in $A$ is at least $k_1+1$.
        // The total number of elements less than or equal to $m_2$ in $A$ is at least $k_1+1 + k_2+1 = n+1$.
        // (This is because $m_1 \le m_2$, so elements $\le m_1$ are also $\le m_2$).
        //
        // If $m_2 < a_n$, then all elements $a_n, \dots, a_{2n-1}$ are greater than $m_2$.
        // This means that all $n$ elements $a_n, \dots, a_{2n-1}$ must be in $C_1$ or $C_2$ and be greater than $m_2$.
        //
        // The number of elements in $A$ that are $\le m_2$ is at most $n-1$ (if $m_2 < a_n$).
        // But we need at least $k_1+1 + k_2+1 = n+1$ elements $\le m_2$ to form the medians.
        // This is a contradiction.
        // Therefore, $m_2$ must be at least $a_n$.
        //
        // Similarly, consider elements greater than or equal to $m_1$.
        // The number of elements in $C_1$ greater than or equal to $m_1$ is $k_1+1$.
        // The number of elements in $C_2$ greater than or equal to $m_2$ is $k_2+1$.
        //
        // The total number of elements in $A$ greater than or equal to $m_2$ is at least $k_2+1$.
        // The total number of elements in $A$ greater than or equal to $m_1$ is at least $k_1+1 + k_2+1 = n+1$.
        // (This is because $m_1 \le m_2$, so elements $\ge m_2$ are also $\ge m_1$).
        //
        // If $m_1 > a_{n-1}$, then all elements $a_0, \dots, a_{n-1}$ are less than $m_1$.
        // This means that all $n$ elements $a_0, \dots, a_{n-1}$ must be in $C_1$ or $C_2$ and be less than $m_1$.
        //
        // The number of elements in $A$ that are $\ge m_1$ is at most $n$ (if $m_1 > a_{n-1}$).
        // But we need at least $k_1+1 + k_2+1 = n+1$ elements $\ge m_1$ to form the medians.
        // This is a contradiction.
        // Therefore, $m_1$ must be at most $a_{n-1}$.
        //
        // So we must have $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Since we want to minimize $|m_1 - m_2|$, and $m_1 \le m_2$, we want to minimize $m_2 - m_1$.
        // The minimum possible value for $m_2 - m_1$ is achieved when $m_1$ is maximized and $m_2$ is minimized.
        // This means $m_1 = a_{n-1}$ and $m_2 = a_n$.
        // The minimum difference is $a_n - a_{n-1}$.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

