            if (x >= cost_of_staircase) {
                x -= cost_of_staircase;
                count++;
            } else {
                break;
            }

            // Calculate next n for a nice staircase: n_next = 2 * n_current + 1
            // This is equivalent to current_stair_n = 2^(k+1) - 1
            // The cost of the next staircase is (2^(k+1)-1) * (2^(k+1))/2
            // We can also think of it as:
            // current_stair_n = 2 * current_stair_n + 1;
            // This can overflow if current_stair_n is already large.
            // Let's use the pattern for current_cost_base: 1, 3, 7, 15, ...
            // current_cost_base = 2^k - 1
            // The number of cells for such a staircase is (2^k - 1) * 2^k / 2
            // The next one would be (2^(k+1) - 1) * 2^(k+1) / 2
            // The current_stair_n is 2^k - 1.
            // The next current_stair_n is 2 * current_stair_n + 1.
            // If current_stair_n is 1 (k=1), next is 3.
            // If current_stair_n is 3 (k=2), next is 7.
            // If current_stair_n is 7 (k=3), next is 15.

            // Check for potential overflow before multiplication
            // current_stair_n * 2 + 1
            // Max value for long long is ~9 * 10^18.
            // If current_stair_n is ~4.5 * 10^18, then 2 * current_stair_n + 1 will overflow.
            // However, the cost calculation `current_stair_n * (current_stair_n + 1) / 2`
            // will overflow much earlier.
            // The maximum x is 10^18.
            // If current_stair_n * (current_stair_n + 1) / 2 > 10^18, we can stop.
            // This happens when current_stair_n is roughly sqrt(2 * 10^18) = sqrt(200 * 10^16) = 10^8 * sqrt(200) approx 1.4 * 10^9.
            // So current_stair_n will not exceed 2 * 10^9.
            // 2 * (2 * 10^9) + 1 is well within long long limits.

            current_stair_n = 2 * current_stair_n + 1;
        }
        std::cout << count << std::endl;
    }
    return 0;
}

