#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q_i are valid prefix maximums
                // and q_i > q_{i-1}, as q_i would be a new value.
                // But as a safety check.
                possible = false;
                break;
            }
            used_values.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some value less than q_i
            // and not yet used. We need to pick the smallest available value
            // that is not q_i and not already used.
            // The values available for p_i are those from 1 to n that are not in used_values.
            // We need to find the smallest such value that is also less than q_i.
            // However, a simpler approach is to find the smallest available value
            // that is not used and is not equal to q_i.
            // The values that are not used are those from 1 to n that are not in used_values.
            // We need to pick one such value for p_i.
            // To satisfy q_i = max(..., p_i), p_i must be <= q_i.
            // Since q_i = q_{i-1}, p_i must be < q_i.
            // We need to find the smallest available number that is not used and is < q_i.
            // The values that are not used are those from 1 to n that are not in used_values.
            // We can iterate from 1 upwards to find the first unused value.
            // This value must be less than q_i.

            // Find the smallest available number
            int current_val = 1;
            while (used_values.count(current_val)) {
                current_val++;
            }

            // If this smallest available number is greater than q_i,
            // then it's impossible to pick a p_i < q_i.
            // This also covers the case where current_val > n.
            if (current_val > q[i]) {
                possible = false;
                break;
            }

            p[i] = current_val;
            used_values.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    int k = n - 1; // Start from the end of the array

    // Step 1: Find the longest suffix that is non-decreasing
    // This means a[k] >= a[k-1] >= ...
    while (k > 0 && a[k-1] >= a[k]) {
        k--;
    }

    // If k is 0, the entire array is non-decreasing, so it's good.
    // If k is 0, the loop above would have made k=0.
    // The prefix to remove would be 0.
    if (k == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Now, a[k-1] < a[k] (unless k is 0, which is handled).
    // The suffix a[k...n-1] is non-decreasing.
    // We need to find the point where the array stops being non-increasing
    // from the left of k.
    // This means a[k-1] <= a[k-2] <= ...
    // We are looking for the first index j from the right (starting at k-1)
    // such that a[j] > a[j+1].
    // The elements a[j+1 ... k-1] are non-increasing.

    int j = k; // j is the current index we are checking from the left of k
    while (j > 0 && a[j-1] <= a[j]) { // Check if a[j-1] is part of a non-increasing sequence from the right
        j--;
    }

    // The elements from index j to n-1 form the longest suffix that can be made good.
    // The length of the prefix to remove is j.
    std::cout << j << std::endl;
}

