#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we extend the segment to include m.
        // The segment must contain 1, 2, ..., m.
        // The minimum value in the segment must be 1.
        // The maximum value in the segment must be m.
        // The length of the segment must be m.

        // Update current_min_idx and current_max_idx to cover 1...m
        // This means current_min_idx should be min(pos[1], ..., pos[m])
        // and current_max_idx should be max(pos[1], ..., pos[m])

        // When we go from m-1 to m, we only need to consider pos[m].
        // The segment covering 1...m-1 is already defined by current_min_idx and current_max_idx.
        // We just need to expand it to include pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // satisfies the conditions for being a permutation of 1...m.
        // 1. It must contain all numbers from 1 to m. (Guaranteed by how current_min_idx/max_idx are updated)
        // 2. The minimum value in this segment must be 1. (Guaranteed, as pos[1] is always included)
        // 3. The maximum value in this segment must be m. (Guaranteed, as pos[m] is always included)
        // 4. The length of the segment must be m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

