    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if we have already added enough '(' to balance it
            // or if we are forced to add it to reach k length.
            // The problem guarantees a solution exists, and a simple greedy
            // approach of taking first k/2 '(' and then first k/2 ')'
            // from the remaining string (or from the whole string if we just count)
            // will work because the original string is regular.
            // A more robust greedy approach: take '(' until open_needed is 0.
            // Then take ')' until close_needed is 0.
            // This is equivalent to taking the first k/2 '(' and then the first k/2 ')'
            // that appear AFTER the last selected '('.
            // However, a simpler greedy strategy is to just take the first k/2 '('
            // and the first k/2 ')' that appear in the original string.
            // This is because the problem guarantees a solution exists.
            // The most straightforward way to ensure regularity is to take
            // k/2 opening brackets and then k/2 closing brackets.
            // The problem guarantees that s is a regular bracket sequence.
            // We need to pick k/2 '(' and k/2 ')' from s.
            // A simple greedy strategy: pick the first k/2 '(' characters.
            // Then pick the first k/2 ')' characters from the remaining string.
            // This is not quite right. We need to maintain the subsequence property.
            // Let's try to build the string by taking k/2 opening brackets and k/2 closing brackets.
            // We iterate through s. If we need an opening bracket and see one, we take it.
            // If we need a closing bracket and see one, we take it.
            // The condition for taking a closing bracket is that we have already taken
            // more opening brackets than closing brackets in our `result` string.
            // Or, more simply, we need to ensure `open_needed` becomes 0 before `close_needed` does.

            // Let's refine the greedy strategy:
            // We need `k/2` opening brackets and `k/2` closing brackets.
            // Iterate through `s`.
            // If `c == '('` and we still need opening brackets (`open_needed > 0`), take it.
            // If `c == ')'` and we still need closing brackets (`close_needed > 0`), take it.
            // This simple approach might not produce a regular bracket sequence.
            // Example: s = "()(())", k = 4.
            // open_needed = 2, close_needed = 2
            // s[0] = '(': result = "(", open_needed = 1
            // s[1] = ')': result = "()", close_needed = 1
            // s[2] = '(': result = "()(", open_needed = 0
            // s[3] = '(': result = "()()", close_needed = 1 (oops, this is wrong, open_needed is 0)
            // This simple approach would yield "()()". This is correct for the example.

            // Let's try another example: s = "((()))", k = 4
            // open_needed = 2, close_needed = 2
            // s[0] = '(': result = "(", open_needed = 1
            // s[1] = '(': result = "((", open_needed = 0
            // s[2] = ')': result = "(()", close_needed = 1
            // s[3] = ')': result = "(())", close_needed = 0
            // s[4] = ')': skip
            // s[5] = ')': skip
            // Result: "(())". This is correct.

            // The strategy seems to be:
            // 1. Take the first `k/2` opening brackets encountered in `s`.
            // 2. Then, take the first `k/2` closing brackets encountered in `s` AFTER the last opening bracket was taken.
            // This is equivalent to:
            // Iterate through `s`.
            // If `c == '('` and `open_needed > 0`, append `c` to `result` and decrement `open_needed`.
            // Else if `c == ')'` and `close_needed > 0` AND `open_needed == 0` (meaning we've taken all required opening brackets), append `c` to `result` and decrement `close_needed`.
            // This is still not quite right. We need to ensure the balance property.

            // The simplest greedy approach that works for regular bracket sequences:
            // Take the first k/2 opening brackets.
            // Then take the first k/2 closing brackets.
            // This is guaranteed to work because the original string `s` is regular.
            // We need to ensure that the number of open brackets taken is equal to the number of close brackets taken.
            // And that at any point, the count of open brackets is >= count of close brackets.

            // Let's use a counter for open brackets and close brackets in the result.
            // We need `k/2` open and `k/2` close.
            // Iterate through `s`.
            // If `c == '('` and `result_open_count < k/2`, add `(` to result, increment `result_open_count`.
            // If `c == ')'` and `result_close_count < k/2` AND `result_open_count > result_close_count`, add `)` to result, increment `result_close_count`.
            // This ensures regularity.

            // Let's try this refined strategy:
            // s = "()(())", k = 4
            // target_open = 2, target_close = 2
            // result_open_count = 0, result_close_count = 0
            // s[0] = '(': result_open_count < 2. Add '('. result = "(". result_open_count = 1.
            // s[1] = ')': result_close_count < 2 AND result_open_count (1) > result_close_count (0). Add ')'. result = "()". result_close_count = 1.
            // s[2] = '(': result_open_count < 2. Add '('. result = "()(". result_open_count = 2.
            // s[3] = '(': result_open_count is not < 2. Skip.
            // s[4] = ')': result_close_count < 2 AND result_open_count (2) > result_close_count (1). Add ')'. result = "()()". result_close_count = 2.
            // s[5] = ')': result_close_count is not < 2. Skip.
            // Final result: "()()". This works for the example.

            // s = "((()))", k = 4
            // target_open = 2, target_close = 2
            // result_open_count = 0, result_close_count = 0
            // s[0] = '(': Add '('. result = "(". result_open_count = 1.
            // s[1] = '(': Add '('. result = "((". result_open_count = 2.
            // s[2] = ')': result_close_count < 2 AND result_open_count (2) > result_close_count (0). Add ')'. result = "(()". result_close_count = 1.
            // s[3] = ')': result_close_count < 2 AND result_open_count (2) > result_close_count (1). Add ')'. result = "(())". result_close_count = 2.
            // s[4] = ')': result_close_count is not < 2. Skip.
            // s[5] = ')': result_close_count is not < 2. Skip.
            // Final result: "(())". This works for the example.

            // This refined greedy strategy seems correct and robust.
            // It ensures that we always maintain a non-negative balance of open brackets
            // and that we take exactly k/2 open and k/2 close brackets.
            // Since a solution is guaranteed to exist, this greedy approach will find it.
            // The condition `result_open_count > result_close_count` is crucial for regularity.
            // The conditions `result_open_count < k/2` and `result_close_count < k/2` ensure we take exactly `k` characters.
        }
    }

    int target_open = k / 2;
    int target_close = k / 2;
    int current_open = 0;
    int current_close = 0;
    std::string final_result = "";

    for (char c : s) {
        if (final_result.length() == k) {
            break;
        }

        if (c == '(') {
            if (current_open < target_open) {
                final_result += '(';
                current_open++;
            }
        } else { // c == ')'
            if (current_close < target_close && current_open > current_close) {
                final_result += ')';
                current_close++;
            }
        }
    }

    std::cout << final_result << std::endl;

    return 0;
}

#include <iostream>
