#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Cost to make elements to the left of median_idx <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost to make elements to the right of median_idx >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A_sorted[i].value;
        A_sorted[i].original_index = i;
    }

    std::vector<ElementB> B_sorted(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B_sorted[i].value;
        B_sorted[i].original_index = i;
    }

    std::sort(A_sorted.begin(), A_sorted.end(), compareA);
    std::sort(B_sorted.begin(), B_sorted.end(), compareB);

    std::vector<long long> result_A(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (B_sorted[i].value) should be paired with
        // the (m-1-i)-th largest A value (A_sorted[m-1-i].value).
        // The original index of this B value is B_sorted[i].original_index.
        // So, result_A[B_sorted[i].original_index] should be A_sorted[m-1-i].value.
        result_A[B_sorted[i].original_index] = A_sorted[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_A[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

