int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k that satisfies x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x_i, advance right_ptr to find the largest index k such that x[k] - x[i] <= d
        // Since x is sorted, x[k] <= x[i] + d
        while (right_ptr < n && x[right_ptr] <= x[i] + d) {
            right_ptr++;
        }
        // At this point, right_ptr is the first index such that x[right_ptr] > x[i] + d
        // Or right_ptr == n if all remaining points satisfy the condition.
        // The valid indices for k are from i+1 to right_ptr-1.
        // The number of points in this range is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m be the number of points x_j, x_k such that i < j < k and x_k - x_i <= d.
        // These points are x[i+1], x[i+2], ..., x[right_ptr-1].
        // The total number of points available to choose from (excluding x[i]) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let this number be 'num_available'.
        // We need to choose 2 points from these 'num_available' points.
        // The number of ways to choose 2 points from 'num_available' is num_available * (num_available - 1) / 2.

        long long num_available = (long long)right_ptr - 1 - i;

        if (num_available >= 2) {
            count += num_available * (num_available - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
