// Function to check if a box can be the special box
// Parameters:
// initial_A, initial_B, initial_C, initial_D: initial counts of toys in each box
// target_box: the box we are checking (1, 2, 3, or 4)
//
// The logic is based on analyzing the parity of negative numbers and the possibility of
// achieving the target magnitude range.
//
// Box 1: (-inf, -1] (Negative, |val| >= 1)
// Box 2: (-1, 0)    (Negative, |val| < 1)
// Box 3: (0, 1)     (Positive, |val| < 1)
// Box 4: [1, inf)   (Positive, |val| >= 1)
bool can_be_special_box(long long initial_A, long long initial_B, long long initial_C, long long initial_D, int target_box) {
    long long total_toys = initial_A + initial_B + initial_C + initial_D;

    if (total_toys == 0) {
        return false; // No toys, no super toy
    }
    if (total_toys == 1) {
        // If only one toy, it is the super toy. Check if it's in the target box.
        if (initial_A == 1 && target_box == 1) return true;
        if (initial_B == 1 && target_box == 2) return true;
        if (initial_C == 1 && target_box == 3) return true;
        if (initial_D == 1 && target_box == 4) return true;
        return false;
    }

    // Parity of negative numbers
    long long neg_count = initial_A + initial_B;
    bool final_is_negative_possible = (neg_count % 2 != 0);
    bool final_is_positive_possible = (neg_count % 2 == 0);

    // If there are any toys with value 0, the final product will be 0.
    // This problem statement implies fun values are real numbers, but not 0.
    // "fun values in range of (-inf,-1]", "(-1, 0)", "(0, 1)", "[1, inf)"
    // So, 0 is not possible.

    // Case 1: Target Box 1 (Negative, |val| >= 1)
    if (target_box == 1) {
        if (!final_is_negative_possible) return false; // Must be negative

        // To get |val| >= 1:
        // We need at least one toy with |val| >= 1 (from Box 1 or Box 4)
        // OR we need to be able to multiply multiple |val| < 1 toys to get |val| >= 1.
        // The latter is generally not possible if all initial toys are |val| < 1.
        // If all initial toys are in Box 2 or Box 3, the product will always be < 1.
        // So, if initial_A + initial_D == 0, it's impossible to get |val| >= 1.
        if (initial_A + initial_D == 0) return false;

        // If there's at least one toy with |val| >= 1, and we can achieve a negative sign,
        // we can always arrange multiplications to keep the magnitude >= 1.
        // For example, if we have a toy with |val| >= 1 and a toy with |val| < 1,
        // we can multiply them to get a new toy with |val| that can be >= 1 or < 1.
        // However, if we have at least one |val| >= 1, we can always ensure the final product
        // is >= 1 by strategically multiplying it last with a toy that has |val| >= 1,
        // or by multiplying it with a |val| < 1 toy such that the product remains >= 1.
        // The key is that if we have any |val| >= 1, we can always make the final product |val| >= 1.
        // Example: {2, 0.5, 0.5}. (2*0.5)*0.5 = 1*0.5 = 0.5. But 2*(0.5*0.5) = 2*0.25 = 0.5.
        // This is tricky. The problem states "randomly".
        // However, "can be" implies we can choose the sequence.
        // If we have at least one toy with |val| >= 1 (from A or D), and we need a negative result,
        // we can achieve it.
        // The only way to guarantee |val| < 1 is if all initial toys are |val| < 1.
        // If initial_A + initial_D > 0, it's possible to get |val| >= 1.
        return true;
    }

    // Case 2: Target Box 2 (Negative, |val| < 1)
    if (target_box == 2) {
        if (!final_is_negative_possible) return false; // Must be negative

        // To get |val| < 1:
        // If all initial toys are |val| < 1 (i.e., initial_A + initial_D == 0),
        // then the final product will always have |val| < 1.
        if (initial_A + initial_D == 0) return true;

        // If there are toys with |val| >= 1, we need to be able to reduce the magnitude.
        // This is possible if we have at least one toy with |val| < 1 (from Box 2 or Box 3)
        // to "dilute" the magnitude.
        // If initial_A + initial_D > 0 AND initial_B + initial_C > 0,
        // we can always achieve |val| < 1.
        // Example: {2, 0.1}. Product is 0.2.
        // Example: {2, 3, 0.1}. (2*3)*0.1 = 0.6.
        // The only scenario where we cannot get |val| < 1 is if all toys have |val| >= 1.
        // i.e., initial_B + initial_C == 0.
        if (initial_B + initial_C == 0) return false;

        // If we have both |val| >= 1 and |val| < 1 toys, we can achieve |val| < 1.
        return true;
    }

    // Case 3: Target Box 3 (Positive, |val| < 1)
    if (target_box == 3) {
        if (!final_is_positive_possible) return false; // Must be positive

        // Same magnitude logic as Box 2.
        // If all initial toys are |val| < 1, then final product |val| < 1.
        if (initial_A + initial_D == 0) return true;

        // If there are toys with |val| >= 1, we need at least one |val| < 1 to reduce magnitude.
        if (initial_B + initial_C == 0) return false;

        // If we have both |val| >= 1 and |val| < 1 toys, we can achieve |val| < 1.
        return true;
    }

    // Case 4: Target Box 4 (Positive, |val| >= 1)
    if (target_box == 4) {
        if (!final_is_positive_possible) return false; // Must be positive

        // Same magnitude logic as Box 1.
        // If all initial toys are |val| < 1, then final product |val| < 1.
        if (initial_A + initial_D == 0) return false;

        // If there's at least one toy with |val| >= 1, and we can achieve a positive sign,
        // we can always arrange multiplications to keep the magnitude >= 1.
        return true;
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special_box(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 3) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special_box(A, B, C, D, 4) ? "Ya" : "Tidak") << "\n";
    }

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;
    long long chanek_coins = 0;

    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1; // Chanek takes 1
                n -= 1;
            } else if ((n / 2) % 2 != 0) { // N/2 is odd
                // If Chanek takes N/2, opponent gets an odd number (N/2)
                // If Chanek takes 1, opponent gets an odd number (N-1)
                // In both cases, opponent faces an odd number.
                // Taking N/2 is better for Chanek.
                chanek_coins += n / 2;
                n /= 2;
            } else { // N/2 is even
                // If Chanek takes N/2, opponent faces an even number (N/2)
                // If Chanek takes 1, opponent faces an odd number (N-1)
                // Opponent prefers to face an odd number (N-1) because it limits Chanek's next move.
                // So Chanek should take 1 to leave an odd number for the opponent.
                chanek_coins += 1;
                n -= 1;
            }
        }
    }
    return chanek_coins;
}

