void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements x, y, z such that:
        // (current_sum + x + y + z) = 2 * (current_xor_sum ^ x ^ y ^ z)

        // Strategy: Append two elements.
        // Let the two elements be x and y.
        // We want (current_sum + x + y) = 2 * (current_xor_sum ^ x ^ y)

        // A simple choice for x and y that often works is:
        // x = current_xor_sum
        // y = current_sum + current_xor_sum
        // Let's check this:
        // New XOR sum: X' = current_xor_sum ^ x ^ y
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum

        // New sum: S' = current_sum + x + y
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * (current_sum + current_xor_sum)

        // So, with these choices, S' = 2 * X' is satisfied.
        // The appended elements are current_xor_sum and (current_sum + current_xor_sum).
        // These values can be large, up to 10^9 (for current_xor_sum) and 10^5 * 10^9 + 10^9 (for current_sum + current_xor_sum)
        // which is roughly 10^14, well within long long and 10^18 limit.

        long long x = current_xor_sum;
        long long y = current_sum + current_xor_sum;

        std::cout << 2 << std::endl;
        std::cout << x << " " << y << std::endl;
    }
}

