#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w to easily separate w_i=1 and w_i>1

    long long total_happiness = 0;

    // Handle friends with w_i = 1 first.
    // These friends get 2 * a_j. To maximize, they should get the largest available a_j.
    // Since w is sorted, w_i=1 values are at the beginning.
    // Give the largest elements from 'a' to friends with w_i = 1.
    int a_ptr_end = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_end];
            a_ptr_end--;
        } else {
            // All remaining w_i will be > 1, so we can break.
            break;
        }
    }

    // Handle friends with w_i > 1.
    // These friends get max_val + min_val.
    // To maximize, they should get the remaining largest elements as max_val,
    // and the smallest available elements as min_val.
    // The largest elements are already taken care of for w_i=1.
    // The remaining largest elements are from a_ptr_end downwards.
    // The smallest elements are from a_ptr_start upwards.

    // Give the remaining largest elements as max_val for friends with w_i > 1.
    // These are the friends with larger w_i values (at the end of sorted w).
    // The largest w_i values mean they need more elements, but for max_val, it's just one.
    // We iterate through w from largest w_i (which are at the end of sorted w)
    // down to the first w_i > 1.
    // The largest remaining elements from 'a' are assigned as max_val.
    int current_w_idx = k - 1;
    while (current_w_idx >= 0 && w[current_w_idx] == 1) {
        current_w_idx--; // Skip friends already processed (w_i = 1)
    }

    // Now current_w_idx points to the largest w_i that is > 1, or -1 if all w_i were 1.
    // Assign max_val for these friends.
    // The largest remaining elements are at a[a_ptr_end], a[a_ptr_end-1], etc.
    while (current_w_idx >= 0) {
        total_happiness += a[a_ptr_end]; // This is the max_val for this friend
        a_ptr_end--;
        current_w_idx--;
    }

    // Now assign min_val for friends with w_i > 1.
