#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = s[i] - '0';
    }

    for (int p = 0; p <= 9; ++p) {
        std::string colors(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_p = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < p) {
                colors[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > p) {
                colors[i] = '2';
                s2_digits.push_back(d[i]);
            }
        }

        // Check if s1_digits is sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Check if s2_digits is sorted
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_p = false;
                break;
            }
        }
        if (!possible_p) continue;

        // Now assign digits equal to p
        // First pass: assign '1' to d[i] == p if it maintains s1_digits sorted
        // and is <= first s2_digit
        int last_s1 = s1_digits.empty() ? -1 : s1_digits.back();
        int first_s2 = s2_digits.empty() ? 10 : s2_digits.front();

        for (int i = 0; i < n; ++i) {
            if (d[i] == p) {
                if (d[i] >= last_s1 && d[i] <= first_s2) {
                    colors[i] = '1';
                    last_s1 = d[i];
                }
            }
        }

        // Second pass: assign '2' to remaining d[i] == p
        // and check if it maintains s2_digits sorted
        int current_s2_min = first_s2; // This will be the first digit of S2 after all p's are assigned

        // Find the actual first digit of S2 after assigning some p's to S1
        for(int i = 0; i < n; ++i) {
            if (colors[i] == '2') {
                current_s2_min = d[i];
                break;
            }
            if (colors[i] == '1' && d[i] == p) { // If a p was assigned to S1, it might be the new last_s1
                last_s1 = d[i];
            }
        }


        for (int i = 0; i < n; ++i) {
            if (d[i] == p && colors[i] == ' ') { // If not yet colored
                if (d[i] >= current_s2_min) { // Must be >= current first S2 digit
                    possible_p = false;
                    break;
                }
                colors[i] = '2';
                current_s2_min = d[i]; // This digit becomes the new "first" for subsequent S2 digits
            }
        }
        if (!possible_p) continue;

        // Final check for the combined sequence
        std::vector<int> final_seq;
        for (int i = 0; i < n; ++i) {
            if (colors[i] == '1') {
                final_seq.push_back(d[i]);
            }
        }
        for (int i = 0; i < n; ++i) {
            if (colors[i] == '2') {
                final_seq.push_back(d[i]);
            }
        }

        bool sorted = true;
        for (size_t i = 0; i + 1 < final_seq.size(); ++i) {
            if (final_seq[i] > final_seq[i+1]) {
                sorted = false;
                break;
            }
        }

        if (sorted) {
            std::cout << colors << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

