        for (long long i = 2; i * i <= temp_q; ++i) {
            if (temp_q % i == 0) {
                long long current_prime_factor = i;

                // Calculate power of current_prime_factor in q
                long long power_in_q = 0;
                while (temp_q % current_prime_factor == 0) {
                    power_in_q++;
                    temp_q /= current_prime_factor;
                }

                // Calculate power of current_prime_factor in p
                long long temp_p = p;
                long long power_in_p = 0;
                while (temp_p > 0 && temp_p % current_prime_factor == 0) {
                    power_in_p++;
                    temp_p /= current_prime_factor;
                }

                // We need to remove at least (power_in_p - power_in_q + 1) factors of current_prime_factor from p
                // to make p not divisible by q.
                // The largest x will be p / (current_prime_factor ^ (power_in_p - power_in_q + 1))
                // We want to maximize x, so we want to minimize the divisor.
                // The smallest divisor that makes x not divisible by q is current_prime_factor ^ (power_in_p - power_in_q + 1)
                // This is equivalent to p / (current_prime_factor ^ (power_in_q - 1)) / current_prime_factor
                // Or simply p / (current_prime_factor ^ (power_in_q)) * (current_prime_factor ^ (power_in_q - (power_in_q - 1)))
                // The smallest factor to remove from p to make it not divisible by q is current_prime_factor^(power_in_q).
                // No, this is wrong.
                // If p = f^A * ..., q = f^B * ...
                // We need x = f^C * ... such that C < B.
                // We want to maximize x, so we want C to be as large as possible, i.e., C = B-1.
                // So we need to divide p by f^(A - (B-1)) = f^(A - B + 1).
                // The candidate x is p / (f^(A - B + 1)).

                long long factor_to_remove_power = power_in_p - power_in_q + 1;
                long long divisor_val = 1;
                for(int k = 0; k < factor_to_remove_power; ++k) {
                    divisor_val *= current_prime_factor;
                }
                ans = std::max(ans, p / divisor_val);
            }
        }

        // If temp_q is still > 1, it means temp_q itself is a prime factor
        if (temp_q > 1) {
            long long current_prime_factor = temp_q;
            long long power_in_q = 1; // It's a prime factor, so its power is 1

            long long temp_p = p;
            long long power_in_p = 0;
            while (temp_p > 0 && temp_p % current_prime_factor == 0) {
                power_in_p++;
                temp_p /= current_prime_factor;
            }

            long long factor_to_remove_power = power_in_p - power_in_q + 1;
            long long divisor_val = 1;
            for(int k = 0; k < factor_to_remove_power; ++k) {
                divisor_val *= current_prime_factor;
            }
            ans = std::max(ans, p / divisor_val);
        }
        std::cout << ans << "\n";
    }
