    int n, k;
    std::cin >> n >> k;
    long long total_disassemble_ops = 0;
    long long correct_nestings = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }
        if (m > 0) {
            // If the first doll in a chain is 1, it's a potential start of the target chain.
            // We need to count how many subsequent dolls are also in their correct positions.
            if (chain[0] == 1) {
                correct_nestings = 1; // Doll 1 is in its correct place (as the innermost doll)
                for (int j = 1; j < m; ++j) {
                    if (chain[j] == chain[j - 1] + 1) {
                        correct_nestings++;
                    } else {
                        break; // Sequence broken
                    }
                }
            }
            // Each chain of length m has m-1 existing nestings.
            // These m-1 nestings must be disassembled if they are not part of the final 1->2->...->n chain.
            // The total number of dolls is n. The total number of required nestings is n-1.
            // We are counting how many of the required nestings (i -> i+1) are already present.
            // The problem statement guarantees that matryoshkas in each chain are in ascending order.
            // So, if chain[j] == chain[j-1] + 1, this is a "correct" nesting.
            // We only care about the *longest prefix* of the target chain that is already formed.
            // The `correct_nestings` variable will store the length of the prefix 1 -> 2 -> ... -> `correct_nestings`.
            // Any other nesting `a -> b` where `b != a+1` must be disassembled.
            // Any nesting `i -> i+1` that is *not* part of the `1 -> ... -> correct_nestings` prefix
            // must also be disassembled if it's not `1 -> 2` etc.
            // The problem simplifies this: we only need to find the length of the prefix `1 -> 2 -> ... -> X`.
            // All other dolls must be taken out and put back.
            // The total number of dolls is n.
            // The total number of required nestings is n-1.
            // The number of dolls that are part of the `1 -> 2 -> ... -> correct_nestings` prefix is `correct_nestings`.
            // These `correct_nestings` dolls form `correct_nestings - 1` correct nestings.
            // All other `n - correct_nestings` dolls must be moved.
            // Each of these `n - correct_nestings` dolls needs to be taken out (1 op) and put in (1 op).
            // So, `2 * (n - correct_nestings)` operations.
            // However, the `correct_nestings - 1` nestings are already formed.
            // The remaining `(n-1) - (correct_nestings - 1)` nestings need to be formed.
            // This is `n - correct_nestings` new nestings. Each takes 1 op.
            // So, `(n - correct_nestings)` "put in" operations.
            //
            // Let's re-evaluate:
            // Total dolls = n.
            // Target chain: 1 -> 2 -> ... -> n.
            //
            // We find the longest prefix of the target chain that is already formed.
            // E.g., if we have `1 -> 2 -> 3` and `4 -> 5`, `correct_nestings` would be 3.
            // This means dolls 1, 2, 3 are correctly nested.
            //
            // Operations:
            // 1. Disassemble all existing chains that are NOT part of the `1 -> ... -> correct_nestings` prefix.
            //    Number of dolls NOT in the prefix: `n - correct_nestings`.
            //    Each of these `n - correct_nestings` dolls must be "freed" from any nesting it's currently in.
            //    If a doll `x` is nested in `y`, and `x` is not part of the prefix, we need to take `x` out of `y`.
            //    This costs 1 operation.
            //    The total number of existing nestings is `n - k` (total dolls minus number of chains).
            //    The number of *correct* nestings in the prefix is `correct_nestings - 1`.
            //    So, the number of nestings to disassemble is `(n - k) - (correct_nestings - 1)`.
            //    This is `n - k - correct_nestings + 1`.
            //
            // 2. Assemble the remaining parts of the target chain.
            //    We need to form `n - 1` total nestings.
            //    We already have `correct_nestings - 1` nestings.
            //    So, we need to form `(n - 1) - (correct_nestings - 1) = n - correct_nestings` new nestings.
            //    Each new nesting costs 1 operation.
            //    This is `n - correct_nestings` operations.
            //
            // Total operations = (disassemble ops) + (assemble ops)
            // Total operations = `(n - k - correct_nestings + 1)` + `(n - correct_nestings)`
            // Total operations = `2 * n - k - 2 * correct_nestings + 1`.
            //
            // Let's test with examples:
            // Example 1:
            // n=3, k=2
            // Chain 1: 2 1 2
            // Chain 2: 1 3
            //
            // First chain: 1 -> 2. `chain[0]=1`, `chain[1]=2`. `correct_nestings` becomes 2.
            // Second chain: 3. `chain[0]=3`. Not 1. `correct_nestings` remains 2.
            //
            // Total ops = `2 * 3 - 2 - 2 * 2 + 1`
            //           = `6 - 2 - 4 + 1`
            //           = `1`. Correct.
            //
            // Example 2:
            // n=7, k=3
            // Chain 1: 3 1 3 7
            // Chain 2: 2 2 5
            // Chain 3: 2 4 6
            //
            // First chain: 1 -> 3 -> 7. `chain[0]=1`. `chain[1]=3` (not 1+1). `correct_nestings` becomes 1.
            // Second chain: 2 -> 5. `chain[0]=2`. Not 1. `correct_nestings` remains 1.
            // Third chain: 4 -> 6. `chain[0]=4`. Not 1. `correct_nestings` remains 1.
            //
            // Total ops = `2 * 7 - 3 - 2 * 1 + 1`
            //           = `14 - 3 - 2 + 1`
            //           = `10`. Correct.
            //
            // This formula seems correct.
            // `n - k` is the total number of existing nestings across all chains.
            // `correct_nestings - 1` is the number of *useful* existing nestings (part of 1->...->n).
            // So, `(n - k) - (correct_nestings - 1)` is the number of existing nestings that must be disassembled.
            // `n - correct_nestings` is the number of new nestings that must be formed.
            //
            // Total operations = (disassemble non-useful nestings) + (assemble new nestings)
            //                  = ( (n - k) - (correct_nestings - 1) ) + ( n - correct_nestings )
            //                  = n - k - correct_nestings + 1 + n - correct_nestings
            //                  = 2*n - k - 2*correct_nestings + 1
        }
    }
    long long result = 2LL * n - k - 2LL * correct_nestings + 1;
    std::cout << result << std::endl;
    return 0;
