void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] == s[i+k]
    // For each i, s[i] must be equal to s[i+k], s[i+2k], etc.
    // This means all characters at indices i, i+k, i+2k, ... must be the same.
    // We can determine this common character for each residue class modulo k.
    // If there's a conflict (e.g., s[i] = '0' and s[i+k] = '1'), then it's impossible.
    for (int i = 0; i < k; ++i) {
        char fixed_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (fixed_char == '?') {
                    fixed_char = s[j];
                } else if (fixed_char != s[j]) {
                    std::cout << "NO\n";
                    return;
                }
            }
        }
        // Apply the determined character back to the string
        if (fixed_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = fixed_char;
            }
        }
    }

    // Step 2: Check the first k characters for balance
    // After propagation, the first k characters s[0...k-1] must be able to form a balanced string.
    // This means they must contain k/2 zeros and k/2 ones.
    // We count the known zeros, known ones, and question marks in s[0...k-1].
    int zeros_count = 0;
    int ones_count = 0;
    int q_marks_count = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros_count++;
        } else if (s[i] == '1') {
            ones_count++;
        } else { // s[i] == '?'
            q_marks_count++;
        }
    }

    // If the number of known zeros or known ones already exceeds k/2, it's impossible.
    if (zeros_count > k / 2 || ones_count > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If the remaining '?' can be filled to achieve k/2 zeros and k/2 ones, it's possible.
    // We need (k/2 - zeros_count) more zeros and (k/2 - ones_count) more ones.
    // The total number of '?' needed is (k/2 - zeros_count) + (k/2 - ones_count).
    // This sum must be equal to q_marks_count.
    // Since we already checked zeros_count <= k/2 and ones_count <= k/2,
    // and zeros_count + ones_count + q_marks_count = k,
    // this condition simplifies to just checking the counts.
    // If we have enough '?' to fill the deficit for both 0s and 1s, it's possible.
    // The number of '?' that must become '0' is k/2 - zeros_count.
    // The number of '?' that must become '1' is k/2 - ones_count.
    // The sum of these must be exactly q_marks_count.
    if ((k / 2 - zeros_count) + (k / 2 - ones_count) == q_marks_count) {
        std::cout << "YES\n";
    } else {
        // This case should ideally be covered by the previous checks,
        // but as a safeguard, if the counts don't add up, it's impossible.
        std::cout << "NO\n";
    }
}

