    sum_k_val = (sum_k_val * inv2) % MOD;

    long long term1 = (b_mod * sum_k_val) % MOD;
    long long term2 = a % MOD;

    long long sum_k_term = (term1 + term2) % MOD;

    long long total_sum = (sum_r * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Calculate d_i for left-to-right scan
    for (int i = 0; i < n; ++i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = prev_d + 1;
        q.push_back(i);
    }

    q.clear();

    // Calculate d_i for right-to-left scan and combine
    long long max_ops = 0;
    for (int i = n - 1; i >= 0; --i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = std::min(d[i], prev_d + 1);
        q.push_back(i);
        max_ops = std::max(max_ops, d[i]);
    }

    std::cout << max_ops << std::endl;

    return 0;
}

