        long long n, m;
        std::cin >> n >> m;
        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }
        long long total_substrings = n * (n + 1) / 2;
        long long num_zeros = n - m;
        long long k = m + 1; // Number of blocks of zeros
        long long q = num_zeros / k; // Minimum length of a zero block
        long long r = num_zeros % k; // Number of blocks with length q+1

        long long sum_zero_substrings = 0;
        // r blocks of length q+1
        if (r > 0) {
            sum_zero_substrings += r * (q + 1) * (q + 2) / 2;
        }
        // k-r blocks of length q
        if (k - r > 0) {
            sum_zero_substrings += (k - r) * q * (q + 1) / 2;
        }

        long long result = total_substrings - sum_zero_substrings;
        std::cout << result << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> diff_left(n + 1, 0); // diff_left[k] = (count of 1s - count of 2s) in a[0...k-1]
    for (int i = 0; i < n; ++i) {
        diff_left[i + 1] = diff_left[i] + (a[i] == 1 ? 1 : -1);
    }

    std::vector<int> diff_right(n + 1, 0); // diff_right[k] = (count of 1s - count of 2s) in a[2n-k...2n-1]
    for (int i = 0; i < n; ++i) {
        diff_right[i + 1] = diff_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    std::map<int, int> right_diff_to_k; // Stores diff_right[k] -> k
    for (int k = 0; k <= n; ++k) {
        if (right_diff_to_k.find(diff_right[k]) == right_diff_to_k.end()) {
            right_diff_to_k[diff_right[k]] = k;
        }
    }

    int min_removed = 2 * n; // Max possible jars to remove

    for (int k_left = 0; k_left <= n; ++k_left) {
        int current_diff_left = diff_left[k_left];
        int target_diff_right = -current_diff_left;

        if (right_diff_to_k.count(target_diff_right)) {
            int k_right = right_diff_to_k[target_diff_right];
            min_removed = std::min(min_removed, k_left + k_right);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

