    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Operation 1: Handle n-1 elements (a[0] to a[n-2])
    // For each a[i] (0 <= i < n-1), we want to add a multiple of n to make it 0 mod n.
    // Since n and n-1 are coprime (if n > 1), we can make a[i] a multiple of n.
    // Specifically, we want a[i] + x * n = 0 (mod n-1).
    // This is equivalent to a[i] = 0 (mod n-1) after adding x*n.
    // Or, a[i] + k * (n-1) = 0 (mod n).
    // This is not the right approach.

    // Let's use the property that for any x, we can find k such that x + k*len is a multiple of len.
    // We want to make a[i] become 0. So we need to add -a[i].
    // This means -a[i] must be a multiple of len.
    // So a[i] must be a multiple of len.

    // Strategy:
    // 1. Make all elements a[0]...a[n-2] multiples of n.
    //    For each a[i], we need to add some value x_i such that (a[i] + x_i) % n == 0.
    //    And x_i must be a multiple of n. This is impossible if a[i] % n != 0.
    //    The problem states: "add a multiple of len to it".
    //    So we need to add `k * len` such that `a[i] + k * len = 0`.
    //    This means `a[i]` must be a multiple of `len`. This is the core difficulty.

    // Let's use the fact that `n` and `n-1` are coprime (if `n > 1`).
    // If `n = 1`, the array has one element `a[0]`.
    // Op 1: segment [1,1], len=1. Add -a[0]. a[0] becomes 0.
    // Op 2: segment [1,1], len=1. Add 0.
    // Op 3: segment [1,1], len=1. Add 0.
    if (n == 1) {
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // General case for n > 1:

    // Operation 1: Make a[0]...a[n-2] multiples of n.
    // For each a[i] (0 <= i < n-1), we want to add `x_i` such that `a[i] + x_i` is a multiple of `n`.
    // And `x_i` itself must be a multiple of `n`.
    // This means `a[i]` must already be a multiple of `n`. This is not true.

    // The trick is to use the property that `(a[i] % n + n) % n` gives the smallest non-negative remainder.
    // We want to add `x_i` such that `a[i] + x_i = 0`.
    // And `x_i` must be a multiple of `len`.
    // So `a[i]` must be a multiple of `len`.

    // Let's try a different strategy:
    // 1. Select segment [1, n-1]. Length is n-1.
    //    For each a[i] (0 <= i < n-1), we want to add `x_i` such that `a[i] + x_i` is a multiple of `n`.
    //    And `x_i` must be a multiple of `n-1`.
    //    So `a[i] + k * (n-1) = M * n` for some integers `k, M`.
    //    `a[i] = M * n - k * (n-1)`.
    //    `a[i] = M * n - k * n + k`.
    //    `a[i] = (M - k) * n + k`.
    //    So `a[i] % n = k % n`.
    //    We need to find `k` such that `k % n = a[i] % n`.
    //    Let `rem = (a[i] % n + n) % n`.
    //    We need `k % n = rem`.
    //    We can choose `k = rem`.
    //    Then `x_i = k * (n-1) = rem * (n-1)`.
    //    After this operation, `a[i]` becomes `a[i] + rem * (n-1)`.
    //    `a[i] + rem * (n-1) = a[i] + rem * n - rem`.
    //    Since `a[i] % n = rem`, `a[i] = Q * n + rem`.
    //    So `a[i] + rem * (n-1) = Q * n + rem + rem * n - rem = (Q + rem) * n`.
    //    Thus, `a[i]` becomes a multiple of `n`.
    //    This works for `a[0]` to `a[n-2]`.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long rem = (a[i] % n + n) % n;
        long long add_val = rem * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val; // Update a[i]
    }
    std::cout << "\n";

    // At this point, a[0]...a[n-2] are all multiples of n.
    // a[n-1] is unchanged.

    // Operation 2: Make a[n-1] a multiple of n.
    // Select segment [n, n]. Length is 1.
    // For a[n-1], we want to add `x` such that `a[n-1] + x` is a multiple of `n`.
    // And `x` must be a multiple of 1. This is always true.
    // Let `rem = (a[n-1] % n + n) % n`.
    // We want `a[n-1] + x = 0 (mod n)`.
    // We can choose `x = -rem`.
    // Then `a[n-1]` becomes `a[n-1] - rem`. This is a multiple of `n`.
    // Or, we can choose `x = (n - rem) % n`. If rem is 0, x is 0. If rem is not 0, x is n-rem.
    // This makes a[n-1] a multiple of n.
    // Let's just make it 0 mod n.
    std::cout << n << " " << n << "\n";
    long long rem_n_minus_1 = (a[n - 1] % n + n) % n;
    long long add_val_n_minus_1 = rem_n_minus_1 * n; // Add a multiple of n to make it 0 mod n.
                                                      // No, this is wrong. We need to add a multiple of len=1.
                                                      // We want a[n-1] + x = 0 (mod n).
                                                      // x = (n - (a[n-1] % n + n) % n) % n.
                                                      // This makes a[n-1] a multiple of n.
                                                      // Example: a[n-1]=5, n=4. rem=1. x=(4-1)%4=3. a[n-1] becomes 8.
                                                      // Example: a[n-1]=4, n=4. rem=0. x=(4-0)%4=0. a[n-1] becomes 4.
    long long val_to_add_to_last = (n - rem_n_minus_1) % n;
    std::cout << val_to_add_to_last << "\n";
    a[n - 1] += val_to_add_to_last; // Update a[n-1]

    // At this point, all elements a[0]...a[n-1] are multiples of n.

    // Operation 3: Make all elements 0.
    // Select segment [1, n]. Length is n.
    // For each a[i], we want to add `x_i` such that `a[i] + x_i = 0`.
    // And `x_i` must be a multiple of `n`.
    // Since all `a[i]` are currently multiples of `n`, we can choose `x_i = -a[i]`.
    // `-a[i]` is also a multiple of `n`.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false);

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back

        active[k] = true; // Mark vertex k as active

        // Update shortest paths using k as an intermediate vertex
        // This is the core of Floyd-Warshall
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices as source
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices as destination

                // Path i -> k -> j
                if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                    if (dist[i][j] == -1 || dist[i][k] + dist[k][j] < dist[i][j]) {
                        dist[i][j] = dist[i][k] + dist[k][j];
                    }
                }
            }
        }

        // Also update paths involving k as source or destination
        // This is crucial because k itself is now active
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;

                // Path i -> k -> j (already handled above, but ensures all pairs are considered)
                // Path k -> i -> j (using i as intermediate for k to j)
                if (dist[k][i] != -1 && dist[i][j] != -1) {
                    if (dist[k][j] == -1 || dist[k][i] + dist[i][j] < dist[k][j]) {
                        dist[k][j] = dist[k][i] + dist[i][j];
                    }
                }
                // Path i -> j -> k (using j as intermediate for i to k)
                if (dist[i][j] != -1 && dist[j][k] != -1) {
                    if (dist[i][k] == -1 || dist[i][j] + dist[j][k] < dist[i][k]) {
                        dist[i][k] = dist[i][j] + dist[j][k];
                    }
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (forward)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_ones: distance to the nearest 1 on the left (inclusive)
    // If no 1 on left, it's effectively infinity (or n)
    int last_one_idx = -n; // Initialize far left
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            last_one_idx = i;
        }
        left_ones[i] = i - last_one_idx;
    }

    // Calculate right_ones: distance to the nearest 1 on the right (inclusive)
    // If no 1 on right, it's effectively infinity (or n)
    last_one_idx = 2 * n; // Initialize far right
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == 1) {
            last_one_idx = i;
        }
        right_ones[i] = last_one_idx - i;
    }

    std::vector<int> b(n);
    int max_steps = 0;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            if (left_ones[i] == n && right_ones[i] == n) { // All zeros
                b[i] = 0;
            } else if (left_ones[i] == right_ones[i]) { // Equidistant to 1s
                b[i] = 0;
            } else if (left_ones[i] < right_ones[i]) { // Closer to left 1
                b[i] = 1;
                max_steps = std::max(max_steps, left_ones[i]);
            } else { // Closer to right 1
                b[i] = 1;
                max_steps = std::max(max_steps, right_ones[i]);
            }
        } else { // a[i] == 1
            b[i] = 1;
        }
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0; // What 0 becomes after all operations
    int current_val_1023 = 1023; // What 1023 becomes after all operations

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    // Now we have the final state for an input of 0 and an input of 1023.
    // Let f(x) be the function computed by Petya's program.
    // We know f(0) = current_val_0 and f(1023) = current_val_1023.
    // For each bit position b (0 to 9):
    // Let x_b be the b-th bit of input x.
    // Let f(x)_b be the b-th bit of f(x).
    //
    // We need to find a, b, c such that for all x in [0, 1023]:
    // ((x & a) | b) ^ c = f(x)
    //
    // Let's analyze the behavior for each bit.
    // For a given bit b:
    // Let x_b be the b-th bit of x.
    // Let a_b, b_b, c_b be the b-th bits of a, b, c respectively.
    //
    // The final bit f(x)_b can be one of four functions of x_b:
    // 1. f(x)_b = 0 (constant 0)
    // 2. f(x)_b = 1 (constant 1)
    // 3. f(x)_b = x_b (identity)
    // 4. f(x)_b = 1 - x_b (negation)
    //
    // We can determine which function it is by checking f(0)_b and f(1)_b.
    // f(0)_b is the b-th bit of current_val_0.
    // f(1)_b is the b-th bit of current_val_1023, but only if the other bits of 1023 don't interfere.
    // A better way to get f(1)_b is to compute f(2^b) and take its b-th bit.
    // However, we can deduce f(1)_b from f(0)_b and f(1023)_b.
    //
    // Let's define two values:
    // `all_zero_bit_val`: The value of the b-th bit of f(0). This is `(current_val_0 >> b) & 1`.
    // `all_one_bit_val`: The value of the b-th bit of f(1023). This is `(current_val_1023 >> b) & 1`.
    //
    // If `all_zero_bit_val == all_one_bit_val`:
    //   The bit b is constant.
    //   If `all_zero_bit_val == 0`, then f(x)_b = 0 for all x.
    //   If `all_zero_bit_val == 1`, then f(x)_b = 1 for all x.
    // If `all_zero_bit_val != all_one_bit_val`:
    //   The bit b depends on x_b.
    //   If `all_zero_bit_val == 0` and `all_one_bit_val == 1`:
    //     Then f(x)_b = x_b (identity).
    //   If `all_zero_bit_val == 1` and `all_one_bit_val == 0`:
    //     Then f(x)_b = 1 - x_b (negation).
    //
    // We want to find a, b, c such that ((x & a) | b) ^ c matches this behavior for each bit.
    //
    // Let's analyze ((x_b & a_b) | b_b) ^ c_b:
    //
    // Case 1: f(x)_b = 0 (constant 0)
    //   We need ((x_b & a_b) | b_b) ^ c_b = 0 for both x_b=0 and x_b=1.
    //   If x_b=0: (0 | b_b) ^ c_b = 0 => b_b ^ c_b = 0 => b_b = c_b.
    //   If x_b=1: (a_b | b_b) ^ c_b = 0 => a_b | b_b = c_b.
    //   Combining: b_b = c_b and a_b | b_b = b_b. This implies a_b = 0.
    //   So, for f(x)_b = 0, we need a_b=0, b_b=0, c_b=0.
    //   ((x_b & 0) | 0) ^ 0 = (0 | 0) ^ 0 = 0. This works.
    //
    // Case 2: f(x)_b = 1 (constant 1)
    //   We need ((x_b & a_b) | b_b) ^ c_b = 1 for both x_b=0 and x_b=1.
    //   If x_b=0: (0 | b_b) ^ c_b = 1 => b_b ^ c_b = 1 => b_b != c_b.
    //   If x_b=1: (a_b | b_b) ^ c_b = 1 => a_b | b_b != c_b.
    //   Combining: b_b != c_b and a_b | b_b != c_b.
    //   A simple solution: a_b=0, b_b=1, c_b=0.
    //   ((x_b & 0) | 1) ^ 0 = (0 | 1) ^ 0 = 1. This works.
    //
    // Case 3: f(x)_b = x_b (identity)
    //   We need ((x_b & a_b) | b_b) ^ c_b = x_b.
    //   If x_b=0: (0 | b_b) ^ c_b = 0 => b_b ^ c_b = 0 => b_b = c_b.
    //   If x_b=1: (a_b | b_b) ^ c_b = 1 => a_b | b_b != c_b.
    //   Combining: b_b = c_b and a_b | b_b != b_b. This implies a_b = 1 and b_b = 0.
    //   So, for f(x)_b = x_b, we need a_b=1, b_b=0, c_b=0.
    //   ((x_b & 1) | 0) ^ 0 = (x_b | 0) ^ 0 = x_b. This works.
    //
    // Case 4: f(x)_b = 1 - x_b (negation)
    //   We need ((x_b & a_b) | b_b) ^ c_b = 1 - x_b.
    //   If x_b=0: (0 | b_b) ^ c_b = 1 => b_b ^ c_b = 1 => b_b != c_b.
    //   If x_b=1: (a_b | b_b) ^ c_b = 0 => a_b | b_b = c_b.
    //   Combining: b_b != c_b and a_b | b_b = c_b.
    //   A simple solution: a_b=1, b_b=0, c_b=1.
    //   ((x_b & 1) | 0) ^ 1 = (x_b | 0) ^ 1 = x_b ^ 1 = 1 - x_b. This works.

    // Summary of (a_b, b_b, c_b) for each target function:
    // f(x)_b = 0: (0, 0, 0)
    // f(x)_b = 1: (0, 1, 0)
    // f(x)_b = x_b: (1, 0, 0)
    // f(x)_b = 1 - x_b: (1, 0, 1)

    // Now construct the final a, b, c values.
    int final_a = 0;
    int final_b = 0;
    int final_c = 0;

    for (int bit = 0; bit < 10; ++bit) {
        int bit_val_0 = (current_val_0 >> bit) & 1;
        int bit_val_1023 = (current_val_1023 >> bit) & 1;

        if (bit_val_0 == 0 && bit_val_1023 == 0) { // f(x)_b = 0
            // a_b=0, b_b=0, c_b=0. No bits to set in final_a, final_b, final_c.
        } else if (bit_val_0 == 1 && bit_val_1023 == 1) { // f(x)_b = 1
            // a_b=0, b_b=1, c_b=0. Set bit in final_b.
            final_b |= (1 << bit);
        } else if (bit_val_0 == 0 && bit_val_1023 == 1) { // f(x)_b = x_b
            // a_b=1, b_b=0, c_b=0. Set bit in final_a.
            final_a |= (1 << bit);
        } else { // bit_val_0 == 1 && bit_val_1023 == 0, f(x)_b = 1 - x_b
            // a_b=1, b_b=0, c_b=1. Set bit in final_a and final_c.
            final_a |= (1 << bit);
            final_c |= (1 << bit);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_a != 1023) { // If final_a is not all ones, we need an AND operation.
                           // If final_a is 1023 (all ones), x & 1023 is just x for x in [0,1023], so it's identity.
        result_ops.push_back({'&', final_a});
    }
    if (final_b != 0) { // If final_b is not all zeros, we need an OR operation.
        result_ops.push_back({'|', final_b});
    }
    if (final_c != 0) { // If final_c is not all zeros, we need an XOR operation.
        result_ops.push_back({'^', final_c});
    }

    // The problem states "no more than 5 lines". Our construction gives at most 3.
    // The problem also states "arbitrary constants from 0 to 1023".
    // Our `final_a` can be 1023. If `final_a` is 1023, `x & 1023` is effectively `x` for inputs 0-1023.
    // So, if `final_a` is 1023, the `&` operation is redundant.
    // Let's refine the output logic.

    // The operations are applied in order: AND, then OR, then XOR.
    // This is the form ((x & A) | B) ^ C.
    //
    // If A = 1023 (all bits 1), then (x & A) is just x.
    // If B = 0 (all bits 0), then (Y | B) is just Y.
    // If C = 0 (all bits 0), then (Z ^ C) is just Z.

    // We need to output the operations in the order they are applied.
    // The derived (A, B, C) values correspond to the operations:
    // 1. & A
    // 2. | B
    // 3. ^ C

    // Output the operations only if their constant is not the identity for that operation.
    // For '&', identity is 1023.
    // For '|', identity is 0.
    // For '^', identity is 0.

    std::vector<std::pair<char, int>> simplified_ops;
    if (final_a != 1023) {
        simplified_ops.push_back({'&', final_a});
    }
    if (final_b != 0) {
        simplified_ops.push_back({'|', final_b});
    }
    if (final_c != 0) {
        simplified_ops.push_back({'^', final_c});
    }

    std::cout << simplified_ops.size() << std::endl;
    for (const auto& op : simplified_ops) {
