}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    int id;
    long long v, d, p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long cumulative_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply cumulative d_cry from previous children who left
            children[j].p -= cumulative_d_cry;

            // Apply current_v_cry from the child in office
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                cumulative_d_cry += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a with a very large negative number
    // This is because we are looking for a maximum possible initial value
    // that satisfies all constraints.
    // If a[i] + current_sum_d[i] <= m_j, then a[i] <= m_j - current_sum_d[i].
    // We want to maximize a[i] under these constraints.
    std::vector<long long> initial_a(n, std::numeric_limits<long long>::max());

    // Iterate operations in reverse to calculate the maximum possible initial value for each element
    // based on type 2 operations.
    // For each element a[i], we want to find the largest possible initial_a[i]
    // such that all type 2 constraints are met.
    // A type 2 constraint (l, r, m) means that for any j in [l, r],
    // initial_a[j] + sum_of_d_values_applied_to_j_up_to_this_point <= m.
    // So, initial_a[j] <= m - sum_of_d_values_applied_to_j_up_to_this_point.
    // We need to find the minimum of these upper bounds for each initial_a[j].

    // current_d_effect[i] stores the sum of 'd' values applied to a[i]
    // from the current operation (iterating backwards) up to the end.
    std::vector<long long> current_d_effect(n, 0);

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (l, r, d), it means that
            // for elements j in [l, r], their value was increased by d.
            // When going backwards, this means the effect of this 'd'
            // is now removed from the current_d_effect for these elements.
            // So, we subtract d from current_d_effect for j in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_d_effect[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (l, r, m), it means that
            // max(a[j] for j in [l, r]) must be m at this point in time.
            // This implies that for all j in [l, r], a[j] <= m.
            // In terms of initial values: initial_a[j] + current_d_effect[j] <= m.
            // So, initial_a[j] <= m - current_d_effect[j].
            // We update initial_a[j] with the minimum of its current value
            // and this new upper bound.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_d_effect[j]);
            }
        }
    }

    // After iterating backwards, initial_a[j] contains the maximum possible
    // initial value for a[j] that satisfies all type 2 constraints.
    // If any initial_a[j] is still std::numeric_limits<long long>::max(),
    // it means it was never constrained by a type 2 operation.
    // We can set such elements to 0 (or any value within [-10^9, 10^9]).
    // The problem statement says |a_i| <= 10^9.
    // Let's set unconstrained values to 0.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0;
        }
        // Also, ensure the initial values are within the allowed range.
        // If initial_a[i] is outside [-10^9, 10^9], it's an invalid solution.
        // However, the problem constraints on m_i and d_i, combined with n, m <= 5000,
        // suggest that m - current_d_effect will likely stay within reasonable bounds.
        // Max current_d_effect: 5000 * 10^4 = 5 * 10^7.
        // Max m_i: 5 * 10^7. So m_i - current_d_effect could be 5*10^7 - (-5*10^7) = 10^8.
        // Min m_i: -5 * 10^7. So m_i - current_d_effect could be -5*10^7 - (5*10^7) = -10^8.
        // These values are within [-10^9, 10^9].
    }

    // Now, verify if this constructed initial_a satisfies all type 2 constraints
    // and if the maximums are exactly 'm', not just 'less than or equal to m'.
    // We simulate the operations forward with the constructed initial_a.
    std::vector<long long> current_array(initial_a);
    std::vector<long long> current_d_prefix_sum(n + 1, 0); // For efficient range updates

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Apply the 'd' value to the prefix sum array
            current_d_prefix_sum[ops[i].l] += ops[i].val;
            if (ops[i].r + 1 < n) {
                current_d_prefix_sum[ops[i].r + 1] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            long long max_val = std::numeric_limits<long long>::min();
            long long current_delta = 0; // Actual delta for current element
            for (int j = 0; j < n; ++j) {
                current_delta += current_d_prefix_sum[j];
                if (j >= ops[i].l && j <= ops[i].r) {
                    max_val = std::max(max_val, initial_a[j] + current_delta);
                }
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

