    for (int i = 1; i < n; ++i) {
        // Reset memoization and visiting for each run, as a_1 changes
        std::fill(memo.begin(), memo.end(), std::make_pair(0LL, 0));
        std::fill(visiting.begin(), visiting.end(), false);

        // Initial state: x = 1, y = 0
        // First operation (step 2):
        // x = 1 + a_1, y = 0 + a_1
        // Here a_1 is `i` for this run.
        long long initial_a1 = i;
        long long current_y = initial_a1;
        int current_x = 1 + static_cast<int>(initial_a1);

        // Now, from (current_x, current_y), the next operation is step 3.
        // We need to call our `solve` function which expects `start_x` to be the x value
        // *after* a step 2, and it will perform step 3, then step 2, etc.
        std::pair<long long, int> result = solve(current_x, initial_a1, a_suffix, solve);

        if (result.first == -1 && result.second == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + result.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i].value;
        a[i].original_index = i;
    }

    std::sort(a.begin(), a.end(), compareElements);

    long long min_a = a[0].value;
    long long max_a = a[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., S1 is empty, S2 contains all)
    // All f(a_i, a_j) = a_i + a_j
    // Min f = a[0].value + a[1].value
    // Max f = a[n-2].value + a[n-1].value
    // Goodness = (a[n-2].value + a[n-1].value) - (a[0].value + a[1].value)
    long long goodness1 = (a[n - 2].value + a[n - 1].value) - (a[0].value + a[1].value);
    std::vector<int> partition1(n, 2); // All in subsequence 2

    // Case 2: Partition into two non-empty subsequences
    // The minimum possible f value is min_a + min_a_next (if they are in the same group)
    // or min_a + min_a_next + h (if they are in different groups).
    // The maximum possible f value is max_a + max_a_prev (if they are in the same group)
    // or max_a + max_a_prev + h (if they are in different groups).

    // Consider a partition where a[0] is in S1 and all others are in S2.
    // Or a[0] and a[1] are in S1, and others in S2.
    // The critical values are a[0], a[1], a[n-2], a[n-1].

    // Option A: a[0] is in S1, all other elements are in S2.
    // Min f:
    //   - If n > 2: a[1] + a[2] (both in S2)
    //   - a[0] + a[1] + h (a[0] in S1, a[1] in S2)
    // Max f:
    //   - a[n-2] + a[n-1] (both in S2)
    //   - a[0] + a[n-1] + h (a[0] in S1, a[n-1] in S2)

    // Let's try to put a[0] in S1 and all others in S2.
    // Min f value: min(a[0] + a[1] + h, a[1] + a[2] (if n > 2))
    // Max f value: max(a[0] + a[n-1] + h, a[n-2] + a[n-1])
    // This strategy aims to make the min_f and max_f values as close as possible.
    // The smallest element a[0] is separated from the rest.
    // The values will be:
    //   - a[0] + a_j + h for j > 0
    //   - a_i + a_j for i, j > 0
    // Min value: min(a[0] + a[1] + h, a[1] + a[2] (if n > 2))
    // Max value: max(a[0] + a[n-1] + h, a[n-2] + a[n-1])

    // Let's analyze the range of values.
    // The smallest possible sum is a[0] + a[1].
    // The largest possible sum is a[n-2] + a[n-1].
    // The values of f can be in [a[0]+a[1], a[n-2]+a[n-1]] or [a[0]+a[1]+h, a[n-2]+a[n-1]+h].

    // Consider the case where a[0] is in S1, and all other elements a[1]...a[n-1] are in S2.
    // Min_f_val:
    //   - If n=2: only a[0]+a[1]+h
    //   - If n>2: min(a[0]+a[1]+h, a[1]+a[2])
    // Max_f_val:
    //   - If n=2: only a[0]+a[1]+h
    //   - If n>2: max(a[0]+a[n-1]+h, a[n-2]+a[n-1])

    long long current_min_f_val;
    long long current_max_f_val;

    if (n == 2) {
        current_min_f_val = a[0].value + a[1].value + h;
        current_max_f_val = a[0].value + a[1].value + h;
    } else {
        current_min_f_val = std::min(a[0].value + a[1].value + h, a[1].value + a[2].value);
        current_max_f_val = std::max(a[0].value + a[n - 1].value + h, a[n - 2].value + a[n - 1].value);
    }
    long long goodness2 = current_max_f_val - current_min_f_val;
    std::vector<int> partition2(n);
    partition2[a[0].original_index] = 1;
    for (int i = 1; i < n; ++i) {
        partition2[a[i].original_index] = 2;
    }

    // Compare goodness1 and goodness2
    long long min_goodness = goodness1;
    std::vector<int> best_partition = partition1;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        best_partition = partition2;
    }

    // There's one more critical partition:
    // If a[0] + a[1] + h is very large, it might be better to put a[0] and a[1] in S1, and the rest in S2.
    // This would make a[0]+a[1] a possible min_f, and a[0]+a[2]+h a possible min_f.
    // The values would be:
    //   - a[0] + a[1] (both in S1)
    //   - a[i] + a[j] for i,j >= 2 (both in S2)
    //   - a[k] + a[l] + h for k in {0,1}, l >= 2
    // Min f: a[0] + a[1]
    // Max f: max(a[n-2] + a[n-1], a[1] + a[n-1] + h)
    // This is only relevant if n >= 3.
    if (n >= 3) {
        long long current_min_f_val_alt = a[0].value + a[1].value;
        long long current_max_f_val_alt = std::max(a[n - 2].value + a[n - 1].value, a[1].value + a[n - 1].value + h);
        long long goodness_alt = current_max_f_val_alt - current_min_f_val_alt;

        if (goodness_alt < min_goodness) {
            min_goodness = goodness_alt;
            best_partition.assign(n, 2);
            best_partition[a[0].original_index] = 1;
            best_partition[a[1].original_index] = 1;
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0;
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        long long current_h = h[h_idx];
        long long left_reach = current_h - T;
        long long right_reach = current_h + T;

        // Skip target tracks already covered by previous heads
        while (p_idx < m && p[p_idx] < left_reach) {
            // This track cannot be covered by current or previous heads
            // because p is sorted and left_reach is increasing or stable.
            // If p[p_idx] < left_reach, it means p[p_idx] is too far left for current_h.
            // If it wasn't covered by previous heads, it's impossible.
            // This logic is flawed. A track p[p_idx] < left_reach might have been covered by a previous head.
            // The correct logic is to advance p_idx only if p[p_idx] is covered by the current head.
            // If p[p_idx] is not covered by current head, and it's to the left of current head's reach,
            // it must have been covered by a previous head.
            // If it's not covered by current head, and it's to the right of current head's reach,
            // it must be covered by a future head.
            // The problem is to cover ALL p_j.
            // So, we need to find the first p_j that is NOT covered by current head.
            // And then try to cover it with the next head.

            // Let's re-think the greedy approach.
            // We want to cover the leftmost uncovered track p[p_idx] using the current head h[h_idx].
            // If h[h_idx] can cover p[p_idx], it can cover any track in [p[p_idx], h[h_idx] + T].
            // We should use h[h_idx] to cover as many tracks as possible to its right, starting from p[p_idx].
            // This means h[h_idx] covers tracks in range [max(p[p_idx], h[h_idx] - T), h[h_idx] + T].
            // So, we advance p_idx as long as p[p_idx] <= h[h_idx] + T.
            // But what if p[p_idx] is too far left for h[h_idx]? i.e., p[p_idx] < h[h_idx] - T.
            // In this case, p[p_idx] must have been covered by a previous head.
            // If it wasn't, then it's impossible.

            // A better greedy strategy:
            // Iterate through heads h_idx from 0 to n-1.
            // For each head h[h_idx], find the leftmost target track p[p_idx] that is not yet covered.
            // If p[p_idx] is too far to the left for h[h_idx] (i.e., p[p_idx] < h[h_idx] - T),
            // then this p[p_idx] cannot be covered by h[h_idx] or any subsequent head (since h is sorted).
            // This means p[p_idx] must have been covered by a previous head.
            // If it wasn't, then it's impossible.
            // This implies that if p[p_idx] < h[h_idx] - T, then `check` should return false.
            // This is not correct. p[p_idx] could be covered by h[h_idx] if h[h_idx] moves left.
            // The condition is `abs(p_j - h_i) <= T`.

            // Let's use a two-pointer approach.
            // `p_idx` points to the first target track that needs to be covered.
            // `h_idx` points to the current head we are considering.
            // We try to cover `p[p_idx]` with `h[h_idx]`.
            // If `h[h_idx]` cannot cover `p[p_idx]` (i.e., `p[p_idx] > h[h_idx] + T`),
            // then `h[h_idx]` is too far left for `p[p_idx]`.
            // Since `h` is sorted, `h[h_idx]` cannot cover `p[p_idx]`, and neither can any `h[k]` where `k < h_idx`.
            // So, we must use `h[h_idx+1]` or later. This means we advance `h_idx`.
            // If `h[h_idx]` *can* cover `p[p_idx]` (i.e., `p[p_idx] >= h[h_idx] - T`),
            // then `h[h_idx]` can cover the range `[h[h_idx] - T, h[h_idx] + T]`.
            // We use `h[h_idx]` to cover `p[p_idx]` and all subsequent tracks that fall within its range.
            // So, we advance `p_idx` as long as `p[p_idx] <= h[h_idx] + T`.
            // After covering what `h[h_idx]` can, we move to the next head `h[h_idx+1]`.

            // This is the correct greedy strategy:
            // For each head `h[h_idx]`:
            //   It can cover tracks in `[h[h_idx] - T, h[h_idx] + T]`.
            //   We want to cover the current `p[p_idx]`.
            //   If `p[p_idx]` is to the left of `h[h_idx] - T`, it means `p[p_idx]` was not covered by previous heads
            //   and cannot be covered by `h[h_idx]` or subsequent heads. So, return `false`.
            //   If `p[p_idx]` is within `[h[h_idx] - T, h[h_idx] + T]`, then `h[h_idx]` covers it.
            //   We then advance `p_idx` to cover all tracks that `h[h_idx]` can cover to its right.
            //   `p_idx` will then point to the first track not covered by `h[h_idx]`.
            //   If `p[p_idx]` is to the right of `h[h_idx] + T`, then `h[h_idx]` cannot cover `p[p_idx]`.
            //   We must use a subsequent head. So, we just move to the next `h[h_idx+1]`.

        }

        // The `p_idx` pointer always points to the first target track that is not yet covered.
        // We try to cover `p[p_idx]` using `h[h_idx]`.
        // If `p_idx` has reached `m`, all tracks are covered.
        if (p_idx == m) {
            return true;
        }

        // If `p[p_idx]` is too far to the left for `h[h_idx]` to reach,
        // i.e., `p[p_idx] < h[h_idx] - T`, then `p[p_idx]` cannot be covered by `h[h_idx]`
        // or any subsequent head (since `h` is sorted).
        // This means `p[p_idx]` must have been covered by a previous head.
        // But `p_idx` is defined as the first *uncovered* track.
        // So, if `p[p_idx] < h[h_idx] - T`, it's impossible.
        // This is the critical condition for failure.
        if (p[p_idx] < current_h - T) {
            return false;
        }

        // If `p[p_idx]` is within reach of `h[h_idx]` (i.e., `p[p_idx] <= current_h + T`),
        // then `h[h_idx]` can cover `p[p_idx]` and potentially more tracks to its right.
        // We advance `p_idx` past all tracks that `h[h_idx]` can cover.
        while (p_idx < m && p[p_idx] <= current_h + T) {
            p_idx++;
        }
    }

    // After iterating through all heads, check if all target tracks are covered.
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible distance is 10^10. So max time is 10^10.
    // A tighter upper bound could be max(abs(p_i - h_j))
    // Max p_i is 10^10, min h_j is 1. So 10^10 - 1.
    // Max h_i is 10^10, min p_j is 1. So 10^10 - 1.
    // So 10^10 is a safe upper bound.
    long long high = 20000000000LL; // A sufficiently large upper bound, e.g., 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_valid_r[i] stores the maximum r (1-indexed) such that the substring s[i...r-1]
    // does NOT contain any triple pattern starting at or before index i.
    // More precisely, it's the maximum r such that for any x, k with s[x-1]=s[x+k-1]=s[x+2k-1],
    // if x-1 >= i, then x+2k-1 >= r.
    // This is equivalent to: for any x, k with s[x-1]=s[x+k-1]=s[x+2k-1],
    // if x-1 < r, then x-1 < i.
    // Or, for any x, k with s[x-1]=s[x+k-1]=s[x+2k-1],
    // if x-1 >= i, then x+2k-1 >= r.
    //
    // Let's redefine: `last_valid_r[i]` is the smallest `r_idx` (0-indexed) such that
    // the substring `s[i...r_idx]` contains a triple.
    // If no such triple exists starting at or after `i`, then `last_valid_r[i]` is `n`.
    //
    // We are looking for `(l, r)` such that `1 <= l <= r <= n` and `s[l-1...r-1]` contains a triple.
    // This means there exists `x, k` such that `s[x-1]=s[x+k-1]=s[x+2k-1]` and `l-1 <= x-1` and `x+2k-1 <= r-1`.
    //
    // Let `min_r_for_l[l_idx]` be the minimum `r_idx` (0-indexed) such that `s[l_idx...r_idx]` contains a triple.
    // If no such `r_idx` exists, `min_r_for_l[l_idx] = n`.
    //
    // For a fixed `l_idx`, any `r_idx` from `min_r_for_l[l_idx]` to `n-1` will form a "good" pair `(l_idx+1, r_idx+1)`.
    // The number of such `r_idx` values is `n - min_r_for_l[l_idx]`.
    //
    // To compute `min_r_for_l[l_idx]`:
    // `min_r_for_l[l_idx]` is the minimum `x+2k-1` over all `x, k` such that `s[x-1]=s[x+k-1]=s[x+2k-1]` and `x-1 >= l_idx`.
    // If no such `x, k` exists, `min_r_for_l[l_idx] = n`.
    //
    // We can compute `min_r_for_l` from right to left.
    // `min_r_for_l[n-1] = n` (no triple can start at n-1)
    // `min_r_for_l[n-2] = n`
    // ...
    // `min_r_for_l[i] = min(min_r_for_l[i+1], current_min_r_ending_at_i)`
    // where `current_min_r_ending_at_i` is the minimum `x+2k-1` for triples where `x-1 = i`.
    //
    // Let `min_end_idx[i]` be the minimum `j` such that `s[i...j]` contains a triple.
    // Initialize `min_end_idx[i] = n` for all `i`.
    //
    // Iterate `i` from `n-1` down to `0`.
    // `min_end_idx[i] = min_end_idx[i+1]` (if `i+1 < n`, otherwise `n`).
    //
    // For each `i`, check for triples `s[i] = s[i+k] = s[i+2k]`.
    // The maximum `k` is such that `i+2k < n`. So `2k < n-i`, `k < (n-i)/2`.
    // `k` can be `1, 2, 3, 4, 5`.
    // If `k >= 6`, then `2k >= 12`.
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is a potential end index.
    // We need to find the minimum `i+2k` for a given `i`.
    //
    // The maximum `k` we need to check is small.
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is the rightmost index of the triple.
    // The problem states `1 <= x, k <= n`.
    // `x+2k <= n`.
    // `x-1 = i`. So `i+2k <= n-1`.
    //
    // If `s[i] = s[i+k] = s[i+2k]`, then `i+2k` is a candidate for `min_end_idx[i]`.
    //
    // Let `min_r_idx_containing_triple[i]` be the minimum `r_idx` (0-indexed) such that
    // the substring `s[i...r_idx]` contains at least one triple.
    // If no such `r_idx` exists, `min_r_idx_containing_triple[i] = n`.
    //
    // We can compute this from right to left.
    // `min_r_idx_containing_triple[i]` will be `min(min_r_idx_containing_triple[i+1], current_min_r_for_triples_starting_at_i)`.
    // `current_min_r_for_triples_starting_at_i` is the minimum `i+2k` for all `k` such that `s[i]=s[i+k]=s[i+2k]`.
    // If no such `k` exists, this value is `n`.

    std::vector<int> min_r_idx_containing_triple(n + 1, n); // min_r_idx_containing_triple[i] is for s[i...r_idx]

    for (int i = n - 1; i >= 0; --i) {
        if (i + 1 < n) {
            min_r_idx_containing_triple[i] = min_r_idx_containing_triple[i+1];
        }

        // Check for k=1, 2, 3, 4, 5
        // If k is larger, say k=6, then 2k=12.
        // If s[i] = s[i+6] = s[i+12], then the indices are i, i+6, i+12.
        // The maximum length of a string is 300,000.
        // If k is large, say k=100,000, then i+2k could be 200,000.
        // The problem statement implies k can be up to n.
        // However, if s[i] = s[i+k] = s[i+2k], then the indices are i, i+k, i+2k.
        // The maximum value of k for which this pattern can occur is when i=0, k=n/2.
        // Then i+2k = n. But indices are 0 to n-1. So i+2k <= n-1.
        //
        // The key observation is that if a triple `s[x]=s[x+k]=s[x+2k]` exists,
        // and `k` is large, then `s[x]` and `s[x+k]` are far apart.
        // If `s[x]=s[x+k]=s[x+2k]` for some `k >= 6`, then `s[x]=s[x+k]` and `s[x+k]=s[x+2k]`.
        // This means `s[x]` and `s[x+k]` are the same, and `s[x+k]` and `s[x+2k]` are the same.
        //
        // Consider the case where `s[i] = s[i+k] = s[i+2k]`.
        // If `k` is large, say `k >= 6`, then `i+2k` is at least `i+12`.
        // If `s[i] = s[i+k] = s[i+2k]`, then `s[i]` and `s[i+k]` are the same character.
        // And `s[i+k]` and `s[i+2k]` are the same character.
        //
        // The problem is asking for `l <= x < x+2k <= r`.
        // This means `l-1 <= x-1` and `x+2k-1 <= r-1`.
        //
        // The crucial insight for this problem is that if a triple `s[i] = s[i+k] = s[i+2k]` exists,
        // and `k` is large, then there must be a "short" triple nearby.
        //
        // Suppose `s[i] = s[i+k] = s[i+2k]` for some `k >= 6`.
        // If `s[i] = '0'`, then `s[i+k] = '0'` and `s[i+2k] = '0'`.
        // If `s[i] = '1'`, then `s[i+k] = '1'` and `s[i+2k] = '1'`.
        //
        // Consider the string `s`. If there is a triple `s[i]=s[i+k]=s[i+2k]`,
        // then the substring `s[i...i+2k]` contains this triple.
        //
        // The maximum `k` we need to check is small.
        // If `s[i] = s[i+k] = s[i+2k]` for some `k >= 6`, then `s[i]` and `s[i+k]` are the same.
        // And `s[i+k]` and `s[i+2k]` are the same.
        //
        // If `s[i] = s[i+k] = s[i+2k]` for `k >= 6`, then the substring `s[i...i+2k]` contains this pattern.
        //
        // It turns out that if a triple exists for `k >= 6`, then there must be a triple for `k' < 6`
        // that covers the same or a smaller range.
        // This is a known property for this type of problem.
        // The maximum `k` to check is usually 5 or 6. Let's check up to `k=5`.
        //
        // For `k` from 1 to 5:
        for (int k = 1; k <= 5; ++k) {
            if (i + 2 * k < n) {
                if (s[i] == s[i + k] && s[i] == s[i + 2 * k]) {
                    min_r_idx_containing_triple[i] = std::min(min_r_idx_containing_triple[i], i + 2 * k);
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        // For each starting position `l_idx = i`, the number of `r_idx` values
        // that form a "good" pair `(i+1, r_idx+1)` is `n - min_r_idx_containing_triple[i]`.
        // These `r_idx` values range from `min_r_idx_containing_triple[i]` to `n-1`.
        bad_pairs += (n - min_r_idx_containing_triple[i]);
    }

    std::cout << bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1 (2 pieces)
    // Cut s into s1 and s2. Form s2s1.
    // s1 = s.substr(0, i), s2 = s.substr(i)
    // We need s2s1 to be a palindrome and s2s1 != s.
    // The cut cannot be at i=0 or i=n, as that would mean one piece is empty.
    // If s1 is empty, s2s1 = s. If s2 is empty, s2s1 = s.
    // So i must be from 1 to n-1.
    for (int i = 1; i < n; ++i) {
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string new_s = s2 + s1;
        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2 (3 pieces)
    // Cut s into s1, s2, s3. Form s1s2s3, s1s3s2, s2s1s3, s2s3s1, s3s1s2, s3s2s1.
    // The problem statement says "pieces couldn't be turned over, they could be shuffled."
    // This implies we can reorder the pieces.
    // For k=2, we have 3 pieces.
    // s = s_prefix + s_middle + s_suffix
    // s_prefix = s.substr(0, i)
    // s_middle = s.substr(i, j-i)
    // s_suffix = s.substr(j)
    // where 0 <= i < j <= n.
    // If i=0, s_prefix is empty. If j=n, s_suffix is empty.
    // If i=j, s_middle is empty.
    // We need at least two non-empty pieces to form a new string.
    // If we have 3 pieces, and we can reorder them, we can always form a new palindrome
    // if the string is not composed of all identical characters.
    // Example: "nolon" -> "no", "l", "on". Reorder to "on", "l", "no" -> "onlno".
    // This is a palindrome and different from "nolon".
    // The only case where k=2 might not work is if all characters are the same.
    // If s = "aaaaa", then any permutation of "a", "a", "aaa" (or other cuts) will result in "aaaaa".
    // So, if all characters in s are the same, we can't form a new string.
    // Otherwise, k=2 is always possible.
    // Consider s = "ababa". n=5.
    // Cut at i=1, j=2: s1="a", s2="b", s3="aba".
    // Permutations: "ababa", "aabba", "baaba", "baaba", "abaab", "abaab".
    // "abaab" is not a palindrome.
    // "baaba" is a palindrome. It's different from "ababa". So k=2 works.

    // Let's check if all characters in s are the same.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, we can always achieve k=2.
        // Example: s = "abacaba"
        // Cut s into s[0] and s[1...n-2] and s[n-1].
        // s1 = s[0], s2 = s[1...n-2], s3 = s[n-1]
        // Since s is a palindrome, s[0] == s[n-1].
        // So s1 == s3.
        // We have pieces A, B, A.
        // We can form ABA (original), AAB, BAA.
        // If AAB is a palindrome and AAB != ABA, then k=2 works.
        // AAB is palindrome if A == reverse(B).
        // BAA is palindrome if reverse(B) == A.
        // This is not general enough.

        // A simpler argument for k=2:
        // If s is not all same characters, then there exists some character s[i] != s[0].
        // Since s is a palindrome, s[i] == s[n-1-i].
        // Consider the string s' = s.substr(0, n-1).
        // If s' is not a palindrome, then we can cut s into s[0] and s[1...n-1].
        // s1 = s[0], s2 = s[1...n-1].
        // s2s1 = s[1...n-1] + s[0].
        // If s is not all same characters, then s[0] != s[i] for some i.
        // This means s is not of the form "aaaaa".
        // If s is a palindrome and not all characters are the same,
        // then s.substr(0, n/2) is not a palindrome of length n/2.
        // For example, "nolon". n=5.
        // s.substr(0, 2) = "no". Not a palindrome.
        // s.substr(0, n-1) = "nolo". Not a palindrome.
        // If s.substr(0, n-1) is not a palindrome, then we can cut s into s[0] and s[1...n-1].
        // Let s1 = s[0], s2 = s[1...n-1].
        // s2s1 = s[1...n-1] + s[0].
        // If s2s1 is a palindrome and s2s1 != s, then k=1.
        // We already checked k=1.

        // If k=1 didn't work, it means for all i from 1 to n-1,
        // s.substr(i) + s.substr(0, i) is either not a palindrome or is equal to s.
        // This implies a very specific structure for s.
        // For example, "qqqq". k=1 fails.
        // "otto". k=1 works. "toot".
        // "nolon". k=1 fails.
        // "nolon" -> "o", "lon" -> "lono" (not pal)
        // "no", "lon" -> "lonno" (not pal)
        // "nol", "on" -> "onnol" (not pal)
        // "nolo", "n" -> "nnolo" (not pal)

        // The problem states: "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string, and then unite those pieces together to get a new string."
        // This means we can choose any k+1 pieces.
        // For k=2, we have 3 pieces.
        // If s is a palindrome and not all characters are the same, then there must be at least two distinct characters.
        // Let's say s[0] = 'a' and s[i] = 'b' for some i.
        // Since s is a palindrome, s[n-1] = 'a' and s[n-1-i] = 'b'.
        // Consider cutting s into s[0], s.substr(1, n-2), s[n-1].
        // Pieces are P1 = s[0], P2 = s.substr(1, n-2), P3 = s[n-1].
        // Since s is a palindrome, P1 == P3.
        // So we have pieces A, B, A.
        // We can form A B A (original string).
        // We can form A A B.
        // We can form B A A.
        // If A A B is a palindrome and A A B != A B A, then k=2 works.
        // A A B is a palindrome if A == reverse(B).
        // If A A B is not a palindrome, what about B A A?
        // B A A is a palindrome if reverse(B) == A.
        // So if A == reverse(B), then both AAB and BAA are palindromes.
        // If AAB != ABA, then k=2 works.
        // AAB != ABA means B != AB. This is true if B is not empty.
        // If B is empty, n=2. s="aa". This is the all_same case.
        // If n=1, s="a". This is the all_same case.
        // So if n > 2 and not all_same, B is not empty.
        // If A == reverse(B), then AAB is a palindrome.
        // Is AAB == ABA? This means AAB = ABA.
        // Since A is not empty, this implies AB = BA.
        // This means A and B commute.
        // If A and B commute, then A and B must be powers of the same string.
        // e.g., A="ab", B="abab". Then AAB = "ab" "ab" "abab" = "ab ab abab".
        // ABA = "ab" "abab" "ab" = "ab abab ab".
        // These are not necessarily equal.

        // Let's re-evaluate the "all_same" condition.
        // If s is "aaaaa", then any cut and reordering will result in "aaaaa".
        // So "Impossible".
        // If s is "ababa", n=5. Not all same.
        // k=1 check:
        // "babaa" (no)
        // "abaab" (no)
        // "ababa" (yes, but same as s)
        // "babaa" (no)
        // k=1 fails for "ababa".
        // k=2 check:
        // Pieces: s[0], s.substr(1, n-2), s[n-1]
        // P1 = "a", P2 = "bab", P3 = "a".
        // We have A, B, A.
        // Form AAB = "a" + "a" + "bab" = "aabab". Not a palindrome.
        // Form BAA = "bab" + "a" + "a" = "babaa". Not a palindrome.
        // This specific choice of pieces (s[0], s.substr(1, n-2), s[n-1]) doesn't guarantee a new palindrome.

        // The problem statement is "unite those pieces together to get a new string".
        // It doesn't say the pieces must be s[0], s[1...n-2], s[n-1].
        // It says "cut the paper minimum number of times k, so they got k+1 pieces of paper with substrings of the initial string".
        // This means we can choose any k+1 pieces.
        // For k=2, we need 3 pieces.
        // If s is a palindrome and not all characters are the same, then there exists at least one character s[i] such that s[i] != s[0].
        // Let's find the first such character. Let it be at index `idx`.
        // So s[0...idx-1] are all s[0]. s[idx] != s[0].
        // Since s is a palindrome, s[n-1] = s[0], s[n-1-idx] = s[idx].
        // Consider cutting s into three pieces:
        // P1 = s.substr(0, idx)
        // P2 = s.substr(idx, n - 2*idx)
        // P3 = s.substr(n-idx)
        // Example: "nolon". n=5. s[0]='n', s[1]='o'. idx=1.
        // P1 = s.substr(0,1) = "n"
        // P2 = s.substr(1, 5-2*1) = s.substr(1,3) = "olo"
        // P3 = s.substr(5-1) = s.substr(4) = "n"
        // Pieces are "n", "olo", "n".
        // We can reorder them to "n", "n", "olo" -> "nnolo". Not a palindrome.
        // We can reorder them to "olo", "n", "n" -> "olonn". Not a palindrome.
        // We can reorder them to "n", "olo", "n" -> "nolon" (original).

        // The example "nolon" -> 2.
        // Cuts: no|l|on. Pieces: "no", "l", "on".
        // Reorder: "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
        // This means the pieces are s.substr(0,2), s.substr(2,1), s.substr(3,2).
        // P1 = "no", P2 = "l", P3 = "on".
        // Note that P1 is reverse of P3.
        // P1 = "no", P3 = "on". reverse(P1) = "on" = P3.
        // So we have pieces A, B, reverse(A).
        // We can form A B reverse(A) (original).
        // We can form reverse(A) B A. This is a palindrome.
        // Is reverse(A) B A != A B reverse(A)?
        // This means reverse(A) B A != A B reverse(A).
        // If A is not a palindrome itself, then A != reverse(A).
        // If A is not a palindrome, then reverse(A) B A != A B reverse(A) is likely true.
        // For "nolon", A="no", B="l". reverse(A)="on".
        // A B reverse(A) = "no" "l" "on" = "nolon".
        // reverse(A) B A = "on" "l" "no" = "onlno".
        // "onlno" is a palindrome and "onlno" != "nolon".
        // This works!

        // So, the strategy for k=2 is:
        // Find a prefix `A` of `s` such that `A` is not a palindrome.
        // Let `A = s.substr(0, i)`.
        // Then `reverse(A) = s.substr(n-i)`.
        // Let `B = s.substr(i, n-2*i)`.
        // The pieces are `A`, `B`, `reverse(A)`.
        // We can form `reverse(A) B A`. This will be a palindrome.
        // We need `reverse(A) B A != s`.
        // `s = A B reverse(A)`.
        // So we need `reverse(A) B A != A B reverse(A)`.
        // This is true if `A != reverse(A)`.
        // And `B` must not be empty. `n - 2*i > 0`. So `n > 2*i`.
        // If `n <= 2*i`, then `B` is empty or negative length.
        // If `n` is odd, `n = 2m+1`. `i <= m`.
        // If `n` is even, `n = 2m`. `i < m`.

        // We need to find an `i` such that:
        // 1. `s.substr(0, i)` is not a palindrome.
        // 2. `n - 2*i > 0` (middle piece `B` is not empty).
        // If such an `i` exists, then k=2 is possible.
        // If no such `i` exists, it means for all `i` where `n - 2*i > 0`, `s.substr(0, i)` is a palindrome.
        // This implies that `s` must be of the form `AAAA...A` (all same characters).
        // Example: "aaaaa".
        // i=1: s.substr(0,1)="a". Palindrome. n-2*1 = 3 > 0.
        // i=2: s.substr(0,2)="aa". Palindrome. n-2*2 = 1 > 0.
        // For "aaaaa", all prefixes `s.substr(0,i)` are palindromes.
        // So this condition (all prefixes `s.substr(0,i)` are palindromes for `n-2*i > 0`)
        // is equivalent to `s` being composed of all identical characters.

        // So, if `s` is not composed of all identical characters, then there must exist some `i` such that `s.substr(0, i)` is not a palindrome.
        // Let `i_min` be the smallest `i` such that `s.substr(0, i)` is not a palindrome.
        // If `n - 2*i_min > 0`, then we can use this `i_min` to form `reverse(A) B A`.
        // This will be a palindrome and different from `s`.
        // What if `n - 2*i_min <= 0`? This means `i_min >= n/2`.
        // If `i_min >= n/2`, it means all prefixes `s.substr(0, i)` for `i < n/2` are palindromes.
        // This implies that `s` is of the form `c c c ... c`.
        // Example: "abacaba". n=7.
        // i=1: "a" (pal).
        // i=2: "ab" (not pal). So `i_min = 2`.
        // `n - 2*i_min = 7 - 2*2 = 3 > 0`.
        // So we can use `i=2`.
        // A = "ab", B = "aca", reverse(A) = "ba".
        // `reverse(A) B A` = "ba" "aca" "ab" = "baacaab". This is a palindrome.
        // `s` = "abacaba".
        // "baacaab" != "abacaba". So k=2 works.

        // The logic is:
        // If `s` consists of all identical characters (e.g., "aaaaa"), then "Impossible".
        // Otherwise, `s` contains at least two distinct characters.
        // In this case, we can always find an `i` such that `s.substr(0, i)` is not a palindrome and `n - 2*i > 0`.
        // This is because if all `s.substr(0, i)` for `i < n/2` are palindromes, then `s` must be all identical characters.
        // For example, if `s.substr(0,1)` is pal, `s[0]` is pal.
        // If `s.substr(0,2)` is pal, `s[0]s[1]` is pal, so `s[0]=s[1]`.
        // If `s.substr(0,3)` is pal, `s[0]s[1]s[2]` is pal, so `s[0]=s[2]`.
        // By induction, if all prefixes up to `n/2` are palindromes, then `s[0]=s[1]=...=s[n/2-1]`.
        // Since `s` is a palindrome, `s[j] = s[n-1-j]`.
        // So `s[0]=s[1]=...=s[n-1]`.
        // Therefore, if `s` is not all identical characters, there must be some `i < n/2` such that `s.substr(0, i)` is not a palindrome.
        // For such an `i`, `n - 2*i > 0` is guaranteed.
        // So we can use `A = s.substr(0, i)`, `B = s.substr(i, n-2*i)`, `reverse(A) = s.substr(n-i)`.
        // The new string `reverse(A) B A` will be a palindrome and different from `s`.
        // Thus, if not all characters are the same, k=2 is always possible.

        std::cout << 2 << std::endl;
    }

    return 0;
}

