int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n numbers from 2n+1 to 4n,
        // specifically, all even numbers in this range.
        // This range is [2n+1, 4n].
        // The smallest even number >= 2n+1 is 2n+2 (if 2n+1 is odd) or 2n+1 (if 2n+1 is even, which is impossible).
        // So, the smallest even number is 2n+2.
        // The largest even number <= 4n is 4n.
        // The numbers are 2n+2, 2n+4, ..., 4n.
        // The count of these numbers is (4n - (2n+2))/2 + 1 = (2n-2)/2 + 1 = n-1+1 = n.
        // All these numbers are even, so gcd(a,b) >= 2 for any pair.
        // For any two numbers a, b in this set, say a = 2k, b = 2m, where n+1 <= k < m <= 2n.
        // Since m < 2k (because m <= 2n and k >= n+1, so 2k >= 2n+2 > m),
        // b cannot be a multiple of a.
        // For example, if a = 2(n+1), b = 2(n+2), ..., 4n.
        // The smallest number is 2n+2. The largest is 4n.
        // The largest possible ratio is 4n / (2n+2) which is less than 2.
        // So no number in the set can divide another number in the set.
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * (n + 1 + i) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

