int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    // 'e', 'r', 'o' are shared, but 'n' uniquely identifies 'one' and 'z' uniquely identifies 'zero'.
    // The problem guarantees that a valid arrangement is possible.
    // This means if we count 'n's, that's the number of 'one's.
    // If we count 'z's, that's the number of 'zero's.
    // The other letters ('e', 'r', 'o') must be sufficient to form these words.
    // For example, if we have 2 'n's, we form two "one"s.
    // If we have 1 'z', we form one "zero".
    // The total letters used would be:
    // 2 * ('o' + 'n' + 'e') + 1 * ('z' + 'e' + 'r' + 'o')
    // = 2 'o', 2 'n', 2 'e' + 1 'z', 1 'e', 1 'r', 1 'o'
    // = 3 'o', 2 'n', 3 'e', 1 'z', 1 'r'
    // The input string must contain exactly these counts.

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To form the maximum possible binary number, we want as many '1's as possible,
    // and they should appear before '0's.
    // So, print all '1's first, then all '0's.

    bool first_digit = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }

    std::cout << std::endl;

    return 0;
}

