#include <iostream>
#include <string>
#include <vector>
#include <numeric> // For std::iota in C++23, though not strictly needed here.
#include <set>

void solve() {
    std::string s, t;
    std::cin >> s >> t;

    // If s and t are already equal, it's possible.
    if (s == t) {
        std::cout << "YES\n";
        return;
    }

    // The operation allows any character to propagate to an adjacent position.
    // This means if a character 'c' exists in string s, it can eventually
    // replace any other character in s, provided there's a path.
    // However, the crucial part is that it can only propagate to *adjacent* characters.
    // If we have 'a' at s[i] and 'b' at s[i+1], we can make s[i]=s[i+1] or s[i+1]=s[i].
    // This means that if a character 'c' exists in string s, it can be used to
    // change s[i] to 'c' if 'c' is at s[i-1] or s[i+1].
    //
    // The problem asks if s can be transformed into t.
    // This implies that we need to find a common character 'c' such that:
    // 1. 'c' exists in string s.
    // 2. 'c' exists in string t.
    //
    // If such a common character 'c' exists, we can perform operations on s
    // to make s contain only 'c's (e.g., s[0] = s[1], s[1] = s[2], ..., s[N-2] = s[N-1],
    // then s[N-1] = s[N-2], s[N-2] = s[N-3], etc., until all characters are the same as s[k]
    // where s[k] is the character 'c').
    // Similarly, we can perform operations on t to make t contain only 'c's.
    //
    // The key observation is that if there is *any* character 'c' that is present
    // in *both* strings `s` and `t`, then we can make both strings equal to a string
    // consisting entirely of 'c's.
    //
    // For example, if s = "xabb" and t = "aabx".
    // 'a' is in s, 'a' is in t.
    // We can make s into "aaaa" and t into "aaaa".
    //
    // The operation allows a character to "spread" to its neighbors.
    // If 'c' is at s[i], it can spread to s[i-1] or s[i+1].
    // This means that if a character 'c' exists anywhere in the string,
    // it can eventually fill the entire string.
    // For example, if s = "xay", and we want to make it "aaa":
    // s[1] = 'a'.
    // s[0] = s[1] -> "aay"
    // s[2] = s[1] -> "aaa"
    //
    // So, the condition simplifies to: Is there at least one character that is present
    // in both string s and string t?

    std::set<char> s_chars;
    for (char c : s) {
        s_chars.insert(c);
    }

    for (char c : t) {
        if (s_chars.count(c)) {
            std::cout << "YES\n";
            return;
        }
    }

    std::cout << "NO\n";
}

