    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    std::vector<int> p(n);

    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
            if (i != j) { // Exclude a[i][i] which is always 0
                if (a[i][j] > max_val_in_row) {
                    max_val_in_row = a[i][j];
                }
            }
        }
        // If the maximum value in row i (excluding a[i][i]) is n-1,
        // it means p[i] must be n. Otherwise, p[i] is max_val_in_row.
        // This is because if p[i] is n, then min(p[i], p[j]) = p[j] for all j != i.
        // The maximum of these p[j] values would be n-1.
        // If p[i] is not n, then there must be some p[k] > p[i].
        // For such k, min(p[i], p[k]) = p[i].
        // For any j where p[j] < p[i], min(p[i], p[j]) = p[j].
        // So, max_{j!=i} a[i][j] would be p[i].
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

