#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_consecutive_L = 0;
        int current_consecutive_L = 0;

        // We need to consider the "virtual" L at index -1 (cell 0)
        // and the "virtual" L at index n (cell n+1)
        // The problem states "frog can jump only to the right from the cell 0".
        // This means cell 0 acts like an 'R' cell for jumping, but it's not part of 's'.
        // The key insight is that the frog must be able to jump over any sequence of 'L's.
        // If the frog is at cell `i` and `s[i-1]` is 'L', it can only jump left.
        // This means the frog must *never* land on an 'L' cell if it wants to make progress to the right.
        // It must jump from an 'R' cell (or cell 0) *over* any 'L' cells to another 'R' cell or to n+1.
        // So, the frog must be able to jump from the last 'R' cell before a block of 'L's
        // to the next 'R' cell after that block, or to n+1.
        // The distance to jump is from the current 'R' cell to the next 'R' cell,
        // or from cell 0 to the first 'R' cell, or from the last 'R' cell to n+1.

        // Let's find the positions of all 'R' characters.
        // Add 0 as a starting point and n+1 as an ending point.
        std::vector<int> r_positions;
        r_positions.push_back(0); // Represents the starting cell
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                r_positions.push_back(i + 1); // Convert 0-indexed string to 1-indexed cell
            }
        }
        r_positions.push_back(n + 1); // Represents the target cell

        int max_gap = 0;
        for (size_t i = 0; i < r_positions.size() - 1; ++i) {
            // The gap is the distance between two consecutive 'R' cells (or 0, or n+1).
            // If the frog is at r_positions[i], it needs to jump to r_positions[i+1].
            // The minimum d required for this jump is r_positions[i+1] - r_positions[i].
            max_gap = std::max(max_gap, r_positions[i+1] - r_positions[i]);
        }

        std::cout << max_gap << "\n";
    }
    return 0;
}

