#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available (c + m + x) / 3
        // 2. The number of coders available (c)
        // 3. The number of mathematicians available (m)
        //
        // Let 'k' be the number of teams.
        // Each team needs 3 members, so 3*k <= c + m + x.
        // Each team needs at least 1 coder, so k <= c.
        // Each team needs at least 1 mathematician, so k <= m.
        //
        // So, k must be less than or equal to min(c, m, (c + m + x) / 3).
        //
        // We can use binary search to find the maximum k.
        // The search space for k is from 0 to 10^8 (max value of c, m, x).
        // A tighter upper bound is min(c, m, (c + m + x) / 3).

        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3}); // Initial upper bound
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;

            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians as a minimum.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x no-specialization students.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // Each of the 'mid' teams needs 3 members. We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members in total (3 * mid - mid - mid = mid).
            // These 'mid' additional members can come from the remaining students.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // If this sum is greater than or equal to 'mid', then it's possible to form 'mid' teams.

            if (mid <= c && mid <= m && (c - mid) + (m - mid) + x >= mid) {
                // It's possible to form 'mid' teams. Try for more.
                ans = mid;
                low = mid + 1;
            } else {
                // Not possible to form 'mid' teams. Try for fewer.
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

