    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = n;
    bool use_left = true;

    // Generate k distinct differences
    // This part generates k differences: n-1, n-2, ..., n-k
    // by alternating between the smallest available and largest available numbers.
    for (int i = 0; i < k; ++i) {
        if (use_left) {
            p[i] = left;
            left++;
        } else {
            p[i] = right;
            right--;
        }
        use_left = !use_left;
    }

    // The remaining n-k elements should not introduce new distinct differences.
    // The simplest way to do this is to append the remaining numbers in increasing or decreasing order.
    // If the last number added was from 'left' (meaning use_left is now false),
    // then the remaining numbers are `right, right-1, ..., left`.
    // If the last number added was from 'right' (meaning use_left is now true),
    // then the remaining numbers are `left, left+1, ..., right`.

    // If use_left is true, it means the last element added was 'right'.
    // So, the next element should be 'left', and we should continue with 'left, left+1, ...'
    // This means we append the remaining numbers in increasing order.
    if (use_left) { // Last element added was 'right', so current p[k-1] is 'right'
        for (int i = k; i < n; ++i) {
            p[i] = left;
            left++;
        }
    } else { // Last element added was 'left', so current p[k-1] is 'left'
        // We need to append remaining numbers in decreasing order to maintain small differences.
        // The remaining numbers are from 'right' down to 'left'.
        for (int i = k; i < n; ++i) {
            p[i] = right;
            right--;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

