void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_values;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_values.insert(q[0]);

    // For i from 1 to n-1
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_values.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new value.
                // But it's good to check for robustness.
                possible = false;
                break;
            }
            used_values.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some value less than q_i
            // and not yet used. We need to pick the smallest available value
            // to maximize chances for later elements.
            // The values available for p_i are those in [1, q_i-1] that are not yet used.
            // We will fill these in a second pass.
            p[i] = -1; // Placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all unused numbers from 1 to n
    std::vector<int> unused_numbers;
    for (int i = 1; i <= n; ++i) {
        if (used_values.find(i) == used_values.end()) {
            unused_numbers.push_back(i);
        }
    }
    std::sort(unused_numbers.rbegin(), unused_numbers.rend()); // Sort in descending order

    // Fill in the placeholders
    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This means q[i] == q[i-1]
            if (unused_numbers.empty()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int val_to_use = unused_numbers.back(); // Get smallest available
            unused_numbers.pop_back();

            if (val_to_use > q[i]) { // p_i must be <= q_i (and actually < q_i if q_i == q_{i-1})
                possible = false;
                break;
            }
            p[i] = val_to_use;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Final check: ensure all p_i are distinct and within [1, n]
    // This is implicitly handled by using a set and unused_numbers.
    // Also, check if the constructed p generates the given q.
    // This is also implicitly handled by the construction logic.
    // The only remaining check is if p_i < q_i when q_i == q_{i-1}.
    // Our strategy of picking the smallest available number ensures this if possible.
    // If the smallest available number is > q_i, then it's impossible.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

