#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1], which is p[pos[1]...pos[1]].
        // min_idx and max_idx are initialized to pos[1].
        // The length is 1, min is 1, max is 1. So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The value 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from 1 to m. This means the new segment must span from min(pos[1]...pos[m])
        // to max(pos[1]...pos[m]).

        // Update the boundaries to include the position of 'm'
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // forms a permutation of 1 to m.
        // This requires two conditions:
        // 1. The length of the segment must be exactly m.
        // 2. The minimum value in the segment must be 1, and the maximum must be m.
        //    Since we are always expanding the segment to include 'm' and we started
        //    with '1', and we are processing 'm' in increasing order, the minimum
        //    value in the segment [current_min_idx, current_max_idx] will always be 1
        //    and the maximum value will always be m.
        //    So, we only need to check the length.

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

