#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_pairs = std::min(counts['L'], counts['R']);
    int vertical_pairs = std::min(counts['U'], counts['D']);

    std::string result = "";

    if (horizontal_pairs == 0 && vertical_pairs == 0) {
        // No moves possible to return to origin
        // Output 0 and an empty line
        std::cout << 0 << std::endl;
        std::cout << "" << std::endl;
        return;
    }

    if (horizontal_pairs == 0) {
        // Only vertical moves possible, but cannot return to origin without horizontal moves
        // The only valid path is "UD" or "DU" if vertical_pairs >= 1
        // But if horizontal_pairs is 0, we can't make a path like "UD" and then "LR"
        // The problem states "ends the path in the cell (0,0)".
        // If we only have U/D, we can only make "UD" or "DU".
        // If we have "U", it's invalid. If we have "UD", it's valid.
        // If we have "UU", it's invalid. If we have "UUDD", it's invalid.
        // The only way to make a valid path with only U/D is "UD" or "DU".
        // But the problem implies we want to maximize length.
        // If horizontal_pairs is 0, we can only use one 'U' and one 'D' at most.
        // If vertical_pairs is 0, we can only use one 'L' and one 'R' at most.
        // If both are 0, then 0 length.
        // If horizontal_pairs is 0, we can only use one 'U' and one 'D'.
        // If vertical_pairs is 0, we can only use one 'L' and one 'R'.
        // The logic for horizontal_pairs == 0 and vertical_pairs == 0 is handled above.
        // If horizontal_pairs == 0, but vertical_pairs > 0, we can only use one 'U' and one 'D'.
        // The path would be "UD" or "DU".
        // If vertical_pairs == 0, but horizontal_pairs > 0, we can only use one 'L' and one 'R'.
        // The path would be "LR" or "RL".
        // This is covered by the general logic below.
        // The maximum length is 2.
        std::cout << 2 << std::endl;
        result += 'U';
        result += 'D';
        std::cout << result << std::endl;
        return;
    }

    if (vertical_pairs == 0) {
        // Only horizontal moves possible
        std::cout << 2 << std::endl;
        result += 'L';
        result += 'R';
        std::cout << result << std::endl;
        return;
    }

    // Both horizontal and vertical moves are available
    // Construct the path: U...UL...LR...RD...D
    // Or L...LU...UD...DR...R
    // The order doesn't matter for validity, only for the specific sequence.
    // We want to maximize length, so use all available pairs.

    // Add 'U's
    for (int i = 0; i < vertical_pairs; ++i) {
        result += 'U';
    }
    // Add 'L's
    for (int i = 0; i < horizontal_pairs; ++i) {
        result += 'L';
    }
    // Add 'R's
    for (int i = 0; i < horizontal_pairs; ++i) {
        result += 'R';
    }
    // Add 'D's
    for (int i = 0; i < vertical_pairs; ++i) {
        result += 'D';
    }

    std::cout << result.length() << std::endl;
    std::cout << result << std::endl;
}

