int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;

    // Iterate through each point as the leftmost point of a potential triplet
    for (int i = 0; i < n; ++i) {
        // Find the rightmost point 'k' such that x[k] - x[i] <= d
        // Since x is sorted, we can use std::upper_bound to find the first element
        // strictly greater than x[i] + d. The element before it (if it exists)
        // is the rightmost point that satisfies the condition.

        // The target value for x[k] is x[i] + d.
        // upper_bound returns an iterator to the first element that is > value.
        // So, all elements from x[i+1] up to (it - 1) satisfy x[val] <= x[i] + d.
        auto it = std::upper_bound(x.begin() + i + 1, x.end(), x[i] + d);

        // The index of the rightmost point satisfying the condition is (it - x.begin() - 1).
        // Let this index be 'k_max_idx'.
        // The number of points from x[i+1] to x[k_max_idx] (inclusive) is (k_max_idx - (i+1) + 1).
        // This is equivalent to (it - (x.begin() + i + 1)).

        // 'it' points to the first element > x[i] + d.
        // The number of elements from x[i+1] up to (it-1) is (it - (x.begin() + i + 1)).
        // Let 'num_valid_right_points' be this count.
        long long num_valid_right_points = (it - (x.begin() + i + 1));

        // We need to choose two points from these 'num_valid_right_points' points.
        // The number of ways to choose 2 points from 'm' points is m * (m - 1) / 2.
        if (num_valid_right_points >= 2) {
            count += num_valid_right_points * (num_valid_right_points - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    long long current_cost_01 = 0; // Cost to fix '0' -> '1' mismatches by flipping
    long long current_cost_10 = 0; // Cost to fix '1' -> '0' mismatches by flipping

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // If a[i] == b[i], this position is correct.
            // Any pending '0'->'1' or '1'->'0' mismatches from previous positions
            // that could have been swapped with this position are now "passed".
            // So, we must pay for them by flipping.
            total_cost += std::min(current_cost_01, current_cost_10);
            current_cost_01 = 0;
            current_cost_10 = 0;
        } else {
            // If a[i] != b[i], this position is a mismatch.
            if (a[i] == '0' && b[i] == '1') {
                // Mismatch '0' -> '1'
                // We can either flip a[i] (cost 1) or swap it with a '1' from a '1'->'0' mismatch.
                // If we swap, the cost is 1 (for the swap operation itself, as |i-j| is 1 for adjacent).
                // The effective cost of fixing this '0'->'1' mismatch and a '1'->'0' mismatch
                // by swapping them is 1.
                // If there's a pending '1'->'0' mismatch (current_cost_10 > 0), we can pair them.
                if (current_cost_10 > 0) {
                    total_cost += 1; // Cost of swapping
                    current_cost_10--; // One '1'->'0' mismatch is resolved
                } else {
                    // No pending '1'->'0' mismatch to swap with.
                    // This '0'->'1' mismatch must be resolved by flipping (cost 1)
                    // or by swapping with a future '1'->'0' mismatch.
                    // We defer the decision by adding 1 to current_cost_01.
                    current_cost_01++;
                }
            } else { // a[i] == '1' && b[i] == '0'
                // Mismatch '1' -> '0'
                // Similar logic as above.
                if (current_cost_01 > 0) {
                    total_cost += 1; // Cost of swapping
                    current_cost_01--; // One '0'->'1' mismatch is resolved
                } else {
                    current_cost_10++;
                }
            }
        }
    }

    // After iterating through all positions, any remaining pending mismatches
    // must be resolved by flipping.
    total_cost += current_cost_01; // Each remaining '0'->'1' mismatch costs 1 to flip
    total_cost += current_cost_10; // Each remaining '1'->'0' mismatch costs 1 to flip

    std::cout << total_cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);
    a[median_idx] = s; // Conceptually change it to s for subsequent checks

    // 2. Ensure elements to the left of median are <= s
    // These elements are at indices 0 to median_idx - 1
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These elements are at indices median_idx + 1 to n - 1
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

