int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Create pairs (B_i, original_index_i) and sort them by B_i in ascending order
    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }
    std::sort(b_indexed.begin(), b_indexed.end());

    // The optimal strategy is to assign the largest A_i to the largest B_i,
    // the second largest A_i to the second largest B_i, and so on.
    // This means if A is sorted ascending, and B is sorted ascending,
    // we assign A[i] to B[i].
    // Since we want to reconstruct the original order of B, we use b_indexed.

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // b_indexed[i] contains {sorted_B_value, original_index_of_B_value}
        // a[m-1-i] is the i-th largest element from sorted A
        // We assign the i-th largest A to the B value that is i-th largest.
        // Since b_indexed is sorted ascending by B value, b_indexed[i] corresponds
        // to the i-th smallest B value.
        // To maximize the sum, we pair the largest A with the largest B,
        // the second largest A with the second largest B, etc.
        // So, the largest A (a[m-1]) should be paired with the largest B (b_indexed[m-1].first).
        // The second largest A (a[m-2]) should be paired with the second largest B (b_indexed[m-2].first).
        // In general, a[m-1-i] should be paired with b_indexed[m-1-i].first.
        // The original index for this B value is b_indexed[m-1-i].second.
        result_a_prime[b_indexed[m - 1 - i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

