// Function to check if a sub-array is a permutation
// It checks if all numbers from 1 to 'len' are present exactly once.
// 'max_val' is the maximum value encountered in the sub-array.
// 'is_distinct' indicates if all elements in the sub-array are distinct.
bool is_permutation(int len, int max_val, bool is_distinct) {
    return is_distinct && (max_val == len);
}

