    std::vector<int> prefix_max(n + 1, 0);
    std::vector<bool> prefix_distinct(n + 1, true);
    std::vector<bool> seen_prefix(n + 1, false); // For checking distinctness in prefix

    for (int i = 0; i < n; ++i) {
        prefix_max[i + 1] = std::max(prefix_max[i], a[i]);
        if (a[i] > n || seen_prefix[a[i]]) { // a[i] > n is an optimization, max value for p1 is n-1
            prefix_distinct[i + 1] = false;
        } else {
            seen_prefix[a[i]] = true;
            prefix_distinct[i + 1] = prefix_distinct[i];
        }
    }

    // Precompute suffix properties for p2
    std::vector<int> suffix_max(n + 1, 0);
    std::vector<bool> suffix_distinct(n + 1, true);
    std::vector<bool> seen_suffix(n + 1, false); // For checking distinctness in suffix

    for (int i = n - 1; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
        if (a[i] > n || seen_suffix[a[i]]) { // a[i] > n is an optimization, max value for p2 is n-1
            suffix_distinct[i] = false;
        } else {
            seen_suffix[a[i]] = true;
            suffix_distinct[i] = suffix_distinct[i + 1];
        }
