        std::cin >> m;
        if (m == 0) continue; // Should not happen based on constraints m_i >= 1

        int prev_doll;
        std::cin >> prev_doll; // Read the first doll in the chain

        for (int j = 1; j < m; ++j) {
            int current_doll;
            std::cin >> current_doll;
            if (current_doll == prev_doll + 1) {
                correct_consecutive_pairs++;
            }
            prev_doll = current_doll;
        }
    }

    // Total dolls to be moved out of their current position (if not part of a correct chain)
    // Each doll not part of a correct chain needs to be taken out.
    // The number of dolls that are part of a correct chain is `correct_consecutive_pairs + 1`
    // (since a chain of `x` pairs means `x+1` dolls).
    // However, this is not quite right.
    // Let's re-evaluate.
    //
    // The total number of "put" operations needed to form the final chain 1->2->...->n is n-1.
    // Each correct consecutive pair `i -> i+1` means one "put" operation is already done.
    // So, `(n-1) - correct_consecutive_pairs` "put" operations are needed.
    //
    // For "take out" operations:
    // Each doll `i` that is nested in `j` (where `j != i+1`) needs to be taken out.
    // The number of dolls that are *not* the last in their initial chain and are *not* part of a correct `i -> i+1` sequence
    // needs to be taken out.
    //
    // Consider the total number of dolls `n`.
    // The number of dolls that are *not* `1` and are *not* the last doll in their chain,
    // and are *not* part of a correct `i -> i+1` sequence, need to be taken out.
    //
    // Let's simplify:
    // We need to form `n-1` links (1->2, 2->3, ..., n-1->n).
    // `correct_consecutive_pairs` links are already formed.
    // So, `(n-1) - correct_consecutive_pairs` new links need to be formed. Each takes 1 "put" operation.
    //
    // To form these new links, we might need to break existing incorrect links.
    // The total number of existing links in the initial configuration is `n - k` (total dolls minus number of chains).
    // Of these `n - k` links, `correct_consecutive_pairs` are correct.
    // So, `(n - k) - correct_consecutive_pairs` links are incorrect.
    // Each incorrect link `a -> b` means doll `a` is in `b`. To reuse `a` or `b`, `a` must be taken out of `b`.
    // This costs 1 "take out" operation.
    //
    // Total operations = (operations to break incorrect links) + (operations to form new links).
    // Operations to break incorrect links = `(n - k) - correct_consecutive_pairs`.
    // Operations to form new links = `(n - 1) - correct_consecutive_pairs`.
    //
    // Total = `(n - k - correct_consecutive_pairs) + (n - 1 - correct_consecutive_pairs)`
    // Total = `2 * n - k - 1 - 2 * correct_consecutive_pairs`.

    operations_needed = (long long)(n - k - correct_consecutive_pairs) + (long long)(n - 1 - correct_consecutive_pairs);

    std::cout << operations_needed << std::endl;

    return 0;
}

