void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result_coloring(n, ' ');
    bool possible = false;

    for (int k = 0; k <= 9; ++k) {
        std::string current_coloring(n, ' ');
        char last_s1_char = '0' - 1; // Represents a value less than any digit
        char first_s2_char = '9' + 1; // Represents a value greater than any digit
        bool s1_empty = true;
        bool s2_empty = true;
        bool current_k_possible = true;

        // First pass: assign digits based on k
        for (int i = 0; i < n; ++i) {
            char digit_char = s[i];
            if (digit_char < (k + '0')) {
                current_coloring[i] = '1';
                if (digit_char < last_s1_char) {
                    current_k_possible = false;
                    break;
                }
                last_s1_char = digit_char;
                s1_empty = false;
            } else if (digit_char > (k + '0')) {
                current_coloring[i] = '2';
                if (s2_empty) { // This is the first digit assigned to S2
                    first_s2_char = digit_char;
                } else if (digit_char < first_s2_char) { // Check against previous S2 digit
                    // This check is actually wrong. We need to check against the last digit added to S2.
                    // Let's re-evaluate the S2 sorting.
                    // For now, just assign and check S2 sorting in a second pass.
                }
                s2_empty = false;
            }
        }

        if (!current_k_possible) {
            continue;
        }

        // Second pass: assign digits equal to k
        // Digits equal to k that appear before the first S2 digit must be 1.
        // Digits equal to k that appear after the first S2 digit must be 2.
        // The first S2 digit is determined by the first digit > k.
        // If no digit > k, then all digits = k can be 1.
        // If no digit < k, then all digits = k can be 2.

        // Find the first digit that was assigned to color 2 (i.e., > k)
        int first_idx_s2 = -1;
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '2') {
                first_idx_s2 = i;
                break;
            }
        }

        // Assign digits equal to k
        for (int i = 0; i < n; ++i) {
            char digit_char = s[i];
            if (digit_char == (k + '0')) {
                if (first_idx_s2 == -1 || i < first_idx_s2) {
                    current_coloring[i] = '1';
                    if (digit_char < last_s1_char) {
                        current_k_possible = false;
                        break;
                    }
                    last_s1_char = digit_char;
                    s1_empty = false;
                } else { // i >= first_idx_s2
                    current_coloring[i] = '2';
                    if (s2_empty) {
                        first_s2_char = digit_char;
                    } else if (digit_char < first_s2_char) {
                        // This is still not quite right. We need to track the last digit added to S2.
                        // Let's simplify: if a digit 'k' is assigned to S1, it must be >= last_s1_char.
                        // If a digit 'k' is assigned to S2, it must be >= last_s2_char.
                        // And last_s1_char <= first_s2_char.
                        // The current logic for 'k' digits is:
                        // All 'k's before first_idx_s2 go to S1.
                        // All 'k's at or after first_idx_s2 go to S2.
                        // This ensures last_s1_char <= k and first_s2_char >= k.
                        // We still need to check S2's internal sorting.
                    }
                    s2_empty = false;
                }
            }
        }

        if (!current_k_possible) {
            continue;
        }

        // Final check for sorting
        std::string s1_str = "";
        std::string s2_str = "";
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                s1_str += s[i];
            } else {
                s2_str += s[i];
            }
        }

        bool sorted_s1 = true;
        for (size_t i = 1; i < s1_str.length(); ++i) {
            if (s1_str[i] < s1_str[i-1]) {
                sorted_s1 = false;
                break;
            }
        }
        if (!sorted_s1) continue;

        bool sorted_s2 = true;
        for (size_t i = 1; i < s2_str.length(); ++i) {
            if (s2_str[i] < s2_str[i-1]) {
                sorted_s2 = false;
                break;
            }
        }
        if (!sorted_s2) continue;

        if (!s1_str.empty() && !s2_str.empty()) {
            if (s1_str.back() > s2_str.front()) {
                continue;
            }
        }

        possible = true;
        result_coloring = current_coloring;
        break;
    }

    if (possible) {
        std::cout << result_coloring << "\n";
    } else {
        std::cout << "-\n";
    }
}

