void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate constraints based on s[i] != s[i+k]
    // For each residue class modulo k, characters must alternate.
    // E.g., s[r], s[r+k], s[r+2k], ... must be 0, 1, 0, 1, ... or 1, 0, 1, 0, ...
    // We can determine the fixed character for each position based on this.
    // If s[i] is '0', then s[i+k] must be '1', s[i+2k] must be '0', etc.
    // If s[i] is '1', then s[i+k] must be '0', s[i+2k] must be '1', etc.
    // If s[i] is '?', it can be either, but it must be consistent with s[i+k], etc.

    // fixed_char[i] will store the determined character for s[i]
    // '0' or '1' if fixed, '?' if still unknown.
    std::vector<char> fixed_char(n, '?');
    bool possible = true;

    for (int r = 0; r < k; ++r) { // Iterate through each residue class modulo k
        char first_val = '?'; // The value for s[r]

        // Determine first_val based on existing '0's or '1's in this residue class
        for (int i = r; i < n; i += k) {
            if (s[i] != '?') {
                char expected_val = ( (i - r) / k % 2 == 0 ) ? s[i] : (s[i] == '0' ? '1' : '0');
                if (first_val == '?') {
                    first_val = expected_val;
                } else if (first_val != expected_val) {
                    possible = false; // Contradiction within this residue class
                    break;
                }
            }
        }
        if (!possible) break;

        // Apply first_val to all positions in this residue class
        for (int i = r; i < n; i += k) {
            if (first_val != '?') {
                fixed_char[i] = ( (i - r) / k % 2 == 0 ) ? first_val : (first_val == '0' ? '1' : '0');
            }
            // If first_val is '?', then all positions in this residue class remain '?'
            // in fixed_char, meaning they can be either 0 or 1, as long as they alternate.
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check if any original '0' or '1' in s contradicts fixed_char
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?' && fixed_char[i] != '?' && s[i] != fixed_char[i]) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 3: Check the first k characters for balance
    // We need to count '0's, '1's, and '?'s in the first k positions of fixed_char.
    // These '?'s can be filled to satisfy the k/2 balance.
    int zeros_in_prefix = 0;
    int ones_in_prefix = 0;
    int q_marks_in_prefix = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_char[i] == '0') {
            zeros_in_prefix++;
        } else if (fixed_char[i] == '1') {
            ones_in_prefix++;
        } else { // fixed_char[i] == '?'
            q_marks_in_prefix++;
        }
    }

    int target_half = k / 2;

    // Can we fill '?'s to achieve target_half zeros and target_half ones?
    // We need (target_half - zeros_in_prefix) more zeros.
    // We need (target_half - ones_in_prefix) more ones.
    // Both counts must be non-negative and their sum must equal q_marks_in_prefix.
    if (zeros_in_prefix > target_half || ones_in_prefix > target_half) {
        possible = false;
    } else {
        int needed_zeros = target_half - zeros_in_prefix;
        int needed_ones = target_half - ones_in_prefix;
        if (needed_zeros + needed_ones != q_marks_in_prefix) {
            possible = false;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

