int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        std::cout << h[0] << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        while (!dq_L.empty() && dq_L.back().first >= h[i]) {
            dq_L.pop_back();
        }
        long long val = h[i];
        if (!dq_L.empty()) {
            val = std::max(val, dq_L.back().first + (i - dq_L.back().second));
        }
        L[i] = val;
        dq_L.push_back({h[i], i});
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        while (!dq_R.empty() && dq_R.back().first >= h[i]) {
            dq_R.pop_back();
        }
        long long val = h[i];
        if (!dq_R.empty()) {
            val = std::max(val, dq_R.back().first + (dq_R.back().second - i));
        }
        R[i] = val;
        dq_R.push_back({h[i], i});
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(L[i], R[i]));
    }

    std::cout << max_k << std::endl;

    return 0;
}

