long long solve() {
    long long n;
    std::cin >> n;

    if (n % 2 != 0) {
        // If N is odd, Chanek must take 1 coin.
        // The remaining N-1 coins are even.
        // Chanek gets 1 + (N-1)/2 coins.
        // Opponent gets (N-1)/2 coins.
        // This is because if N-1 is even, the optimal strategy for the player whose turn it is
        // is to take (N-1)/2 coins if N-1 is not a power of 2, or 1 coin if N-1 is a power of 2.
        // In either case, the total coins taken by the current player from N-1 coins is (N-1)/2.
        // For example, if N-1 = 2, current player takes 1. Remaining 1. Next player takes 1. Total 1 for current.
        // If N-1 = 4, current player takes 2. Remaining 2. Next player takes 1. Remaining 1. Current player takes 1. Total 3 for current.
        // This logic is flawed. Let's re-evaluate.

        // If N is odd, Chanek's only move is to take 1.
        // N becomes N-1 (which is even).
        // Chanek gets 1 coin.
        // Now it's opponent's turn with N-1 coins.
        // The opponent will try to maximize their coins from N-1.
        // The opponent will take (N-1)/2 coins.
        // The remaining (N-1)/2 coins will be taken by Chanek.
        // So Chanek gets 1 + (N-1)/2.
        // This is because for any even number M, the player whose turn it is can always guarantee M/2 coins.
        // If M is a power of 2 (M=2^k, k>=1), the player takes 1. Remaining M-1. Next player takes 1. Remaining M-2.
        // This continues until M/2 coins are taken by each player.
        // If M is not a power of 2, the player takes M/2. Remaining M/2.
        // The next player takes (M/2)/2 = M/4. Remaining M/4.
        // This continues until 1 coin is left.
        // In total, the first player gets M/2 + M/8 + M/32 + ...
        // The second player gets M/4 + M/16 + M/64 + ...
        // Summing these up, the first player gets M/2 coins.
        // So, if N is odd, Chanek takes 1. Remaining N-1. Opponent takes (N-1)/2. Chanek takes (N-1)/2.
        // Chanek's total: 1 + (N-1)/2 = (N+1)/2.
        return (n + 1) / 2;
    } else { // N is even
        // Chanek has two choices:
        // 1. Take 1 coin: N becomes N-1 (odd).
        //    Chanek gets 1 coin.
        //    Now it's opponent's turn with N-1 coins.
        //    From N-1 coins, opponent will get (N-1+1)/2 = N/2 coins (as per the odd case logic).
        //    Chanek will get the remaining (N-1)/2 coins.
        //    Total for Chanek: 1 + (N-1)/2 = (N+1)/2.
        // 2. Take N/2 coins: N becomes N/2 (can be even or odd).
        //    Chanek gets N/2 coins.
        //    Now it's opponent's turn with N/2 coins.
        //    The opponent will play optimally to maximize their coins from N/2.
        //    The remaining coins will go to Chanek.
        //    Let's find the total coins Chanek gets from the N/2 subgame.
        //    This is a recursive structure.
        //    Let C(M) be the coins Chanek gets if it's his turn with M coins.
        //    If M is odd, C(M) = (M+1)/2.
        //    If M is even, C(M) = max(1 + (M-1)/2, M/2 + (M/2 - C_opp(M/2))).
        //    C_opp(M/2) is the coins opponent gets from M/2.
        //    Total coins in M/2 subgame is M/2. So Chanek gets M/2 - C_opp(M/2).
        //    C_opp(M/2) is the coins the *first player* gets if the game starts with M/2.
        //    So C_opp(M/2) = C(M/2).
        //    Thus, if M is even, C(M) = max( (M+1)/2, M/2 + (M/2 - C(M/2)) ).
        //    This is not quite right. The opponent wants to maximize their own coins, not minimize Chanek's.
        //    If Chanek takes N/2, he gets N/2. Remaining N/2.
        //    Opponent plays on N/2. Opponent gets C(N/2) coins.
        //    Chanek gets N/2 - C(N/2) coins from the subgame.
        //    Total for Chanek: N/2 + (N/2 - C(N/2)).
        //    This is N - C(N/2).

        // Let's analyze the N/2 move more carefully.
        // If Chanek takes N/2, he gets N/2. Remaining N/2.
        // Now it's opponent's turn with N/2 coins.
        // The opponent will play optimally.
        // If N/2 is odd, opponent gets (N/2 + 1)/2 coins. Chanek gets (N/2 - 1)/2 coins.
        // Total for Chanek: N/2 + (N/2 - 1)/2 = (2N/2 + N/2 - 1)/2 = (3N/2 - 1)/2.
        // If N/2 is even, opponent gets N/2 / 2 = N/4 coins. Chanek gets N/4 coins.
        // Total for Chanek: N/2 + N/4 = 3N/4.

        // This recursive definition is complex. Let's look for a pattern.
        // The game ends when N=0.
        // The total coins are N.
        // Each player tries to maximize their share.
        // This is a zero-sum game in terms of total coins, but not in terms of individual strategy.
        // Each player wants to maximize their own coins, not minimize opponent's.

        // Consider the total coins N.
        // If N is even, Chanek can take N/2.
        // If N is a power of 2 (N = 2^k, k >= 1):
        //   Chanek takes 1. Remaining N-1 (odd). Opponent gets (N-1+1)/2 = N/2. Chanek gets (N-1-1)/2 = (N-2)/2.
        //   Total for Chanek: 1 + (N-2)/2 = N/2.
        //   Chanek takes N/2. Remaining N/2. Opponent plays on N/2.
        //   Opponent gets N/4. Chanek gets N/4.
        //   Total for Chanek: N/2 + N/4 = 3N/4.
        //   So if N is a power of 2, Chanek takes N/2.
