    // So, there are no nice integers.
    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Calculate sum_r = sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // We need to divide by 2. Since MOD is prime, we can multiply by modular inverse of 2.
    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 7 + 1) / 2 = 10^9 + 8 / 2 = 500000004
    long long inv2 = 500000004;
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // sum_{k=1 to a} k = a * (a + 1) / 2
    long long sum_k_term = (a % MOD); // This is for the '+ a' part

    long long a_plus_1 = (a + 1) % MOD;
    long long sum_k_series = (a % MOD);
    sum_k_series = (sum_k_series * a_plus_1) % MOD;
    sum_k_series = (sum_k_series * inv2) % MOD;

    long long b_mod = b % MOD;
    long long k_b_part = (b_mod * sum_k_series) % MOD;

    long long sum_k_b_plus_1 = (k_b_part + sum_k_term) % MOD;

    // Total sum = (sum_r_term * sum_k_b_plus_1) % MOD
    long long total_sum = (sum_r_term * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

