    int n;
    std::cin >> n;

    int k = static_cast<int>(std::sqrt(n));
    if (k * k < n) {
        k++;
    }

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; ++i) {
        int start_block = std::max(0, current_val - k);
        for (int j = start_block + 1; j <= current_val; ++j) {
            p[i] = j;
            i++;
        }
        i--; // Adjust i to point to the last element of the current block
        current_val = start_block;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

