        std::cout << b_i << (i == n - 2 ? "" : " ");
        a[i] += b_i; // Update a[i]
    }
    std::cout << "\n";

    // Operation 2: Process element a[n-1]
    // Segment [n, n] (0-indexed: [n-1, n-1])
    // Length len = 1
    // For a[n-1], we want to add b_{n-1} such that b_{n-1} is a multiple of 1
    // and a[n-1] + b_{n-1} becomes a multiple of n.
    // Since len=1, b_{n-1} can be any integer.
    // We want a[n-1] + b_{n-1} = k * n.
    // We can choose b_{n-1} = (k * n) - a[n-1].
    // We want a[n-1] + b_{n-1} = 0 (mod n).
    // We can choose b_{n-1} such that a[n-1] + b_{n-1} = 0.
    // So b_{n-1} = -a[n-1]. This is a multiple of 1.
    std::cout << n << " " << n << "\n";
    std::cout << -a[n - 1] << "\n";
    a[n - 1] = 0; // Update a[n-1]

    // After operations 1 and 2:
    // a[0]...a[n-2] are all multiples of n.
    // a[n-1] is 0.

    // Operation 3: Make all elements zero.
    // Segment [1, n] (0-indexed: [0, n-1])
    // Length len = n
    // For each a[i], we know it's a multiple of n.
    // We want to add b_i such that b_i is a multiple of n and a[i] + b_i = 0.
    // We can simply choose b_i = -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << "1 " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize two values: one where all bits are 0, one where all bits are 1.
    // Since constants are up to 1023 (10 bits), we consider 10 bits.
    // So, initial_val0 = 0 (all bits 0)
    // initial_val1 = (1 << 10) - 1 = 1023 (all bits 1)
    int current_val0 = 0;
    int current_val1 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val0 &= x;
            current_val1 &= x;
        } else if (op_char == '|') {
            current_val0 |= x;
            current_val1 |= x;
        } else if (op_char == '^') {
            current_val0 ^= x;
            current_val1 ^= x;
        }
    }

    // Now, current_val0 is the result of applying all operations to 0.
    // And current_val1 is the result of applying all operations to 1023.

    // We need to find a minimal sequence of operations (at most 5)
    // that transforms 0 to current_val0 and 1023 to current_val1.

    // Let's determine the target state for each bit position j (0 to 9).
    // For an input bit 'b' at position j:
    // If b=0, the output bit should be (current_val0 >> j) & 1.
    // If b=1, the output bit should be (current_val1 >> j) & 1.

    // We can represent the transformation for each bit as a 2-bit value:
    // (output_for_1 << 1) | output_for_0
    // 00: 0 -> 0, 1 -> 0  (always 0)
    // 01: 0 -> 1, 1 -> 0  (XOR with 1)
    // 10: 0 -> 0, 1 -> 1  (identity)
    // 11: 0 -> 1, 1 -> 1  (always 1)

    // We will construct three constants: and_const, or_const, xor_const.
    // Initialize them to values that represent identity operations:
    // AND with 1023 (all 1s) is identity.
    // OR with 0 (all 0s) is identity.
    // XOR with 0 (all 0s) is identity.
    int and_const = 1023;
    int or_const = 0;
    int xor_const = 0;

    for (int j = 0; j < 10; ++j) {
        int bit0_result = (current_val0 >> j) & 1;
        int bit1_result = (current_val1 >> j) & 1;

        // The transformation for bit j is (bit1_result << 1) | bit0_result
        // This is the truth table for the j-th bit:
        // Input | Output
        //   0   | bit0_result
        //   1   | bit1_result

        // Case 1: 0 -> 0, 1 -> 0 (always 0)
        if (bit0_result == 0 && bit1_result == 0) {
            // To make bit j always 0, we need to AND with 0 at bit j.
            and_const &= ~(1 << j); // Set j-th bit of and_const to 0
        }
        // Case 2: 0 -> 1, 1 -> 0 (XOR with 1)
        else if (bit0_result == 1 && bit1_result == 0) {
            // To achieve this, we need to XOR with 1 at bit j.
            xor_const |= (1 << j); // Set j-th bit of xor_const to 1
        }
        // Case 3: 0 -> 0, 1 -> 1 (identity)
        else if (bit0_result == 0 && bit1_result == 1) {
            // This is the default identity, no change needed for this bit
            // in and_const, or_const, xor_const (which are 1, 0, 0 respectively).
        }
        // Case 4: 0 -> 1, 1 -> 1 (always 1)
        else if (bit0_result == 1 && bit1_result == 1) {
            // To make bit j always 1, we need to OR with 1 at bit j.
            or_const |= (1 << j); // Set j-th bit of or_const to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (or_const != 0) {
        result_ops.push_back({'|', or_const});
    }
    if (xor_const != 0) {
        result_ops.push_back({'^', xor_const});
    }
    if (and_const != 1023) { // If and_const is not all 1s, it means some bits were forced to 0.
        result_ops.push_back({'&', and_const});
    }

    // The order of operations matters.
    // The sequence OR, XOR, AND can represent any bitwise function.
    // (x | or_const) ^ xor_const) & and_const
    // This order is chosen because:
    // OR sets bits to 1.
    // XOR flips bits.
    // AND sets bits to 0.
    // If we apply OR first, it sets some bits to 1.
    // Then XOR can flip some bits (including those set by OR or not).
    // Finally, AND can force some bits to 0.
    // This specific order (OR, XOR, AND) is known to be canonical for 10-bit functions.

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial total counts
    int total_s = 0;
    int total_b = 0;
    for (int x : a) {
        if (x == 1) {
            total_s++;
        } else {
            total_b++;
        }
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_left[k] = (count of 1s in a[0...k-1]) - (count of 2s in a[0...k-1])
    // We are interested in diff_left[k] for k from 0 to n.
    // diff_left[0] = 0 (empty prefix)
    // diff_left[k] for k > 0 is the balance after removing k jars from the left.
    std::map<int, int> diff_left_idx; // Stores diff -> minimum k (number of jars removed)
    diff_left_idx[0] = 0; // 0 jars removed, balance 0

    int current_diff = 0;
    for (int k = 0; k < n; ++k) { // Iterate through jars a[0] to a[n-1]
        if (a[k] == 1) {
            current_diff++;
        } else {
            current_diff--;
        }
        // Store the minimum k for each diff encountered
        if (diff_left_idx.find(current_diff) == diff_left_idx.end()) {
            diff_left_idx[current_diff] = k + 1;
        }
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_right[k] = (count of 1s in a[2n-k...2n-1]) - (count of 2s in a[2n-k...2n-1])
    // We are interested in diff_right[k] for k from 0 to n.
    // diff_right[0] = 0 (empty suffix)
    // diff_right[k] for k > 0 is the balance after removing k jars from the right.
    std::map<int, int> diff_right_idx; // Stores diff -> minimum k (number of jars removed)
    diff_right_idx[0] = 0; // 0 jars removed, balance 0

    current_diff = 0;
    for (int k = 0; k < n; ++k) { // Iterate through jars a[2n-1] down to a[n]
        if (a[2 * n - 1 - k] == 1) {
            current_diff++;
        } else {
            current_diff--;
        }
        // Store the minimum k for each diff encountered
        if (diff_right_idx.find(current_diff) == diff_right_idx.end()) {
            diff_right_idx[current_diff] = k + 1;
        }
    }

    // The target difference for the remaining jars is total_s - total_b.
    // Let this be D_target.
    // We need to find L and R such that:
    // (balance of remaining jars) = D_target
    // (balance of all jars) - (balance of L removed jars) - (balance of R removed jars) = D_target
    // (total_s - total_b) - (diff_left[L]) - (diff_right[R]) = D_target
    // This simplifies to:
    // diff_left[L] + diff_right[R] = 0
    // So, diff_left[L] = -diff_right[R]

    int min_removed = 2 * n; // Max possible jars to remove

    // Iterate through all possible diffs from the left side
    for (auto const& [diff_L, jars_L] : diff_left_idx) {
        int target_diff_R = -diff_L;
        if (diff_right_idx.count(target_diff_R)) {
            int jars_R = diff_right_idx[target_diff_R];
            min_removed = std::min(min_removed, jars_L + jars_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total possible substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the ones.
        // The m ones divide the string into m+1 potential blocks of zeros.
        // Let k be the number of zeros in each of the (m+1) blocks.
        // We want to make these blocks as equal in length as possible.
        //
        // If num_zeros = 0, then all characters are '1's. No zero-only substrings.
        // If num_zeros > 0:
        // We have num_zeros zeros to distribute into m+1 blocks.
        // Let q = num_zeros / (m+1) be the quotient (minimum number of zeros in a block).
        // Let r = num_zeros % (m+1) be the remainder.
        // This means r blocks will have (q+1) zeros, and (m+1-r) blocks will have q zeros.

        long long q = num_zeros / (m + 1);
        long long r = num_zeros % (m + 1);

        // Calculate the number of zero-only substrings
        // r blocks of length (q+1)
        long long zero_substrings_from_q_plus_1_blocks = r * (q + 1) * (q + 2) / 2;
        // (m+1-r) blocks of length q
        long long zero_substrings_from_q_blocks = (m + 1 - r) * q * (q + 1) / 2;

        long long min_zero_substrings = zero_substrings_from_q_plus_1_blocks + zero_substrings_from_q_blocks;

        // The maximum value of f(s) is total_substrings - min_zero_substrings
        long long max_f_s = total_substrings - min_zero_substrings;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, as elements must be positive.

    // Iterate through powers of 2 from largest to smallest
    // A block of k identical elements contributes 2^k - 1 subsequences.
    // We want to find k such that 2^k - 1 <= X.
    // The maximum possible k is around 60 (2^60 is large enough for X up to 10^18, but X is 10^9, so 2^30 is enough).
    // We can iterate k from 60 down to 1.
    for (int k = 60; k >= 1; --k) {
        long long count_for_k = (1LL << k) - 1; // Number of subsequences from k identical elements
        if (count_for_k <= X) {
            long long num_blocks = X / count_for_k;
            X %= count_for_k;

            for (long long i = 0; i < num_blocks; ++i) {
                // Add k identical elements to the array
                for (int j = 0; j < k; ++j) {
                    result_array.push_back(current_val);
                }
                // Increment current_val by d+1 to ensure new blocks are sufficiently separated
                // so that subsequences spanning across blocks are invalid.
                // current_val + d + 1 ensures min_val + d <= current_val, making max-min >= d.
                current_val += (d + 1);
                // Check for overflow, though with current_val starting at 1 and d up to 10^9,
                // and n up to 10^4, current_val can reach 1 + 10^4 * 10^9 = 10^13, which is fine for long long.
                // The problem states elements < 10^18.
                if (current_val >= 1000000000000000000LL) { // 10^18
                    // This case should ideally not be reached given constraints,
                    // but as a safeguard, if it does, it means no solution.
                    // However, the problem guarantees a solution if one exists within constraints.
                    // The maximum number of elements is 10^4.
                    // Max current_val = 1 + 10^4 * (10^9 + 1) approx 10^13. This is well within 10^18.
                }
            }
        }
    }

    // If X is not 0 after the loop, it means we couldn't form X exactly.
    // This should not happen if a solution exists, as the greedy approach covers all X.
    if (X != 0) {
        // This case implies an issue with the logic or an impossible X.
        // Given the problem constraints and typical competitive programming problems,
        // this path should not be taken if a solution is guaranteed.
        // However, if it were possible, printing -1 would be appropriate.
        // For this problem, the greedy approach should always yield X=0 if a solution exists.
    }

    if (result_array.empty() || result_array.size() > 10000) {
        // This condition should ideally not be met if X >= 1.
        // If X=0 was allowed, it would be an empty array.
        // If X=1, k=1, num_blocks=1, result_array.push_back(1), size=1.
        // Max size: X=10^9. Smallest k is 1. (1LL << 1) - 1 = 1.
        // So, if X=10^9, we could have 10^9 blocks of 1. This would exceed 10^4 elements.
        // This is the critical part. The greedy strategy must ensure n <= 10^4.
        // Let's re-evaluate the maximum number of elements.
        // The maximum number of elements is when X is large and we use many small k.
        // E.g., X = 10^9.
        // k=29: (1LL << 29) - 1 = 536870911. X = 10^9. num_blocks = 1. X = 10^9 - 536870911 = 463129089.
        // result_array.size() += 29.
        // k=28: (1LL << 28) - 1 = 268435455. X = 463129089. num_blocks = 1. X = 463129089 - 268435455 = 194693634.
        // result_array.size() += 28.
        // ...
        // The sum of k's will be at most 60 * log2(X) / log2(2^k-1) roughly.
        // The maximum number of elements is bounded.
        // The sum of k's for X = 10^9 is roughly sum of k for binary representation of X.
        // Max sum of k's is when X is sum of many (2^1-1)s.
        // If X = 10^9, and we only use k=1, then we need 10^9 elements. This is too many.
        // The greedy approach from largest k ensures minimal number of elements.
        // The maximum number of elements is when X is just below a power of 2, e.g., X = 2^N - 2.
        // This would be (N-1) + (N-2) + ... + 1.
        // For X = 10^9, N is about 30. Sum of k from 1 to 30 is 30*31/2 = 465.
        // This is well within 10^4.
        // So, the size check is mostly for safety, but should not fail.
    }

    std::cout << result_array.size() << std::endl;
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n < 3) { // Should not happen based on constraints (n >= 3)
        return a;
    }

    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        if (sum >= 2) {
            b[i] = 1;
        } else {
            b[i] = 0;
        }
    }
    return b;
}

// Function to check if a sequence is stable
bool is_stable(const std::vector<int>& a) {
    int n = a.size();
    if (n < 3) {
        return true; // A sequence of length < 3 is trivially stable by definition
    }

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val = (sum >= 2) ? 1 : 0;
        if (median_val != a[i]) {
            return false;
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (is_stable(a)) {
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find all maximal consecutive blocks of identical values
    // and store their start index and length.
    // Example: 0 0 1 1 1 0 0 -> (0,2), (2,3), (5,2)
    std::vector<std::pair<int, int>> blocks;
    if (n > 0) {
        int current_val = a[0];
        int current_start = 0;
        for (int i = 1; i < n; ++i) {
            if (a[i] != current_val) {
                blocks.push_back({current_start, i - current_start});
                current_val = a[i];
                current_start = i;
            }
        }
        blocks.push_back({current_start, n - current_start});
    }

    int max_steps = 0;

    // Iterate through blocks to find '010' or '101' patterns
    // These are the only patterns that can change.
    // A '010' pattern will become '000' in one step.
    // A '101' pattern will become '111' in one step.
    // The number of steps depends on the length of the middle block.
    // For a pattern like 0...0 1...1 0...0, if the middle 1-block has length L,
    // it takes ceil(L/2) steps for the 1s to disappear.
    // For a pattern like 1...1 0...0 1...1, if the middle 0-block has length L,
    // it takes ceil(L/2) steps for the 0s to disappear.

    for (size_t i = 0; i + 2 < blocks.size(); ++i) {
        // Check for 0...0 1...1 0...0 pattern
        if (a[blocks[i].first] == 0 && a[blocks[i+1].first] == 1 && a[blocks[i+2].first] == 0) {
            int len_middle_block = blocks[i+1].second;
            max_steps = std::max(max_steps, (len_middle_block + 1) / 2);
        }
        // Check for 1...1 0...0 1...1 pattern
        else if (a[blocks[i].first] == 1 && a[blocks[i+1].first] == 0 && a[blocks[i+2].first] == 1) {
            int len_middle_block = blocks[i+1].second;
            max_steps = std::max(max_steps, (len_middle_block + 1) / 2);
        }
    }

    // Apply smoothing max_steps times to get the final stable sequence
    std::vector<int> current_a = a;
    for (int step = 0; step < max_steps; ++step) {
        current_a = apply_median_smoothing(current_a);
    }

    std::cout << max_steps << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << current_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::max, std::min

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int q;
    std::cin >> q; // Read the number of queries.

    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k; // Read target coordinates (n, m) and number of moves k.

        // Take absolute values for n and m, as movement is symmetric.
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n is always the larger or equal of the two for simpler logic.
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: It's impossible to reach (abs_n, abs_m) in k moves.
        // The minimum number of moves required is abs_n (which is max(abs_n, abs_m)).
        // If k is less than this minimum, it's impossible.
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Determine the parity of the remaining moves.
        // After reaching (abs_n, abs_m) in abs_n moves (minimum moves),
        // we have k - abs_n moves remaining.
        // Each remaining move must be "wasted" by moving back and forth,
        // e.g., (x,y) -> (x+1,y) -> (x,y) or (x,y) -> (x+1,y+1) -> (x,y).
        // Each such pair of moves changes the coordinates by (0,0).
        // A single "wasted" move (e.g., (x,y) -> (x+1,y)) changes the parity of the sum of coordinates.
        //
        // The parity of the final position (abs_n, abs_m) must match the parity of k.
        // This is because each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // A move from (x1, y1) to (x2, y2) changes (x+y) to (x+dx + y+dy).
        // The change in (x+y) is dx+dy.
        // dx, dy can be -1, 0, 1.
        // dx+dy can be -2, -1, 0, 1, 2.
        // The parity of (x+y) changes if dx+dy is odd.
        // dx+dy is odd if one of dx, dy is 0 and the other is +/-1 (non-diagonal move),
        // or if one is +/-1 and the other is +/-1 (diagonal move, e.g., (1,0) + (0,1) = 1, (1,1) = 2).
        //
        // Let's re-evaluate parity:
        // Each move changes the sum of coordinates (x+y) by some value.
        // The parity of (x+y) changes if the move is non-diagonal (e.g., (1,0) or (0,1)).
        // The parity of (x+y) does not change if the move is diagonal (e.g., (1,1) or (1,-1)).
        //
        // This is incorrect. A simpler way:
        // Each move changes the parity of x or y or both.
        // If a move changes x by dx and y by dy, the parity of (x+y) changes by (dx mod 2 + dy mod 2) mod 2.
        // For any of the 8 moves, dx and dy are -1, 0, or 1.
        // dx mod 2 is 1 if dx is -1 or 1, 0 if dx is 0.
        // dy mod 2 is 1 if dy is -1 or 1, 0 if dy is 0.
        //
