#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    int id;
    long long v, d, p;
    bool in_line; // To mark if a child is still in line without physically removing them
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue; // This child has already left the line
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is now being treated

        long long current_v_reduction = children[i].v;
        long long total_d_reduction_from_chain = 0;

        // Apply v_i reduction to children after the current one
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply reductions from the child being treated
            if (current_v_reduction > 0) {
                children[j].p -= current_v_reduction;
                current_v_reduction--;
            }

            // Apply accumulated d_j reductions from previous chain reactions
            children[j].p -= total_d_reduction_from_chain;

            // Check if this child leaves due to confidence drop
            if (children[j].p < 0) {
                if (children[j].in_line) { // Ensure we only add d_j once if they leave
                    total_d_reduction_from_chain += children[j].d;
                    children[j].in_line = false;
                }
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

