    // For type 2 operations, max(a_0[j] + delta[j]) = m.
    // This implies a_0[j] + delta[j] <= m for all j in [l, r].
    // So, a_0[j] <= m - delta[j].
    // We want to maximize a_0[j], so we take the minimum of all such upper bounds.
    // Initialize a_0[i] to a large positive value (e.g., 10^9) and then minimize it.
    std::vector<long long> a0(n, 1000000000LL); // Initial upper bound for a_0[i]

    // Calculate delta values for each type 2 operation
    // delta_at_op[k][j] stores the sum of d's applied to a_0[j] up to operation k-1.
    // This is not efficient. Instead, we can calculate current_delta for each type 2 op.

    // Iterate operations in reverse to determine initial array values
    // For type 2 operations: a_0[j] <= m - current_delta[j]
    // For type 1 operations: current_delta[j] -= d
    std::vector<long long> current_delta(n, 0); // current_delta[j] is sum of d's applied to a_0[j]
                                                // from operations *after* the current one being processed (in reverse)

    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If it's a type 1 operation (1 l r d), it means a_j was increased by d.
            // When going in reverse, this means the value *before* this operation was d less.
            // So, we subtract d from the current_delta for elements in [l, r].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] -= ops[i].val;
            }
        } else { // ops[i].type == 2
            // If it's a type 2 operation (2 l r m), it means max(a_j) = m.
            // This implies a_0[j] + (sum of d's up to this op) <= m.
            // The sum of d's up to this op is (total_delta - current_delta[j]).
            // No, this is wrong. current_delta[j] is the sum of d's *after* this op.
            // So, the sum of d's *before* this op is what we need.
            // Let's redefine current_delta: it's the sum of d's applied to a_0[j] *before* the current operation `i`.
            // This means we need to apply type 1 ops in forward order to build current_delta.

            // Let's stick to the original plan: a0[j] is an upper bound.
            // When we process op `i` (type 2, `l r m`), the values are `a0_initial[j] + delta_sum_up_to_i[j]`.
            // So, `a0_initial[j] + delta_sum_up_to_i[j] <= m` for `j` in `[l, r]`.
            // This means `a0_initial[j] <= m - delta_sum_up_to_i[j]`.
            // We want to find the largest possible `a0_initial[j]`, so we take the minimum of all such upper bounds.
            // `a0[j]` stores `m - delta_sum_up_to_i[j]` for the current `j`.
            // `current_delta[j]` stores the sum of `d` values applied to `a_0[j]` by operations *before* the current one `i`.
            // So, `a0[j]` should be updated with `min(a0[j], ops[i].val - current_delta[j])`.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a0[j] = std::min(a0[j], ops[i].val - current_delta[j]);
            }
        }
        // After processing op `i` (either type 1 or type 2), if it was a type 1 op,
        // its effect `d` is now part of `current_delta` for subsequent (earlier in time) operations.
        // So, if op `i` was type 1, we add its `d` to `current_delta` for elements in `[l, r]`.
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        }
    }

    // Check if the constructed a0 satisfies all constraints
    // First, check if |a0[i]| <= 10^9
    for (int i = 0; i < n; ++i) {
        if (a0[i] > 1000000000LL || a0[i] < -1000000000LL) {
            // If a0[i] is still 10^9, it means no type 2 operation constrained it.
            // We can set it to 0 or any value within bounds.
            // Let's set it to 0 if it's still 10^9.
            if (a0[i] == 1000000000LL) {
                a0[i] = 0;
            } else {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    // Simulate operations with the constructed a0
    std::vector<long long> current_a(a0);
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // op.type == 2
            long long max_val = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a0[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as y can grow large.
// x can also become large temporarily before being reduced.
// a_i values are up to 10^9, n up to 2*10^5.
// y can be n * 2 * max(a_i) which is 2*10^5 * 2 * 10^9 = 4*10^14.
// x can be n + max(a_i) which is 2*10^5 + 10^9, fits in long long.

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Use 0-based indexing for a, so a[0] corresponds to a_1, a[i] to a_{i+1}.
    // The input gives a_2, ..., a_n, which means a[1], ..., a[n-1] in 0-based.
    // We will store a_i values directly in a vector of size n.
    // a[0] will be set for each run.
    // a[1] to a[n-1] are read from input.
    std::vector<long long> a(n);
    for (int i = 1; i < n; ++i) {
        std::cin >> a[i];
    }

    // dp[i] will store the final y value if starting with x=i+1 and a[i] is the initial move.
    // Or -1 if it doesn't terminate.
    // We need to compute this for x_start = 1, ..., n-1.
    // The problem asks for a_1 = i, so x_start is always 1.
    // The value a[0] changes for each run.
    // The state is (current_x, current_move_type).
    // move_type 0: x increases, y increases by a[x-1]
    // move_type 1: x decreases, y increases by a[x-1]
    // The problem states: "program increases both x and y by a_x simultaneously" (step 2)
    // "program now increases y by a_x while decreasing x by a_x" (step 3)
    // This means the value a_x is taken from the x *before* step 2.
    // Let's denote the value of a at current x as `val`.
    // Step 2: x_new = x + val, y_new = y + val
    // Step 3: y_new = y_new + val, x_new = x_new - val
    // So, for a given x, the total y increase is 2 * a[x-1].
    // The x transitions are: x -> x + a[x-1] -> x + a[x-1] - a[x+a[x-1]-1].
    // This is a standard DP on states (x, move_type).
    // Let dp_val[x][0] be the total y accumulated from state (x, move_type 0) until termination.
    // Let dp_val[x][1] be the total y accumulated from state (x, move_type 1) until termination.
    // And dp_next_x[x][0] be the final x from state (x, move_type 0).
    // And dp_next_x[x][1] be the final x from state (x, move_type 1).
    // The states are (x, 0) for step 2, (x, 1) for step 3.
    // The problem's x is 1-indexed. Our array `a` is 0-indexed.
    // So `a[x-1]` is the value.
    // The states are (x, 0) for step 2, (x, 1) for step 3.
    // Let's define `dp_y[x][0]` as the total `y` accumulated from `x` when `a[x-1]` is used for the first time (step 2).
    // Let `dp_y[x][1]` as the total `y` accumulated from `x` when `a[x-1]` is used for the second time (step 3).
    // And `dp_final_x[x][0]` and `dp_final_x[x][1]` for the final `x`.

    // We need to compute for x from 1 to n.
    // The maximum value of x can be n + max(a_i) which is 2*10^5 + 10^9.
    // This is too large for a direct DP table.
    // However, the problem states x <= 0 or x > n terminates.
    // This means we only care about x values in [1, n].
    // If x + a[x-1] > n, then the next state is outside [1, n].
    // If x - a[x-1] <= 0, then the next state is outside [1, n].
    // This suggests that we only need to store DP values for x in [1, n].
    // For x > n or x <= 0, the y accumulated is 0 and final x is that value.

    // Let's define dp_y[x] as the total y accumulated starting from x,
    // and dp_final_x[x] as the final x value, assuming the first operation is step 2.
    // This is for a fixed a[0].
    // This is still not quite right. The problem is that a[x-1] changes based on x.
    // The sequence of operations is:
    // x_curr = 1, y_curr = 0
    // Loop:
    //   val = a[x_curr-1]
    //   y_curr += val
    //   x_curr += val
    //   If x_curr <= 0 or x_curr > n, break.
    //   val_new = a[x_curr-1] // This is the crucial part. The value changes.
    //   y_curr += val_new
    //   x_curr -= val_new
    //   If x_curr <= 0 or x_curr > n, break.

    // This is a standard "jump" problem. We can use DP with memoization.
    // The states are (x, parity_of_step).
    // Parity 0: just finished step 3, about to do step 2.
    // Parity 1: just finished step 2, about to do step 3.
    // Let's define dp_y[x][0] as the total y accumulated from state (x, about to do step 2)
    // and dp_y[x][1] as the total y accumulated from state (x, about to do step 3).
    // And dp_final_x[x][0/1] for the final x.
    // The values a[i] are up to 10^9.
    // The number of states is N * 2.
    // For each state, we compute the next state.
    // If the next state is outside [1, N], it terminates.
    // If the next state is inside [1, N], we recursively call.

    // dp_y[x][0] = a[x-1] + dp_y[x + a[x-1]][1]
    // dp_final_x[x][0] = dp_final_x[x + a[x-1]][1]
    // dp_y[x][1] = a[x-1] + dp_y[x - a[x-1]][0]
    // dp_final_x[x][1] = dp_final_x[x - a[x-1]][0]

    // Base cases:
    // If x + a[x-1] > n or x + a[x-1] <= 0:
    //   dp_y[x][0] = a[x-1]
    //   dp_final_x[x][0] = x + a[x-1]
    // If x - a[x-1] > n or x - a[x-1] <= 0:
    //   dp_y[x][1] = a[x-1]
    //   dp_final_x[x][1] = x - a[x-1]

    // We need to compute this for each starting a[0] = i.
    // This means the `a` array changes for each run.
    // So, we cannot precompute DP for all `a[0]`.
    // The values a[1]...a[n-1] are fixed.
    // Only a[0] changes.
    // This means the DP values for x > 1 are fixed.
    // We can precompute dp_y[x][0/1] and dp_final_x[x][0/1] for x from 2 to n.
    // Then for each query, we compute for x=1.

    // dp_y[x][0] stores total y from (x, step 2)
    // dp_y[x][1] stores total y from (x, step 3)
    // dp_final_x[x][0] stores final x from (x, step 2)
    // dp_final_x[x][1] stores final x from (x, step 3)
    // Use -2 for dp_final_x to indicate non-termination (cycle).
    // Use -1 for dp_y to indicate non-termination (cycle).

    std::vector<std::vector<long long>> dp_y(n + 1, std::vector<long long>(2, 0));
    std::vector<std::vector<long long>> dp_final_x(n + 1, std::vector<long long>(2, 0));
    std::vector<std::vector<bool>> visited(n + 1, std::vector<bool>(2, false));
    std::vector<std::vector<bool>> in_stack(n + 1, std::vector<bool>(2, false));

    // Function to compute DP values for a given state (x, parity)
    // parity 0: about to do step 2 (x += val, y += val)
    // parity 1: about to do step 3 (y += val, x -= val)
    // The `val` for parity 1 is `a[x_after_step2 - 1]`.
    // This means the `val` for parity 1 depends on the previous state.
    // This structure is tricky. Let's redefine.

    // Let's define `solve(current_x, current_y, current_val_from_prev_step)`
    // This is too complex.
    // The problem states:
    // 1. x = x + a_x, y = y + a_x
    // 2. y = y + a_x, x = x - a_x
    // The `a_x` in step 2 and step 3 refers to the value of `a` at the `x` *before* step 2.
    // Let `x_prev` be the value of `x` before step 2.
    // `val = a[x_prev-1]`
    // Step 2: `x_temp = x_prev + val`, `y_temp = y_prev + val`
    // Step 3: `y_final = y_temp + val`, `x_final = x_temp - val`
    // So, from `x_prev`, the total `y` increase is `2 * a[x_prev-1]`.
    // The next `x` is `x_prev + a[x_prev-1] - a[x_prev+a[x_prev-1]-1]`.
    // This is simpler. Let `f(x)` be the function that computes the final `y` and `x` starting from `x`.
    // `f(x)` returns `(final_y, final_x)`.
    // If `x <= 0` or `x > n`, then `f(x)` returns `(0, x)`.
    // Otherwise, `val = a[x-1]`.
    // `next_x_after_step2 = x + val`.
    // If `next_x_after_step2 <= 0` or `next_x_after_step2 > n`:
    //   `f(x)` returns `(val, next_x_after_step2)`.
    // Else:
    //   `val_after_step2 = a[next_x_after_step2 - 1]`.
    //   `next_x_after_step3 = next_x_after_step2 - val_after_step2`.
    //   `res = f(next_x_after_step3)`.
    //   If `res.first == -1` (non-terminating):
    //     `f(x)` returns `(-1, -1)`.
    //   Else:
    //     `f(x)` returns `(2 * val + res.first, res.second)`.

    // This is a DP with memoization.
    // `dp_y[x]` stores the total y accumulated from `x` until termination.
    // `dp_final_x[x]` stores the final x value from `x` until termination.
    // `visited[x]` tracks if `dp_y[x]` has been computed.
    // `in_stack[x]` tracks if `x` is currently in the recursion stack (for cycle detection).

    // Initialize DP tables for x from 2 to n.
    // For x=1, a[0] changes, so we can't precompute.
    // We will compute for x=1 separately for each query.
    // For x from 2 to n, a[x-1] is fixed.
    // We need to compute for x from 2 to n.
    // The values a[i] are up to 10^9.
    // The next x can be outside [1, n].
    // The DP table should be indexed by x.
    // Max x is n.
    // dp_y[x] stores the total y accumulated starting from x.
    // dp_final_x[x] stores the final x value starting from x.
    // -1 for y means non-terminating.
    // -2 for x means non-terminating.

    // Let's use a lambda for the recursive function.
    // `a` is captured by reference.
    auto compute_dp = [&](int current_x, auto& self) -> std::pair<long long, long long> {
        if (current_x <= 0 || current_x > n) {
            return {0, current_x};
        }

        // Check if already computed
        if (visited[current_x][0]) { // Using [0] for the main DP state
            if (in_stack[current_x][0]) { // Cycle detected
                return {-1, -2}; // Indicate non-termination
            }
            return {dp_y[current_x][0], dp_final_x[current_x][0]};
        }

        visited[current_x][0] = true;
        in_stack[current_x][0] = true;

        long long val_at_x = a[current_x - 1];
        long long y_accumulated = 2 * val_at_x;

        long long next_x_after_step2 = current_x + val_at_x;

        // If terminates after step 2
        if (next_x_after_step2 <= 0 || next_x_after_step2 > n) {
            in_stack[current_x][0] = false;
            dp_y[current_x][0] = val_at_x;
            dp_final_x[current_x][0] = next_x_after_step2;
            return {dp_y[current_x][0], dp_final_x[current_x][0]};
        }

        long long val_at_next_x_after_step2 = a[next_x_after_step2 - 1];
        long long next_x_after_step3 = next_x_after_step2 - val_at_next_x_after_step2;

        std::pair<long long, long long> res = self(next_x_after_step3, self);

        in_stack[current_x][0] = false;

        if (res.first == -1) { // Non-terminating path
            dp_y[current_x][0] = -1;
            dp_final_x[current_x][0] = -2;
        } else {
            dp_y[current_x][0] = y_accumulated + res.first;
            dp_final_x[current_x][0] = res.second;
        }
        return {dp_y[current_x][0], dp_final_x[current_x][0]};
    };

    // Precompute for x from 2 to n.
    // Note: a[0] is not used in this loop.
    for (int i = 2; i <= n; ++i) {
        if (!visited[i][0]) {
            compute_dp(i, compute_dp);
        }
    }

    // Now, for each query (a_1 = i)
    for (int i = 1; i < n; ++i) {
        a[0] = i; // Set a_1 for the current run

        // Reset visited and in_stack for x=1 only.
        // Other states (x > 1) are already computed and their values are fixed.
        // We only need to re-evaluate the path starting from x=1.
        // The `compute_dp` function will use the precomputed values for x > 1.
        visited[1][0] = false;
        in_stack[1][0] = false;

        std::pair<long long, long long> result = compute_dp(1, compute_dp);
        std::cout << result.first << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k = 1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_left = s.substr(0, i);
        std::string s_right = s.substr(i);
        std::string s_prime = s_right + s_left;

        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k = 2
    // If k=1 didn't work, we need to check if k=2 is possible.
    // A k=2 solution is always possible unless all characters in s are the same.
    // If all characters are the same (e.g., "aaaa"), then any permutation of its
    // substrings will result in the same string "aaaa", which is not allowed.
    // In this case, it's impossible.

    // Check if all characters in s are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, a k=2 solution is always possible.
        // Example: "nolon" -> "no|l|on" -> "on|l|no" (palindrome, not equal to "nolon")
        // Example: "abacaba" -> "aba|c|aba" -> "aba|c|aba" (equal)
        // But we can always find a cut that works.
        // Consider s = "abacaba".
        // If we cut s into s[0...N/2-1], s[N/2], s[N/2+1...N-1]
        // For example, "abacaba" -> "aba", "c", "aba"
        // Reorder to "aba" + "c" + "aba" -> "abacaba" (same)
        //
        // However, if not all characters are the same, there must be at least two distinct characters.
        // Since s is a palindrome, if s[0] != s[1], then s[N-1] != s[N-2].
        // If s has length N, and not all characters are the same, then there exists some `i` such that `s[i] != s[0]`.
        // Consider the string `s_prefix = s.substr(0, N-1)`.
        // If `s_prefix` is not a palindrome, then `s` cannot be formed by `s_prefix` + `s[N-1]`.
        //
        // Let's re-evaluate the k=2 logic.
        // If `s` is a palindrome and not all characters are the same,
        // then `s` must have at least two distinct characters.
        // For example, `s = "abacaba"`. `N=7`.
        // `s_prefix = "abacab"`. This is not a palindrome.
        // `s_suffix = "bacaba"`. This is not a palindrome.
        //
        // If `s` is a palindrome and not all characters are the same,
        // then `s` must contain at least two distinct characters.
        // Let `s_sub = s.substr(0, N/2)`.
        // If `s_sub` is not a palindrome, then `s` cannot be formed by `s_sub` + `s[N/2]` + `reverse(s_sub)`.
        //
        // The problem states that if not all characters are the same, k=2 is always possible.
        // Example: "nolon" (N=5). Not all same. Output 2.
        // Example: "otto" (N=4). Not all same. Output 1. (Handled by k=1 check)
        // Example: "kinnikkinnik" (N=12). Not all same. Output 1. (Handled by k=1 check)
        //
        // The logic for k=2 is that if k=1 doesn't work, and not all characters are the same,
        // then we can always find a way to make 2 cuts.
        // Consider `s = s[0] s[1] ... s[N-1]`.
        // Since `s` is a palindrome, `s[i] = s[N-1-i]`.
        // If not all characters are the same, there exists some `i` such that `s[i] != s[0]`.
        // This implies `s[N-1-i] != s[0]`.
        //
        // Let's take `s = "abacaba"`. `N=7`.
        // `s_prefix = s.substr(0, N-1) = "abacab"`.
        // `s_suffix = s.substr(1, N-1) = "bacaba"`.
        //
        // If `s.substr(0, N-1)` is not a palindrome, then we can cut `s` into `s[0]` and `s.substr(1, N-1)`.
        // Then reorder to `s.substr(1, N-1) + s[0]`.
        // This is a single cut.
        //
        // The crucial observation for k=2 is that if `s` is a palindrome and not all characters are the same,
        // then `s.substr(0, N-1)` (or `s.substr(1, N-1)`) is NOT a palindrome.
        // Proof: Assume `s.substr(0, N-1)` is a palindrome.
        // Let `s = c_0 c_1 ... c_{N-1}`.
        // `s.substr(0, N-1)` is `c_0 c_1 ... c_{N-2}`.
        // If this is a palindrome, then `c_i = c_{N-2-i}` for `0 <= i < N-1`.
        // Since `s` is a palindrome, `c_i = c_{N-1-i}` for `0 <= i < N`.
        // From `c_i = c_{N-2-i}`, we have `c_0 = c_{N-2}`, `c_1 = c_{N-3}`, etc.
        // From `c_i = c_{N-1-i}`, we have `c_0 = c_{N-1}`, `c_1 = c_{N-2}`, etc.
        // Combining these: `c_0 = c_{N-1}` and `c_1 = c_{N-2}`.
        // If `s.substr(0, N-1)` is a palindrome, then `c_0 = c_{N-2}`.
        // Since `s` is a palindrome, `c_1 = c_{N-2}`.
        // This implies `c_0 = c_1`.
        // By induction, if `s.substr(0, N-1)` is a palindrome, then `c_0 = c_1 = ... = c_{N-1}`.
        // This contradicts the assumption that not all characters are the same.
        // Therefore, if not all characters are the same, `s.substr(0, N-1)` is NOT a palindrome.
        //
        // So, if `s.substr(0, N-1)` is not a palindrome, we can make a cut after `s[N-2]`.
        // `s_left = s.substr(0, N-1)` and `s_right = s.substr(N-1, 1)`.
        // `s_prime = s_right + s_left = s[N-1] + s.substr(0, N-1)`.
        // This `s_prime` is a palindrome if `s.substr(0, N-1)` is a palindrome.
        // But we just proved it's not.
        //
        // The logic for k=2 is simpler:
        // If `s` is a palindrome and not all characters are the same,
        // then `s` has at least two distinct characters.
        // Consider `s_prefix = s.substr(0, N/2)`.
        // If `s_prefix` is not a palindrome, then we can cut `s` into `s_prefix`, `s[N/2]`, `s.substr(N/2+1)`.
        // And reorder them.
        //
        // The problem statement implies that if k=1 doesn't work and not all characters are the same,
        // then k=2 is the answer. This is a common pattern in competitive programming problems.
        // The example "nolon" (N=5) confirms this.
        // "nolon" -> "no|l|on". Reorder to "on|l|no". This is a palindrome and not "nolon".
        // This requires 2 cuts.
        //
        // The proof that k=2 is always possible if k=1 fails and not all characters are the same:
        // If k=1 fails, it means for any split `s = A + B`, `B + A` is either `s` or not a palindrome.
        // If not all characters are the same, then `s` contains at least two distinct characters.
        // Consider `s_sub = s.substr(0, N-1)`.
        // As proven above, if `s` is a palindrome and not all characters are the same,
        // then `s_sub` is NOT a palindrome.
        //
        // Let `s = s_0 s_1 ... s_{N-1}`.
        // Consider the string `s' = s_1 s_2 ... s_{N-1} s_0`.
        // This is formed by one cut. If `s'` is a palindrome and `s' != s`, then k=1.
        // If this is not the case for any single cut, then k=2.
        //
        // The problem statement implies that if k=1 doesn't work and not all characters are the same,
        // then k=2 is the answer. This is a common pattern in competitive programming problems.
        // The example "nolon" (N=5) confirms this.
        // "nolon" -> "no|l|on". Reorder to "on|l|no". This is a palindrome and not "nolon".
        // This requires 2 cuts.
        //
        // The logic is:
        // 1. Check for k=1. If found, print 1 and exit.
        // 2. If k=1 not found, check if all characters in `s` are the same.
        // 3. If all characters are the same, print "Impossible".
        // 4. Otherwise (k=1 not found, but not all characters are the same), print 2.
        // This covers all cases.
        std::cout << 2 << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> p(n); // Partition array for the optimal solution
    long long min_goodness = -1;

    // Case 1: All elements in one subsequence (e.g., all in S1)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    if (n >= 2) {
        min_goodness = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
        for (int i = 0; i < n; ++i) {
            p[elements[i].original_index] = 1;
        }
    } else { // n=1, but problem constraints say n >= 2. This branch is technically unreachable.
        min_goodness = 0; // No pairs, so goodness is 0.
        p[elements[0].original_index] = 1;
    }

    // Case 2: At least one element in S1 and at least one in S2.
    // Consider a partition where elements[0] is in S1, and elements[1]...elements[n-1] are in S2.
    // Or elements[0]...elements[n-2] in S1, and elements[n-1] in S2.
    // The most interesting partitions are those that try to minimize the range of sums.
    // This often involves putting the smallest and largest elements strategically.

    // Let's analyze the structure of f values:
    // min_f can be:
    //   - elements[0].value + elements[1].value (if elements[0], elements[1] are in same S)
    //   - elements[0].value + elements[1].value + h (if elements[0], elements[1] are in different S)
    // max_f can be:
    //   - elements[n-1].value + elements[n-2].value (if elements[n-1], elements[n-2] are in same S)
    //   - elements[n-1].value + elements[n-2].value + h (if elements[n-1], elements[n-2] are in different S)

    // The critical observation is that if h is large, we want to avoid pairs in different subsequences.
    // If h is small, we might want to use the +h term to "fill in" gaps or reduce the overall range.

    // Consider the partition where elements[0] is in S1, and all other elements[1...n-1] are in S2.
    // This is a common strategy for minimizing range when h is large.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // Possible f values:
    // 1. Pairs within S1: None (if n=1, but n>=2)
    // 2. Pairs within S2: elements[i].value + elements[j].value for i,j in [1, n-1]
    //    Min sum in S2: elements[1].value + elements[2].value (if n >= 3)
    //    Max sum in S2: elements[n-1].value + elements[n-2].value (if n >= 3)
    // 3. Pairs between S1 and S2: elements[0].value + elements[j].value + h for j in [1, n-1]
    //    Min sum between S1 and S2: elements[0].value + elements[1].value + h
    //    Max sum between S1 and S2: elements[0].value + elements[n-1].value + h

    // Let's calculate goodness for this specific partition:
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    //
    // min_val_f:
    //   If n >= 3: min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //   If n = 2: elements[0].value + elements[1].value + h (only cross-subsequence pairs)
    //
    // max_val_f:
    //   If n >= 3: max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //   If n = 2: elements[0].value + elements[1].value + h (only cross-subsequence pairs)

    if (n >= 2) { // This condition is always true based on constraints
        long long current_min_f, current_max_f;

        if (n == 2) {
            current_min_f = elements[0].value + elements[1].value + h;
            current_max_f = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            long long min_in_S2 = elements[1].value + elements[2].value;
            long long max_in_S2 = elements[n - 1].value + elements[n - 2].value;
            long long min_cross = elements[0].value + elements[1].value + h;
            long long max_cross = elements[0].value + elements[n - 1].value + h;

            current_min_f = std::min(min_in_S2, min_cross);
            current_max_f = std::max(max_in_S2, max_cross);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            p[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                p[elements[i].original_index] = 2;
            }
        }
    }

    // Consider the partition where elements[n-1] is in S1, and all other elements[0...n-2] are in S2.
    // This is symmetric to the previous case.
    // S1 = {elements[n-1]}, S2 = {elements[0], ..., elements[n-2]}
    //
    // min_val_f:
    //   If n >= 3: min(elements[0].value + elements[1].value, elements[n-1].value + elements[0].value + h)
    //   If n = 2: elements[n-1].value + elements[0].value + h
    //
    // max_val_f:
    //   If n >= 3: max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h)
    //   If n = 2: elements[n-1].value + elements[0].value + h

    if (n >= 2) {
        long long current_min_f, current_max_f;

        if (n == 2) {
            current_min_f = elements[0].value + elements[1].value + h;
            current_max_f = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            long long min_in_S2 = elements[0].value + elements[1].value;
            long long max_in_S2 = elements[n - 2].value + elements[n - 3].value;
            long long min_cross = elements[n - 1].value + elements[0].value + h;
            long long max_cross = elements[n - 1].value + elements[n - 2].value + h;

            current_min_f = std::min(min_in_S2, min_cross);
            current_max_f = std::max(max_in_S2, max_cross);
        }

        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            p[elements[n - 1].original_index] = 1;
            for (int i = 0; i < n - 1; ++i) {
                p[elements[i].original_index] = 2;
            }
        }
    }

    // The problem statement implies that the optimal partition is one of these simple cases.
    // The key insight is that the minimum possible sum is always elements[0].value + elements[1].value
    // and the maximum possible sum is always elements[n-1].value + elements[n-2].value.
    // The only question is whether these sums are augmented by 'h'.
    //
    // If we put all elements in one group, min_f = a_0+a_1, max_f = a_{n-1}+a_{n-2}. Goodness = (a_{n-1}+a_{n-2}) - (a_0+a_1).
    //
    // If we put a_0 in S1 and a_1, ..., a_{n-1} in S2:
    // min_f = min(a_1+a_2, a_0+a_1+h)
    // max_f = max(a_{n-1}+a_{n-2}, a_0+a_{n-1}+h)
    //
    // If we put a_{n-1} in S1 and a_0, ..., a_{n-2} in S2:
    // min_f = min(a_0+a_1, a_0+a_{n-1}+h)
    // max_f = max(a_{n-2}+a_{n-3}, a_{n-2}+a_{n-1}+h)
    //
    // The problem is that the minimum and maximum values of f can come from different types of pairs.
    //
    // Let's re-evaluate the goodness for the partition where elements[0] is in S1 and the rest are in S2.
    // This is the most likely optimal partition when h is large.
    //
    // The minimum possible sum of any two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of any two elements is elements[n-1].value + elements[n-2].value.
    //
    // Let A = elements[0].value, B = elements[1].value, C = elements[n-2].value, D = elements[n-1].value.
    //
    // Option 1: All in one group (e.g., all 1s)
    // min_f = A + B
    // max_f = C + D
    // Goodness = (C + D) - (A + B)
    // Partition: all 1s.

    // Option 2: elements[0] in group 1, rest in group 2.
    // S1 = {A}, S2 = {B, ..., C, D}
    //
    // Possible sums:
    //   - A + X + h (where X is from S2)
    //   - Y + Z (where Y, Z are from S2)
    //
    // min_f:
    //   - A + B + h (smallest cross-group sum)
    //   - B + elements[2].value (smallest within S2, if n >= 3)
    //   So, min_f = min(A + B + h, B + elements[2].value) (if n >= 3)
    //   If n = 2, S2 = {B}, no within-S2 pairs. min_f = A + B + h.
    //
    // max_f:
    //   - A + D + h (largest cross-group sum)
    //   - C + D (largest within S2, if n >= 3)
    //   So, max_f = max(A + D + h, C + D) (if n >= 3)
    //   If n = 2, S2 = {B}, no within-S2 pairs. max_f = A + B + h.

    // Let's calculate the goodness for Option 2 more carefully.
    if (n >= 2) {
        long long current_min_f_val, current_max_f_val;
        if (n == 2) {
            current_min_f_val = elements[0].value + elements[1].value + h;
            current_max_f_val = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            current_min_f_val = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
            current_max_f_val = std::max(elements[0].value + elements[n - 1].value + h, elements[n - 1].value + elements[n - 2].value);
        }
        long long current_goodness = current_max_f_val - current_min_f_val;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            p[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                p[elements[i].original_index] = 2;
            }
        }
    }

    // The problem statement implies that the optimal partition is one of these simple cases.
    // The crucial observation is that the minimum possible sum is always elements[0].value + elements[1].value.
    // The maximum possible sum is always elements[n-1].value + elements[n-2].value.
    //
    // Let a_0 = elements[0].value, a_1 = elements[1].value, a_{n-2} = elements[n-2].value, a_{n-1} = elements[n-1].value.
    //
    // Consider the values:
    // X1 = a_0 + a_1
    // X2 = a_0 + a_1 + h
    // X3 = a_0 + a_{n-1} + h
    // X4 = a_{n-2} + a_{n-1}
    //
    // The minimum possible f value is always X1 or X2.
    // The maximum possible f value is always X3 or X4.
    //
    // If all elements are in one group:
    // min_f = X1
    // max_f = X4
    // Goodness = X4 - X1
    // Partition: all 1s.

    // If elements[0] is in S1, and elements[1...n-1] are in S2:
    // min_f = min(X2, a_1 + elements[2].value) (if n >= 3, else X2)
    // max_f = max(X3, X4) (if n >= 3, else X3)
    //
    // The problem is that a_1 + elements[2].value could be smaller than X2.
    // And X4 could be smaller than X3.
    //
    // Let's consider the four critical values:
    // v1 = elements[0].value + elements[1].value
    // v2 = elements[0].value + elements[1].value + h
    // v3 = elements[n-2].value + elements[n-1].value
    // v4 = elements[n-2].value + elements[n-1].value + h
    //
    // And also:
    // v_min_cross = elements[0].value + elements[1].value + h
    // v_max_cross = elements[0].value + elements[n-1].value + h
    //
    // The minimum possible value of f is always elements[0].value + elements[1].value (if they are in the same group)
    // or elements[0].value + elements[1].value + h (if they are in different groups).
    //
    // The maximum possible value of f is always elements[n-1].value + elements[n-2].value (if they are in the same group)
    // or elements[n-1].value + elements[0].value + h (if they are in different groups).
    //
    // Let's consider the two main candidate partitions:
    // 1. All elements in one group (e.g., all 1s).
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    //    This is already handled by the initial `min_goodness` calculation.

    // 2. One element (elements[0]) in group 1, rest in group 2.
    //    S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    //    min_f:
    //      If n=2: elements[0].value + elements[1].value + h
    //      If n>=3: min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    //    max_f:
    //      If n=2: elements[0].value + elements[1].value + h
    //      If n>=3: max(elements[0].value + elements[n-1].value + h, elements[n-1].value + elements[n-2].value)
    //    This is already handled by the second `min_goodness` update.

    // The problem statement and examples suggest these two cases are sufficient.
    // The first example: 3 2, 1 2 3
    // Sorted: 1 2 3. h=2.
    // Option 1 (all 1s):
    //   min_f = 1+2 = 3
    //   max_f = 2+3 = 5
    //   Goodness = 5-3 = 2. Partition: 1 1 1.
    // Option 2 (1 in S1, 2,3 in S2):
    //   S1={1}, S2={2,3}
    //   min_f = min(1+2+2, 2+3) = min(5, 5) = 5
    //   max_f = max(1+3+2, 2+3) = max(6, 5) = 6
    //   Goodness = 6-5 = 1. Partition: 1 2 2.
    // Optimal is 1, partition 1 2 2. This matches the example.

    // The second example: 5 10, 0 1 0 2 1
    // Sorted: 0 0 1 1 2. h=10.
    // Option 1 (all 1s):
    //   min_f = 0+0 = 0
    //   max_f = 1+2 = 3
    //   Goodness = 3-0 = 3. Partition: 1 1 1 1 1.
    // Option 2 (0 in S1, 0,1,1,2 in S2):
    //   S1={0}, S2={0,1,1,2}
    //   min_f = min(0+0+10, 0+1) = min(10, 1) = 1
    //   max_f = max(0+2+10, 1+2) = max(12, 3) = 12
    //   Goodness = 12-1 = 11. Partition: 1 2 2 2 2.
    // Optimal is 3, partition 1 1 1 1 1. This matches the example (after remapping original indices).

    // The logic seems to cover the examples correctly.
    // The crucial part is that the minimum and maximum possible sums are always formed by the smallest two or largest two elements,
    // possibly with 'h' added if they are in different groups.
    // The two partitions considered (all in one group, or smallest element separated) cover the cases where 'h' is small/large.

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

long long calculate_score(int n, const std::string& s) {
    if (n == 0) {
        return 0;
    }
    long long current_score = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (i > 0 && s[i - 1] == 'W') {
                current_score += 2;
            } else {
                current_score += 1;
            }
        }
    }
    return current_score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1LL * n * 2 - 1 << "\n";
            }
            continue;
        }

        // If k is 0, just calculate the initial score
        if (k == 0) {
            std::cout << calculate_score(n, s) << "\n";
            continue;
        }

        // Find segments of 'L's between 'W's
        std::vector<int> l_segment_lengths;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w == -1) { // All games are 'L' initially
            // Change k 'L's to 'W's.
            // The best way is to make them consecutive: WW...WL...L
            // This gives 1 point for the first W, 2 for subsequent Ws.
            // Total: 1 + (k-1)*2 = 2k - 1 points.
            // If k=0, score is 0. If k=1, score is 1.
            std::cout << (k == 0 ? 0 : 2LL * k - 1) << "\n";
            continue;
        }

        // Calculate initial score
        long long current_score = calculate_score(n, s);

        // Collect lengths of 'L' segments between 'W's
        int current_l_count = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_l_count++;
            } else { // s[i] == 'W'
                if (current_l_count > 0) {
                    l_segment_lengths.push_back(current_l_count);
                }
                current_l_count = 0;
            }
        }
        std::sort(l_segment_lengths.begin(), l_segment_lengths.end());

        // Fill 'L' segments between 'W's
        for (int len : l_segment_lengths) {
            if (k >= len) {
                k -= len;
                current_score += 2LL * len + 1; // Each L becomes W, connecting two Ws.
                                                // len 'L's become 'W's.
                                                // Each of these len 'W's gets 2 points.
                                                // The 'W' after the segment now gets 2 points instead of 1.
                                                // The 'W' before the segment already got 2 points if it was part of a chain.
                                                // The change is: len * 2 points for the new Ws, plus 1 point for the W after the segment.
                                                // Example: W LLL W -> W WWW W.
                                                // Original: W(2) L(0) L(0) L(0) W(1) = 3
                                                // New: W(2) W(2) W(2) W(2) W(2) = 10
                                                // Difference: 7. len=3. 2*3+1 = 7. Correct.
            } else {
                break; // Cannot fill this segment
            }
        }

        // Use remaining k to convert 'L's at the ends
        // Each 'L' converted to 'W' at the ends gives 2 points (if adjacent to existing W)
        // or 1 point (if not adjacent to existing W).
        // Since we already have Ws, converting Ls at ends will extend existing W chains.
        // Each L converted to W will give 2 points.
        // Example: LLLWWL -> WWWWWW.
        // Initial: LLLWWL. Score: 3 (W at 3rd index: 1, W at 4th index: 2)
        // k=5.
        // first_w=3, last_w=4. No L-segments between Ws.
        // current_score = 3.
        // k=5.
        // LLL (first_w=3) -> 3 Ls before first W.
        // L (last_w=4) -> 1 L after last W.
        // We have k=5.
        // We can convert 3 Ls before first W. current_score += 2*3 = 6. k=2.
        // We can convert 1 L after last W. current_score += 2*1 = 2. k=1.
        // Total score: 3+6+2 = 11.
        // This logic is: each L converted to W at the ends adds 2 points.

        // L's before first_w
        current_score += std::min(k, first_w) * 2LL;
        k -= std::min(k, first_w);

        // L's after last_w
        current_score += std::min(k, n - 1 - last_w) * 2LL;
        // k -= std::min(k, n - 1 - last_w); // No need to update k further

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
