void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    int has_pos_one = 0; // Flag to check if there's a '1' in a[0...i-1]
    int has_neg_one = 0; // Flag to check if there's a '-1' in a[0...i-1]

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (b[i] > a[i]) { // Need to increase a[i]
                if (!has_pos_one) {
                    possible = false;
                    break;
                }
            } else { // b[i] < a[i], need to decrease a[i]
                if (!has_neg_one) {
                    possible = false;
                    break;
                }
            }
        }

        // Update flags for elements a[i+1], a[i+2], ...
        if (a[i] == 1) {
            has_pos_one = 1;
        } else if (a[i] == -1) {
            has_neg_one = 1;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

