        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_for_i = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_for_i) {
                max_val_for_i = a[i][j];
            }
        }
        // If max_val_for_i is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_for_i.
        // This logic is derived from the observation that if p[i] is not n,
        // then max_{j!=i} min(p[i], p[j]) = p[i] (because there must be some p[j] > p[i]).
        // If p[i] is n, then max_{j!=i} min(p[i], p[j]) = max_{j!=i} p[j] = n-1.
        if (max_val_for_i == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_for_i;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

