int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The median of the first class will be a[n-1]
        // The median of the second class will be a[n]
        // This is because if we sort all 2n elements,
        // to minimize the difference, we want the medians to be as close as possible.
        // The smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2n-1-k].
        //
        // For the specific partition where class 1 takes elements a[0]...a[n-1] and class 2 takes a[n]...a[2n-1],
        // this is not a valid partition because class sizes are n.
        //
        // However, consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick n elements for one class and n elements for the other.
        // The smallest possible median for a class of size 2k+1 is a_k.
        // The largest possible median for a class of size 2k+1 is a_{2n-1-k}.
        //
        // To minimize the difference, we should pick the medians to be adjacent elements in the sorted full array.
        // The elements a[n-1] and a[n] are the two middle elements of the sorted array.
        //
        // Let's say we form class 1 with elements {a_0, a_1, ..., a_{n-1}} and class 2 with {a_n, a_{n+1}, ..., a_{2n-1}}.
        // This is not a valid partition because class sizes are n, which might be even.
        //
        // The problem states that each class must have an odd number of students.
        // Let the sizes be $2k_1+1$ and $2k_2+1$.
        // $2k_1+1 + 2k_2+1 = 2n \implies 2k_1+2k_2+2 = 2n \implies k_1+k_2+1 = n$.
        //
        // The median of a class of size $2k+1$ is its $(k+1)$-th element.
        //
        // Consider the sorted array $a_0, a_1, \dots, a_{2n-1}$.
        // If we pick $a_{n-1}$ as the median of one class and $a_n$ as the median of the other class,
        // can we always form valid classes?
        //
        // To make $a_{n-1}$ the median of a class $C_1$ of size $2k_1+1$:
        // We need to pick $k_1$ elements smaller than or equal to $a_{n-1}$ and $k_1$ elements greater than or equal to $a_{n-1}$.
        // The smallest $k_1$ elements are $a_0, \dots, a_{k_1-1}$.
        // The largest $k_1$ elements are $a_{n-1+1}, \dots, a_{n-1+k_1}$.
        //
        // To make $a_n$ the median of a class $C_2$ of size $2k_2+1$:
        // We need to pick $k_2$ elements smaller than or equal to $a_n$ and $k_2$ elements greater than or equal to $a_n$.
        //
        // The key insight is that after sorting the entire array, the minimum possible difference between the medians
        // of two classes (each of odd size) is achieved when these medians are $a_{n-1}$ and $a_n$.
        //
        // We can always construct such classes.
        // For example, let $C_1$ consist of $a_0, a_1, \dots, a_{n-1}$. This class has $n$ elements.
        // Let $C_2$ consist of $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ elements.
        // If $n$ is odd, then this is a valid partition, and the medians are $a_{(n-1)/2}$ and $a_{n + (n-1)/2}$.
        // This is not what we are looking for.
        //
        // The problem is simpler: after sorting the entire $2n$ elements, $a_0, a_1, \dots, a_{2n-1}$,
        // the $n$-th element (0-indexed $a_{n-1}$) and the $(n+1)$-th element (0-indexed $a_n$)
        // are the two "middle" elements.
        //
        // It can be proven that the minimum possible absolute difference between the medians of two classes,
        // each of odd size, is $|a_n - a_{n-1}|$.
        //
        // Consider any partition into two classes $C_1$ and $C_2$ with odd sizes.
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // When all $2n$ elements are sorted, $a_0 \le a_1 \le \dots \le a_{2n-1}$.
        //
        // The element $a_{n-1}$ must belong to either $C_1$ or $C_2$.
        // The element $a_n$ must belong to either $C_1$ or $C_2$.
        //
        // If $a_{n-1}$ is in $C_1$ and $a_n$ is in $C_2$:
        // $m_1 \le a_{n-1}$ and $m_2 \ge a_n$.
        // Then $|m_1 - m_2| \ge |a_{n-1} - a_n|$.
        //
        // If $a_{n-1}$ and $a_n$ are both in $C_1$:
        // Then $C_2$ must contain $2n - |C_1|$ elements.
        //
        // The crucial observation is that if we sort all $2n$ students' skill levels,
        // $a_0, a_1, \dots, a_{2n-1}$, then the minimum possible difference between the medians
        // of two classes (each of odd size) is simply the difference between the two middle elements: $a_n - a_{n-1}$.
        //
        // This is because we can always construct two classes such that $a_{n-1}$ is the median of one class
        // and $a_n$ is the median of the other.
        // For example, let $C_1$ be $\{a_0, a_1, \dots, a_{n-1}\}$ and $C_2$ be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is not a valid partition if $n$ is even.
        //
        // A valid construction:
        // Class 1: $\{a_0, a_1, \dots, a_{n-1}\}$
        // Class 2: $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$
        // This is not correct.
        //
        // The correct reasoning is:
        // Sort the array: $a_0, a_1, \dots, a_{2n-1}$.
        // We need to pick $2k_1+1$ students for class 1 and $2k_2+1$ students for class 2, where $k_1+k_2 = n-1$.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // We can form a class $C_1$ with $a_{n-1}$ as its median.
        // We can form a class $C_2$ with $a_n$ as its median.
        //
        // For example, let $k_1 = 0$, so $|C_1|=1$. $C_1 = \{a_{n-1}\}$.
        // Then $k_2 = n-1$, so $|C_2|=2(n-1)+1 = 2n-1$.
        // $C_2$ would need $n-1$ elements smaller than $a_n$ and $n-1$ elements larger than $a_n$.
        // We can pick $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This uses $a_0, \dots, a_{n-2}$ (total $n-1$ elements) and $a_{n+1}, \dots, a_{2n-1}$ (total $n-1$ elements).
        // The remaining elements are $a_{n-1}$ and $a_n$.
        // If $C_1 = \{a_{n-1}\}$, then its median is $a_{n-1}$.
        // If $C_2 = \{a_0, \dots, a_{n-2}, a_n, a_{n+1}, \dots, a_{2n-1}\}$, its median is $a_n$.
        // All students are assigned. $C_1$ has 1 student (odd). $C_2$ has $2n-1$ students (odd).
        // The difference is $|a_n - a_{n-1}|$.
        //
        // This construction always works and gives the minimum possible difference.
        // Any other choice of medians would result in a difference greater than or equal to this.
        // If $m_1$ and $m_2$ are the medians of the two classes, then $m_1 \le a_{n-1}$ and $m_2 \ge a_n$ (or vice versa)
        // is not necessarily true.
        //
        // However, it is a known property that for any partition into two sets, if you sort the combined set,
        // the minimum difference between the medians of the two subsets is achieved by taking the two middle elements
        // of the combined sorted set as the medians of the two subsets.
        //
        // The elements $a_{n-1}$ and $a_n$ are the two elements in the middle of the sorted array.
        // The minimum difference is $a_n - a_{n-1}$.
        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

