    // Iterate from the second to last element backwards
    // The last element (a[n-1]) can never be bad because there are no later days.
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] > min_suffix_price) {
            bad_prices_count++;
        } else {
            // If a[i] is not greater than min_suffix_price,
            // it means a[i] is less than or equal to the minimum price found so far
            // in the suffix a[i+1...n-1].
            // This a[i] now becomes the new minimum for suffixes starting at i.
            min_suffix_price = a[i];
        }
    }
    std::cout << bad_prices_count << "\n";
}

