int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed for string, 0-indexed for cells)
                // The previous 'R' or start was at last_r_pos
                // The gap is (i+1) - last_r_pos
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' (or 0 if no 'R's)
        // to the target n+1.
        // The last_r_pos is the cell index of the last 'R' character.
        // The target is s.length() + 1.
        max_gap = std::max(max_gap, (int)s.length() + 1 - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

