int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The number of coders available (each team needs at least one coder).
        // 2. The number of mathematicians available (each team needs at least one mathematician).
        // 3. The total number of students available divided by 3 (each team needs 3 students).
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3
        // Therefore, k <= min(c, m, (c + m + x) / 3)
        // We can binary search for the maximum k, or simply take the minimum of these three upper bounds.
        // The problem asks for the maximum number of teams.
        // Let's denote the number of teams as 'k'.
        // We need 'k' coders and 'k' mathematicians as a minimum.
        // The remaining 'k' slots (3 members per team - 1 coder - 1 mathematician) can be filled by
        // any remaining students: (c - k) coders, (m - k) mathematicians, or 'x' non-specialized students.
        // The total number of students available for these 'k' remaining slots is (c - k) + (m - k) + x.
        // This sum must be at least 'k'.
        // (c - k) + (m - k) + x >= k
        // c + m + x >= 3k
        // k <= (c + m + x) / 3
        // This condition is already covered by the min(c, m, (c + m + x) / 3) logic.
        // So, the maximum number of teams is simply the minimum of these three values.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For subsequent elements
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i > q_{i-1} implies q_i is a new value.
                // But as a safety check.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some unused number less than q_i
            // We need to find the smallest available number that hasn't been used yet.
            // The numbers available are 1 to n.
            // We can use a set to keep track of available numbers.
            // Or, we can iterate from 1 upwards to find the smallest unused number.
            // A more efficient way is to use a separate set for available numbers.
            // Let's use a set of all numbers from 1 to n, and remove used ones.
            // This is done by iterating through 1 to n and adding to a set, then removing used_numbers.
            // Or, we can just find the smallest number not in used_numbers.
            // The problem states p_i must be distinct and between 1 and n.
            // And p_i <= q_i.
            // Since q_i == q_{i-1}, p_i must be < q_i.
            // We need to find the smallest number `x` such that `1 <= x < q_i` and `x` is not in `used_numbers`.

            // Let's find the smallest available number.
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) { // q[i] is the current prefix maximum
                // If the smallest available number is greater than or equal to q[i],
                // then we cannot pick a p_i such that p_i < q_i.
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

