    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[i] > a[i+1]
    int suffix_start_idx = n - 1;
    while (suffix_start_idx > 0 && a[suffix_start_idx - 1] >= a[suffix_start_idx]) {
        suffix_start_idx--;
    }

    // Now, a[suffix_start_idx ... n-1] is a non-increasing suffix.
    // We need to find the rightmost peak of a non-decreasing suffix
    // starting from suffix_start_idx.
    // This is the first element from the right (starting from suffix_start_idx)
    // that breaks the non-decreasing order.
    // i.e., a[i] < a[i+1]
    int prefix_end_idx = suffix_start_idx;
    while (prefix_end_idx > 0 && a[prefix_end_idx - 1] <= a[prefix_end_idx]) {
        prefix_end_idx--;
    }

    std::cout << prefix_end_idx << std::endl;
}

