    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we extend the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' must be at pos[m].
        // We need to expand the segment [current_min_idx, current_max_idx]
        // to include pos[m].
        // The new segment will be [min(current_min_idx, pos[m]), max(current_max_idx, pos[m])].
        // We update current_min_idx and current_max_idx to reflect this.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if there exists a subsegment [l, r]
        // such that it contains numbers 1 to m, and its length is m.
        // The current segment [current_min_idx, current_max_idx]
        // by construction contains all numbers from 1 to m.
        // Its length is (current_max_idx - current_min_idx + 1).
        // If this length is equal to m, then 'm' is beautiful.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i-1] < p[i] and p[i] > p[i+1] (local maximum)
        // OR
        // p[i-1] > p[i] and p[i] < p[i+1] (local minimum)
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << "\n";
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

