}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long total_cost = 0;
    int prev_diff_01 = -1; // Index of the last '0' in a that needs to be '1' in b
    int prev_diff_10 = -1; // Index of the last '1' in a that needs to be '0' in b

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (prev_diff_10 != -1) { // Found a '1' in a that needs to be '0' in b
                    // We can swap a[prev_diff_10] and a[i]
                    // a[prev_diff_10] was '1', needs '0'
                    // a[i] was '0', needs '1'
                    // After swap: a[prev_diff_10] becomes '0', a[i] becomes '1'
                    // Both are fixed. Cost is (i - prev_diff_10).
                    total_cost += (i - prev_diff_10);
                    prev_diff_10 = -1; // This '10' mismatch is resolved
                    prev_diff_01 = -1; // This '01' mismatch is resolved
                } else {
                    // No '10' mismatch to pair with. This '01' mismatch is pending.
                    prev_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (prev_diff_01 != -1) { // Found a '0' in a that needs to be '1' in b
                    // We can swap a[prev_diff_01] and a[i]
                    // a[prev_diff_01] was '0', needs '1'
                    // a[i] was '1', needs '0'
                    // After swap: a[prev_diff_01] becomes '1', a[i] becomes '0'
                    // Both are fixed. Cost is (i - prev_diff_01).
                    total_cost += (i - prev_diff_01);
                    prev_diff_01 = -1; // This '01' mismatch is resolved
                    prev_diff_10 = -1; // This '10' mismatch is resolved
                } else {
                    // No '01' mismatch to pair with. This '10' mismatch is pending.
                    prev_diff_10 = i;
                }
            }
        } else { // a[i] == b[i]
            // If there's a pending mismatch, it cannot be resolved by swapping with a[i]
            // because a[i] is already correct. So, any pending mismatch must be flipped.
            if (prev_diff_01 != -1) {
                total_cost += 1; // Flip a[prev_diff_01]
                prev_diff_01 = -1;
            }
            if (prev_diff_10 != -1) {
                total_cost += 1; // Flip a[prev_diff_10]
                prev_diff_10 = -1;
            }
        }
    }

    // After iterating through the entire string, any remaining pending mismatches must be flipped.
    if (prev_diff_01 != -1) {
        total_cost += 1;
    }
    if (prev_diff_10 != -1) {
        total_cost += 1;
    }

    std::cout << total_cost << std::endl;

    return 0;
}

#include <iostream>
