int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[i] <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i], advance right_ptr until x[right_ptr] - x[i] > d
        // or right_ptr reaches the end of the array.
        // All points from x[i+1] to x[right_ptr-1] satisfy the condition with x[i].
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }

        // Now, all points x[k] such that i < k < right_ptr satisfy x[k] - x[i] <= d.
        // We need to choose two distinct points x[j] and x[k] from this range (i+1 to right_ptr-1).
        // The number of available points is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

