// Function to check if a box can be the special box
// Parameters:
// A, B, C, D: initial counts of toys in boxes 1, 2, 3, 4
// target_box: the box we are checking (1, 2, 3, or 4)
//
// The logic is based on analyzing the parity of negative numbers and the count of numbers with magnitude >= 1.
//
// Let N_neg be the count of toys with negative fun values (from boxes 1 and 2).
// Let N_mag_ge1 be the count of toys with magnitude >= 1 (from boxes 1 and 4).
//
// The final product's sign depends on the parity of N_neg.
// The final product's magnitude relative to 1 depends on N_mag_ge1.
//
// If N_mag_ge1 is 0, the final product's magnitude will be < 1 (unless all initial toys are 0, which is not allowed as fun values are real numbers in specific ranges).
// If N_mag_ge1 is 1, the final product's magnitude can be < 1 or >= 1.
// If N_mag_ge1 is > 1, the final product's magnitude can be < 1 or >= 1.
//
// This simplified view is not enough. We need to consider the *parity* of N_mag_ge1 for certain scenarios.
//
// Let's refine the state:
// `neg_count`: number of toys with negative fun values (initially A + B)
// `ge1_count`: number of toys with magnitude >= 1 (initially A + D)
// `total_toys`: total number of toys (initially A + B + C + D)
//
// The process involves reducing `total_toys` by 1 in each step.
//
// Box 1: $(-\infty, -1]$ (Negative, Magnitude >= 1)
// Box 2: $(-1, 0)$ (Negative, Magnitude < 1)
// Box 3: $(0, 1)$ (Positive, Magnitude < 1)
// Box 4: $[1, \infty)$ (Positive, Magnitude >= 1)

bool can_be_special_box(long long A, long long B, long long C, long long D, int target_box) {
    long long total_toys = A + B + C + D;

    if (total_toys == 1) {
        if (A == 1 && target_box == 1) return true;
        if (B == 1 && target_box == 2) return true;
        if (C == 1 && target_box == 3) return true;
        if (D == 1 && target_box == 4) return true;
        return false;
    }

    // Calculate initial counts for negative and magnitude >= 1
    long long initial_neg_count = A + B;
    long long initial_ge1_count = A + D;

    // Box 1: Negative, Magnitude >= 1
    if (target_box == 1) {
        // To get a negative result, initial_neg_count must be odd.
        // If initial_neg_count is even, we can always make it odd by pairing up negatives.
        // If initial_neg_count is odd, it will remain odd.
        // So, we need initial_neg_count to be odd.
        if (initial_neg_count % 2 == 0) { // If even, we can't guarantee odd final product
            // Exception: If there are no negative numbers, it's impossible.
            if (initial_neg_count == 0) return false;
            // If initial_neg_count is even and > 0, we can make it odd if we have at least one positive number to pair with a negative.
            // Or, if we have at least two negative numbers, we can pair them to make a positive, reducing neg_count by 2.
            // This means if initial_neg_count is even, the final product will be positive.
            // So, if initial_neg_count is even, Box 1 is impossible.
            return false;
        }

        // To get magnitude >= 1:
        // If initial_ge1_count is 0: impossible to get >= 1.
        if (initial_ge1_count == 0) return false;
        // If initial_ge1_count is 1:
        //   If the single ge1 toy is negative (A=1, D=0), and initial_neg_count is odd (A=1, B=even),
        //   we can make it negative and >=1.
        //   If the single ge1 toy is positive (A=0, D=1), and initial_neg_count is odd (B=odd),
        //   we can make it negative and >=1.
        //   In general, if initial_ge1_count is 1, we can make the final product >= 1 or < 1.
        //   We can choose to make it >= 1.
        // If initial_ge1_count > 1:
        //   We can always make the final product >= 1.
        //   Example: keep multiplying ge1 numbers together.
        return true;
    }

    // Box 2: Negative, Magnitude < 1
    if (target_box == 2) {
        // To get a negative result, initial_neg_count must be odd.
        if (initial_neg_count % 2 == 0) {
            return false;
        }

        // To get magnitude < 1:
        // If initial_ge1_count is 0: always magnitude < 1.
        if (initial_ge1_count == 0) return true;
        // If initial_ge1_count is 1:
        //   We can make the final product magnitude < 1 by multiplying the single ge1 toy with many <1 toys.
        //   Example: -3 * 0.1 * 0.1 = -0.03.
        if (initial_ge1_count == 1) return true;
        // If initial_ge1_count > 1:
        //   We can make the final product magnitude < 1.
        //   Example: -3 * -2 * 0.1 * 0.1 = 0.06.
        //   We need to ensure we can get a negative result.
        //   If initial_neg_count is odd, we can always get a negative result.
        //   If initial_ge1_count > 1, we can always make the magnitude < 1 by multiplying with enough <1 toys.
        //   The only constraint is if we have enough <1 toys.
        //   Total toys with magnitude < 1 is B + C.
        //   If B + C == 0, and initial_ge1_count > 0, then the magnitude will always be >= 1.
        //   So, if B + C == 0, and initial_ge1_count > 0, then Box 2 is impossible.
        if (B + C == 0) return false; // All toys have magnitude >= 1, so final product will have magnitude >= 1.
        return true;
    }

    // Box 3: Positive, Magnitude < 1
    if (target_box == 3) {
        // To get a positive result, initial_neg_count must be even.
        if (initial_neg_count % 2 != 0) {
            return false;
        }

        // To get magnitude < 1:
        // If initial_ge1_count is 0: always magnitude < 1.
        if (initial_ge1_count == 0) return true;
        // If initial_ge1_count is 1:
        //   We can make the final product magnitude < 1.
        if (initial_ge1_count == 1) return true;
        // If initial_ge1_count > 1:
        //   We can make the final product magnitude < 1.
        //   The only constraint is if we have enough <1 toys.
        //   If B + C == 0, and initial_ge1_count > 0, then the magnitude will always be >= 1.
        //   So, if B + C == 0, and initial_ge1_count > 0, then Box 3 is impossible.
        if (B + C == 0) return false;
        return true;
    }

    // Box 4: Positive, Magnitude >= 1
    if (target_box == 4) {
        // To get a positive result, initial_neg_count must be even.
        if (initial_neg_count % 2 != 0) {
            return false;
        }

        // To get magnitude >= 1:
        // If initial_ge1_count is 0: impossible to get >= 1.
        if (initial_ge1_count == 0) return false;
        // If initial_ge1_count is 1:
        //   We can make the final product magnitude >= 1.
        if (initial_ge1_count == 1) return true;
        // If initial_ge1_count > 1:
        //   We can always make the final product magnitude >= 1.
        return true;
    }

    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::string result[4];
        for (int i = 0; i < 4; ++i) {
            if (can_be_special_box(A, B, C, D, i + 1)) {
                result[i] = "Ya";
            } else {
                result[i] = "Tidak";
            }
        }
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
    }

    return 0;
}

