struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // The optimal strategy is to pair the smallest A_i with the smallest B_i,
    // the second smallest A_i with the second smallest B_i, and so on.
    // This is because F(n, k) = n / (k+1).
    // We want to maximize sum(A_i' / (B_i + 1)).
    // To maximize sum(x_i / y_i), where x_i are elements of A and y_i are elements of B+1,
    // we should sort x_i in ascending order and y_i in ascending order, then pair them.
    // This is a known rearrangement inequality property for sums of ratios.
    // Specifically, if a_1 <= a_2 <= ... <= a_m and b_1 <= b_2 <= ... <= b_m,
    // then sum(a_i / b_i) is maximized when a_i is paired with b_i.

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // The sorted a_elements[i].value should be assigned to the original position of b_elements[i].value
    // This means if b_elements[i] was originally at index `b_elements[i].original_index`,
    // then result_a_prime[b_elements[i].original_index] should be a_elements[i].value.
    for (int i = 0; i < m; ++i) {
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int current_score = 0;
        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
                if (i > 0 && s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        if (k == 0) {
            std::cout << current_score << "\n";
            continue;
        }

        if (initial_wins == 0) { // All 'L's
            std::cout << std::max(0, 1 + 2 * (std::min(n, k) - 1)) << "\n";
            continue;
        }

        // Case 1: Fill gaps between existing 'W's
        std::vector<int> gap_lengths;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gap_lengths.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gap_lengths.begin(), gap_lengths.end());

        int changes_used = 0;
        for (int gap_len : gap_lengths) {
            if (changes_used + gap_len <= k) {
                changes_used += gap_len;
                current_score += 2 * gap_len; // Each 'L' in a gap becomes 'W', connecting two 'W's
            } else {
                break;
            }
        }

        // Case 2: Convert 'L's to 'W's at the ends or remaining 'L's
        int remaining_k = k - changes_used;
        int new_wins_from_L = 0;

        // Convert 'L's before the first 'W'
        int L_before_first_W = first_W;
        new_wins_from_L += std::min(L_before_first_W, remaining_k);
        remaining_k -= std::min(L_before_first_W, remaining_k);

        // Convert 'L's after the last 'W'
        int L_after_last_W = n - 1 - last_W;
        new_wins_from_L += std::min(L_after_last_W, remaining_k);
        remaining_k -= std::min(L_after_last_W, remaining_k);

        // Any remaining k can be used to convert 'L's within gaps that were not fully filled
        // or any other 'L's. Each such conversion adds 1 point.
        new_wins_from_L += remaining_k;

        current_score += new_wins_from_L;

        std::cout << current_score << "\n";
    }
    return 0;
}

