// Function to check if a sub-array is a permutation
// `arr` is the original array
// `start_idx` is the starting index of the sub-array
// `len` is the length of the sub-array
// `max_val_expected` is the maximum value expected in the permutation (which is `len`)
bool is_permutation(const std::vector<int>& arr, int start_idx, int len, int max_val_expected) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    if (len > arr.size() - start_idx) {
        return false; // Sub-array length exceeds available elements
    }

    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for values 1 to len
    int current_max = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate found
        }
        seen[val] = true;
        if (val > current_max) {
            current_max = val;
        }
    }

    // After checking all elements, ensure current_max matches expected max
    // and all numbers from 1 to len were seen.
    // The `seen` array check (val < 1 || val > len || seen[val]) already covers
    // that all numbers are within range and distinct.
    // The `current_max == len` check ensures that the maximum value is indeed `len`.
    // If all numbers from 1 to `len` are present and distinct, the max must be `len`.
    // So, `current_max == len` is a sufficient check after the `seen` array logic.
    return current_max == max_val_expected;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i-1], a[i]);
    }

    // Precompute suffix maximums
    std::vector<int> suffix_max(n);
    suffix_max[n-1] = a[n-1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i+1], a[i]);
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if the first l1 elements form a permutation of length l1
        // The maximum value in the first l1 elements must be l1.
        // This is a necessary condition.
        if (prefix_max[l1-1] != l1) {
            continue;
        }

        // Check if the last l2 elements form a permutation of length l2
        // The maximum value in the last l2 elements must be l2.
        // This is a necessary condition.
        if (suffix_max[l1] != l2) { // suffix_max[l1] is max of a[l1...n-1]
            continue;
        }

        // If both necessary conditions (max values) are met,
        // perform the full permutation check for both parts.
        bool p1_is_perm = is_permutation(a, 0, l1, l1);
        bool p2_is_perm = is_permutation(a, l1, l2, l2);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

