int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // Friends who get w_i = 1 integer
        // These friends should get the largest available numbers, and their happiness is 2 * number.
        // We assign them the largest numbers from 'a'.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_ptr_right] * 2;
                a_ptr_right--;
            } else {
                // Since w is sorted, all remaining w[i] will be > 1.
                // We can break here and process them in the next loop.
                break;
            }
        }

        // Friends who get w_i > 1 integers
        // These friends should get the largest available number as their max,
        // and the smallest available number as their min.
        // To maximize sum of happiness, we give the largest remaining numbers to be their max.
        // And the smallest remaining numbers to be their min.
        // The friends with larger w_i values will consume more small numbers.
        // So, assign largest w_i to consume smallest numbers.
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;
                total_happiness += a[a_ptr_left];   // Min value for this friend
                a_ptr_left += (w[i] - 1); // Consume w[i]-1 smallest numbers
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

