#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    // Strategy:
    // If N is odd, Chanek must take 1. N becomes even.
    // If N is even:
    //   If N is a power of 2 (and not 2 itself), Chanek takes N/2.
    //   If N is even but not a power of 2, Chanek takes N/2.
    //   The only exception is N=2, where taking 1 is optimal for Chanek.

    // Let's re-evaluate the optimal strategy.
    // The game is about splitting N into two piles for Chanek and Opponent.
    // Chanek wants to maximize his pile, Opponent wants to maximize theirs.
    // This is a typical minimax game.

    // Consider the total sum of coins taken by Chanek and Opponent.
    // It's always N.
    // Chanek wants to maximize C, Opponent wants to maximize O.
    // C + O = N.
    // If Chanek maximizes C, he implicitly minimizes O.
    // If Opponent maximizes O, they implicitly minimize C.

    // Let's simulate the game with a greedy approach for both players.
    // At each step, a player wants to take as many coins as possible.
    // If N is even, they can take N/2. If N is odd, they can only take 1.
    // Taking N/2 is always better than taking 1 if N/2 > 1.
    // N/2 > 1 implies N > 2.

    // Case 1: N is odd.
    // Chanek must take 1. N becomes N-1 (even). Chanek gets 1.
    // Now it's Opponent's turn with N-1 coins.

    // Case 2: N is even.
    // Chanek can take N/2 or 1.
    // If Chanek takes N/2: N becomes N/2. Chanek gets N/2.
    // If Chanek takes 1: N becomes N-1 (odd). Chanek gets 1.

    // Let's trace the game with the assumption that players always try to take N/2 if possible,
    // otherwise take 1. This is the "greedy" strategy.

    // Example N=5:
    // Chanek's turn, N=5 (odd). Chanek takes 1. Chanek_coins = 1. N=4.
    // Opponent's turn, N=4 (even). Opponent takes 4/2=2. Opponent_coins = 2. N=2.
    // Chanek's turn, N=2 (even). Chanek takes 2/2=1. Chanek_coins = 1+1=2. N=1.
    // Opponent's turn, N=1 (odd). Opponent takes 1. Opponent_coins = 2+1=3. N=0.
    // Result: Chanek 2, Opponent 3. Total 5. This matches example.

    // Example N=6:
    // Chanek's turn, N=6 (even). Chanek takes 6/2=3. Chanek_coins = 3. N=3.
    // Opponent's turn, N=3 (odd). Opponent takes 1. Opponent_coins = 1. N=2.
    // Chanek's turn, N=2 (even). Chanek takes 2/2=1. Chanek_coins = 3+1=4. N=1.
    // Opponent's turn, N=1 (odd). Opponent takes 1. Opponent_coins = 1+1=2. N=0.
    // Result: Chanek 4, Opponent 2. Total 6. This matches example.

    // It seems the greedy strategy (take N/2 if even, else 1) is optimal for both players.
    // Let's verify this.
    // If N is odd, a player *must* take 1. There's no other choice.
    // If N is even, a player can take N/2 or 1.
    //   Taking N/2 leaves N/2 coins for the next player.
    //   Taking 1 leaves N-1 coins for the next player.
    // A player wants to maximize their current take AND minimize what the opponent gets.
    // Taking N/2 is generally better for the current player as it gives them more coins.
    // It also leaves a smaller pile for the opponent (N/2 vs N-1).
    // The only exception is if N/2 is very small, e.g., N=2.
    // If N=2:
    //   Take N/2=1. Leaves 1. Current player gets 1.
    //   Take 1. Leaves 1. Current player gets 1.
    // In this specific case, both moves yield the same immediate result and same remaining coins.

    // Let's consider the case where N is a power of 2, say N = 2^k.
    // If Chanek takes N/2, N becomes 2^(k-1). Chanek gets 2^(k-1).
    // If Chanek takes 1, N becomes 2^k - 1 (odd). Chanek gets 1.
    // If Chanek takes 1, the opponent faces an odd number. Opponent takes 1. N becomes 2^k - 2.
    // This seems to be a complex minimax.

    // Let's analyze the structure of the game.
    // If N is odd, Chanek takes 1. N becomes even.
    // If N is even:
    //   If N is a power of 2 (N = 2^k, k >= 1):
    //     Chanek takes N/2. N becomes N/2. Chanek gets N/2.
    //     Now Opponent faces N/2, which is also a power of 2.
    //     This continues until N=2.
    //     Example N=8:
    //     C: take 4. N=4. C_coins=4.
    //     O: take 2. N=2. O_coins=2.
    //     C: take 1. N=1. C_coins=4+1=5.
    //     O: take 1. N=0. O_coins=2+1=3.
    //     Chanek gets 5.
    //     What if Chanek took 1 at N=8?
    //     C: take 1. N=7. C_coins=1.
    //     O: take 1. N=6. O_coins=1.
    //     C: take 3. N=3. C_coins=1+3=4.
    //     O: take 1. N=2. O_coins=1+1=2.
    //     C: take 1. N=1. C_coins=4+1=5.
    //     O: take 1. N=0. O_coins=2+1=3.
    //     Chanek gets 5.
    //     It seems for powers of 2, taking N/2 is optimal.

    //   If N is even but not a power of 2:
    //     N = 2^k * M, where M is odd and M > 1.
    //     Chanek takes N/2. N becomes N/2. Chanek gets N/2.
    //     Now Opponent faces N/2.
    //     Example N=6:
    //     C: take 3. N=3. C_coins=3.
    //     O: take 1. N=2. O_coins=1.
    //     C: take 1. N=1. C_coins=3+1=4.
    //     O: take 1. N=0. O_coins=1+1=2.
    //     Chanek gets 4.
    //     What if Chanek took 1 at N=6?
    //     C: take 1. N=5. C_coins=1.
    //     O: take 1. N=4. O_coins=1.
    //     C: take 2. N=2. C_coins=1+2=3.
    //     O: take 1. N=1. O_coins=1+1=2.
    //     C: take 1. N=0. C_coins=3+1=4.
    //     Chanek gets 4.

    // It seems the greedy strategy (take N/2 if even, else 1) is indeed optimal for both players.
    // Let's implement this.

    bool chanek_turn = true;
    while (n > 0) {
        if (n % 2 != 0) { // N is odd
            if (chanek_turn) {
                chanek_coins += 1;
            }
            n -= 1;
        } else { // N is even
            // If N is 2, taking 1 or N/2=1 yields the same result.
            // If N > 2, taking N/2 is strictly better than taking 1 for the current player.
            // And it leaves a smaller number of coins for the opponent (N/2 vs N-1).
            // So, the current player will always take N/2 if N is even and N > 2.
            // If N=2, taking 1 is also an option.
            // Let's check if taking 1 is ever better for the current player when N is even and N > 2.
            // Suppose N is even and N > 2.
            // Option A: Take N/2. Current player gets N/2. Next player faces N/2.
            // Option B: Take 1. Current player gets 1. Next player faces N-1 (odd).
            // The next player will take 1 from N-1, leaving N-2 (even).
            // This seems like a standard game theory problem where the greedy choice is optimal.
            // The only edge case is N=2.
            if (n == 2) {
                if (chanek_turn) {
                    chanek_coins += 1;
                }
                n -= 1; // Or n /= 2; both result in n=1
            } else {
                if (chanek_turn) {
                    chanek_coins += n / 2;
                }
                n /= 2;
            }
        }
        chanek_turn = !chanek_turn;
    }

    return chanek_coins;
}

