void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need S' = 2 * X'
    // If current_sum == 2 * current_xor_sum, array is already good.
    // We can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // Strategy: Append two elements.
    // Let the two elements be x and y.
    // New sum S' = current_sum + x + y
    // New XOR sum X' = current_xor_sum ^ x ^ y
    // We want current_sum + x + y = 2 * (current_xor_sum ^ x ^ y)

    // Let's try to make x = current_xor_sum.
    // Then X' = current_xor_sum ^ current_xor_sum ^ y = y.
    // The equation becomes: current_sum + current_xor_sum + y = 2 * y
    // current_sum + current_xor_sum = y
    // So, y = current_sum + current_xor_sum.

    // Let x = current_xor_sum
    // Let y = current_sum + current_xor_sum
    //
    // New XOR sum: X' = current_xor_sum ^ x ^ y
    //                 = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
    //                 = 0 ^ (current_sum + current_xor_sum)
    //                 = current_sum + current_xor_sum
    //
    // New sum: S' = current_sum + x + y
    //             = current_sum + current_xor_sum + (current_sum + current_xor_sum)
    //             = 2 * (current_sum + current_xor_sum)
    //
    // Check condition: S' = 2 * X'
    // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
    // This holds true.

    // The two elements to append are current_xor_sum and (current_sum + current_xor_sum).
    // These are non-negative since all initial a_i are non-negative.
    // The maximum value for a_i is 10^9.
    // Max n is 10^5.
    // Max current_sum is 10^5 * 10^9 = 10^14.
    // Max current_xor_sum is less than 2^30 (since 10^9 < 2^30).
    // So, current_sum + current_xor_sum can be up to approx 10^14.
    // This fits in a long long.
    // The problem states appended elements can be up to 10^18, so this is fine.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

