int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_operations = 0;
    int correct_initial_nestings = 0;
    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }
        if (chain[0] == 1) { // This chain starts with 1
            for (int j = 0; j < m - 1; ++j) {
                if (chain[j] + 1 == chain[j+1]) {
                    correct_initial_nestings++;
                } else {
                    break; // Chain is broken, subsequent elements won't be correct
                }
            }
        }
    }

    // Total operations needed to achieve the final state:
    // 1. Disassemble all existing chains: sum(m_i - 1) operations.
    //    This is equivalent to (n - k) operations.
    // 2. Assemble the final chain: (n - 1) operations.
    // Total = (n - k) + (n - 1)
    //
    // However, we can save operations if parts of the target chain 1->2->...->n
    // already exist in the initial configuration.
    //
    // The number of operations saved is 2 * (number of correct consecutive nestings starting from 1).
    // Each correct nesting (i, i+1) that is part of the 1->2->...->n chain
    // saves 1 disassembly operation and 1 assembly operation.
    //
    // So, total operations = (n - k) + (n - 1) - 2 * correct_initial_nestings
    //
    // Let's re-evaluate:
    // Total dolls = n
    // Total chains = k
    //
    // Operations to disassemble all chains into individual dolls:
    // Each chain of length m_i has m_i - 1 nestings.
    // Total nestings across all chains = sum(m_i - 1) = sum(m_i) - sum(1) = n - k.
    // So, n - k operations to disassemble everything.
    //
    // Operations to assemble the final 1->2->...->n chain:
    // This requires n - 1 nesting operations.
    //
    // Total operations if we disassemble everything and then reassemble:
    // (n - k) + (n - 1)
    //
    // Now, consider the savings.
    // If we have a segment 1 -> 2 -> ... -> X in one of the initial chains,
    // where X is the largest number such that 1, 2, ..., X are consecutive and nested correctly.
    // This segment has X-1 correct nestings.
    //
    // For each such correct nesting (i, i+1) where i < X:
    // - We don't need to disassemble doll i from doll i+1. (Saves 1 operation)
    // - We don't need to assemble doll i into doll i+1. (Saves 1 operation)
    // So, each correct_initial_nestings saves 2 operations.
    //
    // The number of operations saved is 2 * correct_initial_nestings.
    //
    // Final formula: (n - k) + (n - 1) - 2 * correct_initial_nestings
    //
    // Example 1: n=3, k=2. Chains: 2 1 2; 1 3.
    // correct_initial_nestings:
    // Chain 1: 1 -> 2. This is correct. correct_initial_nestings = 1.
    // Chain 2: 3. No nestings.
    // Total correct_initial_nestings = 1.
    //
    // Operations = (3 - 2) + (3 - 1) - 2 * 1
    //            = 1 + 2 - 2
    //            = 1. Correct.
    //
    // Example 2: n=7, k=3. Chains: 3 1 3 7; 2 2 5; 2 4 6.
    // correct_initial_nestings:
    // Chain 1: 1 -> 3 -> 7.
    //   1 -> 3 is not 1 -> 2. So, 0 correct nestings from 1.
    // Chain 2: 2 -> 5.
    //   Does not start with 1. 0 correct nestings from 1.
    // Chain 3: 4 -> 6.
    //   Does not start with 1. 0 correct nestings from 1.
    // Total correct_initial_nestings = 0.
    //
    // Operations = (7 - 3) + (7 - 1) - 2 * 0
    //            = 4 + 6 - 0
    //            = 10. Correct.

    total_operations = (long long)(n - k) + (n - 1) - (2LL * correct_initial_nestings);

    std::cout << total_operations << std::endl;

    return 0;
}

