// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // The strategy is to remove just enough factors from p to make it not divisible by q.
        // To maximize x, we should remove as few factors as possible, and specifically,
        // remove factors that are "small" relative to the overall value of p.

        // Let q = f1^a1 * f2^a2 * ... * fk^ak be the prime factorization of q.
        // If p is divisible by q, then p must contain at least f1^a1, f2^a2, etc.
        // To make x not divisible by q, we must ensure that for at least one fi,
        // the power of fi in x is less than ai.
        // To maximize x, we should try to achieve this by reducing the power of only one fi,
        // and by reducing it as little as possible.
        // Specifically, for each prime factor fi of q, we can form a candidate x_i by
        // dividing p by fi repeatedly until it's no longer divisible by q.
        // The largest such x_i will be our answer.

        std::map<long long, int> q_factors = get_prime_factors(q);
        long long max_x = 1;

        for (auto const& [factor, exponent] : q_factors) {
            long long current_p = p;
            // Divide current_p by 'factor' until it's no longer divisible by q.
            // Or, more precisely, divide current_p by 'factor' until the power of 'factor'
            // in current_p is less than its power in q.
            // Since p is divisible by q, p has at least 'exponent' powers of 'factor'.
            // We need to remove at least one 'factor' from p to potentially break divisibility by q.
            // To maximize x, we should remove as few 'factor's as possible.
            // The smallest number of 'factor's to remove is such that current_p / (factor^k) is not divisible by q.
            // This means we need to find the largest k such that (p / factor^k) % q != 0.
            // Or, equivalently, find the smallest k such that (p / factor^k) % q != 0.
            // We can iterate through possible powers of 'factor' to remove.
            // Let p = P * factor^A and q = Q * factor^B, where P and Q are not divisible by factor.
            // Since p % q == 0, we know A >= B.
            // We want x = p / factor^k such that x % q != 0.
            // This means (P * factor^(A-k)) % (Q * factor^B) != 0.
            // This condition is met if A-k < B.
            // So we need k > A-B. The smallest integer k is A-B+1.
            // Thus, we should divide p by factor^(A-B+1).
            // A is the count of 'factor' in p.
            // B is the count of 'factor' in q (which is 'exponent').

            long long p_factor_count = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % factor == 0) {
                p_factor_count++;
                temp_p /= factor;
            }

            long long num_factors_to_remove = p_factor_count - exponent + 1;

            long long candidate_x = p;
            for (int i = 0; i < num_factors_to_remove; ++i) {
                candidate_x /= factor;
            }
            max_x = std::max(max_x, candidate_x);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

