void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    int split_digit = -1; // The digit where we transition from color 1 to color 2

    // Try to find a split_digit from 0 to 9
    for (int k = 0; k <= 9; ++k) {
        std::string current_result(n, ' ');
        char last1 = '0' - 1; // Represents a value smaller than any digit
        char last2 = '0' - 1; // Represents a value smaller than any digit
        bool possible = true;

        for (int i = 0; i < n; ++i) {
            char digit = s[i];

            // Option 1: Color 1
            // Can we color it 1? Yes, if digit >= last1 AND digit <= k
            bool can_color1 = (digit >= last1) && (digit <= (char)('0' + k));

            // Option 2: Color 2
            // Can we color it 2? Yes, if digit >= last2 AND digit >= k
            bool can_color2 = (digit >= last2) && (digit >= (char)('0' + k));

            if (can_color1 && can_color2) {
                // If both are possible, prioritize coloring 1 if digit < k
                // This ensures that digits smaller than k are colored 1 if possible,
                // and digits larger than k are colored 2 if possible.
                // If digit == k, either choice is fine for the split point.
                if (digit == (char)('0' + k)) {
                    // If current digit is k, and it can go to either,
                    // we prefer to put it in color 1 if last1 is smaller than k,
                    // or in color 2 if last2 is smaller than k.
                    // A simpler heuristic: if it's k, and can go to 1, put it in 1.
                    // This ensures that all k's that can be in S1 are in S1.
                    current_result[i] = '1';
                    last1 = digit;
                } else if (digit < (char)('0' + k)) { // Must be colored 1
                    current_result[i] = '1';
                    last1 = digit;
                } else { // Must be colored 2
                    current_result[i] = '2';
                    last2 = digit;
                }
            } else if (can_color1) {
                current_result[i] = '1';
                last1 = digit;
            } else if (can_color2) {
                current_result[i] = '2';
                last2 = digit;
            } else {
                possible = false;
                break;
            }
        }

        if (possible) {
            std::cout << current_result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

