#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_pattern(k, '?');
    bool possible = true;

    // Step 1: Determine the fixed pattern for s[i] and s[i+k]
    for (int i = 0; i < n; ++i) {
        char current_char = s[i];
        int pattern_idx = i % k;

        if (current_char == '?') {
            // No new information for this position in the pattern
            continue;
        }

        if (fixed_pattern[pattern_idx] == '?') {
            fixed_pattern[pattern_idx] = current_char;
        } else if (fixed_pattern[pattern_idx] != current_char) {
            // Conflict: s[i] and s[j] where i % k == j % k are different
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check if the fixed pattern itself can be k-balanced
    // Count '0's, '1's, and '?'s in the fixed pattern
    int zeros_in_pattern = 0;
    int ones_in_pattern = 0;
    int question_marks_in_pattern = 0;

    for (int i = 0; i < k; ++i) {
        if (fixed_pattern[i] == '0') {
            zeros_in_pattern++;
        } else if (fixed_pattern[i] == '1') {
            ones_in_pattern++;
        } else { // fixed_pattern[i] == '?'
            question_marks_in_pattern++;
        }
    }

    // The number of '0's and '1's must be exactly k/2
    // We can fill '?'s to achieve this.
    // Minimum '0's needed is k/2 - zeros_in_pattern.
    // Minimum '1's needed is k/2 - ones_in_pattern.
    // These must be non-negative and their sum must not exceed question_marks_in_pattern.

    int needed_zeros = k / 2 - zeros_in_pattern;
    int needed_ones = k / 2 - ones_in_pattern;

    if (needed_zeros < 0 || needed_ones < 0) {
        // Already too many 0s or 1s
        possible = false;
    } else if (needed_zeros + needed_ones > question_marks_in_pattern) {
        // Not enough '?'s to satisfy the counts
        possible = false;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

