    if (sum_k_inner_term1 % 2 == 0) {
        sum_k_inner = (sum_k_inner_term1 / 2 % MOD) * (sum_k_inner_term2 % MOD) % MOD;
    } else {
        sum_k_inner = (sum_k_inner_term2 / 2 % MOD) * (sum_k_inner_term1 % MOD) % MOD;
    }

    long long sum_k = (b % MOD * sum_k_inner % MOD + a % MOD) % MOD;

    // Total sum = sum_r * sum_k
    long long total_sum = (sum_r * sum_k) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        long long current_h = h[i];
        long long current_L_val = 0;

        // Remove elements from deque that are taller than current_h
        while (!dq_L.empty() && dq_L.back().first >= current_h) {
            dq_L.pop_back();
        }

        if (dq_L.empty()) {
            // No tower to the left is shorter or equal, so current_h is limited by its own height
            current_L_val = current_h;
        } else {
            // The tower at dq_L.back().second is the first tower to the left that is shorter than current_h.
            // The value at dq_L.back().first is its height.
            // The value at L[dq_L.back().second] is the maximum possible 'k' for that tower.
            // So, current_h is limited by min(current_h, L[dq_L.back().second] + (i - dq_L.back().second)).
            // This is equivalent to min(current_h, L[dq_L.back().second] + distance).
            current_L_val = std::min(current_h, dq_L.back().first + (long long)(i - dq_L.back().second));
        }

        // Add current tower to deque
        dq_L.push_back({current_L_val, i});
        L[i] = current_L_val;
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_h = h[i];
        long long current_R_val = 0;

        // Remove elements from deque that are taller than current_h
        while (!dq_R.empty() && dq_R.back().first >= current_h) {
            dq_R.pop_back();
        }

        if (dq_R.empty()) {
            // No tower to the right is shorter or equal, so current_h is limited by its own height
            current_R_val = current_h;
        } else {
            // The tower at dq_R.back().second is the first tower to the right that is shorter than current_h.
            // The value at dq_R.back().first is its height.
            // The value at R[dq_R.back().second] is the maximum possible 'k' for that tower.
            // So, current_h is limited by min(current_h, R[dq_R.back().second] + (dq_R.back().second - i)).
            // This is equivalent to min(current_h, R[dq_R.back().second] + distance).
            current_R_val = std::min(current_h, dq_R.back().first + (long long)(dq_R.back().second - i));
        }

        // Add current tower to deque
        dq_R.push_back({current_R_val, i});
        R[i] = current_R_val;
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min({h[i], L[i], R[i]}));
    }

    std::cout << max_k << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << 1 << std::endl;
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(n)));

    std::vector<int> p(n);
    int current_val = n;
    for (int i = 0; i < n; ++i) {
        int start_block = std::max(0, current_val - k + 1);
        int end_block = current_val;

        for (int j = end_block; j >= start_block; --j) {
            p[i] = j;
            i++;
        }
        i--; // Adjust i for the next iteration of the outer loop
        current_val = start_block - 1;
        if (current_val <= 0) break;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for each bit
    // For each bit position (0-9):
    // bit_val[0] represents the result if input bit is 0
    // bit_val[1] represents the result if input bit is 1
    // Initially, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<int> bit_val_if_0(10); // Stores the output bit if input bit is 0
    std::vector<int> bit_val_if_1(10); // Stores the output bit if input bit is 1

    for (int i = 0; i < 10; ++i) {
        bit_val_if_0[i] = 0;
        bit_val_if_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        for (int j = 0; j < 10; ++j) {
            int bit_of_val = (val >> j) & 1;
            if (op_char == '&') {
                bit_val_if_0[j] &= bit_of_val;
                bit_val_if_1[j] &= bit_of_val;
            } else if (op_char == '|') {
                bit_val_if_0[j] |= bit_of_val;
                bit_val_if_1[j] |= bit_of_val;
            } else { // '^'
                bit_val_if_0[j] ^= bit_of_val;
                bit_val_if_1[j] ^= bit_of_val;
            }
        }
    }

    // Reconstruct the equivalent operations
    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        if (bit_val_if_0[j] == 0 && bit_val_if_1[j] == 0) {
            // Bit j is always 0. This means it must be ANDed with 0.
            final_and_mask &= ~(1 << j); // Set j-th bit of AND mask to 0
        } else if (bit_val_if_0[j] == 1 && bit_val_if_1[j] == 1) {
            // Bit j is always 1. This means it must be ORed with 1.
            final_or_mask |= (1 << j); // Set j-th bit of OR mask to 1
        } else if (bit_val_if_0[j] == 0 && bit_val_if_1[j] == 1) {
            // Bit j passes through unchanged.
            // No change needed for AND/OR/XOR masks for this bit.
        } else { // bit_val_if_0[j] == 1 && bit_val_if_1[j] == 0
            // Bit j is inverted. This means it must be XORed with 1.
            final_xor_mask |= (1 << j); // Set j-th bit of XOR mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit was forced to 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit was forced to 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit was inverted
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Do nothing (add 0, which is a multiple of 1)
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";

        // Operation 3: Do nothing (add 0, which is a multiple of 1)
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // For each a[i] (0 <= i < n-1), we want a[i] + x_i * n = 0 (mod n)
    // This means a[i] + x_i * n = a[i] (mod n)
    // We want a[i] + b_i = 0 (mod n)
    // b_i must be a multiple of (n-1)
    // This is not the right approach.

    // The strategy is:
    // 1. For elements a[0] to a[n-2], make them multiples of n.
    //    This can be done by selecting segment [1, n-1] (0-indexed: [0, n-2]).
    //    Length is n-1.
    //    For each a[i] in this segment, we want to add b_i such that (a[i] + b_i) % n == 0.
    //    And b_i must be a multiple of (n-1).
    //    Let a[i] % n = rem. If rem != 0, we need to add (n - rem) to make it a multiple of n.
    //    So we need to add (n - rem) + k*n.
    //    We need (n - rem) + k*n to be a multiple of (n-1).
    //    (n - rem) + k*n = (n - rem) + k*(n-1) + k
    //    So we need (n - rem + k) to be a multiple of (n-1).
    //    Let X = n - rem. We need (X + k) % (n-1) == 0.
    //    We can choose k such that X + k = (n-1) * some_integer.
    //    For example, k = (n-1) - (X % (n-1)). If X % (n-1) == 0, k = 0.
    //    Then b_i = X + k*n. This is getting complicated.

    // A simpler strategy:
    // 1. For elements a[0] to a[n-2], make them zero.
    //    Select segment [1, n-1] (0-indexed: [0, n-2]). Length is n-1.
    //    For each a[i] in this segment, we need to add -a[i].
    //    -a[i] must be a multiple of (n-1).
    //    This means a[i] must be a multiple of (n-1). This is not true initially.

    // Let's use the property that n and n-1 are coprime.
    // For each a[i] (0 <= i < n-1):
    // We want to add b_i such that a[i] + b_i = 0 (mod n).
    // And b_i must be a multiple of (n-1).
    // So b_i = k * (n-1) for some integer k.
    // We need a[i] + k * (n-1) = 0 (mod n).
    // a[i] + k * (-1) = 0 (mod n)
    // a[i] - k = 0 (mod n)
    // k = a[i] (mod n).
    // So we can choose k = a[i] % n. If a[i] % n is negative, add n.
    // Let k_val = (a[i] % n + n) % n.
    // Then b_i = k_val * (n-1).
    // After adding b_i, a[i] becomes a[i] + k_val * (n-1).
    // This new value is a multiple of n.
    // Let's call this new value a'[i].
    // So after this operation, a'[0], ..., a'[n-2] are all multiples of n.

    // Operation 1: Modify a[0]...a[n-2]
    std::cout << 1 << " " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure remainder is non-negative
        long long add_val = remainder * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Now a[0]...a[n-2] are all multiples of n.
    // a[n-1] is unchanged.

    // Operation 2: Modify a[n-1]
    // Select segment [n, n] (0-indexed: [n-1, n-1]). Length is 1.
    // We want to add b_{n-1} such that a[n-1] + b_{n-1} = 0 (mod n).
    // b_{n-1} must be a multiple of 1. This is always true.
    // So we can just add -a[n-1].
    std::cout << n << " " << n << "\n";
    long long add_val_n_minus_1 = -a[n - 1];
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1; // a[n-1] is now 0.

    // Now a[0]...a[n-2] are multiples of n.
    // a[n-1] is 0.

    // Operation 3: Make all elements zero.
    // Select segment [1, n] (0-indexed: [0, n-1]). Length is n.
    // For each a[i], we need to add b_i such that a[i] + b_i = 0.
    // b_i must be a multiple of n.
    // Since a[0]...a[n-2] are already multiples of n, and a[n-1] is 0 (which is a multiple of n),
    // we can just add -a[i] for each i.
    // -a[i] will be a multiple of n.
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // Convert 1 to +1, 2 to -1
    // left_diff[i] = sum of (a[0]...a[i-1]) where a[j]=1 -> +1, a[j]=2 -> -1
    // left_diff[0] = 0 (before any jars)
    // left_diff[k] = difference after removing k jars from the left (jars 0 to k-1)
    std::vector<int> left_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        left_diff[i + 1] = left_diff[i] + (a[n - 1 - i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // right_diff[i] = sum of (a[n]...a[n+i-1]) where a[j]=1 -> +1, a[j]=2 -> -1
    // right_diff[0] = 0 (before any jars)
    // right_diff[k] = difference after removing k jars from the right (jars n to n+k-1)
    std::vector<int> right_diff(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        right_diff[i + 1] = right_diff[i] + (a[n + i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain difference
    // map_left[diff] = k_L (min jars removed from left to get diff)
    std::map<int, int> map_left;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff = left_diff[k_L];
        if (map_left.find(current_diff) == map_left.end()) {
            map_left[current_diff] = k_L;
        }
    }

    int min_removed = 2 * n; // Max possible jars removed

    // Iterate through all possible numbers of jars removed from the right (k_R)
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_right_diff = right_diff[k_R];
        // We need total_diff - current_left_diff - current_right_diff = 0
        // So, current_left_diff = total_diff - current_right_diff
        int target_left_diff = -current_right_diff;

        if (map_left.count(target_left_diff)) {
            int k_L = map_left[target_left_diff];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        long long total_substrings = n * (n + 1) / 2;

        // We want to minimize the number of substrings consisting only of '0's.
        // This is achieved by distributing the 'm' ones as evenly as possible
        // to break up the 'n-m' zeros.
        // The 'm' ones create 'm+1' possible gaps for the 'n-m' zeros.
        // However, if we place ones like 10101, we have blocks of zeros.
        // The optimal strategy is to make the blocks of zeros as equal in length as possible.
        // If we have 'm' ones, they divide the string into 'm+1' potential segments of zeros.
        // For example, _1_1_1_ (3 ones, 4 segments).
        // The 'n-m' zeros are distributed among these 'm+1' segments.
        // Let k be the number of zeros in each segment.
        // n-m = q * (m+1) + r, where q is the base length and r segments have q+1 zeros.
        // The number of zeros is n - m.
        // The number of '1's is m.
        // These 'm' ones divide the 'n' positions into 'm+1' potential blocks of zeros.
        // For example, if s = 0010100, n=7, m=2. Zeros: 00, 0, 00.
        // The number of blocks of zeros is m+1.
        // Let num_zeros = n - m.
        // We distribute num_zeros among m+1 blocks.
        // Let k = num_zeros / (m + 1) (integer division).
        // Let r = num_zeros % (m + 1).
        // This means r blocks will have k+1 zeros, and (m+1 - r) blocks will have k zeros.

        long long num_zeros = n - m;
        long long num_blocks_of_zeros = m + 1;

        long long k = num_zeros / num_blocks_of_zeros;
        long long r = num_zeros % num_blocks_of_zeros;

        // Calculate substrings of all zeros from blocks of length k+1
        long long substrings_from_k_plus_1 = r * (k + 1) * (k + 2) / 2;
        // Calculate substrings of all zeros from blocks of length k
        long long substrings_from_k = (num_blocks_of_zeros - r) * k * (k + 1) / 2;

        long long total_zero_substrings = substrings_from_k_plus_1 + substrings_from_k;

        std::cout << total_substrings - total_zero_substrings << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    // Iterate through powers of 2 from largest to smallest
    // 2^60 is roughly 1.15 * 10^18, so 60 is a safe upper bound for k
    // 2^62 - 1 is too large for X (10^9)
    // 2^30 is roughly 10^9, so k up to 30 is relevant for X
    for (int k = 60; k >= 1; --k) {
        long long count_for_k = (1LL << k) - 1; // Number of subsequences for k identical elements
        while (X >= count_for_k) {
            // Add k elements of current_val to the array
            for (int i = 0; i < k; ++i) {
                result_array.push_back(current_val);
            }
            X -= count_for_k;
            // Increment current_val by d + 1 to ensure new elements are "far" from previous ones
            // and form new groups of valid subsequences.
            // current_val + d + 1 could exceed 10^18 if current_val is already large.
            // However, the maximum number of elements is 10^4.
            // If we add 10^4 elements, and each time current_val increases by d+1,
            // max current_val would be 1 + 10^4 * (10^9 + 1) which is ~10^13, well within 10^18.
            current_val += d + 1;
        }
    }

    if (X > 0) { // If X is not fully covered, it means X was not representable
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::abs, std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n <= m by swapping if necessary. This simplifies logic.
        // The problem statement guarantees n, m >= 1, so abs is not strictly needed for input,
        // but it's good practice for general coordinate systems.
        // For this problem, n_i, m_i are given as positive, so std::abs is not strictly necessary
        // for the input values themselves, but the logic often simplifies if we assume N <= M.
        // Let's use N and M for the absolute values of the target coordinates.
        long long N = n;
        long long M = m;

        if (N > M) {
            std::swap(N, M);
        }

        // Minimum moves required to reach (N, M) is M (by making N diagonal moves and M-N straight moves).
        // If k is less than M, it's impossible.
        if (k < M) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 1: k and M have the same parity.
        // This means k - M is an even number.
        // We can reach (N, M) in M moves (N diagonal, M-N straight).
        // The remaining k - M moves must be used to "waste" time.
        // Each pair of moves (e.g., (x,y) -> (x+1,y) -> (x,y)) changes parity of total moves by 2.
        // Or (x,y) -> (x+1,y+1) -> (x,y) also changes parity by 2.
        // So, if k and M have the same parity, we can always reach (N, M) in k moves.
        // The maximum number of diagonal moves is achieved by making as many diagonal moves as possible.
        // We can make N diagonal moves to cover the min(N,M) part.
        // The remaining M-N moves must be straight.
        // Total moves so far: N (diag) + (M-N) (straight) = M moves.
        // Remaining moves: k - M. These must be wasted.
        // Each wasted move can be a diagonal move if we move to (x+1,y+1) and then back to (x,y) in two moves.
        // Or (x+1,y) and back to (x,y).
        // If we make a diagonal move and then a straight move back to the same parity cell,
        // e.g., (x,y) -> (x+1,y+1) -> (x+1,y) or (x,y) -> (x+1,y+1) -> (x,y+1).
        // The key is that if k and M have the same parity, we can always reach (N,M) in k moves.
        // The maximum diagonal moves would be k, if N=M=k.
        // If N < M, we need at least M-N straight moves.
        // The maximum diagonal moves is k - (M-N) if we can convert all remaining k-M moves into diagonal moves.
        // This is equivalent to k.
        // The number of diagonal moves is k.
        // However, we must ensure that the final position has the correct parity.
        // The parity of the sum of coordinates (x+y) changes with each move.
        // (x,y) -> (x',y'). (x'+y') - (x+y) can be 0, 1, or 2.
        // No, this is not correct. (x'+y') - (x+y) is always odd for any move.
