        // When `k` is added, we need to check if `k` can improve paths between existing active vertices,
        // and if existing active vertices can improve paths involving `k`.
        // The following three loops correctly implement this:
        // 1. Paths from existing active `i` to existing active `j` via `k`.
        // 2. Paths from `k` to existing active `j` via existing active `i`.
        // 3. Paths from existing active `i` to `k` via existing active `j`.
        // This is equivalent to running Floyd-Warshall on the subgraph of active vertices,
        // with `k` being the latest vertex added to the set of intermediate vertices.

        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[k][i] + dist[i][j] < dist[k][j]) {
                    dist[k][j] = dist[k][i] + dist[i][j];
                }
            }
        }
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (dist[j][i] + dist[i][k] < dist[j][k]) {
                    dist[j][k] = dist[j][i] + dist[i][k];
                }
            }
        }


        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (reverse of how they were calculated)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

