#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b(n, std::numeric_limits<long long>::max()); // b[i] stores the maximum possible initial value for a[i]

    // Process operations in reverse to determine initial upper bounds
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // If a[j] = b[j] + sum_d, and we know b[j] <= X, then b[j] + d <= X + d
            // So, if we have a constraint on a[j] from a future type 2 op,
            // say a[j] <= M, then b[j] + sum_d_after_this_op <= M.
            // When processing in reverse, we are effectively "undoing" the d values.
            // If a[j] was increased by d, then its initial value b[j] must be
            // such that b[j] + d (plus other future d's) satisfies constraints.
            // So, if b[j] was constrained to be <= X, it means (b[j] + d) was constrained to be <= X.
            // Thus, b[j] must be <= X - d.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (b[j] != std::numeric_limits<long long>::max()) { // Only update if it's already constrained
                    b[j] -= ops[i].val;
                }
            }
        } else { // type 2
            // max(a[j]) = m_i implies a[j] <= m_i for all j in [l_i, r_i].
            // This means b[j] (plus future d's) <= m_i.
            // Since we are processing in reverse, b[j] already reflects the sum of future d's.
            // So, b[j] must be <= m_i.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val);
            }
        }
    }

    // If b[j] is still max_long_long, it means it was never constrained by a type 2 op.
    // We can set it to 0, as |a_i| <= 10^9 is allowed.
    // Or, more precisely, we can set it to 0 because it will satisfy all constraints.
    // The problem asks for *any* suitable array.
    for (int i = 0; i < n; ++i) {
        if (b[i] == std::numeric_limits<long long>::max()) {
            b[i] = 0;
        }
    }

    // Verify the solution by replaying operations
    std::vector<long long> current_a = b;
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_a[j] += op.val;
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = op.l; j <= op.r; ++j) {
                max_val = std::max(max_val, current_a[j]);
            }
            if (max_val != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line; // To mark if child has left
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].in_line = false; // This child is now being cured

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        // Apply initial cry from child i
        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            children[j].p -= accumulated_d_cry;

            // Apply v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }
        }

        // Chain reaction for children leaving
        bool crying_happened;
        do {
            crying_happened = false;
            for (int j = i + 1; j < n; ++j) {
                if (children[j].in_line && children[j].p < 0) {
                    children[j].in_line = false;
                    accumulated_d_cry += children[j].d;
                    crying_happened = true;
                }
            }
            // If children left, their d_cry affects subsequent children
            if (crying_happened) {
                for (int j = i + 1; j < n; ++j) {
                    if (children[j].in_line) {
                        children[j].p -= accumulated_d_cry;
                    }
                }
                // Reset accumulated_d_cry for the next iteration of the do-while loop
                // because it has already been applied to all current children in line.
                // New children leaving will add to it.
                accumulated_d_cry = 0; 
            }
        } while (crying_happened);
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    std::vector<int> b(n);
    if (n == 0) return b;

    b[0] = a[0];
    if (n > 1) {
        b[n - 1] = a[n - 1];
    }

    for (int i = 1; i < n - 1; ++i) {
        int sum = a[i - 1] + a[i] + a[i + 1];
        if (sum >= 2) { // Median is 1 if two or three 1s
            b[i] = 1;
        } else { // Median is 0 if two or three 0s
            b[i] = 0;
        }
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> current_seq = a;
    int steps = 0;

    // Find first 0-1 transition from left
    int first_one_idx = -1;
    for (int i = 0; i < n; ++i) {
        if (current_seq[i] == 1) {
            first_one_idx = i;
            break;
        }
    }

    // Find first 1-0 transition from right
    int last_one_idx = -1;
    for (int i = n - 1; i >= 0; --i) {
        if (current_seq[i] == 1) {
            last_one_idx = i;
            break;
        }
    }

    // If all zeros or all ones, it's stable
    if (first_one_idx == -1 || first_one_idx == n) { // All zeros
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }
    if (first_one_idx == 0 && last_one_idx == n - 1) { // All ones
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Calculate initial left_0_block_len and right_0_block_len
    int left_0_block_len = 0;
    for (int i = 0; i < n; ++i) {
        if (current_seq[i] == 0) {
            left_0_block_len++;
        } else {
            break;
        }
    }

    int right_0_block_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (current_seq[i] == 0) {
            right_0_block_len++;
        } else {
            break;
        }
    }

    // Find all 0-1 and 1-0 transitions
    std::vector<int> transitions;
    for (int i = 0; i < n - 1; ++i) {
        if (current_seq[i] != current_seq[i+1]) {
            transitions.push_back(i);
        }
    }

    // If there are only two transitions (0...01...10...0), it's stable
    // This means the sequence is 0...01...10...0
    // The first_one_idx and last_one_idx already handle all 0s or all 1s.
    // If it's 0...01...1, first_one_idx is valid, last_one_idx is n-1.
    // If it's 1...10...0, first_one_idx is 0, last_one_idx is valid.
    // If it's 0...01...10...0, first_one_idx is valid, last_one_idx is valid.
    // The only case where it's not stable is if there are 010 or 101 patterns.
    // This means there are more than 2 transitions.
    // E.g., 01010 has 4 transitions. 00100 has 2 transitions.
    // A sequence like 001100 is stable.
    // A sequence like 01010 is not stable.
    // The condition for stability is that all 0s are grouped together and all 1s are grouped together.
    // i.e., 0...01...1 or 1...10...0 or 0...0 or 1...1.
    // This means there are at most two transitions.
    // If transitions.size() <= 2, the sequence is stable.
    if (transitions.size() <= 2) {
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << current_seq[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    // Find the maximum length of a 010 or 101 pattern
    // A 010 pattern means a 1 surrounded by 0s.
    // A 101 pattern means a 0 surrounded by 1s.
    // The length of such a pattern is the number of elements in the middle that are different from their neighbors.
    // E.g., 010 has length 1 (the middle 1). 0110 has length 2 (the two 1s).
    // The number of steps required is related to the maximum "distance" a 0 or 1 needs to propagate.
    // This is equivalent to finding the maximum length of a block of alternating values.
    // For example, in 01010, the 1s are at indices 1 and 3.
    // The 0 at index 2 is surrounded by 1s. It will become 1.
    // The 1 at index 1 is surrounded by 0s. It will become 0.
    // The 1 at index 3 is surrounded by 0s. It will become 0.
    // The sequence 01010 -> 00100 -> 00000.
    // The number of steps is ceil(max_len_alternating_block / 2.0).
    // More precisely, it's the maximum distance from a 'wrong' element to the nearest 'correct' element.
    // A 'wrong' element is a 1 in a 0-block or a 0 in a 1-block.
    // The 'distance' is the number of steps it takes for the 'wrong' element to be smoothed out.
    // This is equivalent to finding the maximum 'gap' between two identical values that are separated by different values.
    // For example, 01010. The 0 at index 2 is surrounded by 1s. It needs to become 1.
    // The 1 at index 1 is surrounded by 0s. It needs to become 0.
    // The 1 at index 3 is surrounded by 0s. It needs to become 0.
    // The maximum length of a "010" or "101" pattern is what matters.
    // A 010 pattern is a sequence of 0s, then 1s, then 0s.
    // A 101 pattern is a sequence of 1s, then 0s, then 1s.
    // The length of the middle block determines the number of steps.
    // For 01010, the middle 101 block (indices 1,2,3) has length 3.
    // The middle 0 at index 2 is surrounded by 1s. It will become 1.
    // The 1 at index 1 is surrounded by 0s. It will become 0.
    // The 1 at index 3 is surrounded by 0s. It will become 0.
    // The number of steps is max(ceil(len_010_middle_block / 2.0), ceil(len_101_middle_block / 2.0)).
    // This is equivalent to finding the maximum distance between two consecutive identical values that are separated by different values.
    // E.g., 0 1 0 1 0.
    // The 0 at index 0 and 0 at index 2 are separated by 1. Distance 2.
    // The 1 at index 1 and 1 at index 3 are separated by 0. Distance 2.
    // The 0 at index 2 and 0 at index 4 are separated by 1. Distance 2.
    // Max distance is 2. Steps = 1.
    // This is not quite right.
    // The number of steps is determined by the maximum length of a "run" of alternating values.
    // For example, 01010. The run is 101. Length 3. Steps = ceil(3/2) = 2.
    // For 0110. The run is 11. Length 2. Steps = ceil(2/2) = 1.
    // For 0100. The run is 10. Length 2. Steps = ceil(2/2) = 1.
    // The maximum length of a block of 0s surrounded by 1s, or 1s surrounded by 0s.
    // Let's find the indices of all 0s and 1s.
    // For 01010: 0 at 0, 1 at 1, 0 at 2, 1 at 3, 0 at 4.
    // The 'core' of the sequence is between first_one_idx and last_one_idx.
    // Outside this core, values are stable (0s to the left of first 1, 0s to the right of last 1).
    // The values inside the core will eventually become all 0s or all 1s.
    // The final stable sequence will be all 0s if left_0_block_len + right_0_block_len >= n - 1.
    // No, this is not correct. The final sequence depends on the 'majority' of the sequence.
    // The problem states that the sequence will eventually become stable.
    // The number of steps is max_dist / 2, where max_dist is the maximum distance between two identical values that are separated by different values.
    // For example, 0 1 0 1 0.
    // The 0 at index 0 and 0 at index 2 are separated by 1. Distance 2.
    // The 1 at index 1 and 1 at index 3 are separated by 0. Distance 2.
    // The 0 at index 2 and 0 at index 4 are separated by 1. Distance 2.
    // Max distance is 2. Steps = 1. This is wrong for 01010 -> 2 steps.
    // The number of steps is the maximum length of a "010...10" or "101...01" pattern, divided by 2, rounded up.
    // This is the maximum length of a block of alternating values.
    // For 01010, the alternating block is 101 (indices 1,2,3). Length 3. ceil(3/2) = 2.
    // For 00100, the alternating block is 1 (index 2). Length 1. ceil(1/2) = 1.
    // For 0110, the alternating block is 11 (indices 1,2). Length 2. ceil(2/2) = 1.
    // For 0100, the alternating block is 10 (indices 1,2). Length 2. ceil(2/2) = 1.
    // This seems to be the correct logic for steps.

    int max_alternating_len = 0;
    if (transitions.size() > 0) {
        // The first transition is at transitions[0]. The block starts at transitions[0]+1.
        // The last transition is at transitions.back(). The block ends at transitions.back().
        // The length of the alternating block is transitions.back() - transitions[0].
        // Example: 0 1 0 1 0
        // Transitions at 0, 1, 2, 3.
        // transitions[0] = 0 (0->1)
        // transitions[1] = 1 (1->0)
        // transitions[2] = 2 (0->1)
        // transitions[3] = 3 (1->0)
        // The alternating block is from index 1 to index 3. Length 3.
        // This is transitions[3] - transitions[0] = 3 - 0 = 3.
        max_alternating_len = transitions.back() - transitions[0];
    }

    steps = (max_alternating_len + 1) / 2; // ceil(max_alternating_len / 2.0)

    // The final sequence will have 0s up to first_one_idx + steps - 1
    // and 0s from last_one_idx - steps + 1 to n-1.
    // The middle part will be all 1s if first_one_idx + steps <= last_one_idx - steps.
    // Otherwise, it will be all 0s.
    // This is equivalent to saying:
    // If the '1' block shrinks to nothing, the whole sequence becomes 0.
    // If the '0' block shrinks to nothing, the whole sequence becomes 1.
    // The '1' block shrinks from both ends.
    // The '0' block shrinks from both ends.
    // The final sequence will be all 0s if the '1' block disappears.
    // This happens if first_one_idx + steps > last_one_idx - steps.
    // Or, more simply, if the '1' block is "eaten" by the 0s.
    // The '1' block is from first_one_idx to last_one_idx.
    // The 0s from the left propagate right. The 0s from the right propagate left.
    // The 1s from the middle propagate outwards.
    // The final state is determined by which "wins" or if they meet.
    // The final sequence will be all 0s if the '1' block is completely smoothed out.
    // This happens if the distance between first_one_idx and last_one_idx is less than 2 * steps.
    // No, this is not right.
    // The final sequence is all 0s if the '1' block is "small enough" to be consumed by the 0s.
    // The '1' block is from first_one_idx to last_one_idx. Its length is last_one_idx - first_one_idx + 1.
    // The 0s from the left extend right by `steps` positions.
    // The 0s from the right extend left by `steps` positions.
    // The new first_one_idx will be `first_one_idx + steps`.
    // The new last_one_idx will be `last_one_idx - steps`.
    // If `first_one_idx + steps > last_one_idx - steps`, then the 1s are gone.
    // The sequence becomes all 0s.
    // Otherwise, the sequence becomes 0...01...10...0.
    // The 0s extend up to `first_one_idx + steps - 1`.
    // The 0s extend from `last_one_idx - steps + 1`.
    // The 1s are in between.

    std::vector<int> final_seq(n);
    if (first_one_idx + steps > last_one_idx - steps) { // The 1s are completely smoothed out
        std::fill(final_seq.begin(), final_seq.end(), 0);
    } else {
        for (int i = 0; i < n; ++i) {
            if (i < first_one_idx + steps || i > last_one_idx - steps) {
                final_seq[i] = 0;
            } else {
                final_seq[i] = 1;
            }
        }
    }

    std::cout << steps << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << final_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate large values. x can also become large if n is large
// and a_x is large, but it's constrained by n for termination.
// The problem statement implies x is an index, so it should fit in int,
// but intermediate calculations might exceed int range if not careful.
// However, x is always compared to n, so it's effectively an index.
// The values a_x can be large, so y definitely needs long long.

// Max N is 2 * 10^5.
// Max a_i is 10^9.
// Max y can be N * max(a_i) if it loops many times, but it's more complex.
// If x jumps around, it can be sum of a_i values.
// A path length can be N. So y can be N * max(a_i) = 2*10^5 * 10^9 = 2*10^14.
// This fits in long long.

// We need to detect cycles.
// A state can be defined by (current_x, current_operation_type).
// The current_operation_type is either 'add' or 'subtract'.
// Let's say 0 for 'add' and 1 for 'subtract'.
// So, a state is (x, op_type).
// Since x can be up to N, and op_type is 0 or 1, we can use a 2D array
// or a map to store visited states.
// A 2D array `visited[N+1][2]` storing `true` if visited, `false` otherwise.
// Or, `visited[N+1][2]` storing the `y` value at that state to detect if it's a cycle
// and calculate the cycle contribution.

// The problem states x starts at 1.
// The sequence a_1, a_2, ..., a_n.
// For each i (1 <= i <= n-1), a_1 = i.
// The rest a_2, ..., a_n are given.

// Let's define the states more precisely.
// A state is (current_x, current_y, current_step_parity).
// current_step_parity: 0 for step 2 (x+=a_x, y+=a_x), 1 for step 3 (x-=a_x, y+=a_x).
// The problem says "first step 2, then step 3".
// So, if we are at x, we first do step 2, then step 3.
// The sequence of operations is:
// (x, y) -> (x+a_x, y+a_x) -> (x+a_x-a_{x+a_x}, y+a_x+a_{x+a_x}) -> ...
// This means we always perform step 2, then step 3.
// So, the state only depends on `x`. `y` is accumulated.
// If we visit `x` again, it means we are in a cycle.
// The `y` value will keep increasing.
// So, we need to store `y` for each `x` when we first visit it.
// If we visit `x` again, and `y_current > y_stored_at_first_visit`, it's a cycle.
// But this is not quite right. The `a_x` value depends on `x`.
// The sequence of operations is:
// Start: x_0=1, y_0=0
// Loop:
//   x_curr = x_prev
//   y_curr = y_prev
//   val_ax = a[x_curr]
//   // Step 2
//   x_next1 = x_curr + val_ax
//   y_next1 = y_curr + val_ax
//   // Check termination
//   if x_next1 <= 0 or x_next1 > n: terminate, result y_next1
//   // Step 3
//   val_ax_next1 = a[x_next1]
//   x_next2 = x_next1 - val_ax_next1
//   y_next2 = y_next1 + val_ax_next1
//   // Check termination
//   if x_next2 <= 0 or x_next2 > n: terminate, result y_next2
//   // Continue loop with x_next2, y_next2

// This means the state is just `x`.
// We need to store `(y_value, step_count)` for each `x` when we first reach it.
// If we reach `x` again, we have detected a cycle.
// The `y` value will grow indefinitely. So, `-1`.

// Let's use dynamic programming / memoization.
// For each starting `a_1 = i`, we want to find the final `y`.
// Let `dp[x]` store the result if we start the "step 2, then step 3" sequence from `x`.
// `dp[x]` could be `(final_y, terminates_or_not)`.
// If `dp[x]` is already computed, we use it.
// If `dp[x]` is currently being computed (in recursion stack), it's a cycle.

// `dp[x]` will store `pair<long long, bool>`: `(final_y, is_terminating)`.
// `is_terminating` is true if it terminates, false if it cycles.
// We need to handle the `a_1` value.
// The `a` array is `a_1, a_2, ..., a_n`.
// `a_1` changes for each query. `a_2, ..., a_n` are fixed.
// This means `dp` values depend on `a_1`.
// So, we can't precompute `dp` for all `x` once.
// We need to run the simulation for each `i`.

// For each `i` from `1` to `n-1`:
//   Set `a[0] = i` (using 0-indexed array for `a_1`).
//   `x = 0` (corresponds to `a_1`), `y = 0`.
//   `visited` array to detect cycles for current run: `vector<bool> visited(n, false)`.
//   `path_y` array to store `y` values when `x` is first visited in current path: `vector<long long> path_y(n)`.
//   `path_x_val` array to store `a_x` values when `x` is first visited in current path: `vector<long long> path_x_val(n)`.
//   `current_x = 0` (index for `a_1`), `current_y = 0`.
//   Loop:
//     If `current_x < 0` or `current_x >= n`:
//       Print `current_y`. Break.
//     If `visited[current_x]` is true:
//       Print `-1`. Break (cycle detected).
//     `visited[current_x] = true`.
//     `path_y[current_x] = current_y`.
//     `path_x_val[current_x] = a[current_x]`.

//     // Step 2: x = x + a_x, y = y + a_x
//     `next_x_after_step2 = current_x + a[current_x]`.
//     `next_y_after_step2 = current_y + a[current_x]`.

//     If `next_x_after_step2 < 0` or `next_x_after_step2 >= n`:
//       Print `next_y_after_step2`. Break.

//     // Step 3: x = x - a_x, y = y + a_x (where a_x is a[next_x_after_step2])
//     `current_x = next_x_after_step2 - a[next_x_after_step2]`.
//     `current_y = next_y_after_step2 + a[next_x_after_step2]`.

// This simulation approach for each `i` would be `O(N * N)` in worst case, which is `(2*10^5)^2 = 4*10^10`, too slow.
// We need a faster approach.

// Notice the structure of the problem:
// For a given `a_1`, we start at `x=1`.
// We perform `x += a_x, y += a_x`. Let's call this state `(x_1, y_1)`.
// Then we perform `x -= a_{x_1}, y += a_{x_1}`. Let's call this state `(x_2, y_2)`.
// Then we repeat from `x_2`.
// The `a` array is `a_1, a_2, ..., a_n`.
// Let's use 1-based indexing for `x` and `a` to match problem statement.
// `a[1]` is `a_1`, `a[2]` is `a_2`, etc.

// For a given `x`, the next `x` is determined by `x + a[x]` then `(x + a[x]) - a[x + a[x]]`.
// Let `f(x) = (x + a[x]) - a[x + a[x]]`.
// Let `g(x) = a[x] + a[x + a[x]]`. This is the `y` increment for one full step (step 2 then step 3).
// So, we start with `x=1, y=0`.
// Then `x_new = f(x_old)`, `y_new = y_old + g(x_old)`.
// We need to find `y` when `x` terminates.

// The values `a_2, ..., a_n` are fixed.
// Only `a_1` changes.
// This means `f(x)` and `g(x)` are fixed for `x >= 2`.
// For `x=1`, `f(1)` and `g(1)` depend on `a_1`.

// This looks like a graph problem. Each `x` is a node.
// There's an edge from `x` to `f(x)`. Each edge has a weight `g(x)`.
// We are looking for the sum of weights along a path starting from `x=1` until `x` goes out of bounds or a cycle is detected.

// We can precompute `f(x)` and `g(x)` for `x >= 2`.
// `f_val[x]` stores `f(x)`.
// `g_val[x]` stores `g(x)`.
// `is_terminating[x]` stores whether starting from `x` terminates.
// `final_y_from_x[x]` stores the final `y` if starting from `x` terminates.

// We can use DFS with memoization to compute `is_terminating` and `final_y_from_x`.
// `memo[x]` stores `(final_y, is_terminating)` for `x`.
// `visiting[x]` is a boolean array to detect cycles in the current DFS path.

// `vector<pair<long long, bool>> memo(n + 1, {0, false});` // {final_y, is_terminating}
// `vector<bool> visiting(n + 1, false);`

// `pair<long long, bool> solve(int current_x, const vector<long long>& a_arr, int n)`:
//   If `current_x <= 0` or `current_x > n`: return `{0, true}` (base case for termination)
//   If `visiting[current_x]`: return `{0, false}` (cycle detected)
//   If `memo[current_x].second` is true (already computed and terminates): return `memo[current_x]`
//   If `memo[current_x].first != 0` and `memo[current_x].second` is false (already computed and cycles): return `memo[current_x]`

//   `visiting[current_x] = true`

//   `val_ax = a_arr[current_x]`
//   `next_x_after_step2 = current_x + val_ax`
//   `y_increment_step2 = val_ax`

//   If `next_x_after_step2 <= 0` or `next_x_after_step2 > n`:
//     `visiting[current_x] = false`
//     `memo[current_x] = {y_increment_step2, true}`
//     return `memo[current_x]`

//   `val_ax_next1 = a_arr[next_x_after_step2]`
//   `next_x_after_step3 = next_x_after_step2 - val_ax_next1`
//   `y_increment_step3 = val_ax_next1`

//   `pair<long long, bool> res = solve(next_x_after_step3, a_arr, n)`

//   `visiting[current_x] = false`

//   If `res.second` is false (cycle detected):
//     `memo[current_x] = {0, false}`
//     return `memo[current_x]`
//   Else:
//     `memo[current_x] = {y_increment_step2 + y_increment_step3 + res.first, true}`
//     return `memo[current_x]`

// This `solve` function computes the result for starting from `current_x` *after* the initial `x=1, y=0` step.
// The problem states: "Initially, x = 1 and y = 0. If, after any step, x <= 0 or x > n, the program immediately terminates. The program increases both x and y by a value equal to a_x simultaneously. The program now increases y by a_x while decreasing x by a_x. The program executes steps 2 and 3 (first step 2, then step 3) repeatedly until it terminates."

// Let's re-read carefully:
// Initial: `x=1, y=0`.
// Loop:
//   1. `x_old = x, y_old = y`.
//   2. `x = x_old + a[x_old]`, `y = y_old + a[x_old]`.
//      Check termination: if `x <= 0` or `x > n`, terminate, output `y`.
//   3. `x_temp = x`. `y_temp = y`.
//      `x = x_temp - a[x_temp]`, `y = y_temp + a[x_temp]`.
//      Check termination: if `x <= 0` or `x > n`, terminate, output `y`.
//   Repeat from step 1.

// This means the `solve` function should take `current_x` and `current_y` as arguments.
// But `y` is cumulative, so `memo` cannot store `y` directly.
// `memo[x]` should store `(total_y_increment_from_x, terminates)`.

// Let `dp[x]` store `(total_y_increment, terminates)` if we start the *loop* from `x`.
// `total_y_increment` is the sum of `a_val`s added to `y` from `x` until termination.

// `pair<long long, bool> calculate_path(int start_x, const vector<long long>& a_arr, int n, vector<pair<long long, bool>>& memo, vector<bool>& visiting)`:
//   If `start_x <= 0` or `start_x > n`: return `{0, true}` (base case: out of bounds, 0 additional y, terminates)
//   If `visiting[start_x]`: return `{0, false}` (cycle detected, 0 additional y, does not terminate)
//   If `memo[start_x].second` is true (already computed and terminates): return `memo[start_x]`
//   If `memo[start_x].first != 0` and `memo[start_x].second` is false (already computed and cycles): return `memo[start_x]`

//   `visiting[start_x] = true`

//   `val_ax = a_arr[start_x]`
//   `x_after_step2 = start_x + val_ax`
//   `y_added_step2 = val_ax`

//   // Check termination after step 2
//   If `x_after_step2 <= 0` or `x_after_step2 > n`:
//     `visiting[start_x] = false`
//     `memo[start_x] = {y_added_step2, true}`
//     return `memo[start_x]`

//   `val_ax_after_step2 = a_arr[x_after_step2]`
//   `x_after_step3 = x_after_step2 - val_ax_after_step2`
//   `y_added_step3 = val_ax_after_step2`

//   // Recursively calculate for the next state
//   `pair<long long, bool> res = calculate_path(x_after_step3, a_arr, n, memo, visiting)`

//   `visiting[start_x] = false`

//   If `res.second` is false: // Cycle detected
//     `memo[start_x] = {0, false}`
//     return `memo[start_x]`
//   Else: // Terminates
//     `memo[start_x] = {y_added_step2 + y_added_step3 + res.first, true}`
//     return `memo[start_x]`

// This `calculate_path` function works for `x >= 2`.
// For `x=1`, `a_arr[1]` changes.
// So, for each `i` from `1` to `n-1`:
//   `a_arr[1] = i`.
//   `memo` and `visiting` must be reset or handled carefully.
//   Since `a_arr[1]` changes, `memo[1]` is invalid.
//   But `memo[x]` for `x >= 2` are still valid.
//   So, we only need to compute `calculate_path(1, ...)` for each `i`.
//   The `memo` and `visiting` arrays should be passed by reference and cleared for `x=1` and any `x` that depends on `a_arr[1]`.
//   This is still `O(N)` for each `i` in worst case if the path from `1` is long.
//   Total `O(N^2)`. Still too slow.

// The key observation must be that `a_1` is the only changing value.
// All `a_x` for `x >= 2` are fixed.
// This means the graph structure and edge weights `g(x)` are fixed for `x >= 2`.
// We can precompute `dp[x]` for all `x >= 2`.
// `dp[x]` will store `(total_y_increment, terminates)` for starting the loop from `x`.
// This precomputation takes `O(N)` time using DFS.

// `vector<pair<long long, bool>> dp(n + 1, {0, false});` // {total_y_increment, terminates}
// `vector<bool> visiting_precompute(n + 1, false);`

// `pair<long long, bool> precompute_dp(int start_x, const vector<long long>& a_arr, int n, vector<pair<long long, bool>>& dp, vector<bool>& visiting_precompute)`:
//   (Same logic as `calculate_path` but using `dp` and `visiting_precompute`)
//   Only call this for `start_x >= 2`.

// After precomputing `dp` for `x >= 2`:
// For each `i` from `1` to `n-1`:
//   `a_arr[1] = i`.
//   `current_x = 1`, `current_y = 0`.
//   `val_ax = a_arr[current_x]` (which is `i`)
//   `x_after_step2 = current_x + val_ax`
//   `y_added_step2 = val_ax`

//   If `x_after_step2 <= 0` or `x_after_step2 > n`:
//     Print `y_added_step2`. Continue to next `i`.

//   `val_ax_after_step2 = a_arr[x_after_step2]`
//   `x_after_step3 = x_after_step2 - val_ax_after_step2`
//   `y_added_step3 = val_ax_after_step2`

//   // Now we need to find the result starting from `x_after_step3`.
//   // This is where we use the precomputed `dp` values.
//   `pair<long long, bool> res = dp[x_after_step3]` (if `x_after_step3` is valid index)
//   If `x_after_step3 <= 0` or `x_after_step3 > n`:
//     Print `y_added_step2 + y_added_step3`.
//   Else if `res.second` is false: // Cycle detected
//     Print `-1`.
//   Else: // Terminates
//     Print `y_added_step2 + y_added_step3 + res.first`.

// This approach is `O(N)` for precomputation and `O(1)` for each query. Total `O(N)`. This should work.

// Let's refine the `precompute_dp` function and the main loop.
// `a_arr` will be 1-indexed. `a_arr[0]` will be unused.
// `a_arr[1]` will be set to `i` for each query.
// `a_arr[2]` to `a_arr[n]` are fixed.

#include <iostream>
#include <vector>
#include <numeric>

// dp[x] stores {total_y_increment, terminates} for starting the loop from x.
// total_y_increment is the sum of a_val's added to y from x until termination.
// terminates is true if it terminates, false if it cycles.
std::vector<std::pair<long long, bool>> dp;
std::vector<bool> visiting; // To detect cycles during DFS

// a_arr is 1-indexed. a_arr[0] is unused.
// a_arr[1] will be set for each query.
// a_arr[2]...a_arr[n] are fixed.
const std::vector<long long>* a_ptr; // Pointer to the actual a_arr

int N_val; // Store N globally or pass it around

std::pair<long long, bool> calculate_path(int current_x) {
    // Base cases for termination
    if (current_x <= 0 || current_x > N_val) {
        return {0, true}; // 0 additional y, terminates
    }

    // Cycle detection
    if (visiting[current_x]) {
        return {0, false}; // Cycle detected, does not terminate
    }

    // Memoization: if already computed
    // dp[current_x].first == 0 && dp[current_x].second == false means not computed yet (initial state)
    // If dp[current_x].second is true, it means it terminates and dp[current_x].first holds the value.
    // If dp[current_x].second is false and dp[current_x].first is non-zero, it means it cycles (this is not how we set it, we set it to {0, false} for cycle).
    // So, if dp[current_x].first is non-zero OR dp[current_x].second is true, it's computed.
    // A cycle result is {0, false}. A terminating result can be {0, true} (if it terminates immediately).
    // So, we need a third state for "not computed". Let's use a special value for first, e.g., -1.
    // Or, just check if visiting[current_x] is false and dp[current_x].second is true.
    // If dp[current_x].second is true, it's computed and terminates.
    // If dp[current_x].second is false AND dp[current_x].first is 0, it could be either not computed or a cycle.
    // We need a proper "not computed" flag. Let's use `dp[x].first == -1` for "not computed".
    if (dp[current_x].first != -1) { // Already computed or currently visiting (handled by `visiting` array)
        return dp[current_x];
    }

    visiting[current_x] = true; // Mark as currently visiting

    long long val_ax = (*a_ptr)[current_x];
    long long x_after_step2 = current_x + val_ax;
    long long y_added_step2 = val_ax;

    // Check termination after step 2
    if (x_after_step2 <= 0 || x_after_step2 > N_val) {
        visiting[current_x] = false; // Unmark
        dp[current_x] = {y_added_step2, true};
        return dp[current_x];
    }

    long long val_ax_after_step2 = (*a_ptr)[x_after_step2];
    long long x_after_step3 = x_after_step2 - val_ax_after_step2;
    long long y_added_step3 = val_ax_after_step2;

    // Recursively calculate for the next state
    std::pair<long long, bool> res = calculate_path(x_after_step3);

    visiting[current_x] = false; // Unmark

    if (!res.second) { // Cycle detected
        dp[current_x] = {0, false}; // Store {0, false} for cycle
    } else { // Terminates
        dp[current_x] = {y_added_step2 + y_added_step3 + res.first, true};
    }
    return dp[current_x];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    N_val = n;

    std::vector<long long> a(n + 1); // 1-indexed
    for (int k = 2; k <= n; ++k) {
        std::cin >> a[k];
    }
    a_ptr = &a; // Set the global pointer

    // Initialize dp table: -1 for first element means "not computed"
    dp.assign(n + 1, {-1, false});
    visiting.assign(n + 1, false);

    // Precompute dp values for x >= 2
    // We iterate from n down to 2 to ensure dependencies are met,
    // though DFS handles arbitrary order.
    for (int k = 2; k <= n; ++k) {
        if (dp[k].first == -1) { // If not computed yet
            calculate_path(k);
        }
    }

    // Process queries for a_1 = i
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current query

        long long current_x = 1;
        long long current_y = 0;

        // First pair of operations (step 2 then step 3) starting from x=1
        long long val_ax_initial = a[current_x];
        long long x_after_step2_initial = current_x + val_ax_initial;
        long long y_added_step2_initial = val_ax_initial;

        // Check termination after initial step 2
        if (x_after_step2_initial <= 0 || x_after_step2_initial > n) {
            std::cout << y_added_step2_initial << "\n";
            continue;
        }

        long long val_ax_after_step2_initial = a[x_after_step2_initial];
        long long x_after_step3_initial = x_after_step2_initial - val_ax_after_step2_initial;
        long long y_added_step3_initial = val_ax_after_step2_initial;

        // Now, the state is (x_after_step3_initial, y_added_step2_initial + y_added_step3_initial).
        // We need to find the result from x_after_step3_initial.
        // This is where we use the precomputed dp values.

        // Check termination after initial step 3
        if (x_after_step3_initial <= 0 || x_after_step3_initial > n) {
            std::cout << y_added_step2_initial + y_added_step3_initial << "\n";
            continue;
        }

        // If it reaches here, it means x_after_step3_initial is a valid index (2 to n).
        // We can directly use the precomputed dp value for this state.
        std::pair<long long, bool> res = dp[x_after_step3_initial];

        if (!res.second) { // Cycle detected
            std::cout << -1 << "\n";
        } else { // Terminates
            std::cout << y_added_step2_initial + y_added_step3_initial + res.first << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long min_a = elements[0].value;
    long long max_a = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s or all 2s)
    // min_f = min_a + min_a
    // max_f = max_a + max_a
    // goodness = (max_a + max_a) - (min_a + min_a) = 2 * (max_a - min_a)
    long long goodness1 = 2 * (max_a - min_a);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences
    // This case is only relevant if n >= 2.
    // The minimum possible f value is min_a + min_a.
    // The maximum possible f value is max_a + max_a + h.
    // The goodness would be (max_a + max_a + h) - (min_a + min_a).
    // This is generally worse than Case 1 if h is large.
    // However, we need to consider the specific partition.

    // Let's consider a partition where elements[0] is in S1 and elements[1] is in S2.
    // Or elements[0] is in S1 and elements[n-1] is in S2.
    // The crucial observation is that to minimize max_f - min_f, we want to make the range of f values as small as possible.
    // The values of f are (a_i + a_j) or (a_i + a_j + h).
    // The smallest possible sum is min_a + min_a.
    // The largest possible sum is max_a + max_a.
    // If we put min_a and max_a in different subsequences, then max_f will be at least max_a + min_a + h.
    // If we put min_a and max_a in the same subsequence, then max_f will be at least max_a + max_a.

    // Consider a partition where elements[0] is in S1, and elements[1]...elements[n-1] are in S2.
    // Or elements[0]...elements[n-2] are in S1, and elements[n-1] is in S2.
    // This is effectively splitting off one element.

    // Let's analyze the minimum and maximum f values for a general partition.
    // min_f = min( (a_i + a_j if same), (a_i + a_j + h if different) )
    // max_f = max( (a_i + a_j if same), (a_i + a_j + h if different) )

    // The smallest possible sum is elements[0].value + elements[0].value.
    // The largest possible sum is elements[n-1].value + elements[n-1].value.

    // If we put elements[0] in S1 and elements[1]...elements[n-1] in S2:
    // Pairs within S1: None (if n=1, but n>=2)
    // Pairs within S2: (elements[1].value + elements[1].value) ... (elements[n-1].value + elements[n-1].value)
    // Pairs between S1 and S2: (elements[0].value + elements[1].value + h) ... (elements[0].value + elements[n-1].value + h)

    // min_f = min(elements[1].value + elements[1].value, elements[0].value + elements[1].value + h)
    // max_f = max(elements[n-1].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)

    // This is the "split one element" strategy.
    // Let's try to put elements[0] in S1 and all others in S2.
    // min_f_split = elements[0].value + elements[1].value + h; // Smallest cross-subsequence sum
    // if (n > 2) { // If S2 has at least two elements
    //     min_f_split = std::min(min_f_split, elements[1].value + elements[1].value); // Smallest within S2 sum
    // }
    // max_f_split = elements[n-1].value + elements[n-1].value; // Largest within S2 sum
    // max_f_split = std::max(max_f_split, elements[0].value + elements[n-1].value + h); // Largest cross-subsequence sum

    // The minimum possible value of f is always `elements[0].value + elements[0].value` if elements[0] is paired with itself (not allowed) or another element in the same group.
    // Or `elements[0].value + elements[1].value` if elements[0] and elements[1] are in the same group.
    // Or `elements[0].value + elements[0].value + h` if elements[0] is paired with itself (not allowed) or another element in a different group.
    // Or `elements[0].value + elements[1].value + h` if elements[0] and elements[1] are in different groups.

    // Let's consider the four critical values:
    // A = elements[0].value + elements[1].value
    // B = elements[0].value + elements[n-1].value
    // C = elements[n-2].value + elements[n-1].value
    // D = elements[n-1].value + elements[n-1].value (if n-1 is paired with itself, but it's with another element)
    // E = elements[0].value + elements[0].value (if n-1 is paired with itself, but it's with another element)

    // The actual minimum possible sum of two distinct elements is elements[0].value + elements[1].value.
    // The actual maximum possible sum of two distinct elements is elements[n-2].value + elements[n-1].value.

    // Let's denote `a_min = elements[0].value`, `a_min2 = elements[1].value`, `a_max2 = elements[n-2].value`, `a_max = elements[n-1].value`.
    // The range of `a_i + a_j` is `[a_min + a_min2, a_max2 + a_max]`.
    // The range of `a_i + a_j + h` is `[a_min + a_min2 + h, a_max2 + a_max + h]`.

    // Option 1: All elements in one group.
    // min_f = a_min + a_min2
    // max_f = a_max2 + a_max
    // goodness = (a_max2 + a_max) - (a_min + a_min2)
    long long current_min_goodness = (elements[n-2].value + elements[n-1].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }

    // Option 2: Split the smallest element (elements[0]) into one group, and the rest into another.
    // S1 = {elements[0]}, S2 = {elements[1], ..., elements[n-1]}
    // If n=2, S1={elements[0]}, S2={elements[1]}. Only cross-subsequence pairs.
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[0].value + elements[1].value + h
    // goodness = 0. This is only possible if n=2.
    if (n == 2) {
        long long goodness_n2_split = 0;
        if (goodness_n2_split < current_min_goodness) {
            current_min_goodness = goodness_n2_split;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 2;
        }
    } else { // n > 2
        // min_f:
        //   - From S2: elements[1].value + elements[2].value
        //   - From S1-S2: elements[0].value + elements[1].value + h
        long long min_f_split_smallest = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);

        // max_f:
        //   - From S2: elements[n-2].value + elements[n-1].value
        //   - From S1-S2: elements[0].value + elements[n-1].value + h
        long long max_f_split_smallest = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);

        long long goodness_split_smallest = max_f_split_smallest - min_f_split_smallest;

        if (goodness_split_smallest < current_min_goodness) {
            current_min_goodness = goodness_split_smallest;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
