        }
    }

    // Option 3: Split the largest element (elements[n-1]) into one group, and the rest into another.
    // S1 = {elements[0], ..., elements[n-2]}, S2 = {elements[n-1]}
    // If n=2, this is the same as Option 2.
    if (n > 2) {
        // min_f:
        //   - From S1: elements[0].value + elements[1].value
        //   - From S1-S2: elements[0].value + elements[n-1].value + h
        long long min_f_split_largest = std::min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h);

        // max_f:
        //   - From S1: elements[n-3].value + elements[n-2].value (if n-1 is largest, n-2 is second largest, n-3 is third largest)
        //   - From S1-S2: elements[n-2].value + elements[n-1].value + h
        long long max_f_split_largest = std::max(elements[n-3].value + elements[n-2].value, elements[n-2].value + elements[n-1].value + h);

        long long goodness_split_largest = max_f_split_largest - min_f_split_largest;

        if (goodness_split_largest < current_min_goodness) {
            current_min_goodness = goodness_split_largest;
            for (int i = 0; i < n - 1; ++i) {
