        // p_idx = 0 (p[0] = 1)
        // h_idx = 0 (h[0] = 2)
        //   current_h = 2, first_uncovered_p = 1
        //   current_h + T = 2 + 2 = 4. 4 >= 1. Not too far left.
        //   current_h - T = 2 - 2 = 0. 0 <= 1. Not too far right.
        //   Can cover p[0]=1.
        //   time_to_reach = abs(2 - 1) = 1.
        //   remaining_time = 2 - 1 = 1.
        //   rightmost_reach = 1 + 1 = 2.
        //   p_idx advances: p[0]=1 <= 2. p_idx becomes 1.
        //                   p[1]=3 > 2. Stop.
        //   p_idx = 1.
        //
        // h_idx = 1 (h[1] = 5)
        //   current_h = 5, first_uncovered_p = p[1] = 3
        //   current_h + T = 5 + 2 = 7. 7 >= 3. Not too far left.
        //   current_h - T = 5 - 2 = 3. 3 <= 3. Not too far right.
        //   Can cover p[1]=3.
        //   time_to_reach = abs(5 - 3) = 2.
        //   remaining_time = 2 - 2 = 0.
        //   rightmost_reach = 3 + 0 = 3.
        //   p_idx advances: p[1]=3 <= 3. p_idx becomes 2.
        //                   p[2]=6 > 3. Stop.
        //   p_idx = 2.
        //
        // h_idx = 2 (h[2] = 6)
        //   current_h = 6, first_uncovered_p = p[2] = 6
        //   current_h + T = 6 + 2 = 8. 8 >= 6. Not too far left.
        //   current_h - T = 6 - 2 = 4. 4 <= 6. Not too far right.
        //   Can cover p[2]=6.
        //   time_to_reach = abs(6 - 6) = 0.
        //   remaining_time = 2 - 0 = 2.
        //   rightmost_reach = 6 + 2 = 8.
        //   p_idx advances: p[2]=6 <= 8. p_idx becomes 3.
        //                   p[3]=8 <= 8. p_idx becomes 4.
        //                   p_idx = 4 == m. Stop.
        //   p_idx = 4.
        //
        // Loop ends. p_idx = 4 == m. Return true.
        // This matches the example output.

        // The range of T is [0, 2 * 10^10] (max diff between p_i and h_i).
        // Binary search will take log(2 * 10^10) iterations, which is about 60.
        // Inside check, we iterate n + m times in worst case.
        // n, m <= 10^5. So 10^5 * 60 operations. This is feasible.

        long long current_head_pos = h[h_idx];
        long long first_uncovered_track = p[p_idx];

        // If the current head is too far to the left to reach the first uncovered track,
        // it cannot cover it. Since heads are sorted, this head cannot cover it.
        // We move to the next head.
        if (current_head_pos + T < first_uncovered_track) {
            continue;
        }

        // If the current head is too far to the right to reach the first uncovered track,
        // it cannot cover it. Since heads are sorted, all subsequent heads will also be
        // too far to the right. Thus, this track cannot be covered.
        if (current_head_pos - T > first_uncovered_track) {
            return false;
        }

        // The current head can reach `first_uncovered_track`.
        // Calculate the time it takes to reach `first_uncovered_track`.
        long long time_to_reach = std::abs(current_head_pos - first_uncovered_track);
        // Calculate the remaining time for sweeping.
        long long remaining_sweep_time = T - time_to_reach;
        // The rightmost track this head can cover by moving to `first_uncovered_track` and sweeping right.
        long long rightmost_covered_by_this_head = first_uncovered_track + remaining_sweep_time;

        // Advance `p_idx` past all tracks that are now covered.
        while (p_idx < m && p[p_idx] <= rightmost_covered_by_this_head) {
            p_idx++;
        }
    }

    // After checking all heads, if `p_idx` has reached `m`, all tracks are covered.
    return p_idx == m;
}

