void solve() {
    int n;
    long long k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long min_val = a[0];
    long long operations = 0;

    for (int i = 1; i < n; ++i) {
        // For each pile a[i] (where i > 0), we want to add min_val to it as many times as possible.
        // The current value of a[i] is a[i].
        // We can add min_val to it as long as a[i] + min_val <= k.
        // The number of times we can add min_val to a[i] is floor((k - a[i]) / min_val).
        if (a[i] < k) { // Only consider piles that are not already at k or above (though problem constraints say a_i <= k)
            operations += (k - a[i]) / min_val;
        }
    }

    std::cout << operations << std::endl;
}

