    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    // To maximize the binary number, we should prioritize '1's over '0's.
    // The letter 'n' is unique to "one". So, the number of '1's we can form
    // is limited by the count of 'n'.
    int num_ones = counts['n'];

    // After forming 'num_ones' "one"s, we use up 'n', 'o', 'e' characters.
    // The remaining characters are then used to form "zero"s.
    // The letter 'z' is unique to "zero". So, the number of '0's we can form
    // is limited by the count of 'z'.
    int num_zeros = counts['z'];

    // Output the '1's first, then the '0's.
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

