    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks. This will cost k trades.
        // So, total sticks required = (k * y) for coal + k for torches.
        long long total_sticks_required = k * y + k;

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) more sticks using the first trade offer.
        // Each first trade offer (1 stick for x sticks) effectively gives us (x - 1) net sticks.
        // Number of trades to acquire these sticks:
        // (total_sticks_required - 1) / (x - 1) rounded up.
        long long sticks_to_gain = total_sticks_required - 1;
        long long stick_acquisition_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = trades for acquiring sticks + trades for acquiring coal.
        // Trades for acquiring coal is k.
        long long total_trades = stick_acquisition_trades + k;

        std::cout << total_trades << std::endl;
    }
    return 0;
}

