                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_minus_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this position,
        // but we still need to update has_one/has_minus_one for subsequent positions.
        // The values of has_one and has_minus_one are cumulative up to index i-1.
        // They are correctly maintained by the loop structure.
    }

    std::cout << "YES\n";
}

