int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // This is because all other elements p[j] (j!=i) must be <= n-1.
        // If p[i] was n-1, then max_val_in_row would be at most n-1.
        // If max_val_in_row is n-1, it means there is some p[j] = n-1,
        // and p[i] must be >= n-1.
        // If p[i] = n-1, then min(p[i], p[j]) for all j!=i would be <= n-1.
        // If p[i] = n, then min(p[i], p[j]) for all j!=i would be p[j].
        // The maximum of these p[j] values would be n-1.
        // So, if max_val_in_row is n-1, p[i] must be n.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

