int main() {
    // Optimize C++ standard streams for faster input/output.
    // This unties cin/cout from stdio and disables synchronization.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t; // Read the number of test cases

    while (t--) {
        int n;
        std::cin >> n; // Read the number of days for the current test case

        // Use a vector to store prices.
        // For N up to 150,000, a vector is efficient.
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i]; // Read prices
        }

        if (n == 0) { // Edge case: no days
            std::cout << 0 << "\n";
            continue;
        }
        if (n == 1) { // Edge case: only one day, no later prices to compare
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        // Initialize min_suffix with the last price, as it's the minimum
        // for the suffix starting at n-1.
        int min_suffix = a[n - 1];

        // Iterate from the second to last day backwards to the first day.
        // For each day i, min_suffix will hold the minimum price
        // from day i+1 to day n-1.
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix) {
                // If the current price a[i] is greater than the minimum
                // price found in any subsequent day, then a[i] is a bad price.
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix, it means
                // there is no later price strictly smaller than a[i].
                // Update min_suffix to include a[i] for the next iteration.
                // This is crucial: min_suffix should always be the minimum
                // of prices from a[i+1] to a[n-1].
                // When we move from i to i-1, the new suffix starts at i.
                // So, min_suffix for i-1 will be min(a[i], min_suffix_for_i).
                min_suffix = std::min(min_suffix, a[i]);
            }
        }
        std::cout << bad_prices_count << "\n"; // Print the result for the current test case
    }

    return 0;
}

