    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = 0; // Represents the last position from which a right jump was possible (0 or an 'R' cell)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we are at an 'R' cell (index i, which is cell i+1),
                // the gap from the last 'R' cell (or 0) to this 'R' cell is (i+1) - last_r_pos.
                // The frog must be able to jump over this gap.
                max_gap = std::max(max_gap, (i + 1) - last_r_pos);
                last_r_pos = i + 1; // Update last_r_pos to the current 'R' cell
            }
        }

        // After iterating through all cells, we need to consider the gap from the last 'R' cell
        // (or 0 if no 'R' cells) to the target cell n+1.
        max_gap = std::max(max_gap, (n + 1) - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

