    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians.
            // The remaining students are (c - mid) coders, (m - mid) mathematicians, and x unspecialized.
            // The total number of remaining students is (c - mid) + (m - mid) + x.
            // These remaining students must fill the remaining 'mid' slots in the teams.
            // Each team needs 3 members. 'mid' teams need 3 * 'mid' members.
            // We've already accounted for 'mid' coders and 'mid' mathematicians.
            // So, we need 'mid' more members from the remaining pool.
            // The remaining pool is (c - mid) + (m - mid) + x.
            // If this sum is >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

