int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use in the alternating sequence to generate k distinct differences

    // Generate k distinct differences: 1, 2, ..., k
    // This is done by alternating between left and right pointers.
    // The sequence will be: left, right, left+1, right-1, left+2, right-2, ...
    // The differences generated will be:
    // |right - left| = k
    // |(left+1) - right| = k-1
    // |(right-1) - (left+1)| = k-2
    // ...
    // This generates differences k, k-1, ..., 1.
    // The numbers used are 1, 2, ..., k+1.

    while (left <= right) {
        std::cout << left << " ";
        if (left < right) { // Avoid printing the same number twice if left == right
            std::cout << right << " ";
        }
        left++;
        right--;
    }

    // After generating k distinct differences using numbers 1 to k+1,
    // the remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order.
    // The differences generated by these appended numbers will all be 1.
    // Since 1 is already among the k distinct differences generated above (unless k=0, but k>=1),
    // this does not introduce new distinct differences.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair nice staircase
        long long k = 1;            // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
                                    // k = 2^p - 1 for p = 1, 2, 3, ...
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            k = k * 2 + 1; // Next nice staircase has 2k+1 stairs
            // Cost for a nice staircase with k stairs is k * (k + 1) / 2
            // current_cost = k * (k + 1) / 2;
            // This can be simplified.
            // Let C(k) be the cost for k stairs.
            // C(k) = k * (k+1) / 2
            // Next k' = 2k+1
            // C(k') = (2k+1) * (2k+2) / 2 = (2k+1) * (k+1)
            // C(k') = 2k^2 + 3k + 1
            // C(k') = 2 * (k * (k+1) / 2) + k^2 + 2k + 1
            // C(k') = 2 * C(k) + k^2 + 2k + 1
            // This is not the most efficient way to calculate.
            // The sequence of costs is:
            // k=1: cost = 1*(2)/2 = 1
            // k=3: cost = 3*(4)/2 = 6
            // k=7: cost = 7*(8)/2 = 28
            // k=15: cost = 15*(16)/2 = 120
            // The relationship between consecutive costs C_p and C_{p+1} where k_p = 2^p - 1:
            // C_{p+1} = (2^(p+1)-1) * (2^(p+1)) / 2
            // C_p = (2^p-1) * (2^p) / 2
            // C_{p+1} = (2 * (2^p) - 1) * (2 * (2^p)) / 2
            // C_{p+1} = (2 * (2^p) - 1) * (2^p)
            // C_{p+1} = 2 * (2^p)^2 - 2^p
            // C_p = (2^p)^2 - 2^p / 2
            // C_{p+1} = 2 * C_p + 2^p
            // This is also not quite right.
            // Let's use the direct formula:
            // current_cost = k * (k + 1) / 2;
            // The next k is (k_old * 2 + 1).
            // So, next_cost = (k_old * 2 + 1) * (k_old * 2 + 2) / 2
            // next_cost = (k_old * 2 + 1) * (k_old + 1)
            // next_cost = 2 * k_old * (k_old + 1) + (k_old + 1)
            // next_cost = 4 * (k_old * (k_old + 1) / 2) + (k_old + 1)
            // next_cost = 4 * current_cost_old + (k_old + 1)
            // This is the correct recurrence for the cost.
            current_cost = 4 * current_cost + (k + 1);
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    std::vector<int> available_numbers;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But as a safeguard, if q_i was already used, it's impossible.
                // However, q_i > q_{i-1} implies q_i is a new max, so it cannot be q_j for j < i.
                // And q_i cannot be p_j for j < i because p_j <= q_{j} <= q_{i-1} < q_i.
                // So this check is technically redundant for a valid q.
            }
            used_numbers.insert(q[i]);
        } else {
            // If q_i == q_{i-1}, p_i must be some number less than or equal to q_{i-1}
            // and not yet used. We will fill these later.
            p[i] = -1; // Placeholder
        }
    }

    // Collect all numbers from 1 to n that have not been used in p_i where p_i = q_i
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order

    int current_available_idx = 0;
    for (int i = 1; i < n; ++i) {
        if (p[i] == -1) { // This is a position where p_i needs to be filled
            if (current_available_idx >= available_numbers.size()) {
                // Not enough available numbers to fill all positions
                std::cout << -1 << "\n";
                return;
            }
            int num_to_place = available_numbers[current_available_idx];
            if (num_to_place > q[i]) {
                // The available number is greater than q_i, which means
                // placing it here would make q_i incorrect (q_i would become num_to_place)
                std::cout << -1 << "\n";
                return;
            }
            p[i] = num_to_place;
            current_available_idx++;
        }
    }

    // Final check: ensure all numbers 1 to n are used exactly once
    // This is implicitly handled by the construction if no -1 was printed.
    // And ensure prefix maximums match.
    // The construction guarantees p_i <= q_i for all i.
    // For p_i = q_i, it's correct.
    // For p_i < q_i, we picked the largest available number <= q_i.
    // Since q_i == q_{i-1}, and p_i <= q_i, the maximum up to i will still be q_{i-1} (which is q_i).
    // So the prefix maximums will match.

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

