            } else if (c == 'U') {
                countU++;
            } else if (c == 'D') {
                countD++;
            }
        }

        int horiz_moves = std::min(countL, countR);
        int vert_moves = std::min(countU, countD);

        if (horiz_moves == 0 && vert_moves == 0) {
            std::cout << 0 << "\n\n";
        } else if (horiz_moves == 0) { // Only vertical moves possible
            std::cout << 2 << "\n";
            std::cout << "UD\n";
        } else if (vert_moves == 0) { // Only horizontal moves possible
            std::cout << 2 << "\n";
            std::cout << "LR\n";
        } else {
            int total_len = 2 * horiz_moves + 2 * vert_moves;
            std::cout << total_len << "\n";
            std::string result = "";
            for (int i = 0; i < horiz_moves; ++i) {
                result += 'L';
            }
            for (int i = 0; i < vert_moves; ++i) {
                result += 'U';
            }
            for (int i = 0; i < horiz_moves; ++i) {
                result += 'R';
            }
            for (int i = 0; i < vert_moves; ++i) {
                result += 'D';
            }
            std::cout << result << "\n";
        }
    }
    return 0;
}

