#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n <= 2) {
        std::cout << n << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return;
    }

    std::vector<int> result;
    result.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] and p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] and p[i] < p[i+1]
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result.push_back(p[i]);
        }
    }
    result.push_back(p[n-1]);

    std::cout << result.size() << std::endl;
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x_i, we need to find all x_k such that x_k - x_i <= d.
        // Since x is sorted, we can use a two-pointer approach.
        // The right_ptr will always be non-decreasing.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // Now, all points from x[i] to x[right_ptr-1] satisfy x_k - x_i <= d.
        // We need to choose two distinct points x_j and x_k such that i < j < k.
        // These two points must be chosen from the range (x_i, x[right_ptr-1]].
        // The number of points available for x_j and x_k is (right_ptr - 1) - i.
        // Let m = (right_ptr - 1) - i. These are the points x_{i+1}, ..., x_{right_ptr-1}.
        // If m < 2, we cannot choose two distinct points.
        // Otherwise, we need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = (long long)(right_ptr - 1) - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

