                    // we can swap a[i] and a[last_diff_10]. This costs (i - last_diff_10).
                    // This fixes both positions.
                    cost += (i - last_diff_10);
                    last_diff_10 = -1; // This 10 difference is now resolved
                } else {
                    // No pending 10 difference to pair with.
                    // This 01 difference is now pending.
                    last_diff_01 = i;
                }
            } else { // a[i] = '1', b[i] = '0' (Type 10 difference)
                if (last_diff_01 != -1) { // Found a previous '0' in a where b has '1'
                    // We can swap a[last_diff_01] and a[i]
                    // This fixes both positions. Cost is (i - last_diff_01).
                    cost += (i - last_diff_01);
                    last_diff_01 = -1; // This 01 difference is now resolved
                } else {
                    // No pending 01 difference to pair with.
                    // This 10 difference is now pending.
                    last_diff_10 = i;
                }
            }
        }
    }

    // After iterating through all positions, any remaining pending differences must be fixed by flipping.
    // Each pending difference (either 01 or 10) requires one flip.
    if (last_diff_01 != -1) {
        cost += 1;
    }
    if (last_diff_10 != -1) {
        cost += 1;
    }

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
