#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    // Box 1: (-inf, -1]
    // Box 2: (-1, 0)
    // Box 3: (0, 1)
    // Box 4: [1, inf)

    // Possible outcomes for each box
    bool can_be_box1 = false;
    bool can_be_box2 = false;
    bool can_be_box3 = false;
    bool can_be_box4 = false;

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) can_be_box1 = true;
        if (b == 1) can_be_box2 = true;
        if (c == 1) can_be_box3 = true;
        if (d == 1) can_be_box4 = true;
    } else { // total_toys > 1
        // Analyze parity of negative numbers
        // The final sign depends on the parity of negative numbers multiplied.
        // If an even number of negatives are multiplied, the result is positive.
        // If an odd number of negatives are multiplied, the result is negative.
        // The number of negative toys is A + B.
        // The number of multiplications is total_toys - 1.
        // The final toy's sign is determined by the parity of (A+B) if all toys are multiplied.
        // However, we can choose which toys to multiply.
        // The parity of negative numbers can be flipped by multiplying two negative numbers (N*N = P)
        // or by multiplying a negative and a positive (N*P = N).
        // The parity of negative numbers in the system changes by 0 or 2 (mod 2) with each multiplication.
        // So, the final sign can be positive if (A+B) is even, and negative if (A+B) is odd.
        // This means if A+B is even, the final toy can be positive.
        // If A+B is odd, the final toy can be negative.
        // If A+B is even, it's also possible to make it negative by ensuring one negative toy is left to multiply with a positive product.
        // If A+B is odd, it's also possible to make it positive by ensuring one negative toy is left to multiply with a negative product.
        // In general, if there's at least one negative toy (A+B > 0), we can always make the final product negative.
        // If there are at least two negative toys (A+B > 1), we can always make the final product positive.
        // If A+B == 0, the final product must be positive.
        // If A+B == 1, the final product must be negative.

        // Let's consider the magnitude.
        // We can always make the magnitude arbitrarily large if there's at least one toy with |fun| >= 1 (A+D > 0).
        // We can always make the magnitude arbitrarily small (but > 0) if there's at least one toy with 0 < |fun| < 1 (B+C > 0).

        // Case 1: Final toy is positive (Box 3 or Box 4)
        // This requires an even number of negative toys to be multiplied.
        // If A+B is even, we can achieve a positive product.
        // If A+B is odd, we can achieve a positive product if A+B >= 2 (multiply two negatives first).
        // So, a positive product is possible if A+B != 1.
        // If A+B == 0, it's always positive.
        // If A+B == 1, it's always negative.
        // If A+B >= 2, it can be positive or negative.

        // Can be Box 3 (0, 1) or Box 4 [1, inf)
        // Condition for positive product: (A+B) != 1
        // If A+B == 0, all toys are positive.
        // If A+B == 1, one negative toy. Final product must be negative.
        // If A+B >= 2, we can choose to make it positive (e.g., multiply two negatives first).

        // Can the final product be positive?
        bool can_be_positive = (a + b != 1);

        // Can the final product be negative?
        bool can_be_negative = (a + b != 0);

        // If A+B == 0, all toys are positive. Final product must be positive.
        // If A+B == 1, one negative toy. Final product must be negative.
        // If A+B >= 2, we can make it positive or negative.

        // Box 4: [1, inf)
        // To get a value >= 1, we need at least one toy with |fun| >= 1 (A+D > 0).
        // If A+D == 0, all toys have |fun| < 1. The product of any number of such toys will always be < 1.
        // So, if A+D == 0, Box 4 is impossible.
        if (can_be_positive && (a + d > 0)) {
            can_be_box4 = true;
        }

        // Box 3: (0, 1)
        // To get a value in (0, 1), we need to be able to make the magnitude < 1.
        // This is always possible if B+C > 0 (i.e., there's at least one toy with |fun| < 1).
        // If B+C == 0, then all toys have |fun| >= 1. The product of any number of such toys will always be >= 1.
        // So, if B+C == 0, Box 3 is impossible.
        if (can_be_positive && (b + c > 0)) {
            can_be_box3 = true;
        }

        // Box 1: (-inf, -1]
        // To get a value <= -1, we need a negative product AND at least one toy with |fun| >= 1 (A+D > 0).
        if (can_be_negative && (a + d > 0)) {
            can_be_box1 = true;
        }

        // Box 2: (-1, 0)
        // To get a value in (-1, 0), we need a negative product AND at least one toy with 0 < |fun| < 1 (B+C > 0).
        if (can_be_negative && (b + c > 0)) {
            can_be_box2 = true;
        }
    }

    std::cout << (can_be_box1 ? "Ya" : "Tidak") << " "
              << (can_be_box2 ? "Ya" : "Tidak") << " "
              << (can_be_box3 ? "Ya" : "Tidak") << " "
              << (can_be_box4 ? "Ya" : "Tidak") << std::endl;
}

