bool is_good(const std::vector<int>& b) {
    if (b.empty()) {
        return true;
    }
    int m = b.size();
    int left = 0;
    int right = m - 1;
    int last_c_val = 0; // Smallest possible value for the first element

    while (left <= right) {
        if (b[left] <= last_c_val && b[right] <= last_c_val) {
            return false; // Both ends are too small
        }

        if (b[left] <= last_c_val) { // Only right is an option
            last_c_val = b[right];
            right--;
        } else if (b[right] <= last_c_val) { // Only left is an option
            last_c_val = b[left];
            left++;
        } else { // Both are options
            if (b[left] < b[right]) {
                last_c_val = b[left];
                left++;
            } else {
                last_c_val = b[right];
                right--;
            }
        }
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n == 1) {
            std::cout << 0 << "\n";
            continue;
        }

        // Find the longest suffix that is non-increasing
        int p = n - 1;
        while (p > 0 && a[p-1] >= a[p]) {
            p--;
        }
        // Now a[p...n-1] is non-increasing.
        // We need to find the first element from the left (a[k])
        // such that a[k...n-1] can be made good.
        // The elements a[p...n-1] are already sorted in reverse.
        // We need to find the first index `k` such that `a[k]` is the start of a non-decreasing sequence
        // and `a[k-1] < a[k]`.
        // The elements from `a[k]` to `a[p-1]` must be strictly increasing.
        // The elements from `a[p]` to `a[n-1]` must be strictly decreasing.
        // The combined sequence `a[k...p-1]` (increasing) and `a[p...n-1]` (decreasing)
        // forms a "valley" shape.
        // The prefix to erase is `0...k-1`.

        // Find the first element from the right that breaks the non-decreasing suffix
        // i.e., find the largest `k` such that `a[k] < a[k+1]` for `k < n-1`.
        // The suffix `a[k+1...n-1]` is non-decreasing.
        // We are looking for the first element `a[i]` from the right such that `a[i] < a[i+1]`.
        // The elements `a[i+1], ..., a[n-1]` are non-decreasing.
        // Example: [1, 3, 1, 4, 5, 3, 2]
        // n=7
        // p=6, a[6]=2
        // p=5, a[5]=3, a[5] >= a[6] (3 >= 2) -> p=5
        // p=4, a[4]=5, a[4] >= a[5] (5 >= 3) -> p=4
        // p=3, a[3]=4, a[3] < a[4] (4 < 5) -> stop. p=4.
        // Suffix a[4...6] = [5, 3, 2] is non-increasing.
        // The first element of this suffix is a[4]=5.
        // The elements before it are a[0...3] = [1, 3, 1, 4].
        // We need to find the point where the sequence stops being non-decreasing from the right.
        // This is `p` in the code. `a[p...n-1]` is non-increasing.
        // Example: [4, 3, 3, 8, 4, 5, 2]
        // n=7
        // p=6, a[6]=2
        // p=5, a[5]=5, a[5] >= a[6] (5 >= 2) -> p=5
        // p=4, a[4]=4, a[4] < a[5] (4 < 5) -> stop. p=5.
        // Suffix a[5...6] = [5, 2] is non-increasing.
        // The first element of this suffix is a[5]=5.
        // The elements before it are a[0...4] = [4, 3, 3, 8, 4].
        // We need to find the point where the sequence stops being non-decreasing from the right.
        // This is `p` in the code. `a[p...n-1]` is non-increasing.
        // The elements `a[p], a[p+1], ..., a[n-1]` are such that `a[p] >= a[p+1] >= ... >= a[n-1]`.

        // Now, we need to find the point where the sequence stops being non-decreasing from the right
        // for the *remaining* part.
        // We are looking for the smallest `k` such that `a[k...n-1]` is good.
        // The elements `a[p...n-1]` are already non-increasing.
        // We need to find the smallest `k` such that `a[k...p-1]` is non-decreasing.
        // So, we find the largest `k_prime` such that `a[k_prime] < a[k_prime+1]`
        // and `k_prime < p`.
        // The elements `a[k_prime+1], ..., a[p-1]` are non-decreasing.
        // The elements `a[p], ..., a[n-1]` are non-increasing.
        // The combined sequence `a[k_prime+1...p-1]` (non-decreasing) and `a[p...n-1]` (non-increasing)
        // forms a "mountain" shape (or a "valley" if read from right to left).
        // The prefix to erase is `0...k_prime`.

        // Find the first index `i` from the right such that `a[i] < a[i+1]`.
        // All elements `a[i+1], ..., a[n-1]` are non-decreasing.
        // This `i` is `p-1` in the previous logic.
        // Let's re-evaluate `p`.
        // `p` is the first index from the left such that `a[p...n-1]` is non-increasing.
        // Example: [1, 3, 1, 4, 5, 3, 2]
        // n=7
        // i=6, a[6]=2
        // i=5, a[5]=3, a[5] >= a[6] (3 >= 2)
        // i=4, a[4]=5, a[4] >= a[5] (5 >= 3)
        // i=3, a[3]=4, a[3] < a[4] (4 < 5) -> stop. `i` is 3.
        // So, `a[4...6]` is `[5, 3, 2]`. This is the non-increasing suffix.
        // The index `p` from the problem description is `4`.
        // Now we need to find the first index `k` from the left such that `a[k...p-1]` is non-decreasing.
        // `a[0...p-1]` is `[1, 3, 1, 4]`.
        // We need to find the first index `k` such that `a[k] < a[k+1]` for `k < p-1`.
        // `k_prime = p-1`.
        // While `k_prime > 0` and `a[k_prime-1] <= a[k_prime]` and `k_prime >= p` is not true.
        // We need to find the first index `k` from the left such that `a[k...n-1]` is good.
        // The elements `a[k], ..., a[p-1]` must be non-decreasing.
        // The elements `a[p], ..., a[n-1]` must be non-increasing.
        // This means `a[k] <= a[k+1] <= ... <= a[p-1]` and `a[p] >= a[p+1] >= ... >= a[n-1]`.
        // The overall structure is `/\` or `\`.
        // The `p` we found is the peak of the `/\` or the start of `\`.
        // We need to find the smallest `k` such that `a[k...p-1]` is non-decreasing.
        // So, we iterate `k` from `p-1` down to `0`.
        // If `a[k] > a[k+1]`, then `k` is the start of the non-decreasing part.
        // The prefix to erase is `0...k`.

        // Find the rightmost index `i` such that `a[i] < a[i+1]`.
        // All elements `a[i+1], ..., a[n-1]` are non-decreasing.
        // This is the `p` from the problem description.
        int i = n - 1;
        while (i > 0 && a[i-1] >= a[i]) {
            i--;
        }
        // Now `a[i...n-1]` is non-increasing.
        // `i` is the first element of this non-increasing suffix.
        // Example: [1, 3, 1, 4, 5, 3, 2] -> i=4 (a[4]=5)
        // Example: [4, 3, 3, 8, 4, 5, 2] -> i=5 (a[5]=5)
        // Example: [1, 2, 3, 4] -> i=3 (a[3]=4)
        // Example: [5, 4, 3, 2, 3] -> i=4 (a[4]=3)

        // Now, from `i-1` down to `0`, find the first index `j` such that `a[j] > a[j+1]`.
        // All elements `a[j+1], ..., a[i-1]` are non-decreasing.
        // This `j` is the last element of the prefix to erase.
        int j = i;
        while (j > 0 && a[j-1] <= a[j]) {
            j--;
        }
        // Now `a[j...i-1]` is non-decreasing.
        // `j` is the first element of this non-decreasing part.
        // Example: [1, 3, 1, 4, 5, 3, 2]
        // i=4 (a[4]=5)
        // j=4, a[3]=4, a[3] <= a[4] (4 <= 5) -> j=3
        // j=3, a[2]=1, a[2] <= a[3] (1 <= 4) -> j=2
        // j=2, a[1]=3, a[1] > a[2] (3 > 1) -> stop. `j` is 2.
        // The prefix to erase is `0...j-1`. Length `j`.
        // For [1, 3, 1, 4, 5, 3, 2], j=2. Erase 2 elements. Result [1, 4, 5, 3, 2].
        // This is good. (1,4,5,3,2) -> (1,2,3,4,5)
        // Example: [4, 3, 3, 8, 4, 5, 2]
        // i=5 (a[5]=5)
        // j=5, a[4]=4, a[4] <= a[5] (4 <= 5) -> j=4
        // j=4, a[3]=8, a[3] > a[4] (8 > 4) -> stop. `j` is 4.
        // The prefix to erase is `0...j-1`. Length `j`.
        // For [4, 3, 3, 8, 4, 5, 2], j=4. Erase 4 elements. Result [4, 5, 2].
        // This is good. (4,5,2) -> (2,4,5)
        // Example: [1, 2, 3, 4]
        // i=3 (a[3]=4)
        // j=3, a[2]=3, a[2] <= a[3] (3 <= 4) -> j=2
        // j=2, a[1]=2, a[1] <= a[2] (2 <= 3) -> j=1
        // j=1, a[0]=1, a[0] <= a[1] (1 <= 2) -> j=0
        // j=0. Erase 0 elements. Result [1, 2, 3, 4]. Good.
        // Example: [5, 4, 3, 2, 3]
        // i=4 (a[4]=3)
        // j=4, a[3]=2, a[3] <= a[4] (2 <= 3) -> j=3
        // j=3, a[2]=3, a[2] > a[3] (3 > 2) -> stop. `j` is 3.
        // Erase 3 elements. Result [2, 3]. Good.

        std::cout << j << "\n";
    }
    return 0;
}

#include <iostream>
