#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost for the median element itself
    operations += std::abs(a[median_idx] - s);

    // Cost for elements to the left of the median
    // These elements must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Cost for elements to the right of the median
    // These elements must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElementsA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareElementsB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<Element> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElementsA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareElementsB);

    // Create the result array A_prime
    // A_prime[original_index_of_B_element] = A_element_value
    std::vector<long long> A_prime(m);

    // The strategy is to pair the largest A_i with the smallest B_j,
    // the second largest A_i with the second smallest B_j, and so on.
    // This means A[m-1] (largest A) is paired with B[0] (smallest B),
    // A[m-2] (second largest A) is paired with B[1] (second smallest B), etc.
    // In general, A[m-1-i] is paired with B[i].
    // The value A[m-1-i].value should be placed at the original index of B[i].
    for (int i = 0; i < m; ++i) {
        A_prime[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) return true; // An empty sequence can be considered a permutation of length 0
    if (len > arr.size()) return false; // Not enough elements

    std::vector<bool> seen(len + 1, false);
    int max_val = 0;

    for (int i = 0; i < len; ++i) {
        int val = arr[i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<int, int>> results;

    // Precompute prefix permutation validity
    std::vector<bool> is_prefix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_prefix(n + 1, false);
        int max_prefix_val = 0;
        bool possible_prefix = true;
        for (int l1 = 1; l1 <= n; ++l1) {
            int val = a[l1 - 1];
            if (val < 1 || val > l1 || seen_prefix[val]) {
                possible_prefix = false;
            }
            if (possible_prefix) {
                seen_prefix[val] = true;
                if (val > max_prefix_val) {
                    max_prefix_val = val;
                }
                if (max_prefix_val == l1) {
                    is_prefix_perm[l1] = true;
                }
            }
        }
    }

    // Precompute suffix permutation validity
    std::vector<bool> is_suffix_perm(n + 1, false);
    if (n > 0) {
        std::vector<bool> seen_suffix(n + 1, false);
        int max_suffix_val = 0;
        bool possible_suffix = true;
        for (int l2 = 1; l2 <= n; ++l2) {
            int val = a[n - l2];
            if (val < 1 || val > l2 || seen_suffix[val]) {
                possible_suffix = false;
            }
            if (possible_suffix) {
                seen_suffix[val] = true;
                if (val > max_suffix_val) {
                    max_suffix_val = val;
                }
                if (max_suffix_val == l2) {
                    is_suffix_perm[l2] = true;
                }
            }
        }
    }

    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

