                countR++;
            } else if (c == 'S') {
                countS++;
            } else { // c == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else { // countP is the largest
            most_frequent_bot_move = 'P';
        }

        char optimal_player_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << optimal_player_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k == 0) { // No wins possible even after using all k changes
            std::cout << 0 << "\n";
            continue;
        }

        // If we can make all games wins, that's the maximum possible score.
        // This happens if initial_wins + k >= n.
        if (initial_wins + k >= n) {
            std::cout << 2 * n - 1 << "\n";
            continue;
        }

        // If we cannot make all games wins, we need to be strategic.
        // We want to convert 'L's to 'W's.
        // Each 'W' gives 1 point. An additional 1 point if it's preceded by 'W'.
        // So, we want to maximize 'W's, and then maximize adjacent 'W's.

        // First, find the segments of 'L's between 'W's.
        // These are the gaps we can fill to connect 'W' streaks.
        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) {
                    first_W = i;
                }
                last_W = i;
            }
        }

        // If there are no initial 'W's, we just convert k 'L's to 'W's.
        // The score will be 2*k - 1 (if k > 0), or 0 (if k = 0).
        if (first_W == -1) { // All 'L's initially
            std::cout << std::max(0, 2 * k - 1) << "\n";
            continue;
        }

        // Collect lengths of 'L' segments between 'W's
        int current_L_streak = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_L_streak++;
            } else { // s[i] == 'W'
                if (current_L_streak > 0) {
                    gaps.push_back(current_L_streak);
                }
                current_L_streak = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_score = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                current_score++;
                if (i > 0 && s[i-1] == 'W') {
                    current_score++;
                }
            }
        }

        // Fill the smallest gaps first
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W (2*gap_len points), plus 1 for connecting
            } else {
                break; // Cannot fill this gap or larger ones
            }
        }

        // Use remaining k to convert 'L's to 'W's at the ends or within existing 'L' blocks
        // Each such conversion adds 2 points (1 for the W itself, 1 for connecting to a W)
        // unless it's the very first W in the string.
        // Since we've already handled the case where initial_wins + k >= n,
        // and the case where first_W == -1, we know there's at least one W,
        // and we can't make all games W.
        // So any additional W will either extend a streak or start a new one.
        // If it extends a streak, it's 2 points.
        // If it starts a new streak, it's 1 point.
        // However, we've already counted initial_wins.
        // Any new W will be adjacent to an existing W (if we fill a gap)
        // or extend a streak at the ends.
        // The simplest way to think about it is: each new W adds 1 point for itself.
        // If it's adjacent to another W, it adds another 1 point.
        // By converting k 'L's to 'W's, we add k 'W's.
        // Each of these 'W's contributes 1 point.
        // Additionally, if it's adjacent to another 'W', it contributes another 1 point.
        // The gaps strategy already accounts for the +1 for connecting.
        // The remaining k changes will convert 'L's to 'W's.
        // Each such 'W' will contribute 2 points if it's adjacent to an existing 'W'
        // (either at the ends of the string or within an 'L' block that wasn't fully filled).
        // Since we're trying to maximize, we'll always try to place new 'W's next to existing 'W's.
        // The only exception is if we have no 'W's at all, which is handled.
        // So, each remaining k change adds 2 points.
        current_score += 2 * k;

        std::cout << current_score << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end()); // Sort w in ascending order

        long long total_happiness = 0;

        // Handle friends who get w_i = 1 first
        // These friends should get the largest available numbers, and their happiness is 2 * number.
        // Since w is sorted, w_i = 1 will be at the beginning.
        // We iterate from the end of 'a' for these.
        int a_ptr_max = n - 1;
        for (int i = 0; i < k; ++i) {
            if (w[i] == 1) {
                total_happiness += 2 * a[a_ptr_max];
                a_ptr_max--;
            } else {
                // All remaining w_i will be > 1 because w is sorted.
                // Break and handle them in the next loop.
                break;
            }
        }

        // Handle friends who get w_i > 1
        // These friends need one max and one min.
        // To maximize sum of maxes, give largest remaining numbers as maxes.
        // To maximize sum of mins, give largest remaining numbers as mins.
        // The largest w_i values (which are at the end of sorted w) should get the smallest numbers
        // as their minimums, to leave larger numbers for other friends' minimums or maximums.
        // So, iterate w from largest to smallest (k-1 down to 0).
        // The largest w_i values will consume more small numbers.
        int a_ptr_min = 0;
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_max]; // Max value for this friend
                a_ptr_max--;
                total_happiness += a[a_ptr_min]; // Min value for this friend
                a_ptr_min += (w[i] - 1); // Consume w[i]-1 smallest numbers
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

