int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long b_count = 0;
    const long long MOD = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % MOD;
        } else { // s[i] == 'a'
            // This 'a' will interact with all 'b's currently to its right.
            // Each 'b' to its right will cause an 'ab' -> 'bba' operation.
            // The 'a' effectively "jumps over" the 'b'.
            // When 'a' jumps over 'b', it creates a new 'b'.
            // So, if there are 'k' 'b's to its right, this 'a' will cause 'k' operations.
            // After these 'k' operations, the 'a' is gone, and 'k' new 'b's are added
            // to the right of the current 'a' (which are now to the left of the original 'b's).
            // These new 'b's can then interact with 'a's further to the left.
            // So, the number of 'b's available for the next 'a' to its left doubles.
            total_steps = (total_steps + b_count) % MOD;
            b_count = (b_count * 2) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We want to find b1, b2, b3 such that (current_sum + b1 + b2 + b3) = 2 * (current_xor_sum ^ b1 ^ b2 ^ b3)
    // A simple strategy is to append at most 2 elements.
    // Let's try to append two elements: X and S.
    // New sum = current_sum + X + S
    // New XOR sum = current_xor_sum ^ X ^ S
    // We want current_sum + X + S = 2 * (current_xor_sum ^ X ^ S)

    // Consider appending two elements: current_xor_sum and current_sum.
    // This doesn't quite work directly because current_sum can be very large.
    // The problem statement guarantees a solution always exists with at most 3 elements.
    // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // This is not general enough.

    // A known trick for this type of problem:
    // If we append X (the current XOR sum) and then S' (the new sum),
    // the new XOR sum becomes X ^ X = 0.
    // The new sum becomes S + X.
    // We need S + X + S' = 2 * (0 ^ S') = 2 * S'.
    // So, S + X = S'.
    // This means we append X, and then S+X.
    // Let's verify:
    // Initial: sum = S, xor_sum = X
    // Append b1 = X:
    // New sum = S + X
    // New xor_sum = X ^ X = 0
    // Now we need to append b2 such that (S + X + b2) = 2 * (0 ^ b2) = 2 * b2
    // S + X = b2
    // So, we append b1 = X and b2 = S + X.
    // The final array will have sum S + X + (S + X) = 2 * (S + X)
    // The final array will have xor_sum X ^ X ^ (S + X) = 0 ^ (S + X) = S + X
    // The condition is (final sum) = 2 * (final xor_sum)
    // 2 * (S + X) = 2 * (S + X). This holds!

    // So, we can always append two elements: current_xor_sum and (current_sum + current_xor_sum).
    // The problem asks for at most 3 elements. This strategy uses 2.
    // The values can be large, up to 10^9 for initial elements, sum can be 10^5 * 10^9 = 10^14.
    // current_xor_sum is at most 2^30 (approx 10^9).
    // So current_sum + current_xor_sum can be up to 10^14 + 10^9, which fits in long long.

    std::cout << 2 << std::endl;
    std::cout << current_xor_sum << " " << (current_sum + current_xor_sum) << std::endl;
}

