void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w assuming all '1's

    // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'.
    // We use this to set '0's in our candidate w.
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this candidate w can produce the given s.
    // Construct a 'test_s' string based on our candidate w.
    std::string test_s(n, '0');
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            test_s[i] = '1';
        }
    }

    // Compare the generated test_s with the original s.
    if (test_s == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

