int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long correct_pairs = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;

        // The first doll in a chain must be 1 to potentially start a correct sequence.
        // If the first doll is 1, then we check for 1->2, 2->3, etc.
        // Otherwise, no correct sequence can start from 1 in this chain.
        // The problem statement guarantees that in each chain the numbers of matryoshkas follow in ascending order.
        // So if the first doll is 1, the sequence will be 1, 2, 3, ...
        // We just need to count how many consecutive numbers starting from 1 are present.

        int current_val;
        std::cin >> current_val; // Read the first doll in the chain

        if (current_val == 1) {
            correct_pairs++; // 1 is present, so 1->2 is a potential correct pair if 2 follows
            for (int j = 1; j < m; ++j) {
                int next_val;
                std::cin >> next_val;
                if (next_val == current_val + 1) {
                    correct_pairs++;
                    current_val = next_val;
                } else {
                    // If the sequence 1, 2, 3... is broken, no more correct pairs can be found in this chain.
                    // We still need to consume the rest of the input for this chain.
                    for (int l = j + 1; l < m; ++l) {
                        std::cin >> next_val; // Dummy read
                    }
                    break; 
                }
            }
        } else {
            // If the first doll is not 1, no correct sequence 1->2->... can start here.
            // Consume the rest of the input for this chain.
            for (int j = 1; j < m; ++j) {
                std::cin >> current_val; // Dummy read
            }
        }
    }

    // Total operations needed to form 1->2->...->n is (n-1) put operations.
    // Each existing correct pair (i -> i+1) saves one put operation.
    // So, (n-1) - correct_pairs is the number of new put operations needed.
    long long new_put_operations = (n - 1) - correct_pairs;

    // Each chain that is not part of the 1->2->...->n sequence needs to be disassembled.
    // A chain of length m has m-1 internal nestings.
    // If a chain is 1->2->...->k, it has k-1 internal nestings.
    // The total number of internal nestings in all initial chains is (n - k).
    // The number of internal nestings that are part of the final 1->2->...->n chain is `correct_pairs`.
    // So, the number of nestings that need to be undone is (n - k) - correct_pairs.
    long long get_out_operations = (n - k) - correct_pairs;

    long long total_time = new_put_operations + get_out_operations;

    std::cout << total_time << std::endl;

    return 0;
}

