#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the number 1 is always beautiful.
    // The subsegment is just [1] at pos[1].
    result[0] = '1';

    // Initialize current min and max indices for the segment containing 1 to current_max_val.
    // For m=1, this segment is just [1].
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Get the position of the current number 'm'
        int m_pos = pos[m];

        // Update the bounds of the segment that contains all numbers from 1 to m
        // This segment must contain all numbers from 1 to m-1 (which are already within current_min_idx and current_max_idx)
        // AND it must contain 'm'.
        current_min_idx = std::min(current_min_idx, m_pos);
        current_max_idx = std::max(current_max_idx, m_pos);

        // Check if the current segment [current_min_idx, current_max_idx]
        // has the correct length for a permutation of 1 to m.
        // The length should be m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

