#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            // i is a prime factor of q
            long long current_p = p;
            while (current_p % i == 0) {
                current_p /= i;
            }
            // current_p is p with all factors of i removed.
            // This current_p is a candidate for x.
            // It is a divisor of p.
            // It is not divisible by i, hence not divisible by q (if i is the only prime factor of q, or if we remove enough i's).
            // We need to ensure that current_p is not divisible by q.
            // If current_p is divisible by q, it means q has other prime factors not equal to i.
            // The largest divisor of p that is not divisible by q must be formed by removing some prime factors of q from p.
            // Specifically, for each prime factor f of q, we try to remove just enough f's from p such that the resulting number is not divisible by q.
            // The strategy is to remove all occurrences of a prime factor `f` of `q` from `p` to get `p / f^k` (where `f^k` is the highest power of `f` dividing `p`).
            // Then `p / f^k` is a divisor of `p` and is not divisible by `f`. Thus, it cannot be divisible by `q`.
            // We want the largest such `p / f^k`.
            // So, for each prime factor `i` of `q`, we calculate `p_prime = p`.
            // We divide `p_prime` by `i` until `p_prime` is no longer divisible by `q`.
            // This is equivalent to dividing `p` by `i` until `p / i^k` is not divisible by `q`.
            // The largest such `p / i^k` is `p / (i * (q_i_power_in_p / q_i_power_in_q))` where `q_i_power_in_p` is the highest power of `i` dividing `p`
            // and `q_i_power_in_q` is the highest power of `i` dividing `q`.
            // A simpler way: `p_candidate = p`. While `p_candidate % q == 0`, `p_candidate /= i`.
            // This `p_candidate` is a divisor of `p` and is not divisible by `q`.
            // We take the maximum of all such `p_candidate`s.

            long long current_x_candidate = p;
            while (current_x_candidate % q == 0) {
                current_x_candidate /= i;
            }
            max_x = std::max(max_x, current_x_candidate);

            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }

    if (temp_q > 1) { // temp_q is now a prime factor itself (or 1 if all factors were processed)
        long long current_x_candidate = p;
        while (current_x_candidate % q == 0) {
            current_x_candidate /= temp_q;
        }
        max_x = std::max(max_x, current_x_candidate);
    }

    return max_x;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each position modulo k

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count 0s, 1s, and ?s in the fixed_chars pattern
    int count0 = 0;
    int count1 = 0;
    int count_q = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        } else { // fixed_chars[i] == '?'
            count_q++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 balance
    int target_half = k / 2;
    if (count0 > target_half || count1 > target_half) {
        std::cout << "NO\n";
        return;
    }

    // The remaining '?'s can always be filled to satisfy the balance for the first k characters.
    // If count0 <= target_half and count1 <= target_half,
    // we need (target_half - count0) more '0's and (target_half - count1) more '1's.
    // The total number of '?'s is count_q.
    // (target_half - count0) + (target_half - count1) = k - (count0 + count1) = k - (k - count_q) = count_q.
    // So, there are exactly enough '?'s to fill the remaining counts.

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

