            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If f1 (move left) is 0, robot cannot move left.
            // So, its final X coordinate must be >= its current X coordinate.
            // This means X >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f3 (move right) is 0, robot cannot move right.
            // So, its final X coordinate must be <= its current X coordinate.
            // This means X <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4 (move down) is 0, robot cannot move down.
            // So, its final Y coordinate must be >= its current Y coordinate.
            // This means Y >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If f2 (move up) is 0, robot cannot move up.
            // So, its final Y coordinate must be <= its current Y coordinate.
            // This means Y <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');

    for (int k = 0; k <= 9; ++k) {
        std::vector<char> current_coloring(n);
        bool possible_k = true;

        // Track the last digit seen for color 1 and color 2
        int last_digit_1 = -1;
        int last_digit_2 = -1;

        // First pass: assign digits based on k
        // Digits < k must be 1. Digits > k must be 2.
        // Digits == k are provisionally assigned to 1.
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                current_coloring[i] = '1';
            } else if (digit > k) {
                current_coloring[i] = '2';
            } else { // digit == k
                current_coloring[i] = '1'; // Tentatively assign to 1
            }
        }

        // Second pass: check validity and reassign 'k' digits if necessary
        // For digits == k, if they appear after a '2' has already been assigned,
        // they must be assigned '2' to maintain the non-decreasing property of S2.
        // If they appear before a '2' has been assigned, they can be '1'.
        // This logic is simplified: we want to find the "split point" for 'k' digits.
        // All 'k's before some index `split_idx_k` go to color 1, all 'k's after go to color 2.
        // This is equivalent to finding the first 'k' that must be colored '2'.

        // Find the first 'k' that must be colored '2'
        int first_k_to_be_2_idx = n; // Initialize to n, meaning no 'k' needs to be '2' yet
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit > k) { // A digit greater than k forces all subsequent k's to be 2
                first_k_to_be_2_idx = i;
                break;
            }
        }

        // Re-assign 'k' digits based on first_k_to_be_2_idx
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < k) {
                current_coloring[i] = '1';
            } else if (digit > k) {
                current_coloring[i] = '2';
            } else { // digit == k
                if (i < first_k_to_be_2_idx) {
                    current_coloring[i] = '1';
                } else {
                    current_coloring[i] = '2';
                }
            }
        }

        // Final check for non-decreasing property
        last_digit_1 = -1;
        last_digit_2 = -1;
        int first_digit_2 = -1; // To check S1_last <= S2_first

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (current_coloring[i] == '1') {
                if (digit < last_digit_1) {
                    possible_k = false;
                    break;
                }
                last_digit_1 = digit;
            } else { // current_coloring[i] == '2'
                if (first_digit_2 == -1) {
                    first_digit_2 = digit;
                }
                if (digit < last_digit_2) {
                    possible_k = false;
                    break;
                }
                last_digit_2 = digit;
            }
        }

        if (possible_k) {
            // Check S1_last <= S2_first
            if (last_digit_1 != -1 && first_digit_2 != -1 && last_digit_1 > first_digit_2) {
                possible_k = false;
            }
        }

        if (possible_k) {
            for (int i = 0; i < n; ++i) {
                result[i] = current_coloring[i];
            }
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

long long sum_arithmetic_series(long long n) {
    if (n <= 0) {
        return 0;
    }
    long long MOD = 1000000007;
    long long n_mod = n % MOD;
    long long n_plus_1_mod = (n + 1) % MOD;
    long long term1 = n_mod;
    long long term2 = n_plus_1_mod;

    if (term1 % 2 == 0) {
        term1 /= 2;
    } else {
        term2 /= 2;
    }
    return (term1 * term2) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_{r=1 to b-1} r
    // This is (b-1) * b / 2
    long long sum_r_val = sum_arithmetic_series(b - 1);

    // Calculate sum_{k=1 to a} (k * b + 1)
    // This is sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a+1) / 2) + a
    long long sum_k_b_plus_1_val;
    long long sum_k_val = sum_arithmetic_series(a); // a * (a+1) / 2

    long long term_b_times_sum_k = (b % MOD * sum_k_val) % MOD;
    long long term_a = a % MOD;

    sum_k_b_plus_1_val = (term_b_times_sum_k + term_a) % MOD;

    // Total sum = (sum_{r=1 to b-1} r) * (sum_{k=1 to a} (k * b + 1))
    long long total_sum = (sum_r_val * sum_k_b_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

