    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << 1 << " " << 1 << "\n";
        std::cout << -a[0] << "\n";
        // Operations 2 and 3: Do nothing (add 0)
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        std::cout << 1 << " " << 1 << "\n";
        std::cout << 0 << "\n";
        return 0;
    }

    // Operation 1: Make a[0] zero
    // Segment [1, 1], length 1. Add -a[0] to a[0].
    std::cout << 1 << " " << 1 << "\n";
    std::cout << -a[0] << "\n";
    a[0] = 0; // Update a[0] to reflect the change

    // Operation 2: For elements a[1] to a[n-1], make them multiples of n.
    // Segment [2, n], length n-1.
    // For each a[i] (i from 1 to n-1), we want a[i] + b_i = 0 (mod n).
    // We can add b_i = (n - (a[i] % n)) % n * (n-1) to a[i].
    // This b_i is a multiple of (n-1) and makes a[i] a multiple of n.
    std::cout << 2 << " " << n << "\n";
    for (int i = 1; i < n; ++i) {
        long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
        long long add_val = (n - remainder) % n;
        long long b_i = add_val * (n - 1);
        std::cout << b_i << (i == n - 1 ? "" : " ");
        a[i] += b_i; // Update a[i]
    }
    std::cout << "\n";

    // Operation 3: Make all elements zero.
    // All elements a[0] to a[n-1] are now multiples of n.
    // Segment [1, n], length n.
    // For each a[i], add -a[i] to it. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
    std::cout << 1 << " " << n << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << -a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

