        }
        long long total_substrings = n * (n + 1) / 2;
        long long zeros_count = n - m;
        long long k = zeros_count / (m + 1);
        long long r = zeros_count % (m + 1);
        long long substrings_of_zeros = 0;
        // r blocks of length k+1
        substrings_of_zeros += r * ((k + 1) * (k + 2) / 2);
        // (m+1-r) blocks of length k
        substrings_of_zeros += (m + 1 - r) * (k * (k + 1) / 2);
        long long result = total_substrings - substrings_of_zeros;
        std::cout << result << "\n";
    }
