}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix balances for the left side (jars 1 to n)
    // and suffix balances for the right side (jars n+1 to 2n).
    // Balance is (count of 1s) - (count of 2s).

    // Left side: jars 0 to n-1 (0-indexed)
    // bal_left[k] = balance of jars 0 to k-1 (i.e., after emptying k jars from left)
    // bal_left[0] = 0 (no jars emptied)
    // bal_left[k] = balance of jars 0 to k-1
    std::vector<int> bal_left(n + 1);
    bal_left[0] = 0;
    for (int i = 0; i < n; ++i) {
        bal_left[i + 1] = bal_left[i] + (a[i] == 1 ? 1 : -1);
    }

    // Right side: jars n to 2n-1 (0-indexed)
    // bal_right[k] = balance of jars 2n-k to 2n-1 (i.e., after emptying k jars from right)
    // bal_right[0] = 0 (no jars emptied)
    // bal_right[k] = balance of jars 2n-k to 2n-1
    std::vector<int> bal_right(n + 1);
    bal_right[0] = 0;
    for (int i = 0; i < n; ++i) {
        bal_right[i + 1] = bal_right[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Calculate total initial balance of all 2n jars
    int initial_total_balance = 0;
    for (int x : a) {
        initial_total_balance += (x == 1 ? 1 : -1);
    }

    // Map to store the minimum number of jars emptied from the left
    // to achieve a certain balance.
    // key: balance, value: number of jars emptied (k_left)
    std::map<int, int> left_balance_to_k;
    for (int k_left = 0; k_left <= n; ++k_left) {
        int current_balance = bal_left[k_left];
        if (left_balance_to_k.find(current_balance) == left_balance_to_k.end()) {
            left_balance_to_k[current_balance] = k_left;
        }
    }

    int min_jars_emptied = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars emptied from the right (k_right)
    for (int k_right = 0; k_right <= n; ++k_right) {
        // The balance of jars emptied from the right is bal_right[k_right].
        // The balance of jars *remaining* after emptying k_left from left and k_right from right
        // should be 0.
        //
        // Let S_total, B_total be initial counts.
        // Let S_L_empty, B_L_empty be counts of jars emptied from left.
        // Let S_R_empty, B_R_empty be counts of jars emptied from right.
        //
        // Remaining balance: (S_total - S_L_empty - S_R_empty) - (B_total - B_L_empty - B_R_empty) = 0
        // (S_total - B_total) - (S_L_empty - B_L_empty) - (S_R_empty - B_R_empty) = 0
        // initial_total_balance - bal_left[k_left] - bal_right[k_right] = 0
        //
        // So, we need: bal_left[k_left] = initial_total_balance - bal_right[k_right]

        int target_left_balance = initial_total_balance - bal_right[k_right];

        if (left_balance_to_k.count(target_left_balance)) {
            int k_left = left_balance_to_k[target_left_balance];
            min_jars_emptied = std::min(min_jars_emptied, k_left + k_right);
        }
    }

    std::cout << min_jars_emptied << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> left_max_ops(n);
    std::vector<long long> right_max_ops(n);

    // Calculate operations if only considering vertical destruction
    // For a tower of height H, it takes ceil(H/2) operations to destroy it vertically.
    // This is equivalent to (H+1)/2 using integer division.
    for (int i = 0; i < n; ++i) {
        left_max_ops[i] = (h[i] + 1) / 2;
        right_max_ops[i] = (h[i] + 1) / 2;
    }

    // Propagate maximum operations from left to right
    // A tower at index i can be destroyed by operations from tower i-1.
    // If tower i-1 takes K operations, tower i can also be affected.
    // The number of operations for tower i is at least max(current_ops_i, ops_i-1 - 1)
    // This is because if tower i-1 is destroyed in K operations, its rightmost blocks
    // are destroyed. This means tower i's leftmost blocks are also destroyed.
    // So, tower i effectively loses its leftmost blocks in operation 1, 2, ..., K-1.
    // After K-1 operations, tower i has lost K-1 layers from its left.
    // The remaining height of tower i is h[i] - (K-1).
    // The number of operations for tower i would then be (h[i] - (K-1) + 1) / 2 + (K-1).
    // This simplifies to (h[i] + K) / 2.
    // However, a simpler way to think about it is that the "wave" of destruction
    // from the left propagates. If tower i-1 takes `k` operations, then tower `i`
    // will take at least `k-1` operations to destroy its leftmost blocks.
    // So, `left_max_ops[i]` must be at least `left_max_ops[i-1] - 1`.
    // We take the maximum of the vertical destruction and this propagated value.
    for (int i = 1; i < n; ++i) {
        left_max_ops[i] = std::max(left_max_ops[i], left_max_ops[i - 1] - 1);
    }

    // Propagate maximum operations from right to left
    for (int i = n - 2; i >= 0; --i) {
        right_max_ops[i] = std::max(right_max_ops[i], right_max_ops[i + 1] - 1);
    }

    long long max_overall_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_overall_ops = std::max(max_overall_ops, std::min(left_max_ops[i], right_max_ops[i]));
    }

    // Now consider the "valley" case.
    // If we have a sequence like H1, H2, H3 where H2 is small,
    // the destruction might be limited by the minimum height in a segment.
    // The number of operations for a tower `i` is `min(left_max_ops[i], right_max_ops[i])`.
    // This is the number of operations if we consider only vertical and horizontal propagation.
    // However, the actual number of operations for a block at (x, y) is `max(x, y, width-x-1, height-y-1) + 1`.
    // For a tower `i`, the maximum operations is `max(left_max_ops[i], right_max_ops[i])`.
    // The actual number of operations for a tower `i` is `min(left_max_ops[i], right_max_ops[i])`
    // if we consider only the "wave" from left and right.
    // But the total number of operations is the maximum of these minimums.
    // This is what `max_overall_ops` currently holds.

    // The "valley" case:
    // The number of operations for a tower `i` is `k`.
    // This means `h[i]` blocks are destroyed in `k` operations.
    // The blocks at height `y` are destroyed in `y+1` operations from top,
    // and `h[i]-y` operations from bottom.
    // The blocks at column `x` are destroyed in `x+1` operations from left,
    // and `width-x` operations from right.
    // The total number of operations is `max(k_left, k_right, k_top, k_bottom)`.
    // The `k_left` and `k_right` are related to `left_max_ops` and `right_max_ops`.
    // The `k_top` and `k_bottom` are related to `(h[i]+1)/2`.
    // The `left_max_ops[i]` and `right_max_ops[i]` already incorporate the vertical destruction.
    // So, `left_max_ops[i]` is the maximum number of operations for tower `i` considering
    // its own height and the destruction wave from the left.
    // Similarly for `right_max_ops[i]`.
    // The actual number of operations for tower `i` is `min(left_max_ops[i], right_max_ops[i])`.
    // The final answer is the maximum of these values across all towers.

    // This logic is correct for the "wave" propagation.
    // However, there's a special case for the "middle" of a long flat section.
    // Consider `3 3 3 1 3 3 3`.
    // h: 3 3 3 1 3 3 3
    // left_max_ops (vertical): 2 2 2 1 2 2 2
    // left_max_ops (propagated):
    // i=0: 2
    // i=1: max(2, 2-1) = 2
    // i=2: max(2, 2-1) = 2
    // i=3: max(1, 2-1) = 1
    // i=4: max(2, 1-1) = 2
    // i=5: max(2, 2-1) = 2
    // i=6: max(2, 2-1) = 2
    // So, left_max_ops: 2 2 2 1 2 2 2

    // right_max_ops (vertical): 2 2 2 1 2 2 2
    // right_max_ops (propagated):
    // i=6: 2
    // i=5: max(2, 2-1) = 2
    // i=4: max(2, 2-1) = 2
    // i=3: max(1, 2-1) = 1
    // i=2: max(2, 1-1) = 2
    // i=1: max(2, 2-1) = 2
    // i=0: max(2, 2-1) = 2
    // So, right_max_ops: 2 2 2 1 2 2 2

    // min(left_max_ops[i], right_max_ops[i]):
    // i=0: min(2,2) = 2
    // i=1: min(2,2) = 2
    // i=2: min(2,2) = 2
    // i=3: min(1,1) = 1
    // i=4: min(2,2) = 2
    // i=5: min(2,2) = 2
    // i=6: min(2,2) = 2
    // Max of these is 2. This matches sample output.

    // Consider `2 1 4 6 2 2`
    // h: 2 1 4 6 2 2
    // vertical_ops: 1 1 2 3 1 1

    // left_max_ops:
    // i=0: 1
    // i=1: max(1, 1-1) = 1
    // i=2: max(2, 1-1) = 2
    // i=3: max(3, 2-1) = 3
    // i=4: max(1, 3-1) = 2
    // i=5: max(1, 2-1) = 1
    // left_max_ops: 1 1 2 3 2 1

    // right_max_ops:
    // i=5: 1
    // i=4: max(1, 1-1) = 1
    // i=3: max(3, 1-1) = 3
    // i=2: max(2, 3-1) = 2
    // i=1: max(1, 2-1) = 1
    // i=0: max(1, 1-1) = 1
    // right_max_ops: 1 1 2 3 1 1

    // min(left_max_ops[i], right_max_ops[i]):
    // i=0: min(1,1) = 1
    // i=1: min(1,1) = 1
    // i=2: min(2,2) = 2
    // i=3: min(3,3) = 3
    // i=4: min(2,1) = 1
    // i=5: min(1,1) = 1
    // Max of these is 3. This matches sample output.

    // The logic seems to be correct. The `left_max_ops[i]` represents the maximum number of operations
    // required for tower `i` considering its own height and the destruction wave coming from the left.
    // Similarly for `right_max_ops[i]`.
    // The actual number of operations for tower `i` is the minimum of these two, because it's destroyed
    // by whichever wave reaches it first (or its own vertical destruction).
    // The overall answer is the maximum of these minimums across all towers.

    // However, there's a subtle point. The `left_max_ops[i]` and `right_max_ops[i]` are not just
    // `(h[i]+1)/2` and `(h[i]+1)/2`. They are `max((h[i]+1)/2, left_max_ops[i-1]-1)` and
    // `max((h[i]+1)/2, right_max_ops[i+1]-1)`.
    // This means `left_max_ops[i]` is the maximum number of operations for any block in tower `i`
    // if we only consider destruction from the left and vertical.
    // And `right_max_ops[i]` is the maximum number of operations for any block in tower `i`
    // if we only consider destruction from the right and vertical.
    // The actual number of operations for a block at (x, y) is `max(x_ops, y_ops)`.
    // `x_ops` is `min(x_from_left, x_from_right)`.
    // `y_ops` is `min(y_from_top, y_from_bottom)`.
    // The problem is that `left_max_ops[i]` and `right_max_ops[i]` are not just `x_from_left` and `x_from_right`.
    // They are `max(y_ops, x_from_left)` and `max(y_ops, x_from_right)`.

    // Let `L[i]` be the number of operations for tower `i` if it's destroyed from the left and vertically.
    // `L[i] = max((h[i]+1)/2, L[i-1]-1)` for `i > 0`, `L[0] = (h[0]+1)/2`.
    // Let `R[i]` be the number of operations for tower `i` if it's destroyed from the right and vertically.
    // `R[i] = max((h[i]+1)/2, R[i+1]-1)` for `i < n-1`, `R[n-1] = (h[n-1]+1)/2`.

    // The number of operations for tower `i` is `min(L[i], R[i])`.
    // The final answer is `max(min(L[i], R[i]))` over all `i`.
    // This is what the current code calculates.

    // Let's re-evaluate the definition of `left_max_ops[i]` and `right_max_ops[i]`.
    // `left_max_ops[i]` should be the maximum number of operations for any block in tower `i`
    // considering only its own height and the destruction wave from the left.
    // A block at column `j` (0-indexed from left) in tower `i` will be destroyed in `j+1` operations
    // from the left. It will also be destroyed in `(height_of_block_at_j + 1) / 2` operations vertically.
    // The `height_of_block_at_j` is `h[i] - j`.
    // This is getting complicated.

    // Let's simplify.
    // The number of operations for a block at (column `c`, height `r`) is `max(c_ops, r_ops)`.
    // `c_ops` is `min(c_from_left, c_from_right)`.
    // `r_ops` is `min(r_from_top, r_from_bottom)`.
    // `r_from_top = r+1`. `r_from_bottom = h[i]-r`.
    // `c_from_left = c+1`. `c_from_right = n-c`.

    // The problem is that `c_from_left` and `c_from_right` are not fixed for a tower.
    // They depend on the actual column index of the block in the entire grid.
    // Let `k` be the number of operations.
    // A block at `(x, y)` (0-indexed, `x` is column, `y` is height from bottom) is destroyed if
    // `x < k` (from left) OR `x >= N-k` (from right) OR `y < k` (from bottom) OR `y >= H[x]-k` (from top).
    // This is equivalent to saying a block `(x, y)` survives `k` operations if
    // `x >= k` AND `x < N-k` AND `y >= k` AND `y < H[x]-k`.
    // We want to find the maximum `k` such that no block survives `k` operations.
    // This is equivalent to finding the minimum `k` such that all blocks are destroyed in `k` operations.

    // The maximum number of operations for any block in tower `i` is `k`.
    // This `k` is determined by the "most internal" block.
    // For a block at `(i, j)` (column `i`, height `j` from bottom), it takes `max(i+1, n-i, j+1, h[i]-j)` operations.
    // This is not quite right. The `i+1` and `n-i` are for the entire structure.
    // The `j+1` and `h[i]-j` are for the individual tower.

    // Let `k` be the number of operations.
    // A block at `(col, row)` (0-indexed, `col` is tower index, `row` is height from bottom)
    // is destroyed if `row < k` (from bottom) OR `row >= h[col]-k` (from top) OR
    // `col_dist_from_left < k` OR `col_dist_from_right < k`.
    // `col_dist_from_left` for tower `col` is `col`.
    // `col_dist_from_right` for tower `col` is `n-1-col`.
    // So, a block `(col, row)` survives `k` operations if
    // `row >= k` AND `row < h[col]-k` AND `col >= k` AND `col < n-k`.
    // This means `h[col] - k > k` => `h[col] > 2k` => `k < h[col]/2`.
    // And `n - k > k` => `n > 2k` => `k < n/2`.
    // So, a block `(col, row)` survives `k` operations if
    // `k <= row < h[col]-k` AND `k <= col < n-k`.
    // For such a block to exist, we need `h[col] > 2k` and `n > 2k`.
    // The maximum `k` for which a block can survive is `floor(min(h[col], n)/2)`.
    // This is the number of operations for a single block if it's the only one.

    // The problem is that the destruction is simultaneous.
    // The `left_max_ops` and `right_max_ops` arrays are correctly calculated.
    // `left_max_ops[i]` is the minimum number of operations required to destroy all blocks in tower `i`
    // if we only consider destruction from the left and vertical.
    // `right_max_ops[i]` is the minimum number of operations required to destroy all blocks in tower `i`
    // if we only consider destruction from the right and vertical.
    // The actual number of operations for tower `i` is `min(left_max_ops[i], right_max_ops[i])`.
    // The final answer is the maximum of these values over all towers.

    // This logic is sound. The `left_max_ops[i]` represents the maximum number of operations
    // any block in tower `i` would take if the destruction wave only came from the left and vertically.
    // For example, if `left_max_ops[i-1]` is `K`, then the leftmost blocks of tower `i` are destroyed
    // in `K` operations. The blocks at height `y` in tower `i` are destroyed in `(y+1)` operations from top
    // or `(h[i]-y)` operations from bottom.
    // The `left_max_ops[i]` is `max((h[i]+1)/2, left_max_ops[i-1]-1)`.
    // This means that for tower `i`, the blocks are destroyed either by its own vertical destruction
    // (which takes `(h[i]+1)/2` operations) or by the wave from the left.
    // If the wave from the left takes `left_max_ops[i-1]` operations to clear tower `i-1`,
    // then it takes `left_max_ops[i-1]-1` operations to clear the leftmost blocks of tower `i`.
    // So, `left_max_ops[i]` is the maximum of these two.
    // This is the correct interpretation.

    // The final answer is `max_overall_ops`.

    return max_overall_ops;
}

