#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, then 1 + d, 1 + 2d, etc.

    while (X > 0) {
        int k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, (1LL << k) <= X + 1
        // k = floor(log2(X + 1))
        // Since X can be up to 10^9, X+1 can be up to 10^9+1.
        // log2(10^9) is approx 29.89. So k can be up to 29.
        // We can iterate k from 29 down to 0.
        for (int i = 29; i >= 0; --i) {
            if (((1LL << (i + 1)) - 1) <= X) { // Check if 2^(i+1)-1 is too large
                k = i + 1; // This means we can use 2^k-1 elements
                break;
            }
        }
        if (k == 0 && X > 0) { // If X is not 0 but 2^1-1 (1) is already too large, it means X=1.
            k = 1; // Handle X=1 case, 2^1-1 = 1
        }

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
        }

        X -= ((1LL << k) - 1);
        current_val += (d + 1); // Increment current_val for the next block
    }

    std::cout << result_array.size() << "\n";
    for (size_t i = 0; i < result_array.size(); ++i) {
        std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // For each bit position (0 to 9), track how an input 0 and an input 1
    // would transform.
    // state[0] = result if input bit is 0
    // state[1] = result if input bit is 1
    // Initially, for each bit: (0, 1) -> identity
    std::vector<std::pair<int, int>> bit_states(10);
    for (int i = 0; i < 10; ++i) {
        bit_states[i] = {0, 1};
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int bit_x = (x >> j) & 1;
            int current_0 = bit_states[j].first;
            int current_1 = bit_states[j].second;

            if (op_char == '&') {
                bit_states[j].first = current_0 & bit_x;
                bit_states[j].second = current_1 & bit_x;
            } else if (op_char == '|') {
                bit_states[j].first = current_0 | bit_x;
                bit_states[j].second = current_1 | bit_x;
            } else if (op_char == '^') {
                bit_states[j].first = current_0 ^ bit_x;
                bit_states[j].second = current_1 ^ bit_x;
            }
        }
    }

    // Now, reconstruct the operations.
    // We need to find A_AND, A_OR, A_XOR such that:
    // (0 & A_AND | A_OR ^ A_XOR) = final_0
    // (1 & A_AND | A_OR ^ A_XOR) = final_1

    int final_and_mask = 1023; // All bits 1
    int final_or_mask = 0;     // All bits 0
    int final_xor_mask = 0;    // All bits 0

    for (int j = 0; j < 10; ++j) {
        int final_0 = bit_states[j].first;
        int final_1 = bit_states[j].second;

        // Case 1: (0, 0) -> always 0
        // This means the bit must be 0 after all operations.
        // To achieve this with (AND, OR, XOR):
        // (0 & A_AND_j | A_OR_j ^ A_XOR_j) = 0
        // (1 & A_AND_j | A_OR_j ^ A_XOR_j) = 0
        // This implies A_OR_j ^ A_XOR_j = 0, so A_OR_j = A_XOR_j.
        // And (A_AND_j | A_OR_j ^ A_XOR_j) = 0, which means A_AND_j | 0 = 0, so A_AND_j = 0.
        // So, A_AND_j = 0, A_OR_j = 0, A_XOR_j = 0.
        // This means final_and_mask_j = 0, final_or_mask_j = 0, final_xor_mask_j = 0.
        if (final_0 == 0 && final_1 == 0) {
            final_and_mask &= ~(1 << j); // Set j-th bit of AND mask to 0
            final_or_mask &= ~(1 << j);  // Set j-th bit of OR mask to 0
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
        // Case 2: (0, 1) -> identity
        // (0 & A_AND_j | A_OR_j ^ A_XOR_j) = 0
        // (1 & A_AND_j | A_OR_j ^ A_XOR_j) = 1
        // From first eq: A_OR_j ^ A_XOR_j = 0, so A_OR_j = A_XOR_j.
        // From second eq: (A_AND_j | A_OR_j ^ A_XOR_j) = 1, so (A_AND_j | 0) = 1, so A_AND_j = 1.
        // So, A_AND_j = 1, A_OR_j = 0, A_XOR_j = 0.
        // This means final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 0.
        else if (final_0 == 0 && final_1 == 1) {
            final_and_mask |= (1 << j);  // Set j-th bit of AND mask to 1
            final_or_mask &= ~(1 << j);  // Set j-th bit of OR mask to 0
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
        // Case 3: (1, 0) -> negation
        // (0 & A_AND_j | A_OR_j ^ A_XOR_j) = 1
        // (1 & A_AND_j | A_OR_j ^ A_XOR_j) = 0
        // From first eq: A_OR_j ^ A_XOR_j = 1.
        // From second eq: (A_AND_j | A_OR_j ^ A_XOR_j) = 0, so (A_AND_j | 1) = 0, which is impossible.
        // This means the standard (AND, OR, XOR) sequence (x & A_AND | A_OR ^ A_XOR) cannot produce (1,0) directly.
        // However, we can achieve (1,0) by:
        // x & 1 | 0 ^ 1  => (x | 0) ^ 1 => x ^ 1 (if A_AND_j=1, A_OR_j=0, A_XOR_j=1)
        // Let's re-evaluate the general form:
        // y = (x & A_AND) | A_OR ^ A_XOR
        // If x=0: y = (0 & A_AND) | A_OR ^ A_XOR = 0 | A_OR ^ A_XOR = A_OR ^ A_XOR
        // If x=1: y = (1 & A_AND) | A_OR ^ A_XOR = A_AND | A_OR ^ A_XOR
        //
        // For (0,0): A_OR ^ A_XOR = 0, A_AND | (A_OR ^ A_XOR) = 0 => A_OR = A_XOR, A_AND = 0.
        //    So, A_AND_j=0, A_OR_j=0, A_XOR_j=0.
        // For (0,1): A_OR ^ A_XOR = 0, A_AND | (A_OR ^ A_XOR) = 1 => A_OR = A_XOR, A_AND = 1.
        //    So, A_AND_j=1, A_OR_j=0, A_XOR_j=0.
        // For (1,0): A_OR ^ A_XOR = 1, A_AND | (A_OR ^ A_XOR) = 0 => A_AND | 1 = 0, impossible.
        //    This means we cannot represent (1,0) with A_AND, A_OR, A_XOR where A_OR is applied after A_AND.
        //    The problem states "arbitrary sequence". The canonical form is (x & A_AND | A_OR) ^ A_XOR.
        //    Let's use the form: (x ^ A_XOR1) & A_AND | A_OR ^ A_XOR2.
        //    No, the problem implies a sequence of operations.
        //    The canonical form for 3 operations is:
        //    x' = x & C1
        //    x'' = x' | C2
        //    x''' = x'' ^ C3
        //    This is equivalent to (x & C1 | C2) ^ C3.
        //    Let's re-evaluate the bit states for this form:
        //    If x_bit = 0: (0 & C1_bit | C2_bit) ^ C3_bit = (0 | C2_bit) ^ C3_bit = C2_bit ^ C3_bit
        //    If x_bit = 1: (1 & C1_bit | C2_bit) ^ C3_bit = (C1_bit | C2_bit) ^ C3_bit
        //
        //    We have final_0 = C2_bit ^ C3_bit
        //    We have final_1 = (C1_bit | C2_bit) ^ C3_bit
        //
        //    From final_0: C3_bit = C2_bit ^ final_0
        //    Substitute C3_bit into final_1:
        //    final_1 = (C1_bit | C2_bit) ^ (C2_bit ^ final_0)
        //
        //    Let's analyze the four cases for (final_0, final_1):
        //    1. (0, 0):
        //       C2_bit ^ C3_bit = 0  => C2_bit = C3_bit
        //       (C1_bit | C2_bit) ^ C3_bit = 0 => (C1_bit | C2_bit) ^ C2_bit = 0 => C1_bit | C2_bit = C2_bit
        //       This implies C1_bit = 0.
        //       So, C1_bit = 0, C2_bit = 0, C3_bit = 0. (Or C1_bit=0, C2_bit=1, C3_bit=1)
        //       To minimize operations, we prefer 0s. So C1=0, C2=0, C3=0.
        //       This means: final_and_mask_j = 0, final_or_mask_j = 0, final_xor_mask_j = 0.
        //       (x & 0 | 0) ^ 0 = 0. Correct.
        //
        //    2. (0, 1):
        //       C2_bit ^ C3_bit = 0  => C2_bit = C3_bit
        //       (C1_bit | C2_bit) ^ C3_bit = 1 => (C1_bit | C2_bit) ^ C2_bit = 1 => C1_bit | C2_bit = 1 ^ C2_bit
        //       If C2_bit = 0: C1_bit | 0 = 1 => C1_bit = 1. So C1=1, C2=0, C3=0.
        //       If C2_bit = 1: C1_bit | 1 = 0 (impossible).
        //       So, C1_bit = 1, C2_bit = 0, C3_bit = 0.
        //       This means: final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 0.
        //       (x & 1 | 0) ^ 0 = x. Correct.
        //
        //    3. (1, 0):
        //       C2_bit ^ C3_bit = 1
        //       (C1_bit | C2_bit) ^ C3_bit = 0
        //       From first eq: C3_bit = 1 ^ C2_bit.
        //       Substitute: (C1_bit | C2_bit) ^ (1 ^ C2_bit) = 0
        //       (C1_bit | C2_bit) = 1 ^ C2_bit
        //       If C2_bit = 0: C1_bit | 0 = 1 => C1_bit = 1. So C1=1, C2=0, C3=1.
        //       If C2_bit = 1: C1_bit | 1 = 0 (impossible).
        //       So, C1_bit = 1, C2_bit = 0, C3_bit = 1.
        //       This means: final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 1.
        //       (x & 1 | 0) ^ 1 = x ^ 1. Correct.
        //
        //    4. (1, 1):
        //       C2_bit ^ C3_bit = 1
        //       (C1_bit | C2_bit) ^ C3_bit = 1
        //       From first eq: C3_bit = 1 ^ C2_bit.
        //       Substitute: (C1_bit | C2_bit) ^ (1 ^ C2_bit) = 1
        //       (C1_bit | C2_bit) = 1 ^ (1 ^ C2_bit) = C2_bit
        //       This implies C1_bit = 0.
        //       So, C1_bit = 0, C2_bit = 1, C3_bit = 0. (Or C1_bit=0, C2_bit=0, C3_bit=1)
        //       To minimize operations, we prefer 0s. So C1=0, C2=1, C3=0.
        //       This means: final_and_mask_j = 0, final_or_mask_j = 1, final_xor_mask_j = 0.
        //       (x & 0 | 1) ^ 0 = 1. Correct.

        if (final_0 == 0 && final_1 == 0) {
            // C1=0, C2=0, C3=0
            final_and_mask &= ~(1 << j);
            final_or_mask &= ~(1 << j);
            final_xor_mask &= ~(1 << j);
        } else if (final_0 == 0 && final_1 == 1) {
            // C1=1, C2=0, C3=0
            final_and_mask |= (1 << j);
            final_or_mask &= ~(1 << j);
            final_xor_mask &= ~(1 << j);
        } else if (final_0 == 1 && final_1 == 0) {
            // C1=1, C2=0, C3=1
            final_and_mask |= (1 << j);
            final_or_mask &= ~(1 << j);
            final_xor_mask |= (1 << j);
        } else { // final_0 == 1 && final_1 == 1
            // C1=0, C2=1, C3=0
            final_and_mask &= ~(1 << j);
            final_or_mask |= (1 << j);
            final_xor_mask &= ~(1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit of AND mask is 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit of OR mask is 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit of XOR mask is 1
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n is the larger coordinate for easier calculation
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Case 1: Not enough moves to reach the target
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Case 2: Parity check
        // The parity of (abs_n + abs_m) must be the same as the parity of k.
        // Each move changes the sum of coordinates (x+y) by -2, -1, 0, 1, or 2.
        // A diagonal move changes (x+y) by 0, 2, or -2 (always even change).
        // A non-diagonal move changes (x+y) by 1 or -1 (always odd change).
        // This is not the right parity check.
        //
        // Correct parity check:
        // Each move changes the parity of x or y or both.
        // A move from (x,y) to (x',y') means (x'-x) and (y'-y) are in {-1,0,1}.
        // The parity of (x'+y') changes relative to (x+y) based on the move.
        // (x'+y') - (x+y) = (x'-x) + (y'-y)
        // If (x'-x) and (y'-y) are both non-zero (diagonal move), then (x'-x) + (y'-y) is -2, 0, or 2 (even).
        // If one is zero and the other non-zero (non-diagonal move), then (x'-x) + (y'-y) is -1 or 1 (odd).
        // So, a diagonal move preserves the parity of (x+y).
        // A non-diagonal move flips the parity of (x+y).
        //
        // Starting at (0,0), sum is 0 (even).
        // After K moves, we are at (abs_n, abs_m).
        // If K is even, we must have made an even number of non-diagonal moves.
        // This means the parity of (abs_n + abs_m) must be even.
        // If K is odd, we must have made an odd number of non-diagonal moves.
        // This means the parity of (abs_n + abs_m) must be odd.
        //
        // In other words, (abs_n + abs_m) and K must have the same parity.
        if ((abs_n + abs_m) % 2 != k % 2) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible to reach (abs_n, abs_m) in k moves.
        // We want to maximize diagonal moves.
        // The maximum number of diagonal moves is limited by abs_m (the smaller coordinate).
        // We can make abs_m diagonal moves to reach (abs_m, abs_m) or (abs_m, -abs_m) etc.
        // This takes abs_m moves.
        // Remaining moves: k - abs_m.
        // Remaining distance in one coordinate: abs_n - abs_m.
        //
        // After abs_m diagonal moves, we are at some (x,y) where |x| = abs_m and |y| = abs_m.
        // We need to reach (abs_n, abs_m) in k - abs_m moves.
        // The remaining displacement is (abs_n - abs_m) in one coordinate.
        //
        // We have k - abs_m moves left.
        // We need to cover abs_n - abs_m distance in one coordinate.
        // This requires at least abs_n - abs_m non-diagonal moves.
        //
        // The remaining moves are `k - abs_m`.
        // The remaining displacement is `abs_n - abs_m`.
        //
        // If `k - abs_m` is exactly `abs_n - abs_m`, then all remaining moves are non-diagonal
        // and contribute to reaching `abs_n`. Total diagonal moves: `abs_m`.
        //
        // If `k - abs_m` is greater than `abs_n - abs_m`, we have `(k - abs_m) - (abs_n - abs_m)`
        // extra moves. These extra moves must be used to "waste" moves while staying at the target.
        // Each pair of extra moves can be used as (1,0) then (-1,0) or (1,1) then (-1,-1) etc.
        //
        // Consider the total moves `k`.
        // We can make `abs_m` diagonal moves to reach `(abs_m, abs_m)`.
        // This leaves `k - abs_m` moves.
        // We need to cover `abs_n - abs_m` distance in the x-direction.
        // This takes `abs_n - abs_m` non-diagonal moves.
        // Total moves used so far: `abs_m + (abs_n - abs_m) = abs_n`.
        // Remaining moves: `k - abs_n`.
