#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> current_diff(n, 0);

    // Initialize initial_a based on type 2 operations
    // For each type 2 operation (2 l r m), we know that for any j in [l, r],
    // a[j] + current_diff[j] <= m.
    // This implies a[j] <= m - current_diff[j].
    // We want to maximize a[j] to satisfy constraints, so we take the minimum of these upper bounds.
    // Initially, current_diff is 0 for all elements.
    // So, for each type 2 op (2 l r m), a[j] <= m for j in [l, r].
    // We initialize initial_a[j] to a very large value (or 0, and then take min with m).
    // A better approach is to initialize initial_a[j] to a value that satisfies all type 2 ops
    // assuming no type 1 ops occurred before them.
    // Let's initialize initial_a[j] to a large positive value (e.g., 10^9) and then
    // for each type 2 op (2 l r m), update initial_a[j] = min(initial_a[j], m) for j in [l, r].
    // This is not quite right because current_diff changes.

    // The correct approach for initial_a is to set it to a value that satisfies
    // a[j] + current_diff[j] <= m for all type 2 operations.
    // Since we want to find *any* valid array, and we want to maximize the chance of satisfying
    // a[j] + current_diff[j] == m for some j, we should set initial_a[j] to be as large as possible
    // while still satisfying all constraints.
    // For each j, initial_a[j] must be <= m - current_diff[j] for all type 2 ops covering j.
    // So, initial_a[j] = min(m - current_diff[j]) over all relevant type 2 ops.
    // We can initialize initial_a[j] to a large value (e.g., 10^9) and then iterate through ops.

    // Let's iterate operations in reverse to determine initial_a.
    // When processing operations in reverse:
    // If it's a type 1 op (1 l r d), it means that before this op, elements in [l, r] were d less.
    // So, to find the initial value, we should subtract d from the current_diff for elements in [l, r].
    // If it's a type 2 op (2 l r m), it means that at that point, max(a[j] + current_diff[j]) = m.
    // This implies a[j] + current_diff[j] <= m for all j in [l, r].
    // So, a[j] <= m - current_diff[j].
    // We want to find the largest possible initial_a[j] that satisfies all constraints.
    // So, initial_a[j] = min(initial_a[j], m - current_diff[j]) for j in [l, r].

    // Initialize initial_a with a large value (10^9)
    for (int i = 0; i < n; ++i) {
        initial_a[i] = 1000000000LL; // Max allowed absolute value
    }

    // Iterate operations in reverse to determine upper bounds for initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 1) {
            // This operation added ops[i].val to a[j] for j in [l, r].
            // When going backwards, this means the contribution of this operation
            // to the current_diff should be removed.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_diff[j] -= ops[i].val;
            }
        } else { // Type 2 operation
            // At this point in time (before this operation in reverse order),
            // max(a[j] + current_diff[j]) was ops[i].val.
            // This implies a[j] + current_diff[j] <= ops[i].val for all j in [l, r].
            // So, a[j] <= ops[i].val - current_diff[j].
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_diff[j]);
            }
        }
    }

    // Check if any initial_a[j] exceeds absolute value 10^9
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] > 1000000000LL || initial_a[i] < -1000000000LL) {
            // This case should ideally not happen if constraints are consistent,
            // as initial_a was initialized to 10^9 and only decreased.
            // However, if m - current_diff[j] is less than -10^9, it could be an issue.
            // Let's ensure it's within bounds.
            initial_a[i] = std::clamp(initial_a[i], -1000000000LL, 1000000000LL);
        }
    }

    // Now, verify the constructed initial_a by replaying operations
    std::fill(current_diff.begin(), current_diff.end(), 0); // Reset current_diff for forward pass
    std::vector<long long> current_array_values(n);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_diff[j] += ops[i].val;
            }
        } else { // Type 2 operation
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_array_values[j] = initial_a[j] + current_diff[j];
                max_val_in_range = std::max(max_val_in_range, current_array_values[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_index;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_index);
        children[i].in_line = false; // Child i is now cured and out of line

        long long current_v_effect = children[i].v;
        long long total_d_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply effect from child i's crying in office
            if (current_v_effect > 0) {
                children[j].p -= current_v_effect;
                current_v_effect = std::max(0LL, current_v_effect - 1);
            }

            // Apply cumulative effect from children crying in hall
            children[j].p -= total_d_effect;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // In this case, all f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness_case1 = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_partition(n);
    for (int i = 0; i < n; ++i) {
        best_partition[elements[i].original_index] = 1;
    }
    long long min_goodness = goodness_case1;

    // Case 2: Partition into two non-empty subsequences.
    // Let S1 contain elements[0] and S2 contain elements[1]...elements[n-1].
    // This is not necessarily optimal.
    //
    // Consider a specific partition strategy:
    // Put elements[0] into S1.
    // Put elements[1] into S2.
    // Put elements[2]...elements[n-1] into S2.
    //
    // S1 = {elements[0]}
    // S2 = {elements[1], elements[2], ..., elements[n-1]}
    //
    // Possible f values:
    // 1. elements[i] + elements[j] for i, j >= 1 (both in S2)
    //    Min: elements[1].value + elements[2].value
    //    Max: elements[n-1].value + elements[n-2].value
    // 2. elements[0].value + elements[i].value + h for i >= 1 (one in S1, one in S2)
    //    Min: elements[0].value + elements[1].value + h
    //    Max: elements[0].value + elements[n-1].value + h
    //
    // Overall min_f: min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // Overall max_f: max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // This strategy is good because it tries to make the "cross-subsequence" sums
    // as close as possible to the "same-subsequence" sums.
    //
    // Specifically, if elements[0].value + elements[1].value + h <= elements[1].value + elements[2].value,
    // then the minimum f value is elements[0].value + elements[1].value + h.
    // The maximum f value is max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h).
    //
    // If elements[0].value + elements[1].value + h > elements[1].value + elements[2].value,
    // then the minimum f value is elements[1].value + elements[2].value.
    // The maximum f value is max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h).
    //
    // Let's calculate the goodness for this specific partition.
    // S1 = {elements[0]}
    // S2 = {elements[1], ..., elements[n-1]}
    //
    // If n=2, S1={elements[0]}, S2={elements[1]}. Only cross-subsequence sums exist.
    // f(elements[0], elements[1]) = elements[0].value + elements[1].value + h.
    // min_f = max_f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is handled by the general logic below.

    if (n >= 2) {
        long long min_f_val_S2_internal = elements[1].value + elements[2].value; // if n >= 3
        long long max_f_val_S2_internal = elements[n - 1].value + elements[n - 2].value; // if n >= 3

        long long min_f_val_cross = elements[0].value + elements[1].value + h;
        long long max_f_val_cross = elements[0].value + elements[n - 1].value + h;

        long long current_min_f, current_max_f;

        if (n == 2) {
            current_min_f = min_f_val_cross;
            current_max_f = max_f_val_cross;
        } else { // n >= 3
            current_min_f = std::min(min_f_val_S2_internal, min_f_val_cross);
            current_max_f = std::max(max_f_val_S2_internal, max_f_val_cross);
        }

        long long goodness_case2 = current_max_f - current_min_f;

        if (goodness_case2 < min_goodness) {
            min_goodness = goodness_case2;
            best_partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    // Case 3: S1 = {elements[0], elements[1]}, S2 = {elements[2], ..., elements[n-1]}
    // This is only relevant if n >= 3.
    //
    // f values:
    // 1. elements[0].value + elements[1].value (both in S1)
    // 2. elements[i].value + elements[j].value for i, j >= 2 (both in S2)
    //    Min: elements[2].value + elements[3].value (if n >= 4)
    //    Max: elements[n-1].value + elements[n-2].value (if n >= 4)
    // 3. elements[k].value + elements[l].value + h for k in {0,1}, l >= 2 (one in S1, one in S2)
    //    Min: elements[0].value + elements[2].value + h
    //    Max: elements[1].value + elements[n-1].value + h

    if (n >= 3) {
        long long f_S1_internal = elements[0].value + elements[1].value;

        long long min_f_val_S2_internal;
        long long max_f_val_S2_internal;
        if (n == 3) { // S2 has only one element, no internal pairs
            min_f_val_S2_internal = -1; // Sentinel, won't be used
            max_f_val_S2_internal = -1; // Sentinel
        } else { // n >= 4
            min_f_val_S2_internal = elements[2].value + elements[3].value;
            max_f_val_S2_internal = elements[n - 1].value + elements[n - 2].value;
        }

        long long min_f_val_cross = elements[0].value + elements[2].value + h;
        long long max_f_val_cross = elements[1].value + elements[n - 1].value + h;

        long long current_min_f_c3, current_max_f_c3;

        current_min_f_c3 = std::min(f_S1_internal, min_f_val_cross);
        if (n >= 4) {
            current_min_f_c3 = std::min(current_min_f_c3, min_f_val_S2_internal);
        }

        current_max_f_c3 = std::max(f_S1_internal, max_f_val_cross);
        if (n >= 4) {
            current_max_f_c3 = std::max(current_max_f_c3, max_f_val_S2_internal);
        }

        long long goodness_case3 = current_max_f_c3 - current_min_f_c3;

        if (goodness_case3 < min_goodness) {
            min_goodness = goodness_case3;
            best_partition[elements[0].original_index] = 1;
            best_partition[elements[1].original_index] = 1;
            for (int i = 2; i < n; ++i) {
                best_partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
