#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // last_bad_end[i] stores the maximum r such that s[i...r-1] does NOT contain a bad pattern.
    // Or, more precisely, it stores the minimum r such that s[i...r-1] contains a bad pattern.
    // If no bad pattern starts at or after i, then last_bad_end[i] = n + 1.
    // We want to find the smallest r >= i such that s[i-1...r-1] contains a bad pattern.
    // Let's define `min_r_with_bad_pattern[i]` as the smallest `r` such that `s[i-1...r-1]` contains a bad pattern.
    // If no such `r` exists for a given `i`, we can set it to `n + 1`.
    // Then, for a fixed `l`, the number of `r` values that do NOT contain a bad pattern is `min_r_with_bad_pattern[l] - l`.
    // The sum of these `min_r_with_bad_pattern[l] - l` for `l` from 1 to `n` gives the total number of bad pairs.

    // `next_bad_pattern_end[i]` stores the minimum `j` such that there exists a bad pattern `s_x = s_{x+k} = s_{x+2k}`
    // where `x >= i` and `x+2k = j`.
    // If no such pattern exists starting at or after `i`, then `next_bad_pattern_end[i] = n + 1`.
    std::vector<int> next_bad_pattern_end(n + 1, n + 1);

    // Iterate x from n-1 down to 0 (0-indexed)
    // For each x, iterate k.
    // The maximum possible k is such that x + 2k < n. So 2k < n - x. k < (n - x) / 2.
    // The maximum k is (n - x - 1) / 2.
    // We only need to check small values of k.
    // If k is large, then x+2k is large.
    // The problem constraints on k are 1 <= k <= n.
    // However, x+2k <= r <= n. So x+2k <= n.
    // The maximum value for 2k is n-1 (when x=0). So k can be up to (n-1)/2.
    // For n=300,000, k can be up to 150,000.
    // This approach is too slow if we iterate over all k.

    // Let's reconsider the condition: s_x = s_{x+k} = s_{x+2k}.
    // This means s[x-1] == s[x+k-1] == s[x+2k-1] in 0-indexed.
    // We are looking for the smallest r such that l <= x < x+2k <= r.
    // This means r must be at least x+2k.
    // For a fixed l, we want to find the smallest r.
    // This means we need to find the smallest x+2k for any x >= l.

    // Let `min_r_for_l[i]` be the minimum `r` such that `s[i-1...r-1]` contains a bad pattern.
    // If no such `r` exists, `min_r_for_l[i] = n + 1`.
    // We can compute this by iterating `i` from `n` down to `1`.
    // `min_r_for_l[i] = min(min_r_for_l[i+1], smallest_x_plus_2k_for_x_equals_i)`
    // where `smallest_x_plus_2k_for_x_equals_i` is the minimum `x+2k` for `x=i` that forms a bad pattern.

    // The maximum k we need to check is small.
    // If k is large, say k > 2 * sqrt(N), then 2k > 4 * sqrt(N).
    // The number of such patterns is limited.
    // For N=300,000, sqrt(N) approx 547.
    // Let's try a small constant for max_k, say 60.
    // If k > 60, then x+2k > x+120.
    // The number of such patterns is at most N/120.
    // The total number of (x, k) pairs to check is N * max_k.
    // N * 60 = 18,000,000. This is feasible.

    // Let `min_bad_end_idx[i]` be the minimum `j` such that `s[i-1...j-1]` contains a bad pattern.
    // Initialize `min_bad_end_idx[i] = n + 1` for all `i`.
    std::vector<int> min_bad_end_idx(n + 2, n + 1);

    // Iterate `x` from `n-1` down to `0` (0-indexed string indices)
    for (int x = n - 1; x >= 0; --x) {
        // The current `min_bad_end_idx[x+1]` is the minimum `r` for substrings starting at `x+1` or later.
        // We want to find the minimum `r` for substrings starting at `x` or later.
        // So, `min_bad_end_idx[x+1]` is a candidate for `min_bad_end_idx[x]`.
        min_bad_end_idx[x] = min_bad_end_idx[x + 1];

        // Check for bad patterns starting at `x`
        // k can go up to (n - 1 - x) / 2.
        // We only need to check small k values.
        // If k is large, say k > 60, then x+2k is far away.
        // The problem statement implies that the number of such patterns is small enough.
        // Let's try a small constant for max_k, say 60.
        // If k is larger than this, the patterns are very sparse.
        // The maximum k for which x+2k is within a reasonable distance from x.
        // For example, if x+2k - x <= 120, then 2k <= 120, k <= 60.
        // This means we only check patterns where the three characters are relatively close.
        // This is a common optimization for problems involving (x, k, x+2k) patterns.
        // The total number of such patterns is N * max_k.
        // For N=300,000, max_k=60, this is 1.8 * 10^7 operations, which is fine.
        for (int k = 1; k <= 60; ++k) { // k is 1-indexed gap
            if (x + 2 * k < n) { // x+2k is 0-indexed end of pattern
                if (s[x] == s[x + k] && s[x] == s[x + 2 * k]) {
                    // Found a bad pattern starting at x with gap k, ending at x+2k.
                    // The 1-indexed end position is (x+2k) + 1.
                    min_bad_end_idx[x] = std::min(min_bad_end_idx[x], (x + 2 * k) + 1);
                }
            } else {
                // x + 2k is out of bounds, no need to check larger k for this x.
                break;
            }
        }
    }

    // Now, `min_bad_end_idx[l-1]` (using 0-indexed `l-1` for string start)
    // stores the minimum `r` (1-indexed) such that `s[l-1...r-1]` contains a bad pattern.
    // For each `l` from 1 to `n`:
    // The number of `r` values (where `l <= r <= n`) that do NOT contain a bad pattern
    // is `min_bad_end_idx[l-1] - l`.
    // If `min_bad_end_idx[l-1]` is `n+1`, it means no bad pattern starts at or after `l-1`.
    // In this case, `n+1 - l` is the number of `r` values that do not contain a bad pattern.
    // This is correct: `n - l + 1` total `r` values, all of them are "good".
    for (int l = 0; l < n; ++l) { // l is 0-indexed string start
        bad_pairs += (min_bad_end_idx[l] - (l + 1)); // (l+1) is 1-indexed start
    }

    long long good_pairs = total_pairs - bad_pairs;
    std::cout << good_pairs << std::endl;

    return 0;
}

