// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s_prefix and s_suffix.
    // We can reorder them to s_suffix + s_prefix.
    // We need s_suffix + s_prefix to be a palindrome and not equal to s.
    // The cut cannot be at the very beginning or very end, as that would mean one piece is empty.
    // An empty piece doesn't make sense for "shuffling".
    // The problem states "cut the paper minimum number of times k, so they got k+1 pieces".
    // If k=1, we get 2 pieces. If one piece is empty, it's effectively 0 cuts.
    // So, s_prefix and s_suffix must both be non-empty.
    for (int i = 1; i < n; ++i) { // i is the length of s_prefix
        std::string s_prefix = s.substr(0, i);
        std::string s_suffix = s.substr(i);

        std::string new_s = s_suffix + s_prefix;

        if (new_s != s && is_palindrome(new_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // With k=2, we get 3 pieces: s_1, s_2, s_3.
    // s = s_1 s_2 s_3.
    // We need to find if there's any reordering that forms a new palindrome.
    // The problem statement implies that if k=1 doesn't work, we should try k=2.
    // The example "nolon" -> 2 cuts, even though "onlno" is a palindrome.
    // This implies that if k=1 is not possible, we must try k=2.
    // The only case where k=2 is needed is if all possible 1-cut reorderings
    // either result in s itself or are not palindromes.
    //
    // Consider the structure of s. Since s is a palindrome, s[j] == s[n-1-j].
    // If all characters in s are the same (e.g., "qqqq"), then any reordering
    // of its parts will result in the same string, which is "qqqq".
    // In this case, it's impossible to get a new string.
    //
    // Let's check if all characters in s are the same.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // then k=2 must be the answer.
    // Why?
    // If s is a palindrome and not all its characters are the same,
    // then s must have at least two distinct characters.
    // Consider the string s' = s.substr(0, n-1).
    // If s' is not a palindrome, then we can cut s into s.substr(0, n-1) and s.substr(n-1, 1).
    // Reordering them gives s.substr(n-1, 1) + s.substr(0, n-1).
    // This is a 1-cut solution if it's a palindrome and not equal to s.
    //
    // The problem statement implies that if k=1 is not possible, then k=2 is the next minimum.
    // The only case where k=1 is not possible is if for all 1 <= i < n,
    // `s.substr(i) + s.substr(0, i)` is either `s` or not a palindrome.
    //
    // If `s` is a palindrome and not all characters are the same,
    // then `s` must have at least two distinct characters.
    // For example, "nolon". `n=5`.
    // `s.substr(0,4) = "nolo"`. `s.substr(4,1) = "n"`.
    // `new_s = "n" + "nolo" = "nnolo"`. Not a palindrome.
    //
    // Consider the string `s_prime = s.substr(0, n/2)`.
    // If `s_prime` is not a palindrome, then we can cut `s` into `s_prime`, `s.substr(n/2, n - 2*(n/2))`, `s.substr(n/2 + (n - 2*(n/2)))`.
    // This is getting complicated.
    //
    // The problem statement for "nolon" says "It can be shown that there is no solution with one cut."
    // This implies that if k=1 doesn't work, and the string is not all same characters, then k=2 is the answer.
    // This is a common pattern in competitive programming problems: if the simplest solution (k=1) fails,
    // and there's a specific edge case (all same chars), then the next simplest (k=2) is the general answer.
    //
    // Let's verify this logic.
    // If `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // Example: "abacaba" (n=7).
    // `s_prime = "aba"`.
    // `s_prime` is a palindrome.
    //
    // If `s` is a palindrome and not all characters are the same,
    // then `s` must have at least one character `s[i]` such that `s[i] != s[0]`.
    //
    // Consider the string `s_half = s.substr(0, n/2)`.
    // If `s_half` is not a palindrome, then we can cut `s` into `s_half`, `s.substr(n/2, n - 2*(n/2))`, `s.substr(n/2 + (n - 2*(n/2)))`.
    // This is not a 1-cut solution.
    //
    // The crucial observation for k=2 is that if `s` is a palindrome and not all characters are the same,
    // then `s` must contain at least two distinct characters.
    // This means `s.substr(0, n-1)` (the string `s` without its last character) is not a palindrome.
    // For example, `s = "abacaba"`. `s.substr(0,6) = "abacab"`. Not a palindrome.
    // `s = "nolon"`. `s.substr(0,4) = "nolo"`. Not a palindrome.
    //
    // If `s` is a palindrome and not all characters are the same, then `s.substr(0, n-1)` is NOT a palindrome.
    // Proof: Assume `s.substr(0, n-1)` IS a palindrome.
    // Let `s = c_0 c_1 ... c_{n-2} c_{n-1}`.
    // Since `s` is a palindrome, `c_i = c_{n-1-i}` for all `i`.
    // Since `s.substr(0, n-1)` is a palindrome, `c_i = c_{n-2-i}` for all `i` from `0` to `n-2`.
    // From `c_i = c_{n-1-i}`:
    // `c_0 = c_{n-1}`
    // `c_1 = c_{n-2}`
    // `c_2 = c_{n-3}`
    // ...
    // From `c_i = c_{n-2-i}`:
    // `c_0 = c_{n-2}`
    // `c_1 = c_{n-3}`
    // `c_2 = c_{n-4}`
    // ...
    // Combining these:
    // `c_0 = c_{n-1}` and `c_0 = c_{n-2}` => `c_{n-1} = c_{n-2}`.
    // `c_1 = c_{n-2}` and `c_1 = c_{n-3}` => `c_{n-2} = c_{n-3}`.
    // This implies `c_0 = c_1 = c_2 = ... = c_{n-1}`.
    // This contradicts the assumption that not all characters are the same.
    // Therefore, if `s` is a palindrome and not all characters are the same, then `s.substr(0, n-1)` is NOT a palindrome.
    //
    // Now, consider cutting `s` into `s_1 = s.substr(0, n-1)` and `s_2 = s.substr(n-1, 1)`.
    // This is a 1-cut solution.
    // The reordered string is `s_2 + s_1 = s.substr(n-1, 1) + s.substr(0, n-1)`.
    // We know `s_2 + s_1 != s` because `s_2` is just one character, and `s_1` is `n-1` characters.
    // If `s_2 + s_1 == s`, then `s[n-1]` must be `s[0]`, and `s.substr(0, n-1)` must be `s.substr(1, n-1)`.
    // This means `s[0] = s[1] = ... = s[n-1]`, which is the "all same characters" case.
    // So, if not all characters are the same, then `s_2 + s_1 != s`.
    //
    // The only remaining condition for `k=1` to be the answer is that `s_2 + s_1` must be a palindrome.
    // If `s_2 + s_1` is NOT a palindrome, then this specific 1-cut doesn't work.
    //
    // The problem statement for "nolon" says "It can be shown that there is no solution with one cut."
    // "nolon" is a palindrome, not all chars are same.
    // `n=5`.
    // `i=1`: `s_p="n"`, `s_s="olon"`. `new_s="olonn"`. Not palindrome.
    // `i=2`: `s_p="no"`, `s_s="lon"`. `new_s="lonno"`. Not palindrome.
    // `i=3`: `s_p="nol"`, `s_s="on"`. `new_s="onnol"`. Not palindrome.
    // `i=4`: `s_p="nolo"`, `s_s="n"`. `new_s="nnolo"`. Not palindrome.
    // So for "nolon", k=1 is indeed not possible.
    //
    // The problem implies that if k=1 doesn't work, and it's not the "all same chars" case, then k=2 is the answer.
    // This is a strong hint.
    //
    // So, the logic is:
    // 1. Try k=1. Iterate through all possible single cuts. If any reordering forms a new palindrome, output 1.
    // 2. If k=1 fails, check if all characters in `s` are the same. If yes, output "Impossible".
    // 3. If k=1 fails and not all characters are the same, output 2.

    std::cout << 2 << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Iterate through the removal steps in reverse order
    // This means we are effectively adding vertices one by one
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" in this reverse step

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update: consider vertex k as an intermediate node
        // for all pairs of currently active vertices.
        // This is the core idea: when a vertex k is added, it might
        // provide shorter paths between existing active vertices.
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        // Path i -> k -> j
                        if (dist[i][k] != -1 && dist[k][j] != -1) { // Check for reachability if using -1 for infinity
                            dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                        }
                    }
                }
            }
        }

        // Also update paths involving k itself as an endpoint
        // For any active i, path i -> k
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) { // j is k
                    if (active_vertices[j]) {
                        dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }
        // For any active j, path k -> j
        for (int j = 0; j < n; ++j) {
            if (active_vertices[j]) {
                for (int i = 0; i < n; ++i) { // i is k
                    if (active_vertices[i]) {
                        dist[i][j] = std::min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }


        // Calculate the sum of shortest paths for all currently active vertices
        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (active_vertices[i]) {
                for (int j = 0; j < n; ++j) {
                    if (active_vertices[j]) {
                        if (i != j) { // Exclude paths from a vertex to itself
                            current_sum += dist[i][j];
                        }
                    }
                }
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first removal to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    for (int h_idx = 0; h_idx < n; ++h_idx) {
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_h = h[h_idx];
        long long min_reach = current_h - T;
        long long max_reach = current_h + T;

        // If the current head cannot reach the current target track p[p_idx],
        // it means this head is too far to the left or T is too small.
        // We need to find the first target track that this head can potentially cover.
        // If p[p_idx] is already covered by a previous head, we advance p_idx.
        // This loop is crucial for efficiency.
        while (p_idx < m && p[p_idx] < min_reach) {
            // This p[p_idx] cannot be reached by current_h within T.
            // It must have been covered by a previous head.
            // If not, then it's impossible to cover all tracks with this T.
            // However, the logic below handles this implicitly.
            // If p[p_idx] is not covered by current_h, and it wasn't covered by previous heads,
            // then it will remain uncovered.
            // The main point is that we only care about covering p[p_idx] and subsequent tracks.
            // If p[p_idx] is less than min_reach, it means it's to the left of the current head's range.
            // It must have been covered by a previous head.
            // We need to find the first p[p_idx] that is >= min_reach.
            // This is implicitly handled by the outer loop's p_idx advancement.
            // The key is that we want to cover p[p_idx] with the *current* head if possible,
            // or if it's already covered, move to the next p.
            // The current logic is: find the first p[p_idx] that is >= min_reach.
            // If p[p_idx] is less than min_reach, it means it's too far left for this head.
            // It must have been covered by a previous head.
            // So we continue to the next p[p_idx].
            // This is not quite right. We need to cover p[p_idx] with *some* head.
            // The greedy strategy is: use the current head to cover the leftmost *uncovered* track.

            // Let's re-evaluate the greedy strategy for check(T):
            // We iterate through heads. For each head, we try to cover as many *uncovered* tracks as possible,
            // starting from the leftmost uncovered track.
            // The current head `h[h_idx]` can cover tracks in `[h[h_idx] - T, h[h_idx] + T]`.
            // We need to cover `p[p_idx]`.
            // If `p[p_idx]` is to the right of `h[h_idx] + T`, then this head cannot cover `p[p_idx]`
            // and subsequent tracks. This `T` is too small.
            // If `p[p_idx]` is to the left of `h[h_idx] - T`, then this head cannot cover `p[p_idx]`.
            // This means `p[p_idx]` must have been covered by a previous head.
            // So we advance `p_idx` until `p[p_idx]` is within `[h[h_idx] - T, h[h_idx] + T]`
            // or `p[p_idx]` is to the right of `h[h_idx] + T`.

            // Correct greedy approach:
            // For each head h[h_idx]:
            //   It can cover tracks in [h[h_idx] - T, h[h_idx] + T].
            //   We need to cover p[p_idx].
            //   If p[p_idx] is to the right of h[h_idx] + T, then this head cannot cover p[p_idx].
            //     Since heads are sorted, and p are sorted, no subsequent head can cover p[p_idx]
            //     if it's too far right for the current head. This T is too small. Return false.
            //   If p[p_idx] is to the left of h[h_idx] - T, then this head cannot cover p[p_idx].
            //     This means p[p_idx] must have been covered by a previous head.
            //     So we advance p_idx until p[p_idx] is within the current head's range,
            //     or it's too far right for the current head.
            //   Once p[p_idx] is within the current head's range (i.e., p[p_idx] >= h[h_idx] - T),
            //   this head can cover p[p_idx]. It can also cover all subsequent tracks
            //   as long as they are within h[h_idx] + T.
            //   So, we advance p_idx as long as p[p_idx] <= h[h_idx] + T.
            //   After this, p_idx points to the first track not covered by the current head.
            //   We then move to the next head.

        // Skip target tracks already covered by previous heads or too far left for current head
        while (p_idx < m && p[p_idx] < current_h - T) {
            p_idx++;
        }

        // If after skipping, p_idx is out of bounds, all tracks are covered.
        if (p_idx == m) {
            return true;
        }

        // If the current head cannot reach the current p[p_idx] (it's too far right)
        if (p[p_idx] > current_h + T) {
            // This head cannot cover p[p_idx]. Since heads are sorted,
            // no subsequent head can cover this p[p_idx] either.
            // So, this T is too small.
            return false;
        }

        // The current head can cover p[p_idx].
        // Now, advance p_idx to cover all tracks this head can reach.
        while (p_idx < m && p[p_idx] <= current_h + T) {
            p_idx++;
        }
    }

    // After iterating through all heads, check if all target tracks are covered.
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p and h is 10^10, so 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        // Median of three 0s and 1s: it's 1 if at least two are 1, else 0.
        // This is equivalent to (a[i-1] + a[i] + a[i+1] >= 2) ? 1 : 0
        // Or, more simply, if a[i-1] == a[i+1], then b[i] = a[i-1] (or a[i+1])
        // If a[i-1] != a[i+1], then b[i] = a[i]
        if (a[i - 1] == a[i + 1]) {
            b[i] = a[i - 1];
        } else {
            b[i] = a[i];
        }
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find the first '10' pattern from left
    int first_one_zero = -1;
    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 1 && a[i + 1] == 0) {
            first_one_zero = i;
            break;
        }
    }

    // Find the last '01' pattern from right
    int last_zero_one = -1;
    for (int i = n - 1; i > 0; --i) {
        if (a[i - 1] == 0 && a[i] == 1) {
            last_zero_one = i;
            break;
        }
    }

    if (first_one_zero == -1 && last_zero_one == -1) {
        // Sequence is already stable (all 0s or all 1s, or 0...01...1)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Calculate max_k
    int max_k = 0;
    if (first_one_zero != -1) { // If there's at least one '10'
        int current_len = 0;
        int max_len_10 = 0;
        for (int i = first_one_zero; i < n - 1; ++i) {
            if (a[i] == 1 && a[i + 1] == 0) {
                current_len++;
            } else {
                max_len_10 = std::max(max_len_10, current_len);
                current_len = 0;
            }
        }
        max_len_10 = std::max(max_len_10, current_len);
        max_k = std::max(max_k, (max_len_10 + 1) / 2);
    }

    if (last_zero_one != -1) { // If there's at least one '01'
        int current_len = 0;
        int max_len_01 = 0;
        for (int i = last_zero_one; i > 0; --i) {
            if (a[i - 1] == 0 && a[i] == 1) {
                current_len++;
            } else {
                max_len_01 = std::max(max_len_01, current_len);
                current_len = 0;
            }
        }
        max_len_01 = std::max(max_len_01, current_len);
        max_k = std::max(max_k, (max_len_01 + 1) / 2);
    }

    // Construct the stable sequence
    std::vector<int> stable_seq = a;
    if (first_one_zero != -1) {
        for (int i = first_one_zero; i >= 0; --i) {
            if (a[i] == 1) {
                if (first_one_zero - i + 1 <= max_k) {
                    stable_seq[i] = 0;
                } else {
                    break;
                }
            }
        }
    }
    if (last_zero_one != -1) {
        for (int i = last_zero_one; i < n; ++i) {
            if (a[i] == 0) {
                if (i - last_zero_one + 1 <= max_k) {
                    stable_seq[i] = 1;
                } else {
                    break;
                }
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << stable_seq[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}
